const parseArgs = (argv) => {
  const args = {};
  for (let index = 0; index < argv.length; index += 1) {
    const token = argv[index];
    if (token === "--help" || token === "-h") {
      if (args.help === true) {
        throw new Error("--help may be provided exactly once.");
      }
      args.help = true;
      continue;
    }
    if (
      !/^--[a-z][a-z0-9-]*$/u.test(token) ||
      token.includes("=") ||
      token === "--"
    ) {
      throw new Error(
        "Unexpected positional argument or unsupported option syntax.",
      );
    }
    const key = token.slice(2);
    if (!SOLANA_DEPLOY_CLI_OPTION_KEYS.has(key)) {
      throw new Error(`Unknown option: --${key}`);
    }
    if (Object.prototype.hasOwnProperty.call(args, key)) {
      throw new Error(`--${key} may be provided exactly once.`);
    }
    const next = argv[index + 1];
    if (
      key === SOLANA_PROGRAM_FINALIZATION_CONFIRMATION_FLAG &&
      (next === undefined || next.startsWith("--") || next !== "true")
    ) {
      throw new Error(
        "--confirm-finalize-programs true must be supplied explicitly as the exact flag/value pair.",
      );
    }
    if (next === undefined || next === "" || next.startsWith("--")) {
      throw new Error(`--${key} requires an explicit following value.`);
    }
    args[key] = next;
    index += 1;
  }
  return args;
};

const asBoolean = (value) => value === true || value === "true";

const SOLANA_FINISH_PRODUCTION_COMMANDS = new Set([
  "finish-production",
  "finish",
  "production-finish",
]);

export const resolveSolanaFinishSubmissionMode = (args = {}) => {
  if (!Object.prototype.hasOwnProperty.call(args, "submit")) {
    throw new Error(
      "finish-production requires an explicit --submit true or --submit false before any report, endpoint, signer, or mutation access.",
    );
  }
  if (args.submit === true || args.submit === "true") {
    return {
      mode: "submit",
      explicitlySelected: true,
      mutationAuthorized: true,
    };
  }
  if (args.submit === false || args.submit === "false") {
    return {
      mode: "dry-run",
      explicitlySelected: true,
      mutationAuthorized: false,
    };
  }
  throw new Error(
    "finish-production --submit must be exactly true or false before any report, endpoint, signer, or mutation access.",
  );
};

const asPositiveNumber = (value, fallback, label) => {
  if (value === undefined || value === null || value === "") {
    return fallback;
  }
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    throw new Error(`${label} must be a positive number.`);
  }
  return parsed;
};

const asNonNegativeInteger = (value, fallback, label) => {
  if (value === undefined || value === null || value === "") {
    return fallback;
  }
  const parsed = Number(value);
  if (!Number.isSafeInteger(parsed) || parsed < 0) {
    throw new Error(`${label} must be a non-negative integer.`);
  }
  return parsed;
};

const requireOption = (args, key) => {
  const value = args[key];
  if (typeof value !== "string" || !value.trim()) {
    throw new Error(`--${key} is required.`);
  }
  return value.trim();
};

const optionalStringOption = (args, key) => {
  const value = args[key];
  return typeof value === "string" && value.trim() ? value.trim() : null;
};

