const SOLANA_KEY_MATERIAL_FILE_NAME =
  /(?:^|[-_.])(?:keypair|private[-_]?key|secret[-_]?key|seed|mnemonic)(?:[-_.]|$)/iu;

export const auditFileBackedSolanaKeyMaterial = async ({
  outputRoot = path.join(repoRoot, "output"),
  checkedAt = new Date().toISOString(),
} = {}) => {
  const absoluteRoot = path.resolve(outputRoot);
  const findings = [];
  const visit = async (directory) => {
    let entries;
    try {
      entries = await readdir(directory, { withFileTypes: true });
    } catch (error) {
      if (error?.code === "ENOENT") return;
      throw error;
    }
    for (const entry of entries) {
      const candidate = path.join(directory, entry.name);
      if (entry.isSymbolicLink()) {
        if (SOLANA_KEY_MATERIAL_FILE_NAME.test(entry.name)) {
          findings.push({
            path: path.relative(repoRoot, candidate),
            type: "symbolic-link",
          });
        }
        continue;
      }
      if (entry.isDirectory()) {
        await visit(candidate);
      } else if (
        entry.isFile() &&
        SOLANA_KEY_MATERIAL_FILE_NAME.test(entry.name)
      ) {
        findings.push({
          path: path.relative(repoRoot, candidate),
          type: "regular-file",
        });
      }
    }
  };
  let topLevelEntries = [];
  try {
    topLevelEntries = await readdir(absoluteRoot, { withFileTypes: true });
  } catch (error) {
    if (error?.code !== "ENOENT") throw error;
  }
  for (const entry of topLevelEntries) {
    if (!entry.name.startsWith("sccp-solana")) continue;
    if (entry.isSymbolicLink()) {
      findings.push({
        path: path.relative(repoRoot, path.join(absoluteRoot, entry.name)),
        type: "untrusted-root-link",
      });
    } else if (entry.isDirectory()) {
      await visit(path.join(absoluteRoot, entry.name));
    }
  }
  findings.sort((left, right) => left.path.localeCompare(right.path));
  const ready = findings.length === 0;
  const blockers = ready
    ? []
    : [
        {
          id: "file-backed-solana-key-material",
          detail:
            "File-backed Solana key material exists under output/sccp-solana*. Rotate or revoke affected authorities and remove the files through an explicitly authorized operator procedure before production completion.",
        },
      ];
  return {
    schema: "iroha-demo-sccp-solana-file-backed-key-material-audit/v1",
    checkedAt,
    ready,
    findingCount: findings.length,
    findings,
    blockers,
    blockerIds: blockers.map((blocker) => blocker.id),
  };
};

const commandExists = (command) =>
  spawnSync("sh", ["-c", `command -v ${command}`], {
    encoding: "utf8",
  }).status === 0;

const run = (command, args, options = {}) => {
  const result = spawnSync(command, args, {
    encoding: "utf8",
    stdio: ["ignore", "pipe", "pipe"],
    ...options,
  });
  if (result.status !== 0) {
    const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
    throw new Error(`${command} ${args.join(" ")} failed:\n${output}`);
  }
  return result.stdout?.trim() ?? "";
};

const runNodeHelper = (args, options = {}) =>
  run(process.execPath, [siblingDeployScript, ...args], options);

const syncPublicArtifactDirectory = async (directory) => {
  let handle = null;
  try {
    handle = await open(
      directory,
      fsConstants.O_RDONLY | (fsConstants.O_DIRECTORY ?? 0),
    );
    await handle.sync();
  } catch (error) {
    if (
      !["EINVAL", "ENOTSUP", "EISDIR", "EBADF", "EPERM"].includes(error?.code)
    ) {
      throw error;
    }
  } finally {
    await handle?.close().catch(() => {});
  }
};

const writePublicArtifactAtomically = async (file, contents) => {
  const output = path.resolve(file);
  await mkdir(path.dirname(output), { recursive: true });
  const temporary = `${output}.tmp-${process.pid}-${randomBytes(12).toString("hex")}`;
  let handle = null;
  try {
    handle = await open(
      temporary,
      fsConstants.O_CREAT | fsConstants.O_EXCL | fsConstants.O_WRONLY,
      0o600,
    );
    await handle.writeFile(contents);
    await handle.sync();
    await handle.close();
    handle = null;
    await rename(temporary, output);
    await syncPublicArtifactDirectory(path.dirname(output));
  } catch (error) {
    await handle?.close().catch(() => {});
    await rm(temporary, { force: true }).catch(() => {});
    throw error;
  }
};

const writePublicJson = async (file, value) =>
  writePublicArtifactAtomically(file, `${JSON.stringify(value, null, 2)}\n`);

const writePublicText = async (file, value) =>
  writePublicArtifactAtomically(
    file,
    value.endsWith("\n") ? value : `${value}\n`,
  );

const SOLANA_ONE_SHOT_MUTATION_INTENT_SCHEMA =
  "iroha-demo-sccp-solana-one-shot-mutation-intent/v1";
const SOLANA_ONE_SHOT_MUTATION_RESOLUTION_SCHEMA =
  "iroha-demo-sccp-solana-one-shot-mutation-resolution/v1";

export const solanaOneShotMutationJournalPaths = ({ operation, target }) => {
  if (
    !["program-finalization", "native-verifier-configuration"].includes(
      operation,
    ) ||
    !isRecord(target) ||
    Object.keys(target).length === 0
  ) {
    throw new Error("Solana one-shot mutation journal identity is invalid.");
  }
  const canonicalTarget = Object.fromEntries(
    Object.entries(target).sort(([left], [right]) => left.localeCompare(right)),
  );
  const identitySha256 = sha256JsonHex({
    solanaGenesisHash: SOLANA_TESTNET_GENESIS_HASH,
    operation,
    target: canonicalTarget,
  });
  const directory = path.join(
    SOLANA_ONE_SHOT_MUTATION_JOURNAL_ROOT,
    SOLANA_TESTNET_GENESIS_HASH,
    operation,
    identitySha256.slice(2),
  );
  return Object.freeze({
    root: SOLANA_ONE_SHOT_MUTATION_JOURNAL_ROOT,
    directory,
    identitySha256,
    intent: path.join(directory, "active.intent.json"),
    resolution: path.join(directory, "active.resolution.json"),
  });
};

const writePublicJsonExclusively = async (file, value) => {
  const output = path.resolve(file);
  await mkdir(path.dirname(output), { recursive: true });
  let handle = null;
  try {
    handle = await open(
      output,
      fsConstants.O_CREAT |
        fsConstants.O_EXCL |
        fsConstants.O_WRONLY |
        (fsConstants.O_NOFOLLOW ?? 0),
      0o600,
    );
    await handle.writeFile(`${JSON.stringify(value, null, 2)}\n`);
    await handle.sync();
    await handle.close();
    handle = null;
    await syncPublicArtifactDirectory(path.dirname(output));
  } finally {
    await handle?.close().catch(() => {});
  }
  return output;
};

export const buildSolanaOneShotMutationIntent = ({
  operation,
  transaction,
  rawTransaction,
  latestBlockhash,
  authority,
  target,
  operationBinding,
  bindings = {},
  checkedAt = new Date().toISOString(),
} = {}) => {
  const raw = Buffer.from(rawTransaction ?? []);
  const serialized = Buffer.from(
    transaction?.serialize?.({
      requireAllSignatures: true,
      verifySignatures: true,
    }) ?? [],
  );
  const signature = transaction?.signature
    ? bs58.encode(transaction.signature)
    : null;
  const messageBytes = Buffer.from(transaction?.serializeMessage?.() ?? []);
  if (
    !["program-finalization", "native-verifier-configuration"].includes(
      operation,
    ) ||
    raw.length === 0 ||
    raw.length > SOLANA_PACKET_DATA_SIZE ||
    !serialized.equals(raw) ||
    !isCanonicalSolanaSignature(signature) ||
    !isCanonicalSolanaBlockhash(latestBlockhash?.blockhash) ||
    !Number.isSafeInteger(latestBlockhash?.lastValidBlockHeight) ||
    latestBlockhash.lastValidBlockHeight <= 0 ||
    transaction.recentBlockhash !== latestBlockhash.blockhash ||
    transaction.feePayer?.toBase58?.() !== authority
  ) {
    throw new Error(
      "Canonical Solana one-shot mutation intent is invalid or incomplete.",
    );
  }
  const journalIdentity = solanaOneShotMutationJournalPaths({
    operation,
    target,
  });
  if (!isRecord(operationBinding)) {
    throw new Error("Solana one-shot governed operation binding is missing.");
  }
  const body = {
    schema: SOLANA_ONE_SHOT_MUTATION_INTENT_SCHEMA,
    checkedAt,
    operation,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    solanaNetwork: SOLANA_TESTNET_NETWORK_ID,
    solanaGenesisHash: SOLANA_TESTNET_GENESIS_HASH,
    authority,
    target,
    journalIdentitySha256: journalIdentity.identitySha256,
    operationBinding,
    operationBindingSha256: sha256JsonHex(operationBinding),
    expectedSignature: signature,
    expectedSignatures: [signature],
    blockhash: latestBlockhash.blockhash,
    lastValidBlockHeight: latestBlockhash.lastValidBlockHeight,
    messageSha256: sha256BufferHex(messageBytes),
    packetSha256: sha256BufferHex(raw),
    packetLength: raw.length,
    rawTransactionBase64: raw.toString("base64"),
    bindings,
  };
  validateSolanaOneShotMutationOperation({ intent: body, transaction });
  return {
    ...body,
    intentSha256: sha256JsonHex(body),
  };
};

const validateSolanaOneShotMutationOperation = ({ intent, transaction }) => {
  const bindings = intent?.bindings;
  const operationBinding = intent?.operationBinding;
  const instructions = transaction?.instructions;
  if (
    !isRecord(bindings) ||
    !isRecord(operationBinding) ||
    !Array.isArray(instructions) ||
    operationBinding.authority !== intent.authority
  ) {
    throw new Error("Solana one-shot mutation operation binding is missing.");
  }
  if (intent.operation === "program-finalization") {
    const mutableRoles = Array.isArray(bindings.mutableRoles)
      ? bindings.mutableRoles
      : [];
    const expectedInstructions = Array.isArray(bindings.instructions)
      ? bindings.instructions
      : [];
    const canonicalRoles = SOLANA_FINALIZATION_ROLE_NAMES.filter((role) =>
      mutableRoles.includes(role),
    );
    if (
      mutableRoles.length === 0 ||
      JSON.stringify(mutableRoles) !== JSON.stringify(canonicalRoles) ||
      instructions.length !== mutableRoles.length ||
      expectedInstructions.length !== mutableRoles.length ||
      bindings.instructionSetSha256 !== sha256JsonHex(expectedInstructions) ||
      !isRecord(bindings.artifactSha256ByRole) ||
      bindings.governanceApprovalSha256 !==
        operationBinding.governanceApprovalSha256 ||
      JSON.stringify(bindings.artifactSha256ByRole) !==
        JSON.stringify(operationBinding.artifactSha256ByRole)
    ) {
      throw new Error(
        "Program-finalization intent does not bind the canonical role and instruction set.",
      );
    }
    for (let index = 0; index < instructions.length; index += 1) {
      const instruction = instructions[index];
      const expected = expectedInstructions[index];
      const metas = instruction.keys.map((meta) => ({
        pubkey: meta.pubkey.toBase58(),
        isSigner: meta.isSigner,
        isWritable: meta.isWritable,
      }));
      if (
        expected?.role !== mutableRoles[index] ||
        instruction.programId.toBase58() !== SOLANA_UPGRADEABLE_LOADER_ID ||
        `0x${Buffer.from(instruction.data).toString("hex")}` !==
          SOLANA_LOADER_V3_SET_AUTHORITY_NONE_DATA_HEX ||
        expected.loaderProgramId !== SOLANA_UPGRADEABLE_LOADER_ID ||
        expected.dataHex !== SOLANA_LOADER_V3_SET_AUTHORITY_NONE_DATA_HEX ||
        expected.authorityAddress !== intent.authority ||
        expected.programdataAddress !== intent.target?.[mutableRoles[index]] ||
        !Array.isArray(expected.metas) ||
        expected.metas.length !== 2 ||
        expected.metas[0]?.pubkey !== expected.programdataAddress ||
        expected.metas[0]?.isSigner !== false ||
        expected.metas[0]?.isWritable !== true ||
        expected.metas[1]?.pubkey !== intent.authority ||
        expected.metas[1]?.isSigner !== true ||
        expected.metas[1]?.isWritable !== false ||
        metas.length !== 2 ||
        metas[0].pubkey !== expected.programdataAddress ||
        metas[0].isSigner !== false ||
        metas[0].isWritable !== true ||
        metas[1].pubkey !== intent.authority ||
        metas[1].isSigner !== true
      ) {
        throw new Error(
          "Program-finalization intent packet is not the canonical Loader-v3 SetAuthority-to-None transaction.",
        );
      }
    }
  } else if (intent.operation === "native-verifier-configuration") {
    if (instructions.length !== 1) {
      throw new Error(
        "Native-verifier configuration intent must contain one instruction.",
      );
    }
    const instruction = instructions[0];
    const expectedMetas = [
      [intent.authority, true, false],
      [bindings.verifierStateAddress, false, true],
      [bindings.nativeVerifierProgramId, false, false],
      [bindings.nativeVerifierProgramdataAddress, false, false],
      [bindings.verifierProgramId, false, false],
      [bindings.verifierProgramdataAddress, false, false],
    ];
    const metas = instruction.keys.map((meta) => [
      meta.pubkey.toBase58(),
      meta.isSigner,
      meta.isWritable,
    ]);
    const canonicalMetas =
      metas.length === expectedMetas.length &&
      metas.every(
        (meta, index) =>
          meta[0] === expectedMetas[index][0] &&
          meta[1] === expectedMetas[index][1] &&
          (index === 0 || meta[2] === expectedMetas[index][2]),
      );
    const expectedData = buildConfigureNativeVerifierInstructionData({
      verifierMaterialHash: bindings.verifierMaterialHash,
      verifierConfigHash: bindings.verifierConfigHash,
    });
    if (
      bindings.verifierProgramId !== intent.target?.verifierProgramId ||
      bindings.verifierStateAddress !== intent.target?.verifierStateAddress ||
      bindings.nativeVerifierProgramId !==
        operationBinding.nativeVerifierProgramId ||
      bindings.verifierMaterialHash !== operationBinding.verifierMaterialHash ||
      bindings.verifierConfigHash !== operationBinding.verifierConfigHash ||
      bindings.nativeVerifierArtifactSha256 !==
        operationBinding.nativeVerifierArtifactSha256 ||
      bindings.governedPackageArtifactSha256 !==
        operationBinding.governedPackageArtifactSha256 ||
      bindings.governedManifestArtifactSha256 !==
        operationBinding.governedManifestArtifactSha256 ||
      bindings.governanceApprovalSha256 !==
        operationBinding.governanceApprovalSha256 ||
      instruction.programId.toBase58() !== bindings.verifierProgramId ||
      !canonicalMetas ||
      !Buffer.from(instruction.data).equals(expectedData)
    ) {
      throw new Error(
        "Native-verifier configuration intent packet is not the canonical one-shot instruction.",
      );
    }
  } else {
    throw new Error("Solana one-shot mutation operation is unsupported.");
  }
  const routeAbsenceArtifactSha256 = normalizeProductionMaterialHex32(
    bindings.routeAbsencePublicPreflightArtifactSha256,
    "one-shot route-absence quorum artifact SHA-256",
  );
  const routeAbsenceAuthorizationValidation =
    buildSolanaRouteAbsenceMutationAuthorizationValidation({
      authorization: bindings.routeAbsenceMutationAuthorization,
      expectedPhase: "before-broadcast",
    });
  if (
    !routeAbsenceAuthorizationValidation.ready ||
    bindings.routeAbsenceMutationAuthorization
      ?.publicPreflightArtifactSha256 !== routeAbsenceArtifactSha256
  ) {
    throw new Error(
      "Solana one-shot mutation intent does not contain its exact authoritative route-absence quorum authorization.",
    );
  }
  return true;
};

const validateSolanaOneShotMutationIntent = (intent) => {
  if (!isRecord(intent)) {
    throw new Error("Solana one-shot mutation intent is missing.");
  }
  const { intentSha256, ...body } = intent;
  const raw = Buffer.from(intent.rawTransactionBase64 ?? "", "base64");
  let transaction;
  try {
    transaction = Transaction.from(raw);
  } catch {
    throw new Error("Solana one-shot mutation intent packet is invalid.");
  }
  const signatures = transaction.signatures.map((entry) =>
    entry.signature ? bs58.encode(entry.signature) : null,
  );
  if (
    intent.schema !== SOLANA_ONE_SHOT_MUTATION_INTENT_SCHEMA ||
    intent.routeId !== SCCP_SOLANA_XOR_ROUTE_ID ||
    intent.assetKey !== SCCP_XOR_ASSET_KEY ||
    intent.solanaNetwork !== SOLANA_TESTNET_NETWORK_ID ||
    intent.solanaGenesisHash !== SOLANA_TESTNET_GENESIS_HASH ||
    !isRecord(intent.target) ||
    intent.journalIdentitySha256 !==
      solanaOneShotMutationJournalPaths({
        operation: intent.operation,
        target: intent.target,
      }).identitySha256 ||
    !isRecord(intent.operationBinding) ||
    intent.operationBindingSha256 !== sha256JsonHex(intent.operationBinding) ||
    sha256JsonHex(body) !== intentSha256 ||
    raw.length !== intent.packetLength ||
    sha256BufferHex(raw) !== intent.packetSha256 ||
    sha256BufferHex(Buffer.from(transaction.serializeMessage())) !==
      intent.messageSha256 ||
    JSON.stringify(signatures) !== JSON.stringify(intent.expectedSignatures) ||
    signatures[0] !== intent.expectedSignature ||
    transaction.recentBlockhash !== intent.blockhash ||
    transaction.feePayer?.toBase58() !== intent.authority ||
    !Number.isSafeInteger(intent.lastValidBlockHeight) ||
    intent.lastValidBlockHeight <= 0
  ) {
    throw new Error(
      "Solana one-shot mutation intent bytes, hashes, signature, or identity are invalid.",
    );
  }
  validateSolanaOneShotMutationOperation({ intent, transaction });
  return { intent, rawTransaction: raw, transaction };
};

export const resolveSolanaOneShotMutationIntent = async ({
  connection,
  intent,
  attempts = 4,
  delayMs = 250,
} = {}) => {
  validateSolanaOneShotMutationIntent(intent);
  await assertSolanaTestnetRpcConnection(connection);
  for (let attempt = 1; attempt <= attempts; attempt += 1) {
    const [statuses, observedBlockHeight] = await Promise.all([
      connection.getSignatureStatuses([intent.expectedSignature], {
        searchTransactionHistory: true,
      }),
      connection.getBlockHeight("finalized"),
    ]);
    const status = statuses?.value?.[0] ?? null;
    if (
      status?.confirmationStatus === "finalized" &&
      Number.isSafeInteger(status.slot) &&
      status.slot > 0
    ) {
      if (status.err !== null) {
        return {
          status: "failed",
          signature: intent.expectedSignature,
          finalizedSlot: status.slot,
          transactionError: status.err,
          observedBlockHeight,
        };
      }
      const transactionReadback = await connection.getTransaction(
        intent.expectedSignature,
        { commitment: "finalized", maxSupportedTransactionVersion: 0 },
      );
      const fetchedSignatures =
        transactionReadback?.transaction?.signatures ??
        transactionReadback?.signatures ??
        [];
      if (
        transactionReadback?.slot !== status.slot ||
        !isRecord(transactionReadback?.meta) ||
        transactionReadback.meta.err !== null ||
        JSON.stringify(fetchedSignatures) !==
          JSON.stringify(intent.expectedSignatures) ||
        sha256BufferHex(
          finalizedTransactionMessageBytes(transactionReadback),
        ) !== intent.messageSha256
      ) {
        throw new Error(
          "Resolved Solana one-shot mutation transaction readback is not exact.",
        );
      }
      await assertSolanaTestnetRpcConnection(connection);
      return {
        status: "finalized",
        signature: intent.expectedSignature,
        finalizedSlot: status.slot,
        observedBlockHeight,
        submittedResult: {
          signature: intent.expectedSignature,
          confirmation: { value: { err: null } },
          signatureStatus: status,
          transactionReadback,
        },
      };
    }
    if (
      status === null &&
      Number.isSafeInteger(observedBlockHeight) &&
      observedBlockHeight > intent.lastValidBlockHeight
    ) {
      await assertSolanaTestnetRpcConnection(connection);
      return {
        status: "expired",
        signature: intent.expectedSignature,
        observedBlockHeight,
      };
    }
    if (attempt < attempts) await sleep(delayMs);
  }
  await assertSolanaTestnetRpcConnection(connection);
  return { status: "ambiguous", signature: intent.expectedSignature };
};

const solanaOneShotMutationError = ({ intent, resolution, cause = null }) => {
  const causeDetail =
    cause instanceof Error && cause.message ? ` ${cause.message}` : "";
  const error = new Error(
    `Solana ${intent.operation} transaction ${intent.expectedSignature} is ${resolution?.status ?? "ambiguous"}; no replacement transaction may be signed or broadcast.${causeDetail}`,
  );
  error.cause = cause ?? undefined;
  error.mutationAttempted = true;
  error.mutationSubmitted = ["finalized", "failed"].includes(
    resolution?.status,
  );
  error.mutationAmbiguous = !["finalized", "failed", "expired"].includes(
    resolution?.status,
  );
  error.transactionHash = intent.expectedSignature;
  error.intentSha256 = intent.intentSha256;
  error.resolution = resolution ?? null;
  return error;
};

const buildSolanaOneShotMutationResolution = ({
  intent,
  resolution,
  checkedAt = new Date().toISOString(),
}) => {
  const body = {
    schema: SOLANA_ONE_SHOT_MUTATION_RESOLUTION_SCHEMA,
    checkedAt,
    operation: intent.operation,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    intentSha256: intent.intentSha256,
    expectedSignature: intent.expectedSignature,
    messageSha256: intent.messageSha256,
    packetSha256: intent.packetSha256,
    status: resolution.status,
    finalizedSlot: resolution.finalizedSlot ?? null,
    observedBlockHeight: resolution.observedBlockHeight ?? null,
    transactionError: resolution.transactionError ?? null,
  };
  return {
    ...body,
    resolutionSha256: sha256JsonHex(body),
  };
};

const validateSolanaOneShotMutationResolution = ({ intent, resolution }) => {
  if (!isRecord(resolution)) {
    throw new Error("Solana one-shot mutation resolution is missing.");
  }
  const { resolutionSha256, ...body } = resolution;
  if (
    resolution.schema !== SOLANA_ONE_SHOT_MUTATION_RESOLUTION_SCHEMA ||
    resolution.operation !== intent.operation ||
    resolution.routeId !== SCCP_SOLANA_XOR_ROUTE_ID ||
    resolution.assetKey !== SCCP_XOR_ASSET_KEY ||
    resolution.intentSha256 !== intent.intentSha256 ||
    resolution.expectedSignature !== intent.expectedSignature ||
    resolution.messageSha256 !== intent.messageSha256 ||
    resolution.packetSha256 !== intent.packetSha256 ||
    !["finalized", "failed", "expired"].includes(resolution.status) ||
    sha256JsonHex(body) !== resolutionSha256 ||
    (resolution.status === "finalized" &&
      (!Number.isSafeInteger(resolution.finalizedSlot) ||
        resolution.finalizedSlot <= 0 ||
        resolution.transactionError !== null)) ||
    (resolution.status === "failed" &&
      (!Number.isSafeInteger(resolution.finalizedSlot) ||
        resolution.finalizedSlot <= 0 ||
        resolution.transactionError === null)) ||
    (resolution.status === "expired" &&
      (resolution.finalizedSlot !== null ||
        resolution.transactionError !== null ||
        !Number.isSafeInteger(resolution.observedBlockHeight) ||
        resolution.observedBlockHeight <= intent.lastValidBlockHeight))
  ) {
    throw new Error(
      "Solana one-shot mutation resolution does not exactly bind its intent.",
    );
  }
  return resolution;
};

const persistSolanaOneShotMutationIntent = async ({ file, intent }) => {
  validateSolanaOneShotMutationIntent(intent);
  try {
    await writePublicJsonExclusively(file, intent);
  } catch (error) {
    if (error?.code === "EEXIST") {
      throw solanaOneShotMutationError({
        intent,
        resolution: { status: "active-intent-already-exists" },
        cause: error,
      });
    }
    throw error;
  }
  const artifact = await readStablePublicSolanaJsonArtifact({
    file,
    label: `Durable Solana ${intent.operation} mutation intent`,
    expectedSha256: sha256BufferHex(
      Buffer.from(`${JSON.stringify(intent, null, 2)}\n`),
    ),
  });
  validateSolanaOneShotMutationIntent(artifact.value);
  return artifact;
};

const persistSolanaOneShotMutationResolution = async ({
  file,
  intent,
  resolution,
}) => {
  const record = buildSolanaOneShotMutationResolution({ intent, resolution });
  try {
    await writePublicJsonExclusively(file, record);
  } catch (error) {
    if (error?.code !== "EEXIST") throw error;
  }
  const artifact = await readStablePublicSolanaJsonArtifact({
    file,
    label: `Durable Solana ${intent.operation} mutation resolution`,
  });
  validateSolanaOneShotMutationResolution({
    intent,
    resolution: artifact.value,
  });
  if (JSON.stringify(artifact.value) !== JSON.stringify(record)) {
    throw new Error(
      `Existing durable Solana ${intent.operation} mutation resolution differs from the exact outcome being persisted.`,
    );
  }
  return artifact;
};

const reconcileExistingSolanaOneShotMutation = async ({
  connection,
  intentPath,
  resolutionPath,
  expectedOperation,
  expectedTarget,
  expectedOperationBinding,
}) => {
  if (!existsSync(intentPath)) return null;
  const intentArtifact = await readStablePublicSolanaJsonArtifact({
    file: intentPath,
    label: "Existing Solana one-shot mutation intent",
  });
  const { intent } = validateSolanaOneShotMutationIntent(intentArtifact.value);
  if (
    intent.operation !== expectedOperation ||
    JSON.stringify(intent.target) !== JSON.stringify(expectedTarget) ||
    JSON.stringify(intent.operationBinding) !==
      JSON.stringify(expectedOperationBinding)
  ) {
    throw new Error(
      "Existing Solana one-shot mutation intent does not match the current governed target and operation binding.",
    );
  }
  let resolutionArtifact = null;
  if (existsSync(resolutionPath)) {
    resolutionArtifact = await readStablePublicSolanaJsonArtifact({
      file: resolutionPath,
      label: "Existing Solana one-shot mutation resolution",
    });
    validateSolanaOneShotMutationResolution({
      intent,
      resolution: resolutionArtifact.value,
    });
  } else {
    let liveResolution;
    try {
      liveResolution = await resolveSolanaOneShotMutationIntent({
        connection,
        intent,
      });
    } catch (cause) {
      throw solanaOneShotMutationError({
        intent,
        resolution: { status: "ambiguity-resolution-read-failed" },
        cause,
      });
    }
    if (liveResolution.status === "ambiguous") {
      throw solanaOneShotMutationError({ intent, resolution: liveResolution });
    }
    resolutionArtifact = await persistSolanaOneShotMutationResolution({
      file: resolutionPath,
      intent,
      resolution: liveResolution,
    });
  }
  if (resolutionArtifact.value.status !== "finalized") {
    throw solanaOneShotMutationError({
      intent,
      resolution: resolutionArtifact.value,
    });
  }
  return {
    intent,
    intentPath: intentArtifact.path,
    intentArtifactSha256: intentArtifact.sha256,
    resolution: resolutionArtifact.value,
    resolutionPath: resolutionArtifact.path,
    resolutionArtifactSha256: resolutionArtifact.sha256,
  };
};

const readJson = async (file) => JSON.parse(await readFile(file, "utf8"));

const readOptionalJson = async (file) =>
  existsSync(file) ? readJson(file) : null;

const SOLANA_PUBLIC_CONFIG_SECRET_FIELDS = new Set([
  "deployerKeypairFile",
  "programIdKeypairFile",
  "verifierProgramIdKeypairFile",
  "nativeVerifierProgramIdKeypairFile",
  "bridgeProgramIdKeypairFile",
  "sourceBridgeProgramIdKeypairFile",
  "verifierStateKeypairFile",
  "sourceStateKeypairFile",
  "tokenMintKeypairFile",
]);
const SOLANA_PUBLIC_CONFIG_SECRET_FIELD_PATTERN =
  /keypair|private.?key|secret.?key|mnemonic|seed.?phrase|wallet.?backup/iu;

export const sanitizeSolanaPublicConfig = (config) => {
  if (Array.isArray(config)) {
    return config.map((entry) => sanitizeSolanaPublicConfig(entry));
  }
  if (!isRecord(config)) {
    return config;
  }
  return Object.fromEntries(
    Object.entries(config)
      .filter(
        ([key]) =>
          !SOLANA_PUBLIC_CONFIG_SECRET_FIELDS.has(key) &&
          !SOLANA_PUBLIC_CONFIG_SECRET_FIELD_PATTERN.test(key),
      )
      .map(([key, value]) => [key, sanitizeSolanaPublicConfig(value)]),
  );
};

const readSolanaPublicConfig = async (file) => {
  const parsed = await readJson(file);
  const sanitized = sanitizeSolanaPublicConfig(parsed);
  if (JSON.stringify(sanitized) !== JSON.stringify(parsed)) {
    await writePublicJson(file, sanitized);
  }
  return sanitized;
};

const readOptionalSolanaPublicConfig = async (file) => {
  if (!existsSync(file)) {
    return null;
  }
  return readSolanaPublicConfig(file);
};

const writeSolanaPublicConfig = async (file, value) =>
  writePublicJson(file, sanitizeSolanaPublicConfig(value));

const RUNTIME_SECRET_ENV_NAME_PATTERN = /^[A-Z][A-Z0-9_]{2,127}$/u;

export const normalizeRuntimeSecretEnvName = (
  value,
  fallback = DEFAULT_SOLANA_RUNTIME_SIGNER_ENV,
) => {
  const candidate =
    typeof value === "string" && value.trim() ? value.trim() : fallback;
  if (!RUNTIME_SECRET_ENV_NAME_PATTERN.test(candidate)) {
    throw new Error("Runtime signer environment variable name is invalid.");
  }
  return candidate;
};

const decodeRuntimeSolanaSecretKey = (value) => {
  if (typeof value !== "string") {
    throw new Error("missing");
  }
  if (/^hex:[0-9a-f]{128}$/iu.test(value)) {
    return Uint8Array.from(Buffer.from(value.slice(4), "hex"));
  }
  if (/^base64:[A-Za-z0-9+/]+={0,2}$/u.test(value)) {
    const encoded = value.slice(7);
    const bytes = Buffer.from(encoded, "base64");
    if (bytes.length === 64) {
      return Uint8Array.from(bytes);
    }
  }
  throw new Error("invalid");
};

export const zeroizeRuntimeSolanaSigner = (signer) => {
  const internalSecret = signer?._keypair?.secretKey;
  if (ArrayBuffer.isView(internalSecret)) {
    internalSecret.fill(0);
  }
  const exposedCopy = signer?.secretKey;
  if (ArrayBuffer.isView(exposedCopy)) {
    exposedCopy.fill(0);
  }
};

export const loadRuntimeSolanaSigner = ({
  env = process.env,
  envName = DEFAULT_SOLANA_RUNTIME_SIGNER_ENV,
  expectedAddress = null,
  label = "Solana transaction",
} = {}) => {
  const normalizedEnvName = normalizeRuntimeSecretEnvName(envName);
  const operationLabel =
    typeof label === "string" && /^[A-Za-z0-9 -]{1,80}$/u.test(label)
      ? label
      : "Solana transaction";
  const encoded = env?.[normalizedEnvName];
  if (typeof encoded !== "string" || !encoded) {
    throw new Error(
      `${operationLabel} requires 64-byte runtime-only signer material in ${normalizedEnvName} (hex:<128 hex characters> or base64:<bytes>); file-backed keypairs are forbidden.`,
    );
  }
  let bytes = null;
  let signer = null;
  try {
    bytes = decodeRuntimeSolanaSecretKey(encoded);
    signer = Keypair.fromSecretKey(bytes);
  } catch {
    throw new Error(
      `${operationLabel} runtime-only signer material is invalid.`,
    );
  } finally {
    bytes?.fill(0);
  }
  if (typeof expectedAddress !== "string" || !expectedAddress.trim()) {
    zeroizeRuntimeSolanaSigner(signer);
    throw new Error(
      `${operationLabel} requires a reviewed public signer address before runtime authority can be used.`,
    );
  }
  let expected = null;
  try {
    expected = new PublicKey(expectedAddress).toBase58();
  } catch {
    zeroizeRuntimeSolanaSigner(signer);
    throw new Error(
      `${operationLabel} reviewed public signer address is invalid.`,
    );
  }
  if (signer.publicKey.toBase58() !== expected) {
    zeroizeRuntimeSolanaSigner(signer);
    throw new Error(
      `${operationLabel} runtime-only signer does not match the reviewed public address.`,
    );
  }
  return signer;
};

export const assertNoFileBackedSolanaSignerOptions = (args = {}) => {
  if (
    args.keypair !== undefined ||
    args["program-id-keypair"] !== undefined ||
    args["keypair-path"] !== undefined ||
    args["private-key-file"] !== undefined
  ) {
    throw new Error(
      "File-backed Solana signer options are forbidden; inject signer bytes through an approved runtime-only environment variable.",
    );
  }
};

const runtimeSolanaSignerEnvName = (args = {}) =>
  normalizeRuntimeSecretEnvName(
    args["solana-signer-env"],
    DEFAULT_SOLANA_RUNTIME_SIGNER_ENV,
  );

const runtimeSolanaSigner = ({ args = {}, expectedAddress, label }) => {
  assertNoFileBackedSolanaSignerOptions(args);
  return loadRuntimeSolanaSigner({
    envName: runtimeSolanaSignerEnvName(args),
    expectedAddress,
    label,
  });
};

export const runtimeOnlySolanaDeploymentBlocker = () =>
  new Error(
    "Creating or deploying a new stable Solana Program id is blocked because that lifecycle requires a stable file-backed program keypair. This helper will not create, read, inventory, echo, or stage signer files. For an already-existing reviewed Loader-v3 Program, use upgrade-existing-program-readiness followed by upgrade-existing-program with runtime-only authority and payer signers.",
  );

const deriveMintAuthority = (verifierProgramId, verifierStateAddress) => {
  const seeds = [
    Buffer.from(SCCP_SOLANA_MINT_AUTHORITY_SEED, "utf8"),
    Buffer.from(verifierStateAddress.toBytes()),
  ];
  for (let bump = 255; bump > 0; bump -= 1) {
    try {
      return [
        PublicKey.createProgramAddressSync(
          [...seeds, Buffer.from([bump])],
          verifierProgramId,
        ),
        bump,
      ];
    } catch (error) {
      if (/address must fall off the curve/iu.test(String(error?.message))) {
        continue;
      }
      throw new Error("Solana mint-authority PDA derivation failed.");
    }
  }
  throw new Error("Solana mint-authority PDA derivation exhausted all bumps.");
};

const encodeBorshVecs = (...values) =>
  Buffer.concat(
    values.flatMap((value) => {
      const bytes = Buffer.isBuffer(value)
        ? value
        : Buffer.from(String(value), "utf8");
      const length = Buffer.alloc(4);
      length.writeUInt32LE(bytes.length, 0);
      return [length, bytes];
    }),
  );

const createConnection = (args) =>
  new Connection(args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL, "confirmed");

export const assertSolanaTestnetRpcConnection = async (connection) => {
  let genesisHash;
  try {
    genesisHash = await connection.getGenesisHash();
  } catch {
    throw new Error(
      "Solana RPC identity check failed before testnet operation.",
    );
  }
  if (genesisHash !== SOLANA_TESTNET_GENESIS_HASH) {
    throw new Error(
      "Solana RPC identity mismatch: the endpoint is not Solana testnet.",
    );
  }
  return genesisHash;
};

const assertExactSolanaRuntimeUpgradeMutationGuard = ({
  args,
  confirmationFlag,
  operation,
}) => {
  if (args.submit !== "true" || args[confirmationFlag] !== "true") {
    throw new Error(
      `${operation} requires the exact --submit true --${confirmationFlag} true guard before any signer or journal access.`,
    );
  }
};

export const loadSolanaExistingProgramUpgradeInputs = async (args = {}) => {
  const upgradePlanPath = requireOption(args, "upgrade-plan");
  const targetProgramPath = requireOption(args, "target-program-so");
  const sbfValidationEvidencePath = requireOption(
    args,
    "sbf-validation-evidence",
  );
  const expectedPlanSha256 = normalizeExpectedSolanaUpgradePlanSha256(
    requireOption(args, "expected-upgrade-plan-sha256"),
  );
  const [upgradePlan, targetProgram, sbfValidationEvidenceArtifact] =
    await Promise.all([
      readStablePublicSolanaUpgradeArtifact({
        file: upgradePlanPath,
        label: "Reviewed existing-program upgrade plan",
        maxBytes: SOLANA_RUNTIME_UPGRADE_PLAN_MAX_BYTES,
      }),
      readStablePublicSolanaUpgradeArtifact({
        file: targetProgramPath,
        label: "Reviewed existing-program target SBF",
        maxBytes: SOLANA_RUNTIME_UPGRADE_ELF_MAX_BYTES,
      }),
      readStablePublicSolanaUpgradeArtifact({
        file: sbfValidationEvidencePath,
        label: "Governance-pinned production local SBF structural evidence",
        maxBytes: SOLANA_RUNTIME_UPGRADE_PLAN_MAX_BYTES,
      }),
    ]);
  const normalized = validateSolanaLoaderV3RuntimeUpgradePlan({
    planBytes: upgradePlan.bytes,
    expectedPlanSha256,
    targetExecutableBytes: targetProgram.bytes,
  });
  let sbfValidationEvidence;
  try {
    const text = sbfValidationEvidenceArtifact.bytes.toString("utf8");
    if (
      !Buffer.from(text, "utf8").equals(sbfValidationEvidenceArtifact.bytes)
    ) {
      throw new Error("not strict UTF-8");
    }
    sbfValidationEvidence = JSON.parse(text);
  } catch {
    throw new Error(
      "Governance-pinned production local SBF structural evidence must be strict UTF-8 JSON.",
    );
  }
  const canonicalEvidence = canonicalSolanaLoaderV3SbfValidationEvidenceBytes(
    sbfValidationEvidence,
  );
  if (
    !canonicalEvidence.equals(sbfValidationEvidenceArtifact.bytes) ||
    sbfValidationEvidenceArtifact.sha256 !==
      normalized.sbfValidationEvidenceSha256 ||
    sbfValidationEvidence.schema !==
      SOLANA_LOADER_V3_SBF_VALIDATION_EVIDENCE_SCHEMA ||
    sbfValidationEvidence.valid !== true ||
    sbfValidationEvidence.deterministic !== true ||
    sbfValidationEvidence.validationScope !==
      SOLANA_LOADER_V3_SBF_VALIDATION_SCOPE ||
    sbfValidationEvidence.exactClusterAdmission !== false ||
    sbfValidationEvidence.productionEligible !== true ||
    sbfValidationEvidence.validatorId !== SOLANA_LOADER_V3_SBF_VALIDATOR_ID ||
    sbfValidationEvidence.validatorVersion !==
      SOLANA_LOADER_V3_SBF_VALIDATOR_VERSION ||
    sbfValidationEvidence.policySha256 !==
      SOLANA_LOADER_V3_SBF_VALIDATION_POLICY_SHA256 ||
    sbfValidationEvidence.artifactSha256 !== normalized.targetSha256 ||
    sbfValidationEvidence.codeHash !== normalized.targetCodeHash ||
    sbfValidationEvidence.executableLength !== normalized.targetLength ||
    ![
      sbfValidationEvidence.helperBinarySha256,
      sbfValidationEvidence.validatorSourceBundleSha256,
      sbfValidationEvidence.cargoLockSha256,
      sbfValidationEvidence.rustcIdentitySha256,
    ].every(
      (value) => typeof value === "string" && /^0x[0-9a-f]{64}$/u.test(value),
    ) ||
    !/^x86_64-unknown-linux-(?:gnu|musl)$/u.test(
      sbfValidationEvidence.helperTargetTriple ?? "",
    ) ||
    sbfValidationEvidence.jitOutcome !== "compiled" ||
    sbfValidationEvidence.buildProfile !== "release" ||
    typeof sbfValidationEvidence.rustcIdentity !== "string" ||
    sbfValidationEvidence.rustcIdentity.length < 32 ||
    sbfValidationEvidence.rustcIdentity.length > 2048 ||
    `0x${createHash("sha256")
      .update(sbfValidationEvidence.rustcIdentity, "utf8")
      .digest("hex")}` !== sbfValidationEvidence.rustcIdentitySha256 ||
    sbfValidationEvidence.resourceLimits !== "unix-rlimit-v1" ||
    JSON.stringify(sbfValidationEvidence.checks) !==
      JSON.stringify(SOLANA_LOADER_V3_REQUIRED_SBF_VALIDATION_CHECKS)
  ) {
    throw new Error(
      "Production local SBF structural evidence is not canonical or does not match the reviewed plan and target bytes.",
    );
  }
  return Object.freeze({
    upgradePlan,
    targetProgram,
    sbfValidationEvidenceArtifact,
    sbfValidationEvidence: Object.freeze({
      ...sbfValidationEvidence,
      checks: Object.freeze([...sbfValidationEvidence.checks]),
    }),
    expectedPlanSha256,
    normalized,
  });
};

export const solanaExistingProgramUpgradeJournalPaths = (normalized) => {
  if (
    typeof normalized?.operationId !== "string" ||
    !/^0x[0-9a-f]{64}$/u.test(normalized.operationId) ||
    typeof normalized?.programId !== "string" ||
    new PublicKey(normalized.programId).toBase58() !== normalized.programId ||
    typeof normalized?.authorityAddress !== "string" ||
    new PublicKey(normalized.authorityAddress).toBase58() !==
      normalized.authorityAddress
  ) {
    throw new Error(
      "Canonical existing-program upgrade journal identity is invalid.",
    );
  }
  const operationDirectory = path.join(
    SOLANA_RUNTIME_UPGRADE_JOURNAL_ROOT,
    SOLANA_TESTNET_NETWORK_ID,
    SOLANA_TESTNET_GENESIS_HASH,
    normalized.programId,
    normalized.operationId.slice(2),
  );
  return Object.freeze({
    root: SOLANA_RUNTIME_UPGRADE_JOURNAL_ROOT,
    operationDirectory,
    journal: path.join(operationDirectory, "operation.journal.jsonl"),
    recoveryLock: path.join(operationDirectory, "recovery.lock.json"),
    completionReceipt: path.join(operationDirectory, "completion.receipt.json"),
    authorityLease: path.join(
      SOLANA_RUNTIME_UPGRADE_JOURNAL_ROOT,
      "authority-leases",
      SOLANA_TESTNET_GENESIS_HASH,
      `${normalized.authorityAddress}.lock.json`,
    ),
  });
};

export const solanaExistingProgramUpgradeLeaseIdentity = (normalized) => {
  const paths = solanaExistingProgramUpgradeJournalPaths(normalized);
  const journalId = `upgrade-${normalized.operationId.slice(2, 34)}`;
  const leaseDigest = createHash("sha256")
    .update(
      JSON.stringify({
        network: SOLANA_TESTNET_NETWORK_ID,
        genesisHash: SOLANA_TESTNET_GENESIS_HASH,
        authorityAddress: normalized.authorityAddress,
        programId: normalized.programId,
        operationId: normalized.operationId,
        planSha256: normalized.planSha256,
      }),
      "utf8",
    )
    .digest("hex");
  return Object.freeze({
    path: paths.authorityLease,
    journalId,
    leaseId: `lease-${leaseDigest.slice(0, 32)}`,
    leaseGeneration: 1,
    expiresAtFinalizedSlot: normalized.expiresAtFinalizedSlot,
    authorityLeaseScope: solanaLoaderV3AuthorityGlobalLeaseScope(
      normalized.authorityAddress,
    ),
  });
};

const createPinnedSolanaSbfValidator =
  (inputs, generateEvidence = generateSolanaLoaderV3SbfValidationEvidence) =>
  async (request) => {
    if (
      !Buffer.from(request?.executableBytes ?? []).equals(
        inputs.targetProgram.bytes,
      ) ||
      request?.validatorId !== SOLANA_LOADER_V3_SBF_VALIDATOR_ID ||
      request?.validatorVersion !== SOLANA_LOADER_V3_SBF_VALIDATOR_VERSION ||
      request?.policySha256 !== SOLANA_LOADER_V3_SBF_VALIDATION_POLICY_SHA256 ||
      request?.artifactSha256 !== inputs.normalized.targetSha256 ||
      request?.codeHash !== inputs.normalized.targetCodeHash ||
      request?.executableLength !== inputs.normalized.targetLength ||
      JSON.stringify(request?.requiredChecks) !==
        JSON.stringify(SOLANA_LOADER_V3_REQUIRED_SBF_VALIDATION_CHECKS)
    ) {
      throw new Error(
        "Runtime SBF validation request does not match the exact reviewed target and policy.",
      );
    }
    const generated = generateEvidence({
      artifactPath: inputs.targetProgram.path,
      artifactRoot: path.dirname(inputs.targetProgram.path),
      expectedArtifactSha256: inputs.normalized.targetSha256,
      expectedValidatorSha256: inputs.sbfValidationEvidence.helperBinarySha256,
    });
    if (
      !generated.evidenceBytes.equals(
        inputs.sbfValidationEvidenceArtifact.bytes,
      ) ||
      generated.evidenceSha256 !== inputs.normalized.sbfValidationEvidenceSha256
    ) {
      throw new Error(
        "Authenticated local SBF validator output does not match the exact governance-pinned evidence bytes.",
      );
    }
    return {
      ...generated.evidence,
      checks: [...generated.evidence.checks],
    };
  };

const createSolanaExistingProgramUpgradeConnection = (args, dependencies) =>
  dependencies.connection ??
  dependencies.createConnection?.(args) ??
  new Connection(args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL, "finalized");

export const simulateSolanaRuntimeUpgradeRawTransaction = async ({
  connection,
  rawTransaction,
  config,
  expectedSignature,
  expectedSignatures,
  messageSha256,
  packetSha256,
  stage,
} = {}) => {
  const raw = Buffer.from(rawTransaction ?? []);
  const configKeys = isRecord(config) ? Object.keys(config).sort() : [];
  if (
    !connection ||
    typeof connection.simulateTransaction !== "function" ||
    raw.length <= 0 ||
    raw.length > SOLANA_PACKET_DATA_SIZE ||
    ![
      "deploy-rollback-sentinel-admission",
      "upgrade-rollback-sentinel-admission",
    ].includes(stage) ||
    JSON.stringify(configKeys) !==
      JSON.stringify([
        "commitment",
        "minContextSlot",
        "replaceRecentBlockhash",
        "sigVerify",
      ]) ||
    config.sigVerify !== true ||
    config.replaceRecentBlockhash !== false ||
    config.commitment !== "finalized" ||
    !Number.isSafeInteger(config.minContextSlot) ||
    config.minContextSlot <= 0 ||
    typeof expectedSignature !== "string" ||
    !Array.isArray(expectedSignatures) ||
    !/^0x[0-9a-f]{64}$/u.test(messageSha256) ||
    !/^0x[0-9a-f]{64}$/u.test(packetSha256)
  ) {
    throw new Error(
      "Rollback-sentinel simulation request is not the exact bounded no-broadcast contract.",
    );
  }
  let transaction;
  try {
    transaction = VersionedTransaction.deserialize(raw);
  } catch {
    throw new Error("Rollback-sentinel simulation transaction is invalid.");
  }
  const serialized = Buffer.from(transaction.serialize());
  const signatures = transaction.signatures.map((signature) =>
    bs58.encode(signature),
  );
  const actualMessageSha256 = `0x${createHash("sha256")
    .update(transaction.message.serialize())
    .digest("hex")}`;
  const actualPacketSha256 = `0x${createHash("sha256")
    .update(serialized)
    .digest("hex")}`;
  if (
    !serialized.equals(raw) ||
    signatures[0] !== expectedSignature ||
    JSON.stringify(signatures) !== JSON.stringify(expectedSignatures) ||
    actualMessageSha256 !== messageSha256 ||
    actualPacketSha256 !== packetSha256
  ) {
    throw new Error(
      "Rollback-sentinel simulation bytes, signatures, or intent hashes changed at the RPC boundary.",
    );
  }
  try {
    return await connection.simulateTransaction(transaction, { ...config });
  } catch {
    throw new Error(
      "Finalized rollback-sentinel simulation RPC failed before exact admission evidence was returned.",
    );
  }
};

export const resolveSolanaRuntimeUpgradeAmbiguousTransaction = async ({
  connection,
  intent,
  rawTransaction,
  latestBlockhash,
} = {}) => {
  const raw =
    rawTransaction instanceof Uint8Array
      ? Buffer.from(rawTransaction)
      : Buffer.alloc(0);
  if (
    !connection ||
    !isRecord(intent) ||
    !isRecord(latestBlockhash) ||
    raw.length <= 0 ||
    raw.length > SOLANA_PACKET_DATA_SIZE ||
    !Number.isSafeInteger(intent.packetLength) ||
    intent.packetLength !== raw.length ||
    !Number.isSafeInteger(intent.lastValidBlockHeight) ||
    intent.lastValidBlockHeight <= 0 ||
    intent.blockhash !== latestBlockhash.blockhash ||
    intent.lastValidBlockHeight !== latestBlockhash.lastValidBlockHeight ||
    intent.packetSha256 !==
      `0x${createHash("sha256").update(raw).digest("hex")}` ||
    !isCanonicalSolanaSignature(intent.expectedPrimarySignature) ||
    !Array.isArray(intent.expectedSignatures) ||
    !/^0x[0-9a-f]{64}$/u.test(intent.messageSha256) ||
    !isCanonicalSolanaBlockhash(intent.blockhash)
  ) {
    throw new Error(
      "Ambiguous transaction resolution requires the exact prepared no-retry intent.",
    );
  }
  let transaction;
  try {
    transaction = VersionedTransaction.deserialize(raw);
  } catch {
    throw new Error(
      "Ambiguous transaction resolution packet is not an exact signed Solana transaction.",
    );
  }
  const serialized = Buffer.from(transaction.serialize());
  const signatures = transaction.signatures.map((signature) =>
    bs58.encode(signature),
  );
  const messageBytes = Buffer.from(transaction.message.serialize());
  if (
    !serialized.equals(raw) ||
    JSON.stringify(signatures) !== JSON.stringify(intent.expectedSignatures) ||
    signatures[0] !== intent.expectedPrimarySignature ||
    transaction.message.recentBlockhash !== intent.blockhash ||
    `0x${createHash("sha256").update(messageBytes).digest("hex")}` !==
      intent.messageSha256
  ) {
    throw new Error(
      "Ambiguous transaction packet, signatures, message, or blockhash changed.",
    );
  }
  await assertSolanaTestnetRpcConnection(connection);
  for (let attempt = 0; attempt < 8; attempt += 1) {
    let status;
    let blockHeight;
    try {
      const [statuses, observedBlockHeight] = await Promise.all([
        connection.getSignatureStatuses([intent.expectedPrimarySignature], {
          searchTransactionHistory: true,
        }),
        connection.getBlockHeight("finalized"),
      ]);
      status = statuses?.value?.[0] ?? null;
      blockHeight = observedBlockHeight;
    } catch {
      throw new Error("Read-only ambiguous transaction resolution RPC failed.");
    }
    if (
      status?.confirmationStatus === "finalized" &&
      Number.isSafeInteger(status.slot) &&
      status.slot > 0
    ) {
      if (status.err !== null) {
        await assertSolanaTestnetRpcConnection(connection);
        return {
          status: "failed",
          signature: intent.expectedPrimarySignature,
          finalized: true,
          err: status.err,
          observedBlockHeight: blockHeight,
        };
      }
      let transactionReadback;
      try {
        transactionReadback = await connection.getTransaction(
          intent.expectedPrimarySignature,
          {
            commitment: "finalized",
            maxSupportedTransactionVersion: 0,
          },
        );
      } catch {
        transactionReadback = null;
      }
      if (transactionReadback) {
        await assertSolanaTestnetRpcConnection(connection);
        return {
          status: "finalized",
          submittedResult: {
            signature: intent.expectedPrimarySignature,
            confirmation: { value: { err: null } },
            signatureStatus: status,
            transactionReadback,
          },
        };
      }
    }
    if (
      status === null &&
      Number.isSafeInteger(blockHeight) &&
      blockHeight > intent.lastValidBlockHeight
    ) {
      await assertSolanaTestnetRpcConnection(connection);
      return {
        status: "expired",
        observedBlockHeight: blockHeight,
        signatureStatus: null,
      };
    }
    if (attempt < 7) {
      await new Promise((resolve) => setTimeout(resolve, 250));
    }
  }
  await assertSolanaTestnetRpcConnection(connection);
  return { status: "ambiguous" };
};

const broadcastFencedSolanaRuntimeUpgradeTransaction = async ({
  assertLeaseHeld,
  leasePolicy,
  delegate = null,
  request,
}) => {
  if (typeof assertLeaseHeld !== "function") {
    throw new Error("Runtime transaction broadcast lacks an authority fence.");
  }
  await assertSolanaTestnetRpcConnection(request.connection);
  if (leasePolicy?.kind === "finalized-slot-bounded") {
    const slot = await request.connection.getSlot("finalized");
    if (
      !Number.isSafeInteger(slot) ||
      slot > leasePolicy.expiresAtFinalizedSlot
    ) {
      throw new Error(
        "The generation-1 authority lease expired before fenced broadcast.",
      );
    }
  } else if (leasePolicy?.kind !== "owner-death-fence-and-capability-bounded") {
    throw new Error("Runtime broadcast lease lifetime policy is invalid.");
  }
  await assertLeaseHeld();
  if (delegate !== null) {
    if (typeof delegate !== "function") {
      throw new Error("Runtime broadcast delegate is invalid.");
    }
    const result = await delegate(request);
    await assertLeaseHeld();
    await assertSolanaTestnetRpcConnection(request.connection);
    return result;
  }
  const signature = await request.connection.sendRawTransaction(
    request.rawTransaction,
    { skipPreflight: false, maxRetries: 0 },
  );
  if (signature !== request.expectedPrimarySignature) {
    throw new Error(
      "RPC signature differs from the fenced locally signed transaction.",
    );
  }
  const confirmation = await request.connection.confirmTransaction(
    {
      signature,
      blockhash: request.latestBlockhash.blockhash,
      lastValidBlockHeight: request.latestBlockhash.lastValidBlockHeight,
    },
    "finalized",
  );
  const statuses = await request.connection.getSignatureStatuses([signature], {
    searchTransactionHistory: true,
  });
  let transactionReadback = null;
  for (let attempt = 0; attempt < 8 && !transactionReadback; attempt += 1) {
    transactionReadback = await request.connection.getTransaction(signature, {
      commitment: "finalized",
      maxSupportedTransactionVersion: 0,
    });
    if (!transactionReadback && attempt < 7) {
      await (
        request.sleep ??
        ((milliseconds) =>
          new Promise((resolve) => setTimeout(resolve, milliseconds)))
      )(250);
    }
  }
  await assertLeaseHeld();
  await assertSolanaTestnetRpcConnection(request.connection);
  return {
    signature,
    confirmation,
    signatureStatus: statuses?.value?.[0] ?? null,
    transactionReadback,
  };
};

const solanaUpgradeRuntimeSignerFactory = ({
  args,
  env,
  trackedSigners,
  operationLabel,
  reviewedPlan = null,
  requireAuthorityLease = false,
  authorizeAuthorityLease = null,
  authorizeRecovery = null,
}) => {
  const roleEnvNames = {
    authority: normalizeRuntimeSecretEnvName(
      args["upgrade-authority-signer-env"],
      SOLANA_UPGRADE_AUTHORITY_RUNTIME_SIGNER_ENV,
    ),
    payer: normalizeRuntimeSecretEnvName(
      args["upgrade-payer-signer-env"],
      SOLANA_UPGRADE_PAYER_RUNTIME_SIGNER_ENV,
    ),
  };
  const reviewedLease = reviewedPlan
    ? solanaExistingProgramUpgradeLeaseIdentity(reviewedPlan)
    : null;
  return async ({ role, address, authorityLease, recoveryAuthorization }) => {
    if (!Object.hasOwn(roleEnvNames, role)) {
      throw new Error(
        "Existing-program upgrade requested an unknown signer role.",
      );
    }
    const reviewedAddress =
      role === "authority"
        ? reviewedPlan?.authorityAddress
        : reviewedPlan?.payerAddress;
    if (
      reviewedPlan !== null &&
      (typeof reviewedAddress !== "string" || address !== reviewedAddress)
    ) {
      throw new Error(
        "Runtime signer role and address do not match the reviewed operation identity.",
      );
    }
    if (authorizeRecovery !== null) {
      if (typeof authorizeRecovery !== "function") {
        throw new Error("Recovery signer authorization is unavailable.");
      }
      await authorizeRecovery(recoveryAuthorization);
    }
    if (
      requireAuthorityLease &&
      (!reviewedLease ||
        !isRecord(authorityLease) ||
        Object.keys(authorityLease).length !== 11 ||
        authorityLease.journalId !== reviewedLease.journalId ||
        authorityLease.leaseId !== reviewedLease.leaseId ||
        authorityLease.leaseGeneration !== 1 ||
        authorityLease.authorityLeaseScope !==
          reviewedLease.authorityLeaseScope ||
        authorityLease.leaseExpiresAtFinalizedSlot !==
          reviewedLease.expiresAtFinalizedSlot ||
        authorityLease.network !== SOLANA_TESTNET_NETWORK_ID ||
        authorityLease.genesisHash !== SOLANA_TESTNET_GENESIS_HASH ||
        authorityLease.authorityAddress !== reviewedPlan.authorityAddress ||
        authorityLease.programId !== reviewedPlan.programId ||
        authorityLease.operationId !== reviewedPlan.operationId)
    ) {
      throw new Error(
        "Runtime signer acquisition requires the exact durable authority lease bound to the reviewed plan.",
      );
    }
    if (requireAuthorityLease) {
      if (typeof authorizeAuthorityLease !== "function") {
        throw new Error("Runtime signer authority capability is unavailable.");
      }
      await authorizeAuthorityLease(authorityLease);
    }
    const signer = loadRuntimeSolanaSigner({
      env,
      envName: roleEnvNames[role],
      expectedAddress: address,
      label: `${operationLabel} ${role}`,
    });
    trackedSigners.push(signer);
    return signer;
  };
};

const solanaExistingProgramUpgradeInputReport = (inputs) => ({
  plan: {
    path: inputs.upgradePlan.path,
    sizeBytes: inputs.upgradePlan.sizeBytes,
    sha256: inputs.upgradePlan.sha256,
    independentlyExpectedSha256: inputs.expectedPlanSha256,
  },
  targetProgram: {
    path: inputs.targetProgram.path,
    sizeBytes: inputs.targetProgram.sizeBytes,
    artifactSha256: inputs.targetProgram.sha256,
  },
  sbfValidationEvidence: {
    path: inputs.sbfValidationEvidenceArtifact.path,
    sizeBytes: inputs.sbfValidationEvidenceArtifact.sizeBytes,
    sha256: inputs.sbfValidationEvidenceArtifact.sha256,
    validatorId: inputs.sbfValidationEvidence.validatorId,
    validatorVersion: inputs.sbfValidationEvidence.validatorVersion,
    policySha256: inputs.sbfValidationEvidence.policySha256,
    validationScope: inputs.sbfValidationEvidence.validationScope,
    exactClusterAdmission: false,
    exactClusterAdmissionAuthority: "rollback-sentinel-simulation",
    helperBinarySha256: inputs.sbfValidationEvidence.helperBinarySha256,
    helperTargetTriple: inputs.sbfValidationEvidence.helperTargetTriple,
    jitOutcome: inputs.sbfValidationEvidence.jitOutcome,
    buildProfile: inputs.sbfValidationEvidence.buildProfile,
    validatorSourceBundleSha256:
      inputs.sbfValidationEvidence.validatorSourceBundleSha256,
    cargoLockSha256: inputs.sbfValidationEvidence.cargoLockSha256,
    rustcIdentitySha256: inputs.sbfValidationEvidence.rustcIdentitySha256,
  },
});

const closeSolanaRuntimeUpgradeResources = async ({
  journal,
  journalCloseOptions = {},
  auxiliaryResources = [],
  trackedSigners,
  failure,
}) => {
  const failures = failure ? [failure] : [];
  const resources = [
    { resource: journal, closeOptions: journalCloseOptions },
    ...auxiliaryResources.map((entry) =>
      entry?.resource ? entry : { resource: entry, closeOptions: {} },
    ),
  ];
  for (const { resource, closeOptions } of resources) {
    try {
      await resource.close(closeOptions);
    } catch (error) {
      failures.push(error instanceof Error ? error : new Error(String(error)));
    }
  }
  for (const signer of trackedSigners) {
    try {
      zeroizeRuntimeSolanaSigner(signer);
    } catch {
      failures.push(
        new Error("Runtime upgrade signer zeroization could not be completed."),
      );
    }
  }
  if (failures.length === 1) throw failures[0];
  if (failures.length > 1) {
    throw new AggregateError(
      failures,
      "Runtime upgrade operation and durable resource cleanup were incomplete.",
    );
  }
};

const closeSolanaRuntimeRecoveryResources = async ({
  journal,
  recoveryLock,
  authorityLease,
  releaseEvidenceReady,
  trackedSigners,
  failure,
}) => {
  const failures = failure ? [failure] : [];
  let journalClosed = false;
  let candidateRemoved = false;
  try {
    await journal.close();
    journalClosed = true;
  } catch (error) {
    failures.push(error instanceof Error ? error : new Error(String(error)));
  }
  try {
    await recoveryLock.close({
      removeCompleted: releaseEvidenceReady && journalClosed,
    });
    candidateRemoved = releaseEvidenceReady && journalClosed;
  } catch (error) {
    failures.push(error instanceof Error ? error : new Error(String(error)));
  }
  try {
    await authorityLease.close({
      releaseLease: releaseEvidenceReady && journalClosed && candidateRemoved,
    });
  } catch (error) {
    failures.push(error instanceof Error ? error : new Error(String(error)));
  }
  for (const signer of trackedSigners) {
    try {
      zeroizeRuntimeSolanaSigner(signer);
    } catch {
      failures.push(
        new Error(
          "Runtime recovery signer zeroization could not be completed.",
        ),
      );
    }
  }
  if (failures.length === 1) throw failures[0];
  if (failures.length > 1) {
    throw new AggregateError(
      failures,
      "Runtime recovery report, journal, candidate, lease, and signer cleanup were incomplete.",
    );
  }
  return Object.freeze({ journalClosed, candidateRemoved });
};

const SOLANA_RUNTIME_UPGRADE_COMPLETION_RECEIPT_SCHEMA =
  "iroha-demo-solana-loader-v3-runtime-completion-receipt/v1";

const publicJsonArtifactBytes = (value) =>
  Buffer.from(`${JSON.stringify(value, null, 2)}\n`, "utf8");

const writeAndVerifyPublicJsonArtifact = async ({
  file,
  value,
  writer = writePublicJson,
  label,
}) => {
  const expectedBytes = publicJsonArtifactBytes(value);
  await writer(file, value);
  const selected = await readStablePublicSolanaUpgradeArtifact({
    file,
    label,
    maxBytes: SOLANA_RUNTIME_UPGRADE_JOURNAL_MAX_BYTES,
  });
  if (!selected.bytes.equals(expectedBytes)) {
    throw new Error(`${label} durable bytes do not match the exact report.`);
  }
  return selected;
};

const solanaUpgradeReceiptTerminal = (summary) =>
  summary.classification === "no-programdata-mutation-safe-abort"
    ? {
        classification: summary.classification,
        createSucceeded: summary.createSucceeded,
        cleanupSucceeded: summary.cleanupSucceeded,
      }
    : {
        classification: "finalized-transaction",
        signature: summary.signature,
        expectedSignatures: [...summary.expectedSignatures],
        blockhash: summary.blockhash,
        lastValidBlockHeight: summary.lastValidBlockHeight,
        messageSha256: summary.messageSha256,
        packetSha256: summary.packetSha256,
        packetLength: summary.packetLength,
        finalizedSlot: summary.finalizedSlot,
      };

const buildSolanaUpgradeCompletionReceipt = ({
  kind,
  summary,
  journal,
  configuredReport = null,
}) => ({
  schema: SOLANA_RUNTIME_UPGRADE_COMPLETION_RECEIPT_SCHEMA,
  kind,
  operationId: summary.operationId,
  planSha256: summary.planSha256,
  programId: summary.programId,
  programdataAddress: summary.programdataAddress,
  authorityAddress: summary.authorityAddress,
  payerAddress: summary.payerAddress,
  bufferAddress: summary.bufferAddress,
  target: {
    artifactSha256: summary.targetArtifactSha256,
    executableLength: summary.targetExecutableLength,
  },
  authorityLease: {
    leaseId: summary.leaseId,
    generation: summary.leaseGeneration,
    scope: summary.authorityLeaseScope,
  },
  terminal: solanaUpgradeReceiptTerminal(summary),
  journal: {
    path: journal.path,
    sha256: journal.sha256,
  },
  configuredReport:
    configuredReport === null
      ? null
      : {
          path: configuredReport.path,
          sha256: configuredReport.sha256,
        },
});

const exactSolanaUpgradeCompletionReceipt = ({ receipt, expected }) => {
  if (
    JSON.stringify({ ...receipt, configuredReport: null }) !==
    JSON.stringify({ ...expected, configuredReport: null })
  ) {
    return false;
  }
  const configured = receipt.configuredReport;
  return (
    configured === null ||
    (isRecord(configured) &&
      Object.keys(configured).length === 2 &&
      typeof configured.path === "string" &&
      path.isAbsolute(configured.path) &&
      /^0x[0-9a-f]{64}$/u.test(configured.sha256))
  );
};

const writeSolanaUpgradeCompletionReceipt = async ({
  receiptPath,
  receipt,
}) => {
  await assertTrustedSolanaUpgradeDirectory({
    directory: path.dirname(receiptPath),
    create: false,
  });
  return writeAndVerifyPublicJsonArtifact({
    file: receiptPath,
    value: receipt,
    writer: writePublicJson,
    label: "Runtime upgrade completion receipt",
  });
};

const persistSolanaUpgradeCompletionReceipt = async ({
  kind,
  summary,
  journalPath,
  receiptPath,
  configuredReport = null,
}) => {
  const journal = await readStablePublicSolanaUpgradeArtifact({
    file: journalPath,
    label: "Completed runtime upgrade journal",
    maxBytes: SOLANA_RUNTIME_UPGRADE_JOURNAL_MAX_BYTES,
  });
  const receipt = buildSolanaUpgradeCompletionReceipt({
    kind,
    summary,
    journal: { path: journal.path, sha256: journal.sha256 },
    configuredReport:
      configuredReport === null
        ? null
        : {
            path: configuredReport.path,
            sha256: configuredReport.sha256,
          },
  });
  const written = await writeSolanaUpgradeCompletionReceipt({
    receiptPath,
    receipt,
  });
  return Object.freeze({
    path: written.path,
    sha256: written.sha256,
    receipt: Object.freeze(receipt),
  });
};

const ensureSolanaUpgradeCompletionReceiptUnderFence = async ({
  kind,
  summary,
  journal,
  receiptPath,
}) => {
  const expected = buildSolanaUpgradeCompletionReceipt({
    kind,
    summary,
    journal: { path: journal.path, sha256: journal.sha256 },
  });
  let selected = null;
  try {
    selected = await readStablePublicSolanaUpgradeArtifact({
      file: receiptPath,
      label: "Runtime upgrade completion receipt",
      maxBytes: SOLANA_RUNTIME_UPGRADE_JOURNAL_EVENT_MAX_BYTES,
    });
  } catch (error) {
    if (error?.code !== "ENOENT") throw error;
  }
  if (selected === null) {
    const synthesized = await writeSolanaUpgradeCompletionReceipt({
      receiptPath,
      receipt: expected,
    });
    return Object.freeze({
      path: synthesized.path,
      sha256: synthesized.sha256,
      configuredReport: null,
      synthesized: true,
    });
  }
  let receipt;
  try {
    receipt = JSON.parse(selected.bytes.toString("utf8"));
  } catch {
    throw new Error("Runtime upgrade completion receipt is not strict JSON.");
  }
  if (
    !selected.bytes.equals(publicJsonArtifactBytes(receipt)) ||
    !exactSolanaUpgradeCompletionReceipt({ receipt, expected })
  ) {
    throw new Error(
      "Runtime upgrade completion receipt does not match its terminal journal.",
    );
  }
  if (receipt.configuredReport !== null) {
    if (kind === "upgrade-safe-abort") {
      throw new Error(
        "A safe-abort completion receipt cannot claim a configured success report.",
      );
    }
    const configured = await readStablePublicSolanaUpgradeArtifact({
      file: receipt.configuredReport.path,
      label: "Configured runtime upgrade report",
      maxBytes: SOLANA_RUNTIME_UPGRADE_JOURNAL_MAX_BYTES,
    });
    if (configured.sha256 !== receipt.configuredReport.sha256) {
      throw new Error(
        "Configured runtime upgrade report no longer matches its receipt.",
      );
    }
    await assertConfiguredSolanaRuntimeReportMatchesTerminalJournal({
      kind,
      configured,
      journal,
      summary,
      receiptPath,
    });
  }
  return Object.freeze({
    path: selected.path,
    sha256: selected.sha256,
    configuredReport: receipt.configuredReport,
    synthesized: false,
  });
};

const hasExactPublicKeys = (value, keys) =>
  isRecord(value) &&
  Object.keys(value).length === keys.length &&
  Object.keys(value).every((key) => keys.includes(key));

const captureCanonicalRuntimeReportValue = (value, seen = new Set()) => {
  if (
    value === null ||
    typeof value === "string" ||
    typeof value === "boolean" ||
    (typeof value === "number" && Number.isFinite(value))
  ) {
    return value;
  }
  if (
    typeof value !== "object" ||
    seen.has(value) ||
    nodeUtilTypes.isProxy(value)
  ) {
    throw new Error("Runtime report is not acyclic plain public JSON.");
  }
  seen.add(value);
  let snapshot;
  if (Array.isArray(value)) {
    const descriptors = Object.getOwnPropertyDescriptors(value);
    const keys = Reflect.ownKeys(descriptors);
    const length = descriptors.length?.value;
    if (
      Object.getPrototypeOf(value) !== Array.prototype ||
      !Number.isSafeInteger(length) ||
      length < 0 ||
      keys.length !== length + 1 ||
      keys.at(-1) !== "length" ||
      keys.slice(0, -1).some((key, index) => key !== String(index))
    ) {
      throw new Error("Runtime report array shape is not exact.");
    }
    snapshot = [];
    for (let index = 0; index < length; index += 1) {
      const descriptor = descriptors[String(index)];
      if (
        !descriptor ||
        !("value" in descriptor) ||
        descriptor.enumerable !== true
      ) {
        throw new Error("Runtime report array shape is not exact.");
      }
      snapshot.push(captureCanonicalRuntimeReportValue(descriptor.value, seen));
    }
  } else {
    const prototype = Object.getPrototypeOf(value);
    if (prototype !== Object.prototype && prototype !== null) {
      throw new Error("Runtime report object prototype is not plain.");
    }
    const descriptors = Object.getOwnPropertyDescriptors(value);
    const keys = Reflect.ownKeys(descriptors);
    if (keys.some((key) => typeof key !== "string")) {
      throw new Error("Runtime report object shape is not exact.");
    }
    snapshot = Object.create(null);
    for (const key of keys) {
      const descriptor = descriptors[key];
      if (!("value" in descriptor) || descriptor.enumerable !== true) {
        throw new Error("Runtime report object shape is not exact.");
      }
      Object.defineProperty(snapshot, key, {
        value: captureCanonicalRuntimeReportValue(descriptor.value, seen),
        enumerable: true,
        configurable: true,
        writable: true,
      });
    }
  }
  seen.delete(value);
  return snapshot;
};

export const snapshotCanonicalSolanaRuntimeReport = (report) => {
  const captured = captureCanonicalRuntimeReportValue(report);
  let encoded;
  try {
    encoded = JSON.stringify(captured);
  } catch {
    throw new Error("Runtime report could not be canonically serialized.");
  }
  if (
    typeof encoded !== "string" ||
    Buffer.byteLength(encoded, "utf8") >
      SOLANA_RUNTIME_UPGRADE_JOURNAL_MAX_BYTES
  ) {
    throw new Error("Runtime report exceeds its canonical public bound.");
  }
  const snapshot = JSON.parse(encoded);
  if (JSON.stringify(snapshot) !== encoded) {
    throw new Error("Runtime report is not canonical plain JSON.");
  }
  return freezePublicSolanaUpgradeJournalValue(snapshot);
};

const exactPublicJsonValue = (actual, expected) => {
  if (Array.isArray(expected)) {
    return (
      Array.isArray(actual) &&
      actual.length === expected.length &&
      Object.keys(actual).length === actual.length &&
      Object.keys(actual).every((key, index) => key === String(index)) &&
      expected.every((entry, index) =>
        exactPublicJsonValue(actual[index], entry),
      )
    );
  }
  if (isRecord(expected)) {
    const keys = Object.keys(expected);
    return (
      hasExactPublicKeys(actual, keys) &&
      keys.every((key) => exactPublicJsonValue(actual[key], expected[key]))
    );
  }
  return actual === expected;
};

const isCanonicalSolanaPublicKey = (value) => {
  try {
    return (
      typeof value === "string" && new PublicKey(value).toBase58() === value
    );
  } catch {
    return false;
  }
};

const exactRuntimeInstructionSummary = (instruction) =>
  hasExactPublicKeys(instruction, ["programId", "dataHex", "metas"]) &&
  isCanonicalSolanaPublicKey(instruction.programId) &&
  typeof instruction.dataHex === "string" &&
  /^0x(?:[0-9a-f]{2})*$/u.test(instruction.dataHex) &&
  Array.isArray(instruction.metas) &&
  instruction.metas.every(
    (entry) =>
      hasExactPublicKeys(entry, ["pubkey", "isSigner", "isWritable"]) &&
      isCanonicalSolanaPublicKey(entry.pubkey) &&
      typeof entry.isSigner === "boolean" &&
      typeof entry.isWritable === "boolean",
  );

const runtimeInstructionSummaryForValidation = (instruction) => ({
  programId: instruction.programId.toBase58(),
  dataHex: `0x${Buffer.from(instruction.data).toString("hex")}`,
  metas: instruction.keys.map((entry) => ({
    pubkey: entry.pubkey.toBase58(),
    isSigner: entry.isSigner === true,
    isWritable: entry.isWritable === true,
  })),
});

const exactSystemCreateBufferInstruction = ({
  instruction,
  payerAddress,
  bufferAddress,
  bufferSpace,
}) => {
  if (
    !exactRuntimeInstructionSummary(instruction) ||
    instruction.programId !== SystemProgram.programId.toBase58() ||
    !exactPublicJsonValue(instruction.metas, [
      { pubkey: payerAddress, isSigner: true, isWritable: true },
      { pubkey: bufferAddress, isSigner: true, isWritable: true },
    ])
  ) {
    return false;
  }
  let data;
  try {
    data = Buffer.from(instruction.dataHex.slice(2), "hex");
  } catch {
    return false;
  }
  return (
    data.length === 52 &&
    data.readUInt32LE(0) === 0 &&
    data.readBigUInt64LE(4) > 0n &&
    data.readBigUInt64LE(12) === BigInt(bufferSpace) &&
    new PublicKey(data.subarray(20, 52)).toBase58() ===
      SOLANA_UPGRADEABLE_LOADER_ID
  );
};

const exactInitializeTransactionInstructions = ({
  transaction,
  normalized,
  bufferAddress,
}) =>
  Array.isArray(transaction?.instructions) &&
  transaction.instructions.length === 2 &&
  exactSystemCreateBufferInstruction({
    instruction: transaction.instructions[0],
    payerAddress: normalized.payerAddress,
    bufferAddress,
    bufferSpace: SOLANA_BUFFER_METADATA_LENGTH + normalized.targetLength,
  }) &&
  exactPublicJsonValue(
    transaction.instructions[1],
    runtimeInstructionSummaryForValidation(
      buildLoaderV3InitializeBufferInstruction({
        bufferAddress,
        authorityAddress: normalized.authorityAddress,
      }),
    ),
  );

const exactWriteTransactionInstructions = ({
  transaction,
  normalized,
  inputs,
  bufferAddress,
}) => {
  if (
    !Array.isArray(transaction?.instructions) ||
    transaction.instructions.length !== 1
  ) {
    return false;
  }
  try {
    return exactPublicJsonValue(
      transaction.instructions[0],
      runtimeInstructionSummaryForValidation(
        buildLoaderV3WriteInstruction({
          bufferAddress,
          authorityAddress: normalized.authorityAddress,
          offset: transaction.offset,
          bytes: Buffer.from(inputs.targetProgram.bytes).subarray(
            transaction.offset,
            transaction.endOffset,
          ),
        }),
      ),
    );
  } catch {
    return false;
  }
};

const exactUpgradeTransactionInstructions = ({
  transaction,
  normalized,
  bufferAddress,
}) =>
  Array.isArray(transaction?.instructions) &&
  transaction.instructions.length === 1 &&
  exactPublicJsonValue(
    transaction.instructions[0],
    runtimeInstructionSummaryForValidation(
      buildLoaderV3UpgradeInstruction({
        programId: normalized.programId,
        programdataAddress: normalized.programdataAddress,
        bufferAddress,
        spillAddress: normalized.spillAddress,
        authorityAddress: normalized.authorityAddress,
      }),
    ),
  );

const exactExtensionTransactionInstructions = ({ transaction, normalized }) =>
  normalized.extension !== null &&
  Array.isArray(transaction?.instructions) &&
  transaction.instructions.length === 1 &&
  exactPublicJsonValue(
    transaction.instructions[0],
    runtimeInstructionSummaryForValidation(
      buildLoaderV3ExtendProgramCheckedInstruction({
        programId: normalized.programId,
        programdataAddress: normalized.programdataAddress,
        authorityAddress: normalized.authorityAddress,
        payerAddress: normalized.payerAddress,
        additionalBytes: normalized.extension.additionalBytes,
        currentProgramdataDataLength: normalized.beforeDataLength,
      }),
    ),
  );

const exactRecoveryTransactionInstructions = ({
  transaction,
  normalized,
  bufferAddress,
}) =>
  Array.isArray(transaction?.instructions) &&
  transaction.instructions.length === 1 &&
  exactPublicJsonValue(
    transaction.instructions[0],
    runtimeInstructionSummaryForValidation(
      buildLoaderV3CloseBufferInstruction({
        bufferAddress,
        recipientAddress: normalized.payerAddress,
        authorityAddress: normalized.authorityAddress,
      }),
    ),
  );

const exactRuntimeTransactionReport = ({
  transaction,
  stage,
  minimumFinalizedSlot,
  maximumFinalizedSlot,
  terminal = null,
  writeRange = null,
}) => {
  const keys = [
    "stage",
    "signature",
    "signatures",
    "finalizedSlot",
    "packetLength",
    "packetSha256",
    "blockhash",
    "lastValidBlockHeight",
    "messageSha256",
    "fetchedMessageSha256",
    "instructions",
    ...(writeRange === null ? [] : ["offset", "length", "endOffset"]),
  ];
  if (
    !hasExactPublicKeys(transaction, keys) ||
    transaction.stage !== stage ||
    !isCanonicalSolanaSignature(transaction.signature) ||
    !Array.isArray(transaction.signatures) ||
    transaction.signatures.length < 1 ||
    transaction.signatures[0] !== transaction.signature ||
    transaction.signatures.some(
      (signature) => !isCanonicalSolanaSignature(signature),
    ) ||
    new Set(transaction.signatures).size !== transaction.signatures.length ||
    !Number.isSafeInteger(transaction.finalizedSlot) ||
    transaction.finalizedSlot < minimumFinalizedSlot ||
    transaction.finalizedSlot > maximumFinalizedSlot ||
    !Number.isSafeInteger(transaction.packetLength) ||
    transaction.packetLength <= 0 ||
    transaction.packetLength > SOLANA_PACKET_DATA_SIZE ||
    !/^0x[0-9a-f]{64}$/u.test(transaction.packetSha256) ||
    !isCanonicalSolanaBlockhash(transaction.blockhash) ||
    !Number.isSafeInteger(transaction.lastValidBlockHeight) ||
    transaction.lastValidBlockHeight <= 0 ||
    !/^0x[0-9a-f]{64}$/u.test(transaction.messageSha256) ||
    transaction.fetchedMessageSha256 !== transaction.messageSha256 ||
    !Array.isArray(transaction.instructions) ||
    transaction.instructions.length < 1 ||
    !transaction.instructions.every(exactRuntimeInstructionSummary)
  ) {
    return false;
  }
  if (
    writeRange !== null &&
    (transaction.offset !== writeRange.offset ||
      !Number.isSafeInteger(transaction.length) ||
      transaction.length <= 0 ||
      transaction.endOffset !== transaction.offset + transaction.length ||
      transaction.endOffset > writeRange.targetLength)
  ) {
    return false;
  }
  return (
    terminal === null ||
    (transaction.signature === terminal.signature &&
      JSON.stringify(transaction.signatures) ===
        JSON.stringify(terminal.expectedSignatures ?? terminal.signatures) &&
      transaction.finalizedSlot === terminal.finalizedSlot &&
      transaction.packetLength === terminal.packetLength &&
      transaction.packetSha256 === terminal.packetSha256 &&
      transaction.blockhash === terminal.blockhash &&
      transaction.lastValidBlockHeight === terminal.lastValidBlockHeight &&
      transaction.messageSha256 === terminal.messageSha256)
  );
};

const exactRuntimeAdmissionEvidence = ({
  evidence,
  mode,
  inputs,
  bufferAddress,
  minimumContextSlot,
  journalAdmission,
}) => {
  const normalized = inputs.normalized;
  const keys = [
    "schema",
    "mode",
    "ready",
    "simulationOnly",
    "broadcast",
    "network",
    "genesisHash",
    "solanaCoreVersion",
    "featureSet",
    "programId",
    "programdataAddress",
    "bufferAddress",
    "bufferExecutableSha256",
    "targetArtifactSha256",
    "targetCodeHash",
    "targetExecutableLength",
    "intendedExecutableCapacity",
    "bufferContextSlot",
    "simulationContextSlot",
    "sentinelInstructionIndex",
    "expectedError",
    "expectedSignature",
    "expectedSignatures",
    "blockhash",
    "lastValidBlockHeight",
    "messageSha256",
    "packetSha256",
    "packetLength",
    "logSha256",
    "probeProgramAddress",
    "probeProgramdataAddress",
  ];
  const afterDataLength =
    normalized.extension?.resultProgramdataDataLength ??
    normalized.beforeDataLength;
  const probeValid =
    mode === "deploy"
      ? isCanonicalSolanaPublicKey(evidence?.probeProgramAddress) &&
        isCanonicalSolanaPublicKey(evidence?.probeProgramdataAddress) &&
        evidence.probeProgramAddress !== evidence.probeProgramdataAddress
      : evidence?.probeProgramAddress === null &&
        evidence?.probeProgramdataAddress === null;
  return (
    hasExactPublicKeys(evidence, keys) &&
    evidence.schema === SOLANA_LOADER_V3_TARGET_ADMISSION_EVIDENCE_SCHEMA &&
    evidence.mode === mode &&
    evidence.ready === true &&
    evidence.simulationOnly === true &&
    evidence.broadcast === false &&
    evidence.network === SOLANA_TESTNET_NETWORK_ID &&
    evidence.genesisHash === SOLANA_TESTNET_GENESIS_HASH &&
    evidence.solanaCoreVersion === normalized.solanaCoreVersion &&
    evidence.featureSet === normalized.featureSet &&
    evidence.programId === normalized.programId &&
    evidence.programdataAddress === normalized.programdataAddress &&
    evidence.bufferAddress === bufferAddress &&
    evidence.bufferExecutableSha256 === normalized.targetSha256 &&
    evidence.targetArtifactSha256 === normalized.targetSha256 &&
    evidence.targetCodeHash === normalized.targetCodeHash &&
    evidence.targetExecutableLength === normalized.targetLength &&
    evidence.intendedExecutableCapacity ===
      afterDataLength - SOLANA_PROGRAMDATA_METADATA_LENGTH &&
    Number.isSafeInteger(evidence.bufferContextSlot) &&
    evidence.bufferContextSlot >= minimumContextSlot &&
    Number.isSafeInteger(evidence.simulationContextSlot) &&
    evidence.simulationContextSlot >= evidence.bufferContextSlot &&
    evidence.simulationContextSlot <= normalized.expiresAtFinalizedSlot &&
    evidence.sentinelInstructionIndex === (mode === "deploy" ? 2 : 1) &&
    evidence.expectedError === "InvalidInstructionData" &&
    isCanonicalSolanaSignature(evidence.expectedSignature) &&
    Array.isArray(evidence.expectedSignatures) &&
    evidence.expectedSignatures[0] === evidence.expectedSignature &&
    evidence.expectedSignatures.every(isCanonicalSolanaSignature) &&
    isCanonicalSolanaBlockhash(evidence.blockhash) &&
    Number.isSafeInteger(evidence.lastValidBlockHeight) &&
    evidence.lastValidBlockHeight > 0 &&
    /^0x[0-9a-f]{64}$/u.test(evidence.messageSha256) &&
    /^0x[0-9a-f]{64}$/u.test(evidence.packetSha256) &&
    Number.isSafeInteger(evidence.packetLength) &&
    evidence.packetLength > 0 &&
    evidence.packetLength <= SOLANA_PACKET_DATA_SIZE &&
    /^0x[0-9a-f]{64}$/u.test(evidence.logSha256) &&
    probeValid &&
    isRecord(journalAdmission) &&
    evidence.simulationContextSlot === journalAdmission.simulationContextSlot &&
    evidence.intendedExecutableCapacity ===
      (journalAdmission.intendedExecutableCapacity ??
        evidence.intendedExecutableCapacity) &&
    evidence.expectedSignature === journalAdmission.expectedSignature &&
    JSON.stringify(evidence.expectedSignatures) ===
      JSON.stringify(journalAdmission.expectedSignatures) &&
    evidence.blockhash === journalAdmission.blockhash &&
    evidence.lastValidBlockHeight === journalAdmission.lastValidBlockHeight &&
    evidence.messageSha256 === journalAdmission.messageSha256 &&
    evidence.packetSha256 === journalAdmission.packetSha256 &&
    evidence.packetLength === journalAdmission.packetLength &&
    evidence.logSha256 === journalAdmission.logSha256
  );
};

const exactRuntimeProgramReadback = ({
  readback,
  normalized,
  phase,
  terminal,
  inputs,
}) => {
  const keys = [
    "programId",
    "programOwner",
    "programExecutable",
    "programContextSlot",
    "programdataAddress",
    "programdataOwner",
    "programdataExecutable",
    "programdataContextSlot",
    "programdataSlot",
    "authorityAddress",
    "programdataDataLength",
    "executableLength",
    "executableSha256",
    "codeHash",
  ];
  if (
    !hasExactPublicKeys(readback, keys) ||
    readback.programId !== normalized.programId ||
    readback.programOwner !== SOLANA_UPGRADEABLE_LOADER_ID ||
    readback.programExecutable !== true ||
    !Number.isSafeInteger(readback.programContextSlot) ||
    readback.programdataAddress !== normalized.programdataAddress ||
    readback.programdataOwner !== SOLANA_UPGRADEABLE_LOADER_ID ||
    readback.programdataExecutable !== false ||
    !Number.isSafeInteger(readback.programdataContextSlot) ||
    readback.authorityAddress !== normalized.authorityAddress
  ) {
    return false;
  }
  if (phase === "before") {
    return (
      readback.programContextSlot >= normalized.minFinalizedSlot &&
      readback.programdataContextSlot >= normalized.minFinalizedSlot &&
      readback.programContextSlot <= normalized.expiresAtFinalizedSlot &&
      readback.programdataContextSlot <= normalized.expiresAtFinalizedSlot &&
      readback.programdataSlot === normalized.beforeSlot &&
      readback.programdataDataLength === normalized.beforeDataLength &&
      readback.executableLength === normalized.beforeExecutableLength &&
      readback.executableSha256 === normalized.beforeExecutableSha256 &&
      readback.codeHash === normalized.beforeCodeHash
    );
  }
  const afterDataLength =
    normalized.extension?.resultProgramdataDataLength ??
    normalized.beforeDataLength;
  const afterExecutableLength =
    afterDataLength - SOLANA_PROGRAMDATA_METADATA_LENGTH;
  const expectedExecutable = Buffer.alloc(afterExecutableLength);
  Buffer.from(inputs.targetProgram.bytes).copy(expectedExecutable);
  const expectedSha256 = `0x${createHash("sha256")
    .update(expectedExecutable)
    .digest("hex")}`;
  const expectedCodeHash = solanaExecutableBlake2b256(expectedExecutable);
  return (
    readback.programContextSlot >= terminal.finalizedSlot &&
    readback.programdataContextSlot >= terminal.finalizedSlot &&
    readback.programdataSlot === String(terminal.finalizedSlot) &&
    readback.programdataDataLength === afterDataLength &&
    readback.executableLength === afterExecutableLength &&
    readback.executableSha256 === expectedSha256 &&
    readback.codeHash === expectedCodeHash
  );
};

export const exactSolanaRuntimeUpgradeReportMatchesJournal = ({
  report,
  inputs,
  journal,
}) => {
  const terminal = journal?.terminalSummary;
  const normalized = inputs?.normalized;
  const lease = normalized
    ? solanaExistingProgramUpgradeLeaseIdentity(normalized)
    : null;
  const topKeys = [
    "schema",
    "operationId",
    "planSha256",
    "ready",
    "productionReady",
    "mode",
    "network",
    "genesisHash",
    "clusterRuntime",
    "programId",
    "programdataAddress",
    "authorityAddress",
    "payerAddress",
    "target",
    "sbfValidation",
    "rollbackSentinelAdmission",
    "journal",
    "before",
    "ephemeralBuffer",
    "extension",
    "upgrade",
    "after",
    "policy",
    "cleanup",
    "secretsZeroized",
  ];
  if (
    !normalized ||
    !isRecord(terminal) ||
    !hasExactPublicKeys(report, topKeys)
  ) {
    return false;
  }
  const expectedSbfValidation = {
    schema: inputs.sbfValidationEvidence.schema,
    valid: true,
    deterministic: true,
    validationScope: inputs.sbfValidationEvidence.validationScope,
    exactClusterAdmission: false,
    exactClusterAdmissionAuthority: "rollback-sentinel-simulation",
    productionEligible: true,
    validatorId: inputs.sbfValidationEvidence.validatorId,
    validatorVersion: inputs.sbfValidationEvidence.validatorVersion,
    policySha256: inputs.sbfValidationEvidence.policySha256,
    evidenceSha256: normalized.sbfValidationEvidenceSha256,
    artifactSha256: normalized.targetSha256,
    codeHash: normalized.targetCodeHash,
    executableLength: normalized.targetLength,
    helperBinarySha256: inputs.sbfValidationEvidence.helperBinarySha256,
    helperTargetTriple: inputs.sbfValidationEvidence.helperTargetTriple,
    jitOutcome: inputs.sbfValidationEvidence.jitOutcome,
    buildProfile: inputs.sbfValidationEvidence.buildProfile,
    validatorSourceBundleSha256:
      inputs.sbfValidationEvidence.validatorSourceBundleSha256,
    cargoLockSha256: inputs.sbfValidationEvidence.cargoLockSha256,
    rustcIdentity: inputs.sbfValidationEvidence.rustcIdentity,
    rustcIdentitySha256: inputs.sbfValidationEvidence.rustcIdentitySha256,
    resourceLimits: inputs.sbfValidationEvidence.resourceLimits,
    checks: [...inputs.sbfValidationEvidence.checks],
  };
  const journalKeys = [
    "durable",
    "journalId",
    "authorityLeaseId",
    "authorityLeaseGeneration",
    "authorityLeaseScope",
    "authorityLeaseExpiresAtFinalizedSlot",
    "authorityCustodyScope",
    "crossHostAuthorityUseExcluded",
    "claimedBeforeMutation",
    "completedAfterFinalizedReadback",
    "recoveryBufferAddress",
  ];
  const bufferKeys = [
    "address",
    "dataLength",
    "executableSha256",
    "codeHash",
    "initialize",
    "writes",
  ];
  const mutationTransactions = terminal.mutationTransactions;
  const rollbackAdmissions = terminal.rollbackAdmissions;
  if (
    !Array.isArray(mutationTransactions) ||
    !Array.isArray(rollbackAdmissions) ||
    rollbackAdmissions.length !== 2 ||
    rollbackAdmissions[0]?.stage !== "pre-extension-deploy-admission" ||
    rollbackAdmissions[1]?.stage !== "post-extension-upgrade-admission"
  ) {
    return false;
  }
  const createTerminal = mutationTransactions.find(
    (entry) => entry.stage === "create-and-initialize-buffer",
  );
  const initializeValid =
    exactRuntimeTransactionReport({
      transaction: report.ephemeralBuffer?.initialize,
      stage: "create-and-initialize-buffer",
      minimumFinalizedSlot: normalized.minFinalizedSlot,
      maximumFinalizedSlot: terminal.finalizedSlot,
      terminal: createTerminal,
    }) &&
    exactInitializeTransactionInstructions({
      transaction: report.ephemeralBuffer?.initialize,
      normalized,
      bufferAddress: terminal.bufferAddress,
    });
  let writeFloor = report.ephemeralBuffer?.initialize?.finalizedSlot;
  let writeOffset = 0;
  const writesValid =
    Array.isArray(report.ephemeralBuffer?.writes) &&
    report.ephemeralBuffer.writes.length >= 1 &&
    report.ephemeralBuffer.writes.every((transaction, index) => {
      const journalTransaction = mutationTransactions.find(
        (entry) => entry.stage === `write-buffer-${index}`,
      );
      const valid = exactRuntimeTransactionReport({
        transaction,
        stage: `write-buffer-${index}`,
        minimumFinalizedSlot: writeFloor,
        maximumFinalizedSlot: terminal.finalizedSlot,
        terminal: journalTransaction,
        writeRange: {
          offset: writeOffset,
          targetLength: normalized.targetLength,
        },
      });
      const instructionsValid = exactWriteTransactionInstructions({
        transaction,
        normalized,
        inputs,
        bufferAddress: terminal.bufferAddress,
      });
      writeFloor = transaction?.finalizedSlot;
      writeOffset = transaction?.endOffset;
      return valid && instructionsValid;
    }) &&
    writeOffset === normalized.targetLength;
  const extensionValid =
    normalized.extension === null
      ? report.extension === null
      : hasExactPublicKeys(report.extension, [
          "additionalBytes",
          "resultProgramdataDataLength",
          "transaction",
        ]) &&
        report.extension.additionalBytes ===
          normalized.extension.additionalBytes &&
        report.extension.resultProgramdataDataLength ===
          normalized.extension.resultProgramdataDataLength &&
        exactRuntimeTransactionReport({
          transaction: report.extension.transaction,
          stage: "checked-extend-programdata",
          minimumFinalizedSlot: writeFloor,
          maximumFinalizedSlot: terminal.finalizedSlot,
          terminal: mutationTransactions.find(
            (entry) => entry.stage === "checked-extend-programdata",
          ),
        }) &&
        exactExtensionTransactionInstructions({
          transaction: report.extension.transaction,
          normalized,
        });
  const expectedMutationStages = [
    "create-and-initialize-buffer",
    ...(Array.isArray(report.ephemeralBuffer?.writes)
      ? report.ephemeralBuffer.writes.map(
          (_transaction, index) => `write-buffer-${index}`,
        )
      : []),
    ...(normalized.extension === null ? [] : ["checked-extend-programdata"]),
    "upgrade-existing-program",
  ];
  return (
    report.schema === SOLANA_LOADER_V3_RUNTIME_UPGRADE_REPORT_SCHEMA &&
    report.ready === true &&
    report.productionReady === false &&
    report.mode === "existing-program-only-runtime-upgrade" &&
    report.network === SOLANA_TESTNET_NETWORK_ID &&
    report.genesisHash === SOLANA_TESTNET_GENESIS_HASH &&
    exactPublicJsonValue(report.clusterRuntime, {
      solanaCoreVersion: normalized.solanaCoreVersion,
      featureSet: normalized.featureSet,
    }) &&
    report.operationId === terminal.operationId &&
    report.planSha256 === terminal.planSha256 &&
    report.programId === terminal.programId &&
    report.programdataAddress === terminal.programdataAddress &&
    report.authorityAddress === terminal.authorityAddress &&
    report.payerAddress === terminal.payerAddress &&
    exactPublicJsonValue(report.target, {
      executableLength: normalized.targetLength,
      artifactSha256: normalized.targetSha256,
      executableSha256: normalized.targetSha256,
      codeHash: normalized.targetCodeHash,
    }) &&
    exactPublicJsonValue(report.sbfValidation, expectedSbfValidation) &&
    hasExactPublicKeys(report.rollbackSentinelAdmission, [
      "deploy",
      "upgrade",
    ]) &&
    exactRuntimeAdmissionEvidence({
      evidence: report.rollbackSentinelAdmission.deploy,
      mode: "deploy",
      inputs,
      bufferAddress: terminal.bufferAddress,
      minimumContextSlot: normalized.minFinalizedSlot,
      journalAdmission: rollbackAdmissions[0],
    }) &&
    exactRuntimeAdmissionEvidence({
      evidence: report.rollbackSentinelAdmission.upgrade,
      mode: "upgrade",
      inputs,
      bufferAddress: terminal.bufferAddress,
      minimumContextSlot:
        report.rollbackSentinelAdmission.deploy.simulationContextSlot,
      journalAdmission: rollbackAdmissions[1],
    }) &&
    hasExactPublicKeys(report.journal, journalKeys) &&
    report.journal.durable === true &&
    report.journal.journalId === lease.journalId &&
    report.journal.authorityLeaseId === terminal.leaseId &&
    report.journal.authorityLeaseGeneration === terminal.leaseGeneration &&
    report.journal.authorityLeaseScope === terminal.authorityLeaseScope &&
    report.journal.authorityLeaseExpiresAtFinalizedSlot ===
      normalized.expiresAtFinalizedSlot &&
    report.journal.authorityCustodyScope === "same-host-exclusive" &&
    report.journal.crossHostAuthorityUseExcluded === true &&
    report.journal.claimedBeforeMutation === true &&
    report.journal.completedAfterFinalizedReadback === true &&
    report.journal.recoveryBufferAddress === terminal.bufferAddress &&
    exactRuntimeProgramReadback({
      readback: report.before,
      normalized,
      phase: "before",
      terminal,
      inputs,
    }) &&
    hasExactPublicKeys(report.ephemeralBuffer, bufferKeys) &&
    report.ephemeralBuffer.address === terminal.bufferAddress &&
    report.ephemeralBuffer.dataLength ===
      SOLANA_BUFFER_METADATA_LENGTH + normalized.targetLength &&
    report.ephemeralBuffer.executableSha256 === normalized.targetSha256 &&
    report.ephemeralBuffer.codeHash === normalized.targetCodeHash &&
    initializeValid &&
    writesValid &&
    extensionValid &&
    JSON.stringify(mutationTransactions.map((entry) => entry.stage)) ===
      JSON.stringify(expectedMutationStages) &&
    exactRuntimeTransactionReport({
      transaction: report.upgrade,
      stage: "upgrade-existing-program",
      minimumFinalizedSlot:
        report.rollbackSentinelAdmission.upgrade.simulationContextSlot,
      maximumFinalizedSlot: terminal.finalizedSlot,
      terminal,
    }) &&
    exactUpgradeTransactionInstructions({
      transaction: report.upgrade,
      normalized,
      bufferAddress: terminal.bufferAddress,
    }) &&
    exactRuntimeProgramReadback({
      readback: report.after,
      normalized,
      phase: "after",
      terminal,
      inputs,
    }) &&
    exactPublicJsonValue(report.policy, {
      existingProgramOnly: true,
      stableProgramKeypairAccepted: false,
      fileBackedSignersAccepted: false,
      automaticMutationRetries: 0,
      maxPacketBytes: SOLANA_PACKET_DATA_SIZE,
      everyMutationFinalizedAndFetched: true,
      exactZeroPaddingRequired: true,
    }) &&
    exactPublicJsonValue(report.cleanup, {
      required: false,
      finalized: true,
      reason: "Loader-v3 Upgrade consumed the ephemeral buffer.",
    }) &&
    report.target?.artifactSha256 === terminal.targetArtifactSha256 &&
    report.target?.executableLength === terminal.targetExecutableLength &&
    report.target?.codeHash === inputs.normalized.targetCodeHash &&
    report.secretsZeroized === true
  );
};

export const exactSolanaRuntimeRecoveryReportMatchesJournal = ({
  report,
  inputs,
  journal,
}) => {
  const terminal = journal?.terminalSummary;
  const normalized = inputs?.normalized;
  const topKeys = [
    "schema",
    "operationId",
    "planSha256",
    "claimEventSha256",
    "ready",
    "mode",
    "network",
    "genesisHash",
    "programId",
    "programdataAddress",
    "bufferAddress",
    "authorityAddress",
    "payerAddress",
    "target",
    "journal",
    "transaction",
    "secretsZeroized",
  ];
  if (
    !normalized ||
    !isRecord(terminal) ||
    !hasExactPublicKeys(report, topKeys)
  ) {
    return false;
  }
  return (
    report.schema === SOLANA_LOADER_V3_RUNTIME_RECOVERY_REPORT_SCHEMA &&
    report.ready === true &&
    report.mode === "journaled-buffer-finalized-close" &&
    report.network === SOLANA_TESTNET_NETWORK_ID &&
    report.genesisHash === SOLANA_TESTNET_GENESIS_HASH &&
    report.operationId === terminal.operationId &&
    report.planSha256 === terminal.planSha256 &&
    report.claimEventSha256 === terminal.claimEventSha256 &&
    report.programId === terminal.programId &&
    report.programdataAddress === terminal.programdataAddress &&
    report.authorityAddress === terminal.authorityAddress &&
    report.payerAddress === terminal.payerAddress &&
    report.bufferAddress === terminal.bufferAddress &&
    exactPublicJsonValue(report.target, {
      executableLength: normalized.targetLength,
      artifactSha256: normalized.targetSha256,
      executableSha256: normalized.targetSha256,
      codeHash: normalized.targetCodeHash,
    }) &&
    hasExactPublicKeys(report.journal, [
      "durable",
      "journalId",
      "authorityLeaseId",
      "authorityLeaseGeneration",
      "authorityLeaseScope",
      "recoveryCompleted",
    ]) &&
    report.journal.durable === true &&
    report.journal.journalId ===
      solanaRuntimeUpgradeJournalId(terminal.operationId) &&
    report.journal.authorityLeaseId === terminal.leaseId &&
    report.journal.authorityLeaseGeneration === terminal.leaseGeneration &&
    report.journal.authorityLeaseScope === terminal.authorityLeaseScope &&
    report.journal.recoveryCompleted === true &&
    exactRuntimeTransactionReport({
      transaction: report.transaction,
      stage: "recover-close-orphan-buffer",
      minimumFinalizedSlot: terminal.finalizedSlot,
      maximumFinalizedSlot: terminal.finalizedSlot,
      terminal,
    }) &&
    exactRecoveryTransactionInstructions({
      transaction: report.transaction,
      normalized,
      bufferAddress: terminal.bufferAddress,
    }) &&
    report.secretsZeroized === true &&
    inputs.normalized.targetSha256 === terminal.targetArtifactSha256
  );
};

