const buildProductionPostDeployLiveEvidence = ({
  manifest,
  offlineFullTomlSha256,
}) => {
  const existing = readFirstManifestRecord(
    manifest,
    "postDeployLiveEvidence",
    "post_deploy_live_evidence",
  );
  const normalizedOfflineFullTomlSha256 = normalizeManifestHex32(
    offlineFullTomlSha256,
    "offlineFullTomlSha256",
  );
  const sourceBridgeConfigHash = normalizeManifestHex32(
    requireManifestString(
      existing,
      ["sourceBridgeConfigHash", "source_bridge_config_hash"],
      "postDeployLiveEvidence.sourceBridgeConfigHash",
    ),
    "postDeployLiveEvidence.sourceBridgeConfigHash",
  );
  const routeCanaryEvidenceHash = normalizeManifestHex32(
    requireManifestString(
      existing,
      ["routeCanaryEvidenceHash", "route_canary_evidence_hash"],
      "postDeployLiveEvidence.routeCanaryEvidenceHash",
    ),
    "postDeployLiveEvidence.routeCanaryEvidenceHash",
  );
  const sourceEventTransactionSignature = normalizeSolanaSignature(
    requireManifestString(
      existing,
      [
        "sourceEventTransactionSignature",
        "source_event_transaction_signature",
        "sourceEventSignature",
        "source_event_signature",
        "sourceEventTransactionId",
        "source_event_transaction_id",
      ],
      "postDeployLiveEvidence.sourceEventTransactionSignature",
    ),
    "postDeployLiveEvidence.sourceEventTransactionSignature",
  );
  const routeCanaryTransactionSignature = normalizeSolanaSignature(
    requireManifestString(
      existing,
      [
        "routeCanaryTransactionSignature",
        "route_canary_transaction_signature",
        "routeCanarySignature",
        "route_canary_signature",
        "routeCanaryTransactionId",
        "route_canary_transaction_id",
      ],
      "postDeployLiveEvidence.routeCanaryTransactionSignature",
    ),
    "postDeployLiveEvidence.routeCanaryTransactionSignature",
  );
  return {
    schema: "iroha-sccp-solana-post-deploy-live-evidence/v1",
    fullTomlReady: true,
    full_toml_ready: true,
    sourceBridgeConfigHash,
    source_bridge_config_hash: sourceBridgeConfigHash,
    routeCanaryEvidenceHash,
    route_canary_evidence_hash: routeCanaryEvidenceHash,
    offlineFullTomlSha256: normalizedOfflineFullTomlSha256,
    offline_full_toml_sha256: normalizedOfflineFullTomlSha256,
    sourceEventTransactionSignature,
    source_event_transaction_signature: sourceEventTransactionSignature,
    routeCanaryTransactionSignature,
    route_canary_transaction_signature: routeCanaryTransactionSignature,
  };
};

const buildProductionBrowserProverRecord = ({
  manifest,
  recordKeys,
  label,
  direction,
  moduleHash,
  sidecarHash,
  routeAllowlistHash,
}) => {
  const existing = readFirstManifestRecord(manifest, ...recordKeys) ?? {};
  const normalizedModuleHash = normalizeManifestHex32(
    moduleHash,
    `${label}.moduleHash`,
  );
  const normalizedSidecarHash = normalizeManifestHex32(
    sidecarHash,
    `${label}.sidecarHash`,
  );
  const moduleUrl = requireManifestString(
    existing,
    ["moduleUrl", "module_url"],
    `${label}.moduleUrl`,
  );
  const sidecarUrl =
    readFirstManifestString(existing, "sidecarUrl", "sidecar_url") ||
    defaultSolanaProverSidecarUrl(moduleUrl, `${label}.sidecarUrl`);
  const destination = direction === "destination";
  const proofBackend = destination
    ? SOLANA_DESTINATION_PROOF_BACKEND
    : SOLANA_SOURCE_PROOF_BACKEND;
  const destinationBindingHash = normalizeManifestHex32(
    requireManifestString(
      manifest,
      ["destinationBindingHash", "destination_binding_hash"],
      "Solana destinationBindingHash",
    ),
    "Solana destinationBindingHash",
  );
  const boundProofHash = normalizeManifestHex32(
    readFirstManifestString(existing, "boundProofHash", "bound_proof_hash") ||
      normalizedModuleHash,
    `${label}.boundProofHash`,
  );
  return {
    route_id: SCCP_SOLANA_XOR_ROUTE_ID,
    asset_key: SCCP_XOR_ASSET_KEY,
    network: SOLANA_TESTNET_NETWORK_ID,
    solana_network: SOLANA_TESTNET_NETWORK_ID,
    genesis_hash: SOLANA_TESTNET_GENESIS_HASH,
    direction,
    source_domain: destination ? SCCP_SORA_DOMAIN : SCCP_SOLANA_DOMAIN,
    target_domain: destination ? SCCP_SOLANA_DOMAIN : SCCP_SORA_DOMAIN,
    module_specifier:
      typeof existing.module_specifier === "string"
        ? existing.module_specifier
        : null,
    module_url: moduleUrl,
    sidecar_url: sidecarUrl,
    module_hash: normalizedModuleHash,
    manifest_hash: normalizedSidecarHash,
    sidecar_hash: normalizedSidecarHash,
    proof_backend: proofBackend,
    required_proof_backend: proofBackend,
    ...(destination
      ? {
          destination_verifier_plan: SOLANA_DESTINATION_VERIFIER_PLAN,
          verifier_target: SOLANA_VERIFIER_TARGET,
        }
      : {}),
    production_proofs_ready: true,
    bound_route_hash: destinationBindingHash,
    bound_proof_hash: boundProofHash,
    route_allowlist_hash: routeAllowlistHash,
  };
};

const stripRetiredSolanaManifestAliases = (manifest) => {
  const nextManifest = clonePublicJson(manifest);
  for (const [alias, canonical] of [
    ["productionReady", "production_ready"],
    ["routeId", "route_id"],
    ["assetKey", "asset_key"],
    ["solanaNetwork", "solana_network"],
    ["chainIdHex", "chain_id_hex"],
    ["counterpartyAccountCodec", "counterparty_account_codec"],
    ["counterpartyAccountCodecKey", "counterparty_account_codec_key"],
    ["counterpartyDomain", "counterparty_domain"],
    ["verifierTarget", "verifier_target"],
    ["networkIdHex", "network_id_hex"],
    ["sourceVerifierMaterial", "source_verifier_material"],
    ["sourceAdapterEngineDeployment", "source_adapter_engine_deployment"],
    ["sourceAdapterEngine", "source_adapter_engine"],
    ["solanaProgramId", "taira_xor_bridge_address"],
    ["tairaXorSolanaProgramId", "taira_xor_bridge_address"],
    ["solana_program_id", "taira_xor_bridge_address"],
    ["taira_xor_solana_program_id", "taira_xor_bridge_address"],
    ["tairaXorTokenAddress", "taira_xor_token_address"],
    ["solana_token_mint", "taira_xor_token_address"],
    ["solanaTokenMint", "taira_xor_token_address"],
    ["sccpSolanaSourceBridgeAddress", "sccp_solana_source_bridge_address"],
    ["solana_source_bridge_address", "sccp_solana_source_bridge_address"],
    ["solanaSourceBridgeAddress", "sccp_solana_source_bridge_address"],
    ["solanaVerifierProgramId", "solana_verifier_program_id"],
    ["solanaNativeVerifierProgramId", "solana_native_verifier_program_id"],
    [
      "solanaNativeVerifierProgramdataAddress",
      "solana_native_verifier_programdata_address",
    ],
    [
      "solanaNativeVerifierProgramdataSlot",
      "solana_native_verifier_programdata_slot",
    ],
    ["solanaNativeVerifierCodeHash", "solana_native_verifier_code_hash"],
    [
      "solanaNativeVerifierArtifactSha256",
      "solana_native_verifier_artifact_sha256",
    ],
    [
      "solanaNativeVerifierMaterialHash",
      "solana_native_verifier_material_hash",
    ],
    ["solanaNativeVerifierConfigHash", "solana_native_verifier_config_hash"],
    ["solanaNativeVerifierKeyHash", "solana_native_verifier_key_hash"],
    [
      "solanaNativeVerifierGovernanceApprovalEvidenceHash",
      "solana_native_verifier_governance_approval_evidence_hash",
    ],
  ]) {
    if (
      nextManifest[canonical] === undefined &&
      nextManifest[alias] !== undefined
    ) {
      nextManifest[canonical] = clonePublicJson(nextManifest[alias]);
    }
  }
  for (const [alias, canonical] of [
    ["destinationBrowserProver", "destination_browser_prover"],
    ["sourceBrowserProver", "source_browser_prover"],
  ]) {
    if (
      nextManifest[canonical] === undefined &&
      isRecord(nextManifest[alias])
    ) {
      nextManifest[canonical] = clonePublicJson(nextManifest[alias]);
    }
  }
  for (const key of SOLANA_ROUTE_MANIFEST_RETIRED_TOP_LEVEL_ALIASES) {
    delete nextManifest[key];
  }
  for (const key of ["destination_browser_prover", "source_browser_prover"]) {
    if (isRecord(nextManifest[key])) {
      for (const [alias, canonical] of [
        ["moduleSpecifier", "module_specifier"],
        ["moduleUrl", "module_url"],
        ["moduleHash", "module_hash"],
        ["manifestHash", "manifest_hash"],
        ["sidecarHash", "sidecar_hash"],
        ["proofBackend", "proof_backend"],
        ["requiredProofBackend", "required_proof_backend"],
        ["productionProofsReady", "production_proofs_ready"],
        ["expectedExports", "expected_exports"],
        ["boundRouteHash", "bound_route_hash"],
        ["boundProofHash", "bound_proof_hash"],
      ]) {
        if (
          nextManifest[key][canonical] === undefined &&
          nextManifest[key][alias] !== undefined
        ) {
          nextManifest[key][canonical] = clonePublicJson(
            nextManifest[key][alias],
          );
        }
      }
      for (const alias of SOLANA_BROWSER_PROVER_RETIRED_ALIASES) {
        delete nextManifest[key][alias];
      }
    }
  }
  return nextManifest;
};

const applySolanaProductionManifestPatch = (manifest, patch) => {
  const nextManifest = clonePublicJson(manifest);
  for (const key of [
    "disabledReason",
    "disabled_reason",
    "destinationProofAdmission",
    "destination_proof_admission",
    "verifierEnforcement",
    "verifier_enforcement",
    "destinationRollout",
    "destination_rollout",
    "productionReadiness",
    "production_readiness",
    "postDeployLiveEvidence",
    "post_deploy_live_evidence",
  ]) {
    delete nextManifest[key];
  }
  return stripRetiredSolanaManifestAliases({
    ...nextManifest,
    ...clonePublicJson(patch),
  });
};

const normalizeSolanaGovernanceProgramRolePinsForPublication = (value) => {
  if (
    value?.schema !== "iroha-demo-sccp-solana-governance-program-role-pins/v1"
  ) {
    throw new Error(
      "An independently approved Solana governance program-role pin record is required for manifest publication.",
    );
  }
  const approvalSha256 = normalizeProductionMaterialHex32(
    value.approvalSha256,
    "governance program-role approval SHA-256",
  );
  const expectedApprovalSha256 = normalizeProductionMaterialHex32(
    value.expectedApprovalSha256,
    "governance program-role expected approval SHA-256",
  );
  if (approvalSha256 !== expectedApprovalSha256) {
    throw new Error(
      "Solana governance program-role pins are not bound to the independently expected approval SHA-256.",
    );
  }
  const roles = {};
  for (const spec of SOLANA_GOVERNANCE_PROGRAM_ROLE_SPECS) {
    const role = value.roles?.[spec.role];
    if (!isRecord(role)) {
      throw new Error(`${spec.label} governance pins are missing.`);
    }
    roles[spec.role] = {
      programId: new PublicKey(role.programId).toBase58(),
      programdataAddress: new PublicKey(role.programdataAddress).toBase58(),
      programdataSlot: normalizeRoleProgramdataSlot(
        role.programdataSlot,
        `${spec.label} ProgramData slot`,
      ),
      artifactSha256: normalizeProductionMaterialHex32(
        role.artifactSha256,
        `${spec.label} artifact SHA-256`,
      ),
      codeHash: normalizeProductionMaterialHex32(
        role.codeHash,
        `${spec.label} code hash`,
      ),
    };
  }
  for (const field of ["programId", "programdataAddress"]) {
    const values = Object.values(roles).map((role) => role[field]);
    if (new Set(values).size !== values.length) {
      throw new Error(
        `Solana governance program-role ${field} values must be distinct.`,
      );
    }
  }
  return { approvalSha256, expectedApprovalSha256, roles };
};

