const valueStatus = ({ record, requirement, label, validator }) => {
  const keys = [
    requirement.key,
    requirement.snakeKey,
    ...(requirement.aliases ?? []),
  ].filter(Boolean);
  const value = readFirstManifestString(record, ...keys);
  if (!value) {
    return {
      key: requirement.key,
      manifestKeys: keys,
      helperArg: requirement.helperArg,
      description: requirement.description,
      status: "missing",
      ...(requirement.value ? { value: requirement.value } : {}),
      ...(requirement.source ? { source: requirement.source } : {}),
    };
  }
  try {
    const normalized = validator(value, `${label}.${requirement.key}`);
    const expected = requirement.value
      ? validator(requirement.value, `${label}.${requirement.key}`)
      : null;
    if (expected && normalized !== expected) {
      return {
        key: requirement.key,
        manifestKeys: keys,
        helperArg: requirement.helperArg,
        description: requirement.description,
        status: "invalid",
        value: normalized,
        expected,
        ...(requirement.source ? { source: requirement.source } : {}),
        error: `${label}.${requirement.key} must match the canonical Solana source-adapter verifier profile.`,
      };
    }
    return {
      key: requirement.key,
      manifestKeys: keys,
      helperArg: requirement.helperArg,
      description: requirement.description,
      status: "present",
      value: normalized,
      ...(expected ? { expected } : {}),
      ...(requirement.source ? { source: requirement.source } : {}),
    };
  } catch (error) {
    return {
      key: requirement.key,
      manifestKeys: keys,
      helperArg: requirement.helperArg,
      description: requirement.description,
      status: "invalid",
      value,
      ...(requirement.value ? { expected: requirement.value } : {}),
      ...(requirement.source ? { source: requirement.source } : {}),
      error: error instanceof Error ? error.message : String(error),
    };
  }
};

const hexRequirementStatuses = (record, requirements, label) =>
  requirements.map((requirement) =>
    valueStatus({
      record,
      requirement,
      label,
      validator: normalizeProductionMaterialHex32,
    }),
  );

const genericHexRequirementStatuses = (record, requirements, label) =>
  requirements.map((requirement) =>
    valueStatus({
      record,
      requirement,
      label,
      validator: normalizeManifestHex32,
    }),
  );

const signatureRequirementStatuses = (record, requirements, label) =>
  requirements.map((requirement) =>
    valueStatus({
      record,
      requirement,
      label,
      validator: (value) => {
        const normalized = String(value ?? "").trim();
        if (!/^[1-9A-HJ-NP-Za-km-z]{64,88}$/u.test(normalized)) {
          throw new Error("Solana signature must be Base58.");
        }
        return normalized;
      },
    }),
  );

const exactStringRequirementStatuses = (record, requirements, label) =>
  requirements.map((requirement) =>
    valueStatus({
      record,
      requirement,
      label,
      validator: (value) => {
        const normalized = String(value ?? "").trim();
        if (normalized !== requirement.expectedValue) {
          throw new Error(
            `${label}.${requirement.key} must be ${requirement.expectedValue}.`,
          );
        }
        return normalized;
      },
    }),
  );

const missingOrInvalid = (statuses) =>
  statuses.filter((status) => status.status !== "present");

const readManifestHash = (record, requirement) =>
  readFirstManifestString(record, requirement.key, requirement.snakeKey);

const admissionHashBindingStatuses = (admission, manifest) =>
  [
    {
      key: "verifierCodeHash",
      snakeKey: "verifier_code_hash",
      description: "Must match the route manifest verifierCodeHash.",
    },
    {
      key: "verifierKeyHash",
      snakeKey: "verifier_key_hash",
      description: "Must match the route manifest verifierKeyHash.",
    },
    {
      key: "destinationBindingHash",
      snakeKey: "destination_binding_hash",
      description: "Must match the route manifest destinationBindingHash.",
    },
  ].map((requirement) => {
    const base = valueStatus({
      record: admission,
      requirement,
      label: "destinationProofAdmission",
      validator: normalizeManifestHex32,
    });
    if (base.status !== "present") {
      return base;
    }
    try {
      const expected = normalizeManifestHex32(
        requireManifestString(
          manifest,
          [requirement.key, requirement.snakeKey],
          `Solana ${requirement.key}`,
        ),
        `Solana ${requirement.key}`,
      );
      if (base.value !== expected) {
        return {
          ...base,
          status: "invalid",
          expected,
          error: `${requirement.key} does not match the route manifest.`,
        };
      }
      return { ...base, expected };
    } catch (error) {
      return {
        ...base,
        status: "invalid",
        error: error instanceof Error ? error.message : String(error),
      };
    }
  });

const requirementCommandValue = (requirement) =>
  requirement.value ?? placeholderFor(requirement.snakeKey);

const proofRequirementDescriptor = ({
  key,
  snakeKey,
  helperArg,
  description,
  value,
  source,
}) => ({
  key,
  snakeKey,
  helperArg,
  description,
  ...(value ? { value } : {}),
  ...(source ? { source } : {}),
});

const requiredInputDescriptor = ({
  key,
  helperArg,
  description,
  value,
  source,
}) => ({
  id: key,
  helperArg,
  description,
  ...(value ? { value } : {}),
  ...(source ? { source } : {}),
});

const buildSourceEvidenceCommand = () => [
  "python3",
  "../iroha/scripts/sccp_solana_source_state_evidence.py",
  "--solana-network",
  SOLANA_TESTNET_NETWORK_ID,
  ...[
    ...SOLANA_SOURCE_ADAPTER_REQUIREMENTS,
    ...SOLANA_FULL_LIGHT_CLIENT_REQUIREMENTS,
    ...SOLANA_EXPECTED_SOURCE_RECORD_REQUIREMENTS,
  ].flatMap((requirement) => [
    requirement.helperArg,
    requirementCommandValue(requirement),
  ]),
  "--toml",
];

const buildLiveEvidenceCommand = ({
  args,
  publicConfig,
  deploymentAddresses = null,
  verifierEvidence,
  verifierLiveEvidence,
  manifest,
}) => [
  "python3",
  "../iroha/scripts/sccp_solana_live_evidence.py",
  "--rpc-url",
  args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
  "--verifier-program-id",
  deploymentAddresses?.verifierProgramId ||
    readFirstManifestString(
      manifest,
      "solanaVerifierProgramId",
      "solana_verifier_program_id",
      "verifierIdentity",
      "verifier_identity",
    ) ||
    publicConfig?.verifierProgramId ||
    publicConfig?.programId ||
    "<solana-verifier-program-id>",
  "--expected-verifier-code-hash",
  readFirstManifestString(manifest, "verifierCodeHash", "verifier_code_hash") ||
    verifierLiveEvidence?.verifier_code_hash ||
    placeholderFor("verifier_code_hash"),
  "--expected-programdata-address",
  readFirstManifestString(
    manifest,
    "solanaProgramdataAddress",
    "solana_programdata_address",
    "programDataAddress",
    "programdataAddress",
  ) ||
    outerVerifierEvidenceFacts(verifierEvidence).programDataAddress ||
    "<programdata-address>",
  "--expected-programdata-slot",
  readFirstManifestStringLike(
    manifest,
    "solanaProgramdataSlot",
    "solana_programdata_slot",
    "programDataSlot",
    "programdataSlot",
  ) ||
    String(
      outerVerifierEvidenceFacts(verifierEvidence).programDataSlot ??
        "<programdata-slot>",
    ),
  "--route-allowlist-hash",
  placeholderFor("route_allowlist_hash"),
  "--source-verifier-material-hash",
  placeholderFor("source_verifier_material_hash"),
  "--source-adapter-engine-deployment-hash",
  placeholderFor("source_adapter_engine_deployment_hash"),
  "--route-canary-evidence-hash",
  placeholderFor("route_canary_evidence_hash"),
  "--expected-destination-binding-hash",
  SOLANA_DESTINATION_BINDING_HASH,
  "--toml",
];

const normalizeSolanaPublicKeyString = (value, label) => {
  const raw = String(value ?? "").trim();
  if (!raw) {
    throw new Error(`${label} is required.`);
  }
  return new PublicKey(raw).toBase58();
};

const normalizePositiveSlotString = (value, label) => {
  const raw = String(value ?? "").trim();
  if (!/^[1-9][0-9]*$/u.test(raw)) {
    throw new Error(`${label} must be a positive integer slot.`);
  }
  return raw;
};

const materialRecordReadyForHash = (record, requirements, label) =>
  isRecord(record) &&
  readFirstManifestBoolean(
    record,
    "placeholderMaterial",
    "placeholder_material",
  ) !== true &&
  readFirstManifestBoolean(record, "templateOnly", "template_only") !== true &&
  !readFirstManifestString(record, "disabledReason", "disabled_reason") &&
  missingOrInvalid(hexRequirementStatuses(record, requirements, label))
    .length === 0;

const readyInventoryMaterialHash = (productionMaterialInventory, role) => {
  const material = productionMaterialInventory?.readyMaterial?.[role];
  const hash = readFirstManifestString(material, "recordHash", "record_hash");
  return hash || "";
};

const materialHashFromManifestRecord = ({ record, requirements, label }) => {
  const explicitHash = readFirstManifestString(
    record,
    `${label}Hash`,
    `${label.replace(/[A-Z]/gu, (char) => `_${char.toLowerCase()}`)}_hash`,
  );
  if (explicitHash) {
    return explicitHash;
  }
  return materialRecordReadyForHash(record, requirements, label)
    ? sha256JsonHex(record)
    : "";
};

const readSolanaPostDeployLiveEvidence = ({
  postDeployManifestEvidence = null,
  manifest = null,
} = {}) =>
  readFirstManifestRecord(
    postDeployManifestEvidence,
    "postDeployLiveEvidence",
    "post_deploy_live_evidence",
  ) ??
  readFirstManifestRecord(
    manifest,
    "postDeployLiveEvidence",
    "post_deploy_live_evidence",
  );

const resolveSolanaPostDeployFullTomlRawInputs = ({
  args = {},
  publicConfig = null,
  verifierEvidence = null,
  verifierLiveEvidence = null,
  manifest = null,
  postDeployManifestEvidence = null,
  routeCanarySubmission = null,
  productionMaterialInventory = null,
  routeAllowlistHash = null,
} = {}) => {
  const sourceVerifierMaterial = readFirstManifestRecord(
    manifest,
    "sourceVerifierMaterial",
    "source_verifier_material",
  );
  const sourceAdapterEngineDeployment = readFirstManifestRecord(
    manifest,
    "sourceAdapterEngineDeployment",
    "source_adapter_engine_deployment",
    "sourceAdapterDeployment",
    "source_adapter_deployment",
  );
  const postDeployLiveEvidence = readSolanaPostDeployLiveEvidence({
    postDeployManifestEvidence,
    manifest,
  });
  const destinationProofAdmission = readDestinationProofAdmission(manifest);
  return {
    rpcUrl: args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
    commitment: args.commitment || "finalized",
    verifierProgramId:
      args["program-id"] ||
      publicConfig?.verifierProgramId ||
      publicConfig?.programId ||
      readFirstManifestString(
        manifest,
        "solanaVerifierProgramId",
        "solana_verifier_program_id",
      ),
    expectedVerifierCodeHash:
      args["expected-verifier-code-hash"] ||
      readFirstManifestString(
        manifest,
        "verifierCodeHash",
        "verifier_code_hash",
      ) ||
      readFirstManifestString(
        verifierLiveEvidence,
        "verifier_code_hash",
        "verifierCodeHash",
      ),
    expectedProgramdataAddress:
      args["expected-programdata-address"] ||
      readFirstManifestString(
        verifierLiveEvidence,
        "programdata_address",
        "programdataAddress",
      ) ||
      readFirstManifestString(
        manifest,
        "solanaProgramdataAddress",
        "solana_programdata_address",
      ) ||
      outerVerifierEvidenceFacts(verifierEvidence).programDataAddress,
    expectedProgramdataSlot:
      args["expected-programdata-slot"] ||
      readFirstManifestString(
        verifierLiveEvidence,
        "programdata_slot",
        "programdataSlot",
      ) ||
      readFirstManifestString(
        manifest,
        "solanaProgramdataSlot",
        "solana_programdata_slot",
      ) ||
      outerVerifierEvidenceFacts(verifierEvidence).programDataSlot,
    destinationBindingHash:
      args["expected-destination-binding-hash"] ||
      readFirstManifestString(
        manifest,
        "destinationBindingHash",
        "destination_binding_hash",
      ) ||
      SOLANA_DESTINATION_BINDING_HASH,
    sourceVerifierMaterialHash:
      args["source-verifier-material-hash"] ||
      readyInventoryMaterialHash(
        productionMaterialInventory,
        "sourceVerifierMaterial",
      ) ||
      materialHashFromManifestRecord({
        record: sourceVerifierMaterial,
        requirements: SOLANA_SOURCE_VERIFIER_REQUIREMENTS,
        label: "sourceVerifierMaterial",
      }),
    sourceAdapterEngineDeploymentHash:
      args["source-adapter-engine-deployment-hash"] ||
      readyInventoryMaterialHash(
        productionMaterialInventory,
        "sourceAdapterEngineDeployment",
      ) ||
      materialHashFromManifestRecord({
        record: sourceAdapterEngineDeployment,
        requirements: SOLANA_SOURCE_ADAPTER_PRODUCTION_REQUIREMENTS,
        label: "sourceAdapterEngineDeployment",
      }),
    routeAllowlistHash:
      args["route-allowlist-hash"] ||
      routeAllowlistHash ||
      readFirstManifestString(
        destinationProofAdmission,
        "routeAllowlistHash",
        "route_allowlist_hash",
      ),
    routeCanaryEvidenceHash:
      args["route-canary-evidence-hash"] ||
      readFirstManifestString(
        postDeployLiveEvidence,
        "routeCanaryEvidenceHash",
        "route_canary_evidence_hash",
      ) ||
      readFirstManifestString(
        routeCanarySubmission?.envelope,
        "canaryEvidenceHash",
        "canary_evidence_hash",
      ),
  };
};

const postDeployFullTomlInputStatus = ({
  key,
  value,
  description,
  validator,
}) => {
  if (value === undefined || value === null || String(value).trim() === "") {
    return {
      key,
      status: "missing",
      description,
    };
  }
  try {
    return {
      key,
      status: "present",
      description,
      value: validator(value, key),
    };
  } catch (error) {
    return {
      key,
      status: "invalid",
      description,
      value,
      error: error instanceof Error ? error.message : String(error),
    };
  }
};

const normalizeSolanaPostDeployFullTomlInputs = (rawInputs) => [
  postDeployFullTomlInputStatus({
    key: "verifierProgramId",
    value: rawInputs.verifierProgramId,
    description: "Deployed Solana verifier program id.",
    validator: normalizeSolanaPublicKeyString,
  }),
  postDeployFullTomlInputStatus({
    key: "expectedVerifierCodeHash",
    value: rawInputs.expectedVerifierCodeHash,
    description: "Pinned deployed verifier ProgramData code hash.",
    validator: normalizeManifestHex32,
  }),
  postDeployFullTomlInputStatus({
    key: "expectedProgramdataAddress",
    value: rawInputs.expectedProgramdataAddress,
    description: "Pinned Solana ProgramData account address.",
    validator: normalizeSolanaPublicKeyString,
  }),
  postDeployFullTomlInputStatus({
    key: "expectedProgramdataSlot",
    value: rawInputs.expectedProgramdataSlot,
    description: "Pinned positive ProgramData deployment slot.",
    validator: normalizePositiveSlotString,
  }),
  postDeployFullTomlInputStatus({
    key: "sourceVerifierMaterialHash",
    value: rawInputs.sourceVerifierMaterialHash,
    description: "Governed source verifier material record hash.",
    validator: normalizeProductionMaterialHex32,
  }),
  postDeployFullTomlInputStatus({
    key: "sourceAdapterEngineDeploymentHash",
    value: rawInputs.sourceAdapterEngineDeploymentHash,
    description: "Governed source adapter engine deployment record hash.",
    validator: normalizeProductionMaterialHex32,
  }),
  postDeployFullTomlInputStatus({
    key: "routeAllowlistHash",
    value: rawInputs.routeAllowlistHash,
    description:
      "Governed route allowlist hash derived from source material and destination binding.",
    validator: normalizeProductionMaterialHex32,
  }),
  postDeployFullTomlInputStatus({
    key: "routeCanaryEvidenceHash",
    value: rawInputs.routeCanaryEvidenceHash,
    description: "Live post-deploy route canary evidence hash.",
    validator: normalizeProductionMaterialHex32,
  }),
  postDeployFullTomlInputStatus({
    key: "destinationBindingHash",
    value: rawInputs.destinationBindingHash,
    description: "Canonical SORA-to-Solana destination binding hash.",
    validator: normalizeManifestHex32,
  }),
];

const statusValue = (statuses, key) =>
  statuses.find((status) => status.key === key)?.value ?? null;

const buildSolanaPostDeployFullTomlHelperArgs = ({ rawInputs, statuses }) => [
  siblingLiveEvidenceScript,
  "--rpc-url",
  rawInputs.rpcUrl,
  "--verifier-program-id",
  statusValue(statuses, "verifierProgramId") || "<solana-verifier-program-id>",
  "--commitment",
  rawInputs.commitment,
  "--expected-verifier-code-hash",
  statusValue(statuses, "expectedVerifierCodeHash") ||
    placeholderFor("verifier_code_hash"),
  "--expected-programdata-address",
  statusValue(statuses, "expectedProgramdataAddress") ||
    "<programdata-address>",
  "--expected-programdata-slot",
  statusValue(statuses, "expectedProgramdataSlot") || "<programdata-slot>",
  "--route-allowlist-hash",
  statusValue(statuses, "routeAllowlistHash") ||
    placeholderFor("route_allowlist_hash"),
  "--source-verifier-material-hash",
  statusValue(statuses, "sourceVerifierMaterialHash") ||
    placeholderFor("source_verifier_material_hash"),
  "--source-adapter-engine-deployment-hash",
  statusValue(statuses, "sourceAdapterEngineDeploymentHash") ||
    placeholderFor("source_adapter_engine_deployment_hash"),
  "--route-canary-evidence-hash",
  statusValue(statuses, "routeCanaryEvidenceHash") ||
    placeholderFor("route_canary_evidence_hash"),
  "--expected-destination-binding-hash",
  statusValue(statuses, "destinationBindingHash") ||
    SOLANA_DESTINATION_BINDING_HASH,
  "--toml",
];

export const buildSolanaPostDeployFullTomlReportBody = ({
  args = {},
  publicConfig = null,
  verifierEvidence = null,
  verifierLiveEvidence = null,
  manifest = null,
  postDeployManifestEvidence = null,
  routeCanarySubmission = null,
  productionMaterialInventory = null,
  routeAllowlistHash = null,
  routeAllowlistDerivationError = null,
  helperResult = null,
  tomlPath = null,
  tomlSha256 = null,
  appliedPostDeployManifestEvidence = null,
  applyError = null,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const rawInputs = resolveSolanaPostDeployFullTomlRawInputs({
    args,
    publicConfig,
    verifierEvidence,
    verifierLiveEvidence,
    manifest,
    postDeployManifestEvidence,
    routeCanarySubmission,
    productionMaterialInventory,
    routeAllowlistHash,
  });
  const inputStatuses = normalizeSolanaPostDeployFullTomlInputs(rawInputs);
  const inputBlockers = inputStatuses
    .filter((status) => status.status !== "present")
    .map((status) => ({
      id: normalizeSolanaReportBlockerId(status.key),
      detail:
        status.error ||
        `${normalizeSolanaReportBlockerId(status.key)} is required.`,
    }));
  if (routeAllowlistDerivationError) {
    inputBlockers.push({
      id: "route-allowlist-hash-derivation",
      detail: routeAllowlistDerivationError,
    });
  }
  const readyToRender = inputBlockers.length === 0;
  const helperExitStatus =
    helperResult && typeof helperResult.status === "number"
      ? helperResult.status
      : null;
  const helperSucceeded = helperExitStatus === 0;
  const normalizedTomlSha256 =
    typeof tomlSha256 === "string"
      ? normalizeManifestHex32(tomlSha256, "offlineFullTomlSha256")
      : null;
  const fullTomlReady =
    readyToRender &&
    helperSucceeded &&
    Boolean(tomlPath) &&
    Boolean(tomlSha256);
  const blockers = [
    ...inputBlockers,
    ...(readyToRender && helperResult && !helperSucceeded
      ? [
          {
            id: "live-evidence-helper",
            detail:
              helperResult.stderr ||
              helperResult.stdout ||
              "Solana live-evidence helper failed to render TOML.",
          },
        ]
      : []),
    ...(applyError
      ? [
          {
            id: "post-deploy-manifest-evidence-apply",
            detail: applyError,
          },
        ]
      : []),
  ];
  const helperArgs = buildSolanaPostDeployFullTomlHelperArgs({
    rawInputs,
    statuses: inputStatuses,
  });
  const commands = {
    renderPostDeployFullToml: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "post-deploy-full-toml",
      "--source-verifier-material-hash",
      statusValue(inputStatuses, "sourceVerifierMaterialHash") ||
        placeholderFor("source_verifier_material_hash"),
      "--source-adapter-engine-deployment-hash",
      statusValue(inputStatuses, "sourceAdapterEngineDeploymentHash") ||
        placeholderFor("source_adapter_engine_deployment_hash"),
      "--route-allowlist-hash",
      statusValue(inputStatuses, "routeAllowlistHash") ||
        placeholderFor("route_allowlist_hash"),
      "--route-canary-evidence-hash",
      statusValue(inputStatuses, "routeCanaryEvidenceHash") ||
        placeholderFor("route_canary_evidence_hash"),
    ],
    renderSourceMaterialToml: buildSourceEvidenceCommand(),
    deriveRouteAllowlistHash: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "route-allowlist-hash",
      "--source-verifier-material-hash",
      statusValue(inputStatuses, "sourceVerifierMaterialHash") ||
        placeholderFor("source_verifier_material_hash"),
      "--source-adapter-engine-deployment-hash",
      statusValue(inputStatuses, "sourceAdapterEngineDeploymentHash") ||
        placeholderFor("source_adapter_engine_deployment_hash"),
    ],
    helper: ["python3", ...helperArgs],
    applyPostDeployManifestEvidence: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "post-deploy-manifest-evidence",
      "--offline-full-toml",
      tomlPath ||
        "output/sccp-solana-deploy/taira-solana-xor-post-deploy-full.toml",
      "--apply",
      "true",
    ],
    refreshProductionRequirements: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "production-requirements",
    ],
  };
  const sourceVerifierRequiredInputs = SOLANA_SOURCE_VERIFIER_REQUIREMENTS.map(
    requiredInputDescriptor,
  );
  const sourceAdapterRequiredInputs =
    SOLANA_SOURCE_ADAPTER_PRODUCTION_REQUIREMENTS.map(requiredInputDescriptor);
  const nextActionDetails =
    blockers.length === 0
      ? [
          asBoolean(args.apply)
            ? {
                id: "refresh-production-requirements",
                title: "Refresh production requirements",
                detail:
                  "Recheck the Solana production route gates after applying the final full-TOML hash.",
                blockedBy: [],
                command: commands.refreshProductionRequirements,
                requiredInputs: [],
              }
            : {
                id: "apply-post-deploy-manifest-evidence",
                title: "Apply post-deploy manifest evidence",
                detail:
                  "Apply the rendered full Solana TOML hash to postDeployLiveEvidence after review.",
                blockedBy: [],
                command: commands.applyPostDeployManifestEvidence,
                requiredInputs: [
                  {
                    id: "reviewed-final-solana-offline-toml",
                    kind: "reviewed-evidence-file",
                    path:
                      tomlPath ||
                      "output/sccp-solana-deploy/taira-solana-xor-post-deploy-full.toml",
                  },
                ],
              },
        ]
      : blockers.map((blocker) => {
          if (blocker.id === "source-verifier-material-hash") {
            return {
              id: "provide-source-verifier-material-hash",
              title: "Provide source verifier material hash",
              detail:
                "Render or provide the governed Solana source verifier material record hash from reviewed trust-anchor, consensus, message-inclusion, finality-policy, and source-state verifier inputs.",
              blockedBy: [{ id: blocker.id, detail: blocker.detail }],
              command: commands.renderSourceMaterialToml,
              requiredInputs: uniqueActionRequiredInputs(
                sourceVerifierRequiredInputs,
              ),
            };
          }
          if (blocker.id === "source-adapter-engine-deployment-hash") {
            return {
              id: "provide-source-adapter-engine-deployment-hash",
              title: "Provide source adapter deployment hash",
              detail:
                "Render or provide the governed Solana source adapter engine deployment hash from reviewed source verifier, adapter VK, and deployment receipt inputs.",
              blockedBy: [{ id: blocker.id, detail: blocker.detail }],
              command: commands.renderSourceMaterialToml,
              requiredInputs: uniqueActionRequiredInputs(
                sourceAdapterRequiredInputs,
              ),
            };
          }
          if (blocker.id === "route-allowlist-hash") {
            return {
              id: "provide-route-allowlist-hash",
              title: "Derive route allowlist hash",
              detail:
                "Derive the Solana route allowlist hash from the governed source verifier material hash, source adapter deployment hash, and destination binding hash.",
              blockedBy: [{ id: blocker.id, detail: blocker.detail }],
              command: commands.deriveRouteAllowlistHash,
              requiredInputs: uniqueActionRequiredInputs([
                {
                  id: "source-verifier-material-hash",
                  description: "Governed source verifier material record hash.",
                },
                {
                  id: "source-adapter-engine-deployment-hash",
                  description:
                    "Governed source adapter engine deployment record hash.",
                },
                {
                  id: "destinationBindingHash",
                  description: "Canonical Solana destination binding hash.",
                  value:
                    statusValue(inputStatuses, "destinationBindingHash") ||
                    SOLANA_DESTINATION_BINDING_HASH,
                },
              ]),
            };
          }
          if (blocker.id === "live-evidence-helper") {
            return {
              id: "rerun-post-deploy-full-toml-helper",
              title: "Rerun full-TOML helper",
              detail:
                "Rerun the Solana live-evidence helper after fixing the reported RPC or pin mismatch.",
              blockedBy: [{ id: blocker.id, detail: blocker.detail }],
              command: commands.helper,
              requiredInputs: [],
            };
          }
          return {
            id: `provide-${blocker.id}`,
            title: `Resolve ${blocker.id}`,
            detail: blocker.detail,
            blockedBy: [{ id: blocker.id, detail: blocker.detail }],
            command: commands.renderPostDeployFullToml,
            requiredInputs: [],
          };
        });
  return {
    schema: "iroha-demo-sccp-solana-post-deploy-full-toml/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    readyToRender,
    fullTomlReady,
    full_toml_ready: fullTomlReady,
    offlineFullTomlSha256: normalizedTomlSha256,
    offline_full_toml_sha256: normalizedTomlSha256,
    tomlPath,
    inputStatuses,
    normalizedInputs: Object.fromEntries(
      inputStatuses.map((status) => [status.key, status.value ?? null]),
    ),
    helper: {
      script: siblingLiveEvidenceScript,
      command: ["python3", ...helperArgs],
      exitStatus: helperExitStatus,
      stdoutBytes:
        typeof helperResult?.stdout === "string"
          ? Buffer.byteLength(helperResult.stdout, "utf8")
          : null,
      stderr: helperResult?.stderr || null,
    },
    applyRequested: asBoolean(args.apply),
    appliedPostDeployManifestEvidence:
      appliedPostDeployManifestEvidence ?? null,
    blockers,
    blockerIds: blockerIds(blockers),
    nextActions: actionIds(nextActionDetails),
    nextActionDetails: withActionRequiredInputIdsList(nextActionDetails),
    commands,
  };
};

const templateRequirementFields = (requirements) =>
  Object.fromEntries(
    requirements.map((requirement) => [
      requirement.key,
      requirementCommandValue(requirement),
    ]),
  );

