const solanaProverPackageArtifactId = (direction) => {
  if (direction === "destination") {
    return "solana-destination-production-prover-package";
  }
  if (direction === "source") {
    return "solana-source-production-prover-package";
  }
  return null;
};

const appendMissingProductionArtifact = (artifacts, artifact) => {
  if (!artifact || typeof artifact.id !== "string" || !artifact.id.trim()) {
    return;
  }
  const id = artifact.id.trim();
  const current = artifacts.get(id) ?? {
    id,
    kind: artifact.kind ?? "production-artifact",
    description: artifact.description ?? null,
    sources: [],
    blockerIds: [],
    directions: [],
    statuses: [],
  };
  current.kind = current.kind || artifact.kind || "production-artifact";
  current.description =
    current.description || artifact.description || artifact.detail || null;
  for (const source of Array.isArray(artifact.sources)
    ? artifact.sources
    : [artifact.source]) {
    if (
      typeof source === "string" &&
      source &&
      !current.sources.includes(source)
    ) {
      current.sources.push(source);
    }
  }
  for (const blockerId of Array.isArray(artifact.blockerIds)
    ? artifact.blockerIds
    : [artifact.blockerId]) {
    if (
      typeof blockerId === "string" &&
      blockerId &&
      !current.blockerIds.includes(blockerId)
    ) {
      current.blockerIds.push(blockerId);
    }
  }
  for (const direction of Array.isArray(artifact.directions)
    ? artifact.directions
    : [artifact.direction]) {
    if (
      typeof direction === "string" &&
      direction &&
      !current.directions.includes(direction)
    ) {
      current.directions.push(direction);
    }
  }
  for (const status of Array.isArray(artifact.statuses)
    ? artifact.statuses
    : [artifact.status]) {
    if (
      typeof status === "string" &&
      status &&
      !current.statuses.includes(status)
    ) {
      current.statuses.push(status);
    }
  }
  if (!Array.isArray(current.upstreamArtifactIds)) {
    current.upstreamArtifactIds = [];
  }
  for (const upstreamArtifactId of [
    ...(SOLANA_PRODUCTION_ARTIFACT_UPSTREAM_IDS[id] ?? []),
    ...(Array.isArray(artifact.upstreamArtifactIds)
      ? artifact.upstreamArtifactIds
      : [artifact.upstreamArtifactId]),
  ]) {
    if (
      typeof upstreamArtifactId === "string" &&
      upstreamArtifactId &&
      !current.upstreamArtifactIds.includes(upstreamArtifactId)
    ) {
      current.upstreamArtifactIds.push(upstreamArtifactId);
    }
  }
  artifacts.set(id, current);
};

const missingProductionArtifactsFromInventory = ({
  blockers = [],
  browserProverModules = [],
} = {}) => {
  const artifacts = new Map();
  for (const blocker of Array.isArray(blockers) ? blockers : []) {
    const blockerId = typeof blocker === "string" ? blocker : blocker?.id;
    const descriptor = missingProductionArtifactForBlocker(blockerId);
    if (!descriptor) {
      continue;
    }
    appendMissingProductionArtifact(artifacts, {
      ...descriptor,
      source: "production-material-inventory",
      blockerId,
    });
  }
  for (const module of Array.isArray(browserProverModules)
    ? browserProverModules
    : []) {
    const direction = module?.direction;
    const moduleBlockerIds = [
      ...new Set([
        ...blockerIds(module?.blockers),
        ...blockerIds(module?.blockerIds),
      ]),
    ];
    if (module?.productionProofsReady !== true) {
      const packageId = solanaProverPackageArtifactId(direction);
      if (packageId) {
        appendMissingProductionArtifact(artifacts, {
          ...productionInputDescriptorById(packageId),
          source: `${direction}-browser-prover`,
          direction,
          blockerIds: moduleBlockerIds,
          status: "missing",
        });
      }
    }
    const requiredArtifacts = Array.isArray(module?.requiredArtifacts)
      ? module.requiredArtifacts
      : [];
    const missingArtifactIds = new Set(
      Array.isArray(module?.missingArtifactIds)
        ? module.missingArtifactIds
            .map((id) => (typeof id === "string" ? id.trim() : ""))
            .filter(Boolean)
        : [],
    );
    for (const artifact of requiredArtifacts) {
      if (!isRecord(artifact)) {
        continue;
      }
      if (
        artifact.required === false ||
        (artifact.status === "present" && !missingArtifactIds.has(artifact.id))
      ) {
        continue;
      }
      appendMissingProductionArtifact(artifacts, {
        id: artifact.id,
        kind: artifact.kind ?? "browser-prover-required-artifact",
        description: artifact.description ?? null,
        source: `${direction}-browser-prover-self-test`,
        direction,
        blockerIds: moduleBlockerIds,
        status: artifact.status ?? "missing",
      });
      missingArtifactIds.delete(artifact.id);
    }
    for (const id of missingArtifactIds) {
      appendMissingProductionArtifact(artifacts, {
        id,
        kind: "browser-prover-required-artifact",
        source: `${direction}-browser-prover-self-test`,
        direction,
        blockerIds: moduleBlockerIds,
        status: "missing",
      });
    }
  }
  return [...artifacts.values()].map((artifact) => ({
    ...artifact,
    sources: artifact.sources.sort(),
    blockerIds: artifact.blockerIds.sort(),
    directions: artifact.directions.sort(),
    statuses: artifact.statuses.sort(),
    ...(Array.isArray(artifact.upstreamArtifactIds) &&
    artifact.upstreamArtifactIds.length > 0
      ? { upstreamArtifactIds: artifact.upstreamArtifactIds.sort() }
      : {}),
  }));
};

