export const buildSolanaSettlementProofContextHash = ({
  statementHash,
  destinationBindingHash,
  messageId,
  tokenMintAddress,
  destinationTokenAddress,
  payerAddress,
  amountBaseUnits,
} = {}) => {
  const amount = u64LeBufferFromString(
    amountBaseUnits,
    "Solana settlement amount",
  );
  const digest = sha256Digest(
    Buffer.concat([
      Buffer.from(SCCP_SOLANA_SETTLEMENT_CONTEXT_PREFIX, "utf8"),
      hex32Buffer(statementHash, "statement hash"),
      hex32Buffer(destinationBindingHash, "destination binding hash"),
      hex32Buffer(messageId, "canonical message id"),
      new PublicKey(tokenMintAddress).toBuffer(),
      new PublicKey(destinationTokenAddress).toBuffer(),
      new PublicKey(payerAddress).toBuffer(),
      amount,
    ]),
  );
  return hex32(digest.toString("hex"));
};

export const assertSolanaSettlementProofContextHash = (input = {}) => {
  const expected = buildSolanaSettlementProofContextHash(input);
  const actual = hex32(
    hex32Buffer(input.proofContextHash, "proof context hash").toString("hex"),
  );
  if (actual !== expected) {
    throw new Error(
      "Solana settlement proof context hash does not match the canonical message, mint, destination, payer, and amount binding.",
    );
  }
  return expected;
};

export const buildSolanaRouteCanaryEnvelope = ({
  amountBaseUnits,
  ownerAddress = "",
  destinationTokenAddress = "",
  tokenMintAddress = "",
  verifierProgramId = "",
  verifierStateAddress = "",
  nonce = "",
  destinationBindingHash = SOLANA_DESTINATION_BINDING_HASH,
} = {}) => {
  const amount = asPositiveU64String(
    amountBaseUnits ?? "1",
    "--amount-base-units",
  );
  const canaryNonce =
    typeof nonce === "string" && nonce.trim()
      ? normalizeSolanaSourceBurnNonce(nonce.trim())
      : createSolanaSourceBurnNonce();
  const payer = new PublicKey(ownerAddress).toBase58();
  const destinationToken = new PublicKey(destinationTokenAddress).toBase58();
  const tokenMint = new PublicKey(tokenMintAddress).toBase58();
  const verifierProgram = new PublicKey(verifierProgramId).toBase58();
  const verifierState = new PublicKey(verifierStateAddress).toBase58();
  const transferPayload = {
    version: 1,
    source_domain: SCCP_SORA_DOMAIN,
    dest_domain: SCCP_SOLANA_DOMAIN,
    nonce: canaryNonce,
    asset_home_domain: SCCP_SORA_DOMAIN,
    asset_id_codec: SCCP_CODEC_TEXT_UTF8,
    asset_id: SCCP_XOR_ASSET_KEY,
    amount,
    sender_codec: SCCP_CODEC_TEXT_UTF8,
    sender: "diagnostic-canary",
    recipient_codec: SCCP_SOLANA_BASE58_CODEC,
    recipient: payer,
    route_id_codec: SCCP_CODEC_TEXT_UTF8,
    route_id: SCCP_SOLANA_XOR_ROUTE_ID,
  };
  const payloadEnvelope = { kind: "Transfer", value: transferPayload };
  const canonicalPayloadBytes = Buffer.from(
    canonicalSccpPayloadEnvelopeBytes(payloadEnvelope),
  );
  const payloadHash = sccpPayloadHash(canonicalPayloadBytes);
  const messageId = sccpTransferMessageId(transferPayload);
  const merkleProof = { steps: [] };
  const commitment = {
    version: 1,
    kind: "Transfer",
    target_domain: SCCP_SOLANA_DOMAIN,
    message_id: messageId,
    payload_hash: payloadHash,
  };
  const commitmentRoot = sccpMerkleRootFromCommitment(commitment, merkleProof);
  const finalityBlockHash = sha256BufferHex(
    Buffer.from(`diagnostic-finality-block:${canaryNonce}`, "utf8"),
  );
  const publicInputs = Buffer.from(
    canonicalSccpMessageTransparentPublicInputsBytes({
      version: 1,
      messageId,
      payloadHash,
      targetDomain: SCCP_SOLANA_DOMAIN,
      commitmentRoot,
      finalityHeight: "1",
      finalityBlockHash,
    }),
  );
  const bundleBytes = Buffer.from(
    canonicalSccpMessageProofBundleBytes({
      version: 1,
      commitmentRoot,
      commitment,
      merkleProof,
      payload: payloadEnvelope,
      finalityProof: Buffer.from(
        `diagnostic-finality-proof:${canaryNonce}`,
        "utf8",
      ),
    }),
  );
  const publicInputRecord = {
    schema: "iroha-demo-sccp-solana-route-canary-public-inputs/v1",
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    networkId: SOLANA_TESTNET_NETWORK_ID,
    amountBaseUnits: amount,
    ownerAddress: payer,
    destinationTokenAddress: destinationToken,
    tokenMintAddress: tokenMint,
    verifierProgramId: verifierProgram,
    verifierStateAddress: verifierState,
    nonce: canaryNonce,
    messageId,
    payloadHash,
    commitmentRoot,
    finalityBlockHash,
  };
  const bundleRecord = {
    schema: "iroha-demo-sccp-solana-route-canary-bundle/v1",
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    entrypoint: SOLANA_SUBMIT_ENTRYPOINT,
    diagnosticOnly: true,
    productionProof: false,
    note: "This canary exercises the deployed Solana verifier/mint path. It is not governed TAIRA proof material.",
  };
  const proofBytes = Buffer.from(
    `fabricated-diagnostic-proof:${canaryNonce}`,
    "utf8",
  );
  const statementHash = sha256Digest(
    Buffer.concat([
      Buffer.from("sccp:solana:diagnostic-statement:v1", "utf8"),
      publicInputs,
      bundleBytes,
    ]),
  );
  const destinationBinding = hex32Buffer(
    destinationBindingHash,
    "destination binding hash",
  );
  const statementHashHex = hex32(statementHash.toString("hex"));
  const destinationBindingHashHex = hex32(destinationBinding.toString("hex"));
  const proofContextHash = buildSolanaSettlementProofContextHash({
    statementHash: statementHashHex,
    destinationBindingHash: destinationBindingHashHex,
    messageId,
    tokenMintAddress: tokenMint,
    destinationTokenAddress: destinationToken,
    payerAddress: payer,
    amountBaseUnits: amount,
  });
  const messageReceipt = deriveSolanaMessageReceiptAddress({
    verifierProgramId: verifierProgram,
    verifierStateAddress: verifierState,
    messageId,
  });
  const amountBuffer = u64LeBufferFromString(amount, "Solana canary amount");
  const data = encodeBorshVecs(
    SOLANA_SUBMIT_ENTRYPOINT,
    proofBytes,
    publicInputs,
    bundleBytes,
    statementHash,
    destinationBinding,
    hex32Buffer(proofContextHash, "proof context hash"),
    amountBuffer,
  );
  return {
    dataHex: hex32(data.toString("hex")),
    amountBaseUnits: amount,
    nonce: canaryNonce,
    diagnosticOnly: true,
    productionProof: false,
    ownerAddress: payer,
    payerAddress: payer,
    destinationTokenAddress: destinationToken,
    tokenMintAddress: tokenMint,
    verifierProgramId: verifierProgram,
    verifierStateAddress: verifierState,
    messageId,
    messageReceiptAddress: messageReceipt.address,
    messageReceiptBump: messageReceipt.bump,
    payloadHash,
    commitmentRoot,
    finalityBlockHash,
    proofBytesSha256: sha256BufferHex(proofBytes),
    publicInputsSha256: sha256BufferHex(publicInputs),
    bundleBytesSha256: sha256BufferHex(bundleBytes),
    statementHash: statementHashHex,
    destinationBindingHash: destinationBindingHashHex,
    proofContextHash,
    canaryEvidenceHash: sha256JsonHex({
      publicInputRecord,
      bundleRecord,
      statementHash: statementHashHex,
      destinationBindingHash: destinationBindingHashHex,
      proofContextHash,
      messageReceiptAddress: messageReceipt.address,
    }),
  };
};

export const buildSolanaRouteCanaryInstructionDataHex = (input) =>
  buildSolanaRouteCanaryEnvelope(input).dataHex;

const solanaRouteCanaryEnvelopeSummary = (envelope) => {
  assertSolanaSettlementProofContextHash({
    ...envelope,
    payerAddress: envelope.payerAddress ?? envelope.ownerAddress,
  });
  const expectedReceipt = deriveSolanaMessageReceiptAddress(envelope);
  if (expectedReceipt.address !== envelope.messageReceiptAddress) {
    throw new Error(
      "Solana canary message receipt does not match the canonical message PDA.",
    );
  }
  return {
    amountBaseUnits: envelope.amountBaseUnits,
    nonce: envelope.nonce,
    messageId: envelope.messageId,
    messageReceiptAddress: envelope.messageReceiptAddress,
    messageReceiptBump: envelope.messageReceiptBump,
    proofBytesSha256: envelope.proofBytesSha256,
    publicInputsSha256: envelope.publicInputsSha256,
    bundleBytesSha256: envelope.bundleBytesSha256,
    statementHash: envelope.statementHash,
    destinationBindingHash: envelope.destinationBindingHash,
    proofContextHash: envelope.proofContextHash,
    canaryEvidenceHash: envelope.canaryEvidenceHash,
  };
};

export const buildRejectedSolanaRouteCanarySubmissionReportBody = ({
  checkedAt = new Date().toISOString(),
  signature = null,
  preflightSkipped = false,
  canaryError = null,
  canaryLogs = [],
  confirmation = null,
  confirmationError = null,
  signatureStatus = null,
  transactionMeta = null,
  ownerAddress,
  amountBaseUnits,
  tokenAccount,
  tokenAccountAfter,
  tokenMintAddress,
  verifierProgramId,
  nativeVerifierProgramId = null,
  verifierStateAddress,
  mintAuthorityAddress,
  envelope,
} = {}) => {
  const broadcastSubmitted =
    typeof signature === "string" && signature.length > 0;
  const runtimeRejected = broadcastSubmitted;
  const rejectionError =
    canaryError ??
    (signatureStatus?.err
      ? `Solana transaction failed: ${JSON.stringify(signatureStatus.err)}`
      : transactionMeta?.err
        ? `Solana transaction failed: ${JSON.stringify(transactionMeta.err)}`
        : null);
  return {
    schema: "iroha-demo-sccp-solana-route-canary-submission/v1",
    checkedAt,
    submitted: false,
    broadcastAttempted: true,
    broadcastSubmitted,
    preflightSkipped,
    preflightRejected: !broadcastSubmitted && !preflightSkipped,
    runtimeRejected,
    failClosed: true,
    diagnosticOnly: true,
    productionProof: false,
    reason: runtimeRejected
      ? "verifier-rejected-diagnostic-canary-on-chain"
      : "verifier-rejected-diagnostic-canary",
    note: runtimeRejected
      ? "The deployed Solana verifier accepted the diagnostic transaction into the ledger and rejected it before minting. This is expected while the native recursive verifier remains fail-closed, and it is not production proof."
      : "The deployed Solana verifier rejected the diagnostic destination canary before minting. This is expected while the native recursive verifier remains fail-closed.",
    ...(broadcastSubmitted
      ? {
          signature,
          explorerUrl: `https://explorer.solana.com/tx/${signature}?cluster=testnet`,
        }
      : { signature: null }),
    error: rejectionError,
    logs: Array.isArray(canaryLogs) ? canaryLogs : [],
    confirmation: confirmation ?? null,
    ...(confirmationError ? { confirmationError } : {}),
    signatureStatus: signatureStatus ?? null,
    transactionMeta: transactionMeta
      ? {
          err: transactionMeta.err ?? null,
          fee: transactionMeta.fee ?? null,
          computeUnitsConsumed: transactionMeta.computeUnitsConsumed ?? null,
        }
      : null,
    ownerAddress,
    amountBaseUnits,
    destinationTokenAccount: tokenAccount?.address ?? null,
    destinationTokenAccountCreated: tokenAccount?.created === true,
    destinationTokenAccountCreateSignature:
      tokenAccount?.createSignature ?? null,
    tokenMintAddress,
    verifierProgramId,
    nativeVerifierProgramId,
    verifierStateAddress,
    mintAuthorityAddress,
    tokenAccountAfter,
    envelope: solanaRouteCanaryEnvelopeSummary(envelope),
  };
};

export const normalizeTairaSourceBurnRecipient = (value) => {
  if (typeof value !== "string" || value !== value.trim() || !value) {
    throw new Error(
      "TAIRA recipient must be a canonical TAIRA I105 account id.",
    );
  }
  try {
    const canonical = AccountAddress.fromAccountId(
      value,
      TAIRA_NETWORK_PREFIX,
    ).toI105(TAIRA_NETWORK_PREFIX);
    if (canonical !== value || !value.startsWith("testu")) {
      throw new Error("wrong network or non-canonical form");
    }
    return value;
  } catch {
    throw new Error(
      "TAIRA recipient must be a canonical TAIRA I105 account id.",
    );
  }
};

export const normalizeSolanaSourceBurnNonce = (value) => {
  if (
    typeof value !== "string" ||
    !/^(?:0|[1-9][0-9]*)$/u.test(value) ||
    value === "0"
  ) {
    throw new Error(
      "Solana burn nonce must be a canonical positive u64 decimal.",
    );
  }
  let parsed;
  try {
    parsed = BigInt(value);
  } catch {
    throw new Error(
      "Solana burn nonce must be a canonical positive u64 decimal.",
    );
  }
  if (parsed > 0xffff_ffff_ffff_ffffn) {
    throw new Error(
      "Solana burn nonce must be a canonical positive u64 decimal.",
    );
  }
  return value;
};

export const createSolanaSourceBurnNonce = () => {
  let nonce = 0n;
  while (nonce === 0n) {
    nonce = randomBytes(8).readBigUInt64BE();
  }
  return nonce.toString();
};

export const buildSolanaSourceBurnInstructionDataHex = ({
  amountBaseUnits,
  tairaRecipient,
  nonce,
}) =>
  hex32(
    encodeBorshVecs(
      SCCP_SOLANA_BURN_ENTRYPOINT,
      u64LeBufferFromString(amountBaseUnits, "Solana burn amount"),
      utf8BoundedBuffer(
        normalizeTairaSourceBurnRecipient(tairaRecipient),
        "TAIRA recipient",
        128,
      ),
      u64LeBufferFromString(
        normalizeSolanaSourceBurnNonce(nonce),
        "Solana burn nonce",
      ),
    ).toString("hex"),
  );

const buildSolanaSourceBurnTransferPayload = ({
  amountBaseUnits,
  tairaRecipient,
  nonce,
  ownerAddress,
}) => ({
  version: 1,
  source_domain: SCCP_SOLANA_DOMAIN,
  dest_domain: SCCP_SORA_DOMAIN,
  nonce: normalizeSolanaSourceBurnNonce(nonce),
  asset_home_domain: SCCP_SORA_DOMAIN,
  asset_id_codec: SCCP_CODEC_TEXT_UTF8,
  asset_id: SCCP_XOR_ASSET_KEY,
  amount: asPositiveU64String(amountBaseUnits, "Solana source burn amount"),
  sender_codec: SCCP_SOLANA_BASE58_CODEC,
  sender: new PublicKey(ownerAddress).toBase58(),
  recipient_codec: SCCP_CODEC_TEXT_UTF8,
  recipient: normalizeTairaSourceBurnRecipient(tairaRecipient),
  route_id_codec: SCCP_CODEC_TEXT_UTF8,
  route_id: SCCP_SOLANA_XOR_ROUTE_ID,
});

export const buildSolanaSourceBurnProofRequestScaffold = ({
  signature,
  ownerAddress,
  sourceTokenAddress = null,
  tokenMintAddress = null,
  sourceBridgeProgramId = null,
  sourceStateAddress = null,
  sourceBurnReceiptAddress = null,
  amountBaseUnits,
  tairaRecipient,
  nonce,
  sourceBurnHash = null,
  explorerUrl = null,
  solanaRpcUrl = DEFAULT_SOLANA_RPC_URL,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const blockers = [];
  let transferPayload = null;
  let canonical = null;
  let canonicalError = null;
  let canonicalSourceBurnReceipt = null;
  try {
    if (!sourceTokenAddress || !tokenMintAddress) {
      throw new Error(
        "The source token account and route mint are required to bind the Solana source burn proof request.",
      );
    }
    new PublicKey(sourceTokenAddress);
    new PublicKey(tokenMintAddress);
  } catch (error) {
    blockers.push({
      id: "source-burn-accounts",
      detail: error instanceof Error ? error.message : String(error),
    });
  }
  try {
    if (
      !sourceBridgeProgramId ||
      !sourceStateAddress ||
      !ownerAddress ||
      nonce === undefined ||
      nonce === null
    ) {
      throw new Error(
        "The source bridge program, source state, owner, and nonce are required to derive the Solana burn receipt PDA.",
      );
    }
    canonicalSourceBurnReceipt = deriveSolanaSourceBurnReceiptAddress({
      sourceBridgeProgramId,
      sourceStateAddress,
      ownerAddress,
      nonce: String(nonce),
    });
    if (
      sourceBurnReceiptAddress &&
      new PublicKey(sourceBurnReceiptAddress).toBase58() !==
        canonicalSourceBurnReceipt.address
    ) {
      throw new Error(
        "The supplied Solana source burn receipt does not match the canonical nonce-bound PDA.",
      );
    }
  } catch (error) {
    blockers.push({
      id: "source-burn-receipt",
      detail: error instanceof Error ? error.message : String(error),
    });
  }
  try {
    transferPayload = buildSolanaSourceBurnTransferPayload({
      amountBaseUnits,
      tairaRecipient,
      nonce,
      ownerAddress,
    });
    const payloadEnvelope = {
      kind: "Transfer",
      value: transferPayload,
    };
    const canonicalPayloadBytes =
      canonicalSccpPayloadEnvelopeBytes(payloadEnvelope);
    const payloadHash = sccpPayloadHash(canonicalPayloadBytes);
    const messageId = sccpTransferMessageId(transferPayload);
    const merkleProof = { steps: [] };
    const commitment = {
      version: 1,
      kind: "Transfer",
      targetDomain: SCCP_SORA_DOMAIN,
      messageId,
      payloadHash,
    };
    const commitmentRoot = sccpMerkleRootFromCommitment(
      {
        version: commitment.version,
        kind: commitment.kind,
        target_domain: SCCP_SORA_DOMAIN,
        message_id: messageId,
        payload_hash: payloadHash,
      },
      merkleProof,
    );
    canonical = {
      transferPayload,
      canonicalPayloadEnvelopeSha256: sha256BufferHex(canonicalPayloadBytes),
      canonicalPayloadEnvelopeHex: hexFromBytes(canonicalPayloadBytes),
      payloadHash,
      messageId,
      commitmentRoot,
      messageBundle: {
        version: 1,
        commitmentRoot,
        commitment,
        merkleProof,
        payload: payloadEnvelope,
        finalityProof: null,
      },
      settlement: {
        entrypoint: "finalize_inbound",
        route: SCCP_SOLANA_XOR_ROUTE_ID,
        asset: SCCP_XOR_ASSET_KEY,
      },
      publicInputs: {
        sourceDomain: SCCP_SOLANA_DOMAIN,
        targetDomain: SCCP_SORA_DOMAIN,
        routeId: SCCP_SOLANA_XOR_ROUTE_ID,
        asset: SCCP_XOR_ASSET_KEY,
        txId: signature ?? null,
        solanaSender: transferPayload.sender,
        tairaRecipient: transferPayload.recipient,
        amountBaseUnits: transferPayload.amount,
        messageId,
        commitmentRoot,
      },
      bindingInput: {
        txId: signature ?? null,
        solanaSender: transferPayload.sender,
        tairaRecipient: transferPayload.recipient,
        amountBaseUnits: transferPayload.amount,
      },
    };
  } catch (error) {
    canonicalError = error instanceof Error ? error.message : String(error);
    blockers.push({
      id: "canonical-transfer-payload",
      detail: canonicalError,
    });
  }
  if (!signature) {
    blockers.push({
      id: "source-burn-signature",
      detail: "No Solana source-burn transaction signature is available.",
    });
  }
  return {
    schema: "iroha-demo-sccp-solana-source-burn-proof-request/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    sourceDomain: SCCP_SOLANA_DOMAIN,
    targetDomain: SCCP_SORA_DOMAIN,
    readyForSourceProof: blockers.length === 0,
    canonicalTransferReady: canonical !== null,
    productionProof: false,
    proofPackageIncluded: false,
    note: "This scaffold binds the real Solana burn to a canonical TAIRA settlement request. It is not a source proof package; a governed Solana source prover must fill finalityProof/proof material before TAIRA settlement.",
    solanaRpcUrl,
    sourceBurn: {
      signature: signature ?? null,
      explorerUrl,
      ownerAddress: ownerAddress
        ? new PublicKey(ownerAddress).toBase58()
        : null,
      sourceTokenAddress,
      tokenMintAddress,
      sourceBridgeProgramId,
      sourceStateAddress,
      sourceBurnReceiptAddress: canonicalSourceBurnReceipt?.address ?? null,
      sourceBurnReceiptBump: canonicalSourceBurnReceipt?.bump ?? null,
      amountBaseUnits:
        amountBaseUnits === undefined ? null : String(amountBaseUnits),
      tairaRecipient: tairaRecipient ?? null,
      nonce: nonce === undefined ? null : String(nonce),
      sourceBurnHash,
    },
    canonical,
    canonicalError,
    blockers,
  };
};

const tokenAccountSort = (left, right) => {
  const rightAmount = parsePositiveU64(right.amount);
  const leftAmount = parsePositiveU64(left.amount);
  if (rightAmount > leftAmount) {
    return 1;
  }
  if (rightAmount < leftAmount) {
    return -1;
  }
  return left.address.localeCompare(right.address);
};

const summarizeSolanaRouteCanaryForSourceBurn = (routeCanarySubmission) => {
  if (!isRecord(routeCanarySubmission)) {
    return null;
  }
  const logs = Array.isArray(routeCanarySubmission.logs)
    ? routeCanarySubmission.logs.filter((entry) => typeof entry === "string")
    : [];
  return {
    submitted: routeCanarySubmission.submitted === true,
    broadcastAttempted: routeCanarySubmission.broadcastAttempted === true,
    broadcastSubmitted: routeCanarySubmission.broadcastSubmitted === true,
    failClosed: routeCanarySubmission.failClosed === true,
    reason:
      typeof routeCanarySubmission.reason === "string"
        ? routeCanarySubmission.reason
        : null,
    signature:
      typeof routeCanarySubmission.signature === "string"
        ? routeCanarySubmission.signature
        : null,
    explorerUrl:
      typeof routeCanarySubmission.explorerUrl === "string"
        ? routeCanarySubmission.explorerUrl
        : null,
    tokenMintAddress:
      typeof routeCanarySubmission.tokenMintAddress === "string"
        ? routeCanarySubmission.tokenMintAddress
        : null,
    destinationTokenAccount:
      typeof routeCanarySubmission.destinationTokenAccount === "string"
        ? routeCanarySubmission.destinationTokenAccount
        : null,
    tokenAccountAfter: isRecord(routeCanarySubmission.tokenAccountAfter)
      ? {
          address: routeCanarySubmission.tokenAccountAfter.address ?? null,
          amount: routeCanarySubmission.tokenAccountAfter.amount ?? null,
          mint: routeCanarySubmission.tokenAccountAfter.mint ?? null,
          owner: routeCanarySubmission.tokenAccountAfter.owner ?? null,
        }
      : null,
    failClosedLog:
      logs.find((entry) =>
        SOLANA_FAIL_CLOSED_VERIFIER_LOGS.some((expectedLog) =>
          entry.includes(expectedLog),
        ),
      ) ?? null,
  };
};

const solanaRouteCanaryShowsFailClosedVerifier = (routeCanarySubmission) => {
  const summary = summarizeSolanaRouteCanaryForSourceBurn(
    routeCanarySubmission,
  );
  return (
    summary?.failClosed === true ||
    summary?.reason === "verifier-rejected-diagnostic-canary-on-chain" ||
    summary?.reason === "verifier-rejected-diagnostic-canary" ||
    typeof summary?.failClosedLog === "string"
  );
};

export const buildSolanaSourceBurnReadinessReportBody = ({
  args = {},
  manifest = null,
  publicConfig = null,
  accounts = null,
  ownerAddress,
  amountBaseUnits,
  tairaRecipient = "",
  nonce = "",
  tokenMint = null,
  sourceState = null,
  tokenAccounts = [],
  routeCanarySubmission = null,
  checkedAt = new Date().toISOString(),
  requireRecipient = false,
  requireNonce = false,
} = {}) => {
  const addresses = solanaPostDeployDeploymentAddresses({
    publicConfig,
    manifest,
    accounts,
  });
  const amount = asPositiveU64String(
    amountBaseUnits ?? args["amount-base-units"] ?? "1",
    "--amount-base-units",
  );
  const requestedSourceToken =
    typeof args["source-token-account"] === "string"
      ? args["source-token-account"].trim()
      : "";
  const sortedAccounts = [...tokenAccounts].sort(tokenAccountSort);
  const eligibleAccounts = sortedAccounts.filter((account) => {
    if (requestedSourceToken && account.address !== requestedSourceToken) {
      return false;
    }
    return parsePositiveU64(account.amount) >= parsePositiveU64(amount);
  });
  const selectedSourceToken = eligibleAccounts[0] ?? null;
  const blockers = [];
  const routeCanary = summarizeSolanaRouteCanaryForSourceBurn(
    routeCanarySubmission,
  );
  for (const [key, label] of [
    ["sourceBridgeProgramId", "Solana source bridge program id"],
    ["sourceStateAddress", "Solana source bridge state"],
    ["tokenMintAddress", "Solana SPL TairaXOR mint"],
  ]) {
    if (!addresses[key]) {
      blockers.push({
        id: `missing-${key}`,
        detail: `${label} is missing from deployment evidence.`,
      });
    }
  }
  if (typeof ownerAddress !== "string" || !ownerAddress) {
    blockers.push({
      id: "owner-address",
      detail: "A Solana owner address is required.",
    });
  }
  if (requireRecipient) {
    try {
      normalizeTairaSourceBurnRecipient(tairaRecipient);
    } catch (error) {
      blockers.push({
        id: "taira-recipient",
        detail: error instanceof Error ? error.message : String(error),
      });
    }
  }
  if (requireNonce) {
    try {
      normalizeSolanaSourceBurnNonce(nonce);
    } catch (error) {
      blockers.push({
        id: "burn-nonce",
        detail: error instanceof Error ? error.message : String(error),
      });
    }
  }
  if (!tokenMint) {
    blockers.push({
      id: "token-mint-readback",
      detail: "The Solana SPL TairaXOR mint was not read back.",
    });
  } else {
    if (tokenMint.initialized !== true) {
      blockers.push({
        id: "token-mint-initialized",
        detail: "The Solana SPL TairaXOR mint is not initialized.",
      });
    }
    if (tokenMint.decimals !== SPL_TOKEN_DECIMALS) {
      blockers.push({
        id: "token-mint-decimals",
        detail: `The Solana SPL TairaXOR mint must use ${SPL_TOKEN_DECIMALS} decimals.`,
      });
    }
    if (parsePositiveU64(tokenMint.supply) <= 0n) {
      blockers.push({
        id: "token-mint-supply",
        detail:
          "The Solana SPL TairaXOR mint supply is zero; no real bridged balance can be burned.",
      });
      if (solanaRouteCanaryShowsFailClosedVerifier(routeCanarySubmission)) {
        blockers.push({
          id: "solana-verifier-fail-closed-canary",
          detail:
            "The latest Solana destination canary was rejected by the deployed fail-closed verifier before minting SPL TairaXOR.",
        });
      }
    }
  }
  if (!sourceState) {
    blockers.push({
      id: "source-state-readback",
      detail: "The Solana source bridge state was not read back.",
    });
  } else if (
    addresses.tokenMintAddress &&
    sourceState.storedMint !== addresses.tokenMintAddress
  ) {
    blockers.push({
      id: "source-state-mint",
      detail:
        "The Solana source bridge state stored mint does not match the deployment mint.",
    });
  }
  if (sortedAccounts.length === 0) {
    blockers.push({
      id: "source-token-account",
      detail:
        "No SPL TairaXOR token accounts exist for the selected Solana owner.",
    });
  } else if (!selectedSourceToken) {
    blockers.push({
      id: "source-token-balance",
      detail: `No selected SPL TairaXOR token account has at least ${amount} base units.`,
    });
  }
  const ready = blockers.length === 0;
  const reportBlockerIds = blockerIds(blockers);
  const nextActions =
    buildSolanaSourceBurnReadinessNextActions(reportBlockerIds);
  return {
    schema: "iroha-demo-sccp-solana-source-burn-readiness/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    solanaRpcUrl: args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
    ready,
    readyToSubmitBurn: ready,
    note: "This command never mints or fabricates Solana TairaXOR. It only burns an existing SPL token account balance owned by the signer.",
    deployment: addresses,
    ownerAddress: ownerAddress ?? null,
    amountBaseUnits: amount,
    requestedSourceToken: requestedSourceToken || null,
    selectedSourceToken,
    tokenMint,
    sourceState,
    tokenAccounts: sortedAccounts,
    routeCanary,
    tairaRecipient: tairaRecipient || null,
    nonce: nonce || null,
    blockers,
    blockerIds: reportBlockerIds,
    nextActions,
    nextActionDetails: solanaSourceBurnReadinessNextActionDetails(nextActions),
  };
};

export const buildSkippedSolanaSourceBurnReadinessReportBody = ({
  args = {},
  manifest = null,
  publicConfig = null,
  accounts = null,
  ownerAddress,
  amountBaseUnits,
  tairaRecipient = "",
  nonce = "",
  checkedAt = new Date().toISOString(),
  requireRecipient = false,
  requireNonce = false,
} = {}) => ({
  ...buildSolanaSourceBurnReadinessReportBody({
    args,
    manifest,
    publicConfig,
    accounts,
    ownerAddress,
    amountBaseUnits,
    tairaRecipient,
    nonce,
    tokenMint: null,
    sourceState: null,
    tokenAccounts: [],
    routeCanarySubmission: null,
    checkedAt,
    requireRecipient,
    requireNonce,
  }),
  solanaRpcSkipped: true,
  skipReason: SOLANA_RPC_SKIPPED_DETAIL,
});

const summarizeSolanaSourceBurnReadinessForSubmission = (report) => {
  if (!isRecord(report)) {
    return null;
  }
  return {
    checkedAt: report.checkedAt ?? null,
    ready: report.ready === true,
    readyToSubmitBurn: report.readyToSubmitBurn === true,
    ownerAddress: report.ownerAddress ?? null,
    amountBaseUnits: report.amountBaseUnits ?? null,
    selectedSourceToken: report.selectedSourceToken
      ? {
          address: report.selectedSourceToken.address ?? null,
          owner: report.selectedSourceToken.owner ?? null,
          mint: report.selectedSourceToken.mint ?? null,
          amount: report.selectedSourceToken.amount ?? null,
        }
      : null,
    tokenAccounts: Array.isArray(report.tokenAccounts)
      ? report.tokenAccounts.map((account) => ({
          address: account.address ?? null,
          owner: account.owner ?? null,
          mint: account.mint ?? null,
          amount: account.amount ?? null,
        }))
      : [],
    blockers: blockerIds(report.blockers),
  };
};

const buildSolanaSourceBurnReadinessNextActions = (ids = []) => {
  const blockers = new Set(ids);
  const actions = [];
  if (blockers.has("token-mint-supply")) {
    actions.push(
      "link-solana-native-recursive-verifier",
      "rerun-solana-destination-canary",
    );
  }
  if (
    !blockers.has("token-mint-supply") &&
    (blockers.has("source-token-account") ||
      blockers.has("source-token-balance"))
  ) {
    actions.push("fund-solana-source-token-account");
  }
  if (
    blockers.has("taira-recipient") ||
    blockers.has("burn-nonce") ||
    blockers.has("source-token-account") ||
    blockers.has("source-token-balance") ||
    blockers.has("token-mint-supply")
  ) {
    actions.push("rerun-source-burn-readiness");
  }
  return uniqueStrings(actions);
};

const solanaSourceBurnReadinessNextActionDetails = (ids = []) =>
  ids.map((id) => {
    switch (id) {
      case "link-solana-native-recursive-verifier":
        return {
          id,
          title: "Link Solana native recursive verifier",
          detail:
            "Upgrade the Solana verifier program with governed native recursive verifier material so proof envelopes can mint SPL TairaXOR through the program PDA.",
          blockedBy: ["token-mint-supply"],
          command: [
            "npm",
            "run",
            "sccp:solana:deploy",
            "--",
            "verifier-linkage-readiness",
          ],
        };
      case "rerun-solana-destination-canary":
        return {
          id,
          title: "Rerun Solana destination canary",
          detail:
            "After verifier linkage passes, rerun the diagnostic destination canary to create a real SPL TairaXOR balance for burn-readiness checks.",
          blockedBy: ["token-mint-supply"],
          command: [
            "npm",
            "run",
            "sccp:solana:deploy",
            "--",
            "route-canary",
            "--amount-base-units",
            "<units>",
            "--confirm-route-canary",
            "true",
          ],
        };
      case "fund-solana-source-token-account":
        return {
          id,
          title: "Fund Solana source token account",
          detail:
            "Provide an existing SPL TairaXOR token account owned by the source-burn signer with enough real base units to burn.",
          blockedBy: ["source-token-account", "source-token-balance"],
          command: [
            "npm",
            "run",
            "sccp:solana:deploy",
            "--",
            "source-burn-readiness",
            "--source-token-account",
            "<spl-token-account>",
          ],
        };
      case "rerun-source-burn-readiness":
        return {
          id,
          title: "Rerun source-burn readiness",
          detail:
            "Refresh live Solana mint, source-state, and token-account readback before submitting a burn.",
          blockedBy: [
            "token-mint-supply",
            "source-token-account",
            "source-token-balance",
            "taira-recipient",
            "burn-nonce",
          ],
          command: [
            "npm",
            "run",
            "sccp:solana:deploy",
            "--",
            "source-burn-readiness",
          ],
        };
      default:
        return { id };
    }
  });

export const buildSolanaSourceBurnSubmissionReportBody = ({
  checkedAt = new Date().toISOString(),
  signature,
  ownerAddress,
  selectedSourceToken,
  amountBaseUnits,
  tairaRecipient,
  nonce,
  sourceBurnReceiptAddress = null,
  readinessPath,
  preBurnReadiness = null,
  postBurnReadiness = null,
  postBurnReadinessError = null,
  sourceProofRequest,
} = {}) => {
  const postBurnRefreshReady =
    isRecord(postBurnReadiness) && !postBurnReadinessError;
  const sourceProofRequestReady =
    sourceProofRequest?.readyForSourceProof === true;
  return {
    schema: "iroha-demo-sccp-solana-source-burn-submission/v1",
    checkedAt,
    ready: sourceProofRequestReady,
    submitted: true,
    signature,
    productionProof: false,
    sourceProofRequestReady,
    ownerAddress,
    sourceTokenAddress: selectedSourceToken?.address ?? null,
    amountBaseUnits,
    tairaRecipient,
    nonce,
    sourceBurnReceiptAddress,
    readinessPath,
    preBurnReadiness:
      summarizeSolanaSourceBurnReadinessForSubmission(preBurnReadiness),
    postBurnReadinessPath: readinessPath,
    postBurnReadinessRefreshReady: postBurnRefreshReady,
    postBurnReadiness:
      summarizeSolanaSourceBurnReadinessForSubmission(postBurnReadiness),
    ...(postBurnReadinessError ? { postBurnReadinessError } : {}),
    explorerUrl: `https://explorer.solana.com/tx/${signature}?cluster=testnet`,
    sourceProofRequest,
  };
};

export const buildBlockedSolanaSourceBurnSubmissionReportBody = ({
  checkedAt = new Date().toISOString(),
  readinessReport,
  readinessPath,
} = {}) => ({
  schema: "iroha-demo-sccp-solana-source-burn-submission/v1",
  checkedAt,
  ready: false,
  submitted: false,
  productionProof: false,
  reason: "source-burn-readiness-failed",
  readinessPath,
  ownerAddress: readinessReport?.ownerAddress ?? null,
  sourceTokenAddress: readinessReport?.selectedSourceToken?.address ?? null,
  tokenMintAddress: readinessReport?.deployment?.tokenMintAddress ?? null,
  sourceBridgeProgramId:
    readinessReport?.deployment?.sourceBridgeProgramId ?? null,
  sourceStateAddress: readinessReport?.deployment?.sourceStateAddress ?? null,
  amountBaseUnits: readinessReport?.amountBaseUnits ?? null,
  tairaRecipient: readinessReport?.tairaRecipient ?? null,
  nonce: readinessReport?.nonce ?? null,
  selectedSourceToken: readinessReport?.selectedSourceToken ?? null,
  sourceProofRequestReady: false,
  sourceProofRequest: null,
  preBurnReadiness: readinessReport ?? null,
  blockers: Array.isArray(readinessReport?.blockers)
    ? readinessReport.blockers
    : [],
  blockerIds: blockerIds(readinessReport?.blockers),
});

export const normalizePackageRelativeModuleUrl = (value, label) => {
  const hasUnsafeCharacter =
    typeof value === "string" &&
    Array.from(value).some((character) => {
      const codePoint = character.codePointAt(0);
      return (
        codePoint <= 0x1f ||
        codePoint === 0x7f ||
        codePoint === 0x2028 ||
        codePoint === 0x2029 ||
        character === "\\"
      );
    });
  if (
    typeof value !== "string" ||
    !value ||
    value.trim() !== value ||
    hasUnsafeCharacter
  ) {
    throw new Error(`${label} must be a package-relative absolute URL path.`);
  }
  const normalized = value;
  if (
    !normalized.startsWith("/") ||
    normalized.startsWith("//") ||
    normalized.includes("//") ||
    normalized.includes("%") ||
    normalized.includes("?") ||
    normalized.includes("#") ||
    !/^\/[A-Za-z0-9._/-]+$/u.test(normalized) ||
    normalized
      .slice(1)
      .split("/")
      .some((segment) => !segment || segment === "." || segment === "..")
  ) {
    throw new Error(
      `${label} must be a canonical package-relative URL path without an authority, encoding, traversal, query, or fragment.`,
    );
  }
  return normalized;
};

const localPublicModuleFile = (moduleUrl, label) =>
  path.join(
    repoRoot,
    "public",
    normalizePackageRelativeModuleUrl(moduleUrl, label).replace(/^\//u, ""),
  );

const defaultSolanaProverSidecarUrl = (moduleUrl, label) => {
  const normalized = normalizePackageRelativeModuleUrl(moduleUrl, label);
  return normalized.replace(/(?:\.m?js)?$/u, ".sidecar.json");
};

export const buildSolanaProverSidecarBody = ({
  direction,
  moduleUrl,
  moduleHash,
  proveExport,
  selfTestExport,
  selfTest = null,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const destination = direction === "destination";
  if (!destination && direction !== "source") {
    throw new Error("Solana prover direction must be destination or source.");
  }
  const proofBackend = destination
    ? SOLANA_DESTINATION_PROOF_BACKEND
    : SOLANA_SOURCE_PROOF_BACKEND;
  const productionProofsReady = selfTest?.ready === true;
  const disabledReason = productionProofsReady
    ? null
    : typeof selfTest?.reason === "string" && selfTest.reason.trim()
      ? selfTest.reason.trim()
      : `Solana ${direction} prover self-test is not production-ready.`;
  const requiredArtifacts = Array.isArray(selfTest?.requiredArtifacts)
    ? selfTest.requiredArtifacts
    : [];
  const missingArtifactIds = Array.isArray(selfTest?.missingArtifactIds)
    ? selfTest.missingArtifactIds
    : [];
  return {
    schema: SOLANA_PROVER_SIDECAR_SCHEMA,
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    route_id: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    asset_key: SCCP_XOR_ASSET_KEY,
    network: SOLANA_TESTNET_NETWORK_ID,
    solanaNetwork: SOLANA_TESTNET_NETWORK_ID,
    solana_network: SOLANA_TESTNET_NETWORK_ID,
    genesisHash: SOLANA_TESTNET_GENESIS_HASH,
    genesis_hash: SOLANA_TESTNET_GENESIS_HASH,
    direction,
    sourceDomain: destination ? SCCP_SORA_DOMAIN : SCCP_SOLANA_DOMAIN,
    source_domain: destination ? SCCP_SORA_DOMAIN : SCCP_SOLANA_DOMAIN,
    targetDomain: destination ? SCCP_SOLANA_DOMAIN : SCCP_SORA_DOMAIN,
    target_domain: destination ? SCCP_SOLANA_DOMAIN : SCCP_SORA_DOMAIN,
    moduleUrl,
    module_url: moduleUrl,
    moduleHash,
    module_hash: moduleHash,
    proveExport,
    prove_export: proveExport,
    selfTestExport,
    self_test_export: selfTestExport,
    proofBackend,
    proof_backend: proofBackend,
    requiredProofBackend: proofBackend,
    required_proof_backend: proofBackend,
    ...(destination
      ? {
          destinationVerifierPlan: SOLANA_DESTINATION_VERIFIER_PLAN,
          destination_verifier_plan: SOLANA_DESTINATION_VERIFIER_PLAN,
          verifierTarget: SOLANA_VERIFIER_TARGET,
          verifier_target: SOLANA_VERIFIER_TARGET,
        }
      : {}),
    productionProofsReady,
    production_proofs_ready: productionProofsReady,
    selfTest: selfTest ?? null,
    self_test: selfTest ?? null,
    ...(requiredArtifacts.length > 0
      ? {
          requiredArtifacts,
          required_artifacts: requiredArtifacts,
        }
      : {}),
    ...(missingArtifactIds.length > 0
      ? {
          missingArtifactIds,
          missing_artifact_ids: missingArtifactIds,
        }
      : {}),
    ...(disabledReason
      ? {
          disabledReason,
          disabled_reason: disabledReason,
        }
      : {}),
  };
};

const validateSolanaProverSidecar = ({
  sidecar,
  direction,
  moduleUrl,
  moduleHash,
  proveExport,
  selfTestExport,
}) => {
  const errors = [];
  if (!isRecord(sidecar)) {
    return {
      ready: false,
      errors: ["Solana prover sidecar is missing or not a JSON object."],
    };
  }
  const expectString = (keys, expected, label) => {
    const values = keys
      .filter((key) => Object.prototype.hasOwnProperty.call(sidecar, key))
      .map((key) => ({
        key,
        value: typeof sidecar[key] === "string" ? sidecar[key].trim() : "",
      }));
    if (values.length === 0 || values.some(({ value }) => !value)) {
      errors.push(`${label} must be ${expected}.`);
      return null;
    }
    const [{ key: firstKey, value: firstValue }] = values;
    for (const { key, value } of values.slice(1)) {
      if (value !== firstValue) {
        errors.push(
          `${label} aliases must agree: ${firstKey}=${firstValue} but ${key}=${value}.`,
        );
        return firstValue;
      }
    }
    if (firstValue !== expected) {
      errors.push(`${label} must be ${expected}.`);
    }
    return firstValue;
  };
  const expectNumber = (keys, expected, label) => {
    const values = keys
      .map((key) => sidecar?.[key])
      .filter((value) => value !== undefined);
    if (
      values.length === 0 ||
      values.some((value) => Number(value) !== expected)
    ) {
      errors.push(`${label} must be ${expected}.`);
    }
  };
  const destination = direction === "destination";
  const expectedProofBackend = destination
    ? SOLANA_DESTINATION_PROOF_BACKEND
    : SOLANA_SOURCE_PROOF_BACKEND;
  expectString(["schema"], SOLANA_PROVER_SIDECAR_SCHEMA, "schema");
  expectString(["routeId", "route_id"], SCCP_SOLANA_XOR_ROUTE_ID, "routeId");
  expectString(["assetKey", "asset_key"], SCCP_XOR_ASSET_KEY, "assetKey");
  expectString(["direction"], direction, "direction");
  expectString(
    ["network", "solanaNetwork", "solana_network", "sourceChain"],
    SOLANA_TESTNET_NETWORK_ID,
    "network",
  );
  expectString(
    ["genesisHash", "genesis_hash"],
    SOLANA_TESTNET_GENESIS_HASH,
    "genesisHash",
  );
  expectString(["moduleUrl", "module_url"], moduleUrl, "moduleUrl");
  expectString(["proveExport", "prove_export"], proveExport, "proveExport");
  expectString(
    ["selfTestExport", "self_test_export"],
    selfTestExport,
    "selfTestExport",
  );
  expectString(
    ["proofBackend", "proof_backend"],
    expectedProofBackend,
    `${direction} proofBackend`,
  );
  expectString(
    ["requiredProofBackend", "required_proof_backend"],
    expectedProofBackend,
    `${direction} requiredProofBackend`,
  );
  if (destination) {
    expectString(
      ["destinationVerifierPlan", "destination_verifier_plan"],
      SOLANA_DESTINATION_VERIFIER_PLAN,
      "destinationVerifierPlan",
    );
    expectString(
      ["verifierTarget", "verifier_target"],
      SOLANA_VERIFIER_TARGET,
      "verifierTarget",
    );
  }
  expectNumber(
    ["sourceDomain", "source_domain"],
    destination ? SCCP_SORA_DOMAIN : SCCP_SOLANA_DOMAIN,
    "sourceDomain",
  );
  expectNumber(
    ["targetDomain", "target_domain"],
    destination ? SCCP_SOLANA_DOMAIN : SCCP_SORA_DOMAIN,
    "targetDomain",
  );
  const sidecarModuleHash = readFirstManifestString(
    sidecar,
    "moduleHash",
    "module_hash",
  );
  if (!sidecarModuleHash) {
    errors.push("moduleHash is missing.");
  } else {
    try {
      const normalized = normalizeManifestHex32(
        sidecarModuleHash,
        "moduleHash",
      );
      if (moduleHash && normalized !== moduleHash) {
        errors.push("moduleHash does not match the prover module bytes.");
      }
    } catch (error) {
      errors.push(error instanceof Error ? error.message : String(error));
    }
  }
  if (
    sidecar.productionProofsReady !== true &&
    sidecar.production_proofs_ready !== true
  ) {
    errors.push("productionProofsReady must be true.");
  }
  if (
    Object.prototype.hasOwnProperty.call(sidecar, "knownAnswerProbe") ||
    Object.prototype.hasOwnProperty.call(sidecar, "known_answer_probe")
  ) {
    errors.push(
      "Legacy prover-returned known-answer probe metadata is forbidden.",
    );
  }
  errors.push(
    ...validateSolanaProverKnownAnswerSummary({
      direction,
      summary: sidecar.knownAnswer,
    }),
  );
  return {
    ready: errors.length === 0,
    errors,
    schema: readFirstManifestString(sidecar, "schema") || null,
    moduleHash: sidecarModuleHash || null,
    knownAnswerVectorHash:
      typeof sidecar.knownAnswer?.vectorHash === "string"
        ? sidecar.knownAnswer.vectorHash
        : null,
  };
};

const runProverModuleSelfTest = ({
  bytes,
  expectedSha256,
  proveExport,
  selfTestExport,
}) => {
  if (!Buffer.isBuffer(bytes) || bytes.length === 0) {
    return { exportsOk: false, error: "prover module snapshot is empty" };
  }
  const result = spawnSync(
    process.execPath,
    [
      "--input-type=module",
      "-e",
      `
import { createHash } from "node:crypto";
import { readFileSync } from "node:fs";
const [expectedSha256, proveExport, selfTestExport] = process.argv.slice(1);
try {
  const source = readFileSync(0);
  const actualSha256 = "0x" + createHash("sha256").update(source).digest("hex");
  if (actualSha256 !== expectedSha256) throw new Error("prover module snapshot hash mismatch");
  const decoded = source.toString("utf8");
  if (!Buffer.from(decoded, "utf8").equals(source)) throw new Error("prover module is not strict UTF-8");
  const specifier = "data:text/javascript;base64," + source.toString("base64");
  const module = await import(specifier);
  const exportsOk = typeof module[proveExport] === "function" && typeof module[selfTestExport] === "function";
  const selfTest = typeof module[selfTestExport] === "function" ? await module[selfTestExport]() : null;
  console.log(JSON.stringify({ exportsOk, selfTest }));
} catch (error) {
  console.log(JSON.stringify({ exportsOk: false, error: error instanceof Error ? error.message : String(error) }));
  process.exitCode = 1;
}
`,
      expectedSha256,
      proveExport,
      selfTestExport,
    ],
    {
      encoding: "utf8",
      input: bytes,
      stdio: ["pipe", "pipe", "pipe"],
      maxBuffer: 16 * 1024 * 1024,
    },
  );
  const parsed = result.stdout ? JSON.parse(result.stdout) : {};
  if (result.status !== 0 && !parsed.error) {
    parsed.error = result.stderr || "prover module self-test failed";
  }
  return parsed;
};

export const buildSolanaProverReadinessReportBody = ({
  args = {},
  manifest = null,
  entries = [],
  checkedAt = new Date().toISOString(),
} = {}) => {
  const blockers = [];
  for (const entry of entries) {
    const requiredArtifacts = solanaProverRequiredArtifactsFromEntry(entry);
    const missingArtifactIds = solanaProverMissingArtifactIdsFromEntry(
      entry,
      requiredArtifacts,
    );
    if (entry.ready !== true) {
      blockers.push({
        id: `${entry.direction}-prover-readiness`,
        direction: entry.direction,
        detail:
          entry.reason ||
          entry.error ||
          `Solana ${entry.direction} prover self-test is not ready.`,
      });
    }
    if (entry.moduleHashMatchesManifest !== true) {
      blockers.push({
        id: `${entry.direction}-prover-hash`,
        direction: entry.direction,
        detail: `Solana ${entry.direction} prover module hash does not match the route manifest.`,
      });
    }
    if (entry.exportsOk !== true) {
      blockers.push({
        id: `${entry.direction}-prover-exports`,
        direction: entry.direction,
        detail: `Solana ${entry.direction} prover module does not expose the required exports.`,
      });
    }
    if (entry.sidecarReady !== true) {
      blockers.push({
        id: `${entry.direction}-prover-sidecar`,
        direction: entry.direction,
        detail:
          Array.isArray(entry.sidecar?.errors) &&
          entry.sidecar.errors.length > 0
            ? entry.sidecar.errors.join(" ")
            : `Solana ${entry.direction} prover sidecar is not production-ready.`,
      });
    }
    for (const missingArtifactId of missingArtifactIds) {
      const requiredArtifact = requiredArtifacts.find(
        (artifact) => artifact.id === missingArtifactId,
      );
      blockers.push({
        id: missingArtifactId,
        direction: entry.direction,
        detail:
          requiredArtifact?.detail ||
          requiredArtifact?.description ||
          `Solana ${entry.direction} prover is missing ${missingArtifactId}.`,
      });
    }
  }
  for (const direction of ["destination", "source"]) {
    if (!entries.some((entry) => entry.direction === direction)) {
      blockers.push({
        id: `${direction}-prover-missing`,
        direction,
        detail: `Solana ${direction} prover manifest record is missing.`,
      });
    }
  }
  const commands = {
    refresh: ["npm", "run", "sccp:solana:deploy", "--", "prover-readiness"],
    writeSidecars: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "prover-sidecars",
    ],
    refreshSmokeReadiness: ["npm", "run", "e2e:sccp:solana-smoke-readiness"],
    refreshProductionRequirements: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "production-requirements",
    ],
    productionManifestPatch: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "production-manifest-patch",
      "--confirm-governed-solana-material",
      "true",
      "--from-inventory",
      "true",
    ],
  };
  const directionMetadata = {
    destination: {
      routeLeg: "TAIRA -> Solana finalize proof construction",
      env: SCCP_SOLANA_DESTINATION_PROVER_MODULE_URL_ENV,
      moduleUrl: SOLANA_DESTINATION_PROVER_MODULE_URL,
      proveExport: "proveSolanaSccpDestination",
      selfTestExport: "solanaSccpDestinationProverSelfTest",
    },
    source: {
      routeLeg: "Solana -> TAIRA source proof construction",
      env: SCCP_SOLANA_SOURCE_PROVER_MODULE_URL_ENV,
      moduleUrl: SOLANA_SOURCE_PROVER_MODULE_URL,
      proveExport: "proveSolanaSccpSource",
      selfTestExport: "solanaSccpSourceProverSelfTest",
    },
  };
  const nextActionDetails =
    blockers.length === 0
      ? [
          {
            id: "refresh-solana-smoke-readiness",
            title: "Refresh Solana smoke readiness",
            detail:
              "Rerun the app-side Solana smoke-readiness gate with the production prover module URLs configured.",
            blockedBy: [],
            command: commands.refreshSmokeReadiness,
            requiredInputs: [],
          },
          {
            id: "refresh-production-requirements",
            title: "Refresh production requirements",
            detail:
              "Rerun the Solana production requirements gate after prover modules and sidecars are production-ready.",
            blockedBy: [],
            command: commands.refreshProductionRequirements,
            requiredInputs: [],
          },
        ]
      : ["destination", "source"]
          .map((direction) => {
            const directionBlockers = blockers.filter(
              (blocker) =>
                blocker.id.startsWith(`${direction}-prover-`) ||
                blocker.direction === direction,
            );
            if (directionBlockers.length === 0) {
              return null;
            }
            const entry =
              entries.find((candidate) => candidate.direction === direction) ??
              {};
            const meta = directionMetadata[direction];
            const moduleUrl = entry.moduleUrl || meta.moduleUrl;
            const sidecarUrl =
              entry.sidecarUrl ||
              defaultSolanaProverSidecarUrl(
                moduleUrl,
                `Solana ${direction} prover sidecar URL`,
              );
            const moduleFile =
              entry.moduleFile ||
              localPublicModuleFile(
                moduleUrl,
                `Solana ${direction} prover module URL`,
              );
            const sidecarFile =
              entry.sidecarFile ||
              localPublicModuleFile(
                sidecarUrl,
                `Solana ${direction} prover sidecar URL`,
              );
            return {
              id: `publish-${direction}-solana-production-prover-package`,
              title: `Publish ${direction} Solana production prover package`,
              detail: `Replace the fail-closed ${direction} Solana prover with a governed browser-safe package for ${meta.routeLeg}; then publish a matching route-bound sidecar whose productionProofsReady flag and self-test are both true.`,
              blockedBy: directionBlockers,
              command: commands.refresh,
              validationCommands: [
                commands.writeSidecars,
                commands.refresh,
                commands.refreshSmokeReadiness,
              ],
              requiredInputs: [
                {
                  id: `${direction}-browser-prover-module`,
                  kind: "browser-safe-esm-module",
                  env: meta.env,
                  moduleUrl,
                  path: moduleFile,
                  proveExport: meta.proveExport,
                  selfTestExport: meta.selfTestExport,
                  actualModuleHash: entry.actualModuleHash ?? null,
                  expectedModuleHash: entry.expectedModuleHash ?? null,
                },
                {
                  id: `${direction}-prover-sidecar`,
                  kind: "route-bound-sidecar",
                  schema: SOLANA_PROVER_SIDECAR_SCHEMA,
                  sidecarUrl,
                  path: sidecarFile,
                  sidecarHash: entry.sidecarHash ?? null,
                  requiredProductionProofsReady: true,
                },
                {
                  id: `${direction}-self-test-ready`,
                  kind: "module-self-test",
                  expected: { ready: true },
                  observed: entry.selfTest ?? null,
                },
                {
                  id: `${direction}-manifest-hash-binding`,
                  kind: "route-manifest-binding",
                  expectedModuleHash: entry.expectedModuleHash ?? null,
                  actualModuleHash: entry.actualModuleHash ?? null,
                },
              ],
            };
          })
          .filter(Boolean);
  const directionSummaries = Object.fromEntries(
    ["destination", "source"].map((direction) => {
      const entry =
        entries.find((candidate) => candidate.direction === direction) ?? null;
      const directionBlockers = blockers.filter(
        (blocker) =>
          blocker.id.startsWith(`${direction}-prover`) ||
          blocker.direction === direction,
      );
      return [
        direction,
        {
          ready:
            entry?.ready === true &&
            entry?.exportsOk === true &&
            entry?.moduleHashMatchesManifest === true &&
            entry?.sidecarReady === true,
          missing: entry === null,
          productionProofsReady: entry?.productionProofsReady === true,
          moduleUrl: entry?.moduleUrl ?? directionMetadata[direction].moduleUrl,
          sidecarUrl:
            entry?.sidecarUrl ??
            defaultSolanaProverSidecarUrl(
              entry?.moduleUrl ?? directionMetadata[direction].moduleUrl,
              `Solana ${direction} prover sidecar URL`,
            ),
          moduleFile: entry?.moduleFile ?? null,
          sidecarFile: entry?.sidecarFile ?? null,
          expectedModuleHash: entry?.expectedModuleHash ?? null,
          actualModuleHash: entry?.actualModuleHash ?? null,
          moduleHashMatchesManifest: entry?.moduleHashMatchesManifest === true,
          exportsOk: entry?.exportsOk === true,
          sidecarReady: entry?.sidecarReady === true,
          sidecarHash: entry?.sidecarHash ?? null,
          sidecar: entry?.sidecar ?? null,
          selfTest: entry?.selfTest ?? null,
          reason: entry?.reason ?? entry?.error ?? null,
          blockerIds: blockerIds(directionBlockers),
          blockers: directionBlockers,
        },
      ];
    }),
  );
  const readyForProductionProofs = blockers.length === 0;
  return {
    schema: "iroha-demo-sccp-solana-prover-readiness/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    ready: readyForProductionProofs,
    readyForProductionProofs,
    note: "This report imports the browser-safe Solana prover modules, validates their route-bound sidecars, and runs their self-tests. Placeholder modules must remain fail-closed.",
    manifestProductionReady:
      manifest?.productionReady === true || manifest?.production_ready === true,
    destination: directionSummaries.destination,
    source: directionSummaries.source,
    entries,
    blockers,
    blockerIds: blockerIds(blockers),
    nextActions: actionIds(nextActionDetails),
    nextActionDetails: withActionRequiredInputIdsList(nextActionDetails),
    commands,
    solanaRpcUrl: args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
  };
};

const reportPostDeployStatuses = (postDeployLiveEvidence) => {
  const fullTomlReady =
    postDeployLiveEvidence?.fullTomlReady === true ||
    postDeployLiveEvidence?.full_toml_ready === true;
  const liveHashStatuses = genericHexRequirementStatuses(
    postDeployLiveEvidence,
    SOLANA_POST_DEPLOY_LIVE_HASH_REQUIREMENTS,
    "postDeployLiveEvidence",
  );
  const offlineTomlStatuses = genericHexRequirementStatuses(
    postDeployLiveEvidence,
    [SOLANA_POST_DEPLOY_OFFLINE_TOML_REQUIREMENT],
    "postDeployLiveEvidence",
  );
  const signatureStatuses = signatureRequirementStatuses(
    postDeployLiveEvidence,
    SOLANA_POST_DEPLOY_SIGNATURE_REQUIREMENTS,
    "postDeployLiveEvidence",
  );
  const sourceEventSignature = readFirstManifestString(
    postDeployLiveEvidence,
    "sourceEventTransactionSignature",
    "source_event_transaction_signature",
    "sourceEventSignature",
    "source_event_signature",
    "sourceEventTransactionId",
    "source_event_transaction_id",
  );
  const routeCanarySignature = readFirstManifestString(
    postDeployLiveEvidence,
    "routeCanaryTransactionSignature",
    "route_canary_transaction_signature",
    "routeCanarySignature",
    "route_canary_signature",
    "routeCanaryTransactionId",
    "route_canary_transaction_id",
  );
  return {
    fullTomlReady,
    sourceEventSignature,
    routeCanarySignature,
    statuses: [
      {
        key: "fullTomlReady",
        manifestKeys: ["fullTomlReady", "full_toml_ready"],
        description: "Final generated TOML evidence passed all live pins.",
        status: fullTomlReady ? "present" : "missing",
        value: fullTomlReady,
      },
      ...liveHashStatuses,
      ...offlineTomlStatuses,
      ...signatureStatuses,
    ],
    liveStatuses: [...liveHashStatuses, ...signatureStatuses],
    offlineTomlStatuses,
  };
};

const normalizeSolanaSignature = (value, label) => {
  const normalized = String(value ?? "").trim();
  if (!/^[1-9A-HJ-NP-Za-km-z]{64,100}$/u.test(normalized)) {
    throw new Error(`${label} must be a Solana transaction signature.`);
  }
  return normalized;
};

const buildSnakePostDeployLiveEvidence = (evidence) => ({
  schema: evidence.schema,
  full_toml_ready: evidence.fullTomlReady,
  source_bridge_config_hash: evidence.sourceBridgeConfigHash,
  route_canary_evidence_hash: evidence.routeCanaryEvidenceHash,
  ...(evidence.offlineFullTomlSha256
    ? { offline_full_toml_sha256: evidence.offlineFullTomlSha256 }
    : {}),
  source_event_transaction_signature: evidence.sourceEventTransactionSignature,
  route_canary_transaction_signature: evidence.routeCanaryTransactionSignature,
});

const decimalDeltaEquals = (before, after, expected) => {
  try {
    return BigInt(after) - BigInt(before) === BigInt(expected);
  } catch {
    return false;
  }
};

const productionRouteCanaryBlockers = (routeCanarySubmission) => {
  const blockers = [];
  if (
    routeCanarySubmission?.submitted !== true ||
    routeCanarySubmission?.productionProof !== true ||
    routeCanarySubmission?.diagnosticOnly === true ||
    routeCanarySubmission?.runtimeRejected === true ||
    routeCanarySubmission?.failClosed === true
  ) {
    blockers.push({
      id: "route-canary-production-proof",
      detail:
        "Production post-deploy evidence requires a successful non-diagnostic proof canary; fabricated fail-closed canary bytes are negative-test evidence only.",
    });
  }
  if (
    routeCanarySubmission?.signatureStatus?.confirmationStatus !==
      "finalized" ||
    routeCanarySubmission?.signatureStatus?.err != null ||
    routeCanarySubmission?.transactionMeta?.err != null
  ) {
    blockers.push({
      id: "route-canary-finalized-success",
      detail:
        "The production proof canary must be finalized successfully on Solana.",
    });
  }
  const delta = routeCanarySubmission?.productionStateDelta;
  const amount = routeCanarySubmission?.amountBaseUnits;
  if (
    delta?.verifiedFromFinalizedTransaction !== true ||
    !decimalDeltaEquals(
      delta.tokenAmountBefore,
      delta.tokenAmountAfter,
      amount,
    ) ||
    !decimalDeltaEquals(
      delta.verifierAcceptedCountBefore,
      delta.verifierAcceptedCountAfter,
      "1",
    ) ||
    !decimalDeltaEquals(
      delta.verifierTotalMintedBefore,
      delta.verifierTotalMintedAfter,
      amount,
    )
  ) {
    blockers.push({
      id: "route-canary-state-delta",
      detail:
        "The production proof canary must bind its finalized token, accepted-count, and total-minted deltas to the submitted amount.",
    });
  }
  const replay = routeCanarySubmission?.replayProtection;
  if (
    replay?.attempted !== true ||
    replay?.rejected !== true ||
    replay?.stateUnchanged !== true ||
    typeof replay?.signature !== "string" ||
    replay.signature === routeCanarySubmission?.signature
  ) {
    blockers.push({
      id: "route-canary-replay-rejection",
      detail:
        "The exact production proof must be replayed once and rejected with no additional state change.",
    });
  }
  return blockers;
};

export const buildSolanaPostDeployManifestEvidenceReportBody = ({
  postDeployEvidence = null,
  routeCanarySubmission = null,
  sourceBurnSubmission = null,
  offlineFullTomlSha256 = null,
  manifest = null,
  manifestArtifactSha256 = null,
  postDeployEvidenceArtifactSha256 = null,
  routeCanarySubmissionArtifactSha256 = null,
  sourceBurnSubmissionArtifactSha256 = null,
  manifestPath = null,
  applied = false,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const blockers = [];
  let sourceBridgeConfigHash = "";
  let routeCanaryEvidenceHash = "";
  let sourceEventTransactionSignature = "";
  let routeCanaryTransactionSignature = "";
  let normalizedOfflineFullTomlSha256 = "";
  try {
    sourceBridgeConfigHash = normalizeManifestHex32(
      postDeployEvidence?.observedSourceBridgeConfigHash,
      "postDeployEvidence.observedSourceBridgeConfigHash",
    );
  } catch (error) {
    blockers.push({
      id: "source-bridge-config-hash",
      detail: error instanceof Error ? error.message : String(error),
    });
  }
  try {
    routeCanaryEvidenceHash = normalizeManifestHex32(
      routeCanarySubmission?.envelope?.canaryEvidenceHash,
      "routeCanarySubmission.envelope.canaryEvidenceHash",
    );
  } catch (error) {
    blockers.push({
      id: "route-canary-evidence-hash",
      detail: error instanceof Error ? error.message : String(error),
    });
  }
  try {
    sourceEventTransactionSignature = normalizeSolanaSignature(
      sourceBurnSubmission?.signature,
      "sourceBurnSubmission.signature",
    );
  } catch (error) {
    blockers.push({
      id: "source-event-transaction-signature",
      detail: error instanceof Error ? error.message : String(error),
    });
  }
  try {
    routeCanaryTransactionSignature = normalizeSolanaSignature(
      routeCanarySubmission?.signature,
      "routeCanarySubmission.signature",
    );
  } catch (error) {
    blockers.push({
      id: "route-canary-transaction-signature",
      detail: error instanceof Error ? error.message : String(error),
    });
  }
  const routeCanaryLedgered =
    routeCanarySubmission?.submitted === true ||
    routeCanarySubmission?.broadcastSubmitted === true ||
    isRecord(routeCanarySubmission?.signatureStatus) ||
    isRecord(routeCanarySubmission?.transactionMeta) ||
    isRecord(routeCanarySubmission?.confirmation);
  if (!routeCanaryLedgered) {
    blockers.push({
      id: "route-canary-ledger-evidence",
      detail:
        "No ledgered Solana route-canary artifact is available for post-deploy evidence.",
    });
  }
  blockers.push(...productionRouteCanaryBlockers(routeCanarySubmission));
  if (sourceBurnSubmission?.submitted !== true) {
    blockers.push({
      id: "source-burn-submitted",
      detail: "No submitted Solana source-burn artifact is available.",
    });
  }
  if (
    sourceEventTransactionSignature &&
    routeCanaryTransactionSignature &&
    sourceEventTransactionSignature === routeCanaryTransactionSignature
  ) {
    blockers.push({
      id: "distinct-post-deploy-signatures",
      detail:
        "The source-event and route-canary transaction signatures must be distinct.",
    });
  }
  if (
    sourceBridgeConfigHash &&
    routeCanaryEvidenceHash &&
    sourceBridgeConfigHash === routeCanaryEvidenceHash
  ) {
    blockers.push({
      id: "distinct-post-deploy-hashes",
      detail:
        "The source-bridge config hash and route-canary evidence hash must be distinct.",
    });
  }
  if (offlineFullTomlSha256) {
    try {
      normalizedOfflineFullTomlSha256 = normalizeManifestHex32(
        offlineFullTomlSha256,
        "offlineFullTomlSha256",
      );
    } catch (error) {
      blockers.push({
        id: "offline-full-toml-sha256",
        detail: error instanceof Error ? error.message : String(error),
      });
    }
  }
  for (const [value, id, detail] of [
    [
      postDeployEvidenceArtifactSha256,
      "post-deploy-evidence-artifact-sha256",
      "The exact post-deploy evidence artifact SHA-256 is required.",
    ],
    [
      routeCanarySubmissionArtifactSha256,
      "route-canary-submission-artifact-sha256",
      "The exact route-canary submission artifact SHA-256 is required.",
    ],
    [
      sourceBurnSubmissionArtifactSha256,
      "source-burn-submission-artifact-sha256",
      "The exact source-burn submission artifact SHA-256 is required.",
    ],
  ]) {
    if (!/^0x[0-9a-f]{64}$/u.test(value ?? "")) {
      blockers.push({ id, detail });
    }
  }
  const readyForManifestPatch =
    blockers.filter((blocker) => blocker.id !== "offline-full-toml-sha256")
      .length === 0;
  const fullTomlReady = Boolean(normalizedOfflineFullTomlSha256);
  const manifestSourceBridgeConfigHash =
    expectedSourceBridgeConfigHashFromManifest(manifest);
  const canonicalSnapshotSha256 =
    postDeployEvidence?.finalizedReadback?.canonicalSnapshotSha256 ?? null;
  const finalizedReadbackEvidenceArtifactSha256 =
    postDeployEvidence?.finalizedReadback?.evidenceArtifactSha256 ?? null;
  const manifestConformanceReady = Boolean(
    /^0x[0-9a-f]{64}$/u.test(manifestArtifactSha256 ?? "") &&
      /^0x[0-9a-f]{64}$/u.test(finalizedReadbackEvidenceArtifactSha256 ?? "") &&
      /^0x[0-9a-f]{64}$/u.test(canonicalSnapshotSha256 ?? "") &&
      /^0x[0-9a-f]{64}$/u.test(postDeployEvidenceArtifactSha256 ?? "") &&
      /^0x[0-9a-f]{64}$/u.test(routeCanarySubmissionArtifactSha256 ?? "") &&
      /^0x[0-9a-f]{64}$/u.test(sourceBurnSubmissionArtifactSha256 ?? "") &&
      sourceBridgeConfigHash &&
      manifestSourceBridgeConfigHash === sourceBridgeConfigHash,
  );
  const postDeployLiveEvidence = {
    schema: "iroha-sccp-solana-post-deploy-live-evidence/v1",
    fullTomlReady,
    sourceBridgeConfigHash: sourceBridgeConfigHash || null,
    routeCanaryEvidenceHash: routeCanaryEvidenceHash || null,
    ...(normalizedOfflineFullTomlSha256
      ? { offlineFullTomlSha256: normalizedOfflineFullTomlSha256 }
      : {}),
    sourceEventTransactionSignature: sourceEventTransactionSignature || null,
    routeCanaryTransactionSignature: routeCanaryTransactionSignature || null,
  };
  const productionBlockers = [...blockers];
  if (!manifestConformanceReady) {
    productionBlockers.push({
      id: "manifest-finalized-readback-conformance",
      detail:
        "The exact selected manifest bytes are not bound to the same canonical finalized-readback artifact and source-bridge config hash.",
    });
  }
  if (!fullTomlReady) {
    productionBlockers.push({
      id: "offline-full-toml",
      detail:
        "A reviewed final Solana evidence TOML hash is required before postDeployLiveEvidence.fullTomlReady can be true.",
    });
  }
  return {
    schema: "iroha-demo-sccp-solana-post-deploy-manifest-evidence/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    manifestPath,
    applied,
    readyForManifestPatch,
    readyForProductionPostDeployEvidence: productionBlockers.length === 0,
    postDeployLiveEvidence,
    post_deploy_live_evidence: buildSnakePostDeployLiveEvidence(
      postDeployLiveEvidence,
    ),
    manifestConformance: {
      ready: manifestConformanceReady,
      manifestPath,
      manifestArtifactSha256,
      finalizedReadbackEvidenceArtifactSha256,
      canonicalSnapshotSha256,
      expectedSourceBridgeConfigHash: manifestSourceBridgeConfigHash ?? null,
      observedSourceBridgeConfigHash: sourceBridgeConfigHash || null,
    },
    sourceArtifacts: {
      postDeployEvidenceArtifactSha256,
      routeCanarySubmissionArtifactSha256,
      sourceBurnSubmissionArtifactSha256,
      finalizedReadbackSchema:
        postDeployEvidence?.finalizedReadback?.schema ?? null,
      canonicalSnapshotSha256:
        postDeployEvidence?.finalizedReadback?.canonicalSnapshotSha256 ?? null,
      finalizedSnapshotContextSlot:
        postDeployEvidence?.finalizedReadback?.snapshotContextSlot ?? null,
      postDeployEvidenceLiveReadbackReady:
        postDeployEvidence?.liveReadbackReady === true,
      postDeployEvidenceReady:
        postDeployEvidence?.readyForProductionPostDeploy === true,
      observedSourceBridgeConfigHash:
        postDeployEvidence?.observedSourceBridgeConfigHash ?? null,
      observedSourceStateTotalBurned:
        postDeployEvidence?.observedSourceState?.totalBurned ?? null,
      observedSourceStateLastBurnHash:
        postDeployEvidence?.observedSourceState?.lastBurnHash ?? null,
      routeCanarySubmitted: routeCanarySubmission?.submitted === true,
      routeCanaryBroadcastSubmitted:
        routeCanarySubmission?.broadcastSubmitted === true,
      routeCanaryLedgered,
      routeCanaryDiagnosticOnly: routeCanarySubmission?.diagnosticOnly === true,
      routeCanaryProductionProof:
        routeCanarySubmission?.productionProof === true,
      routeCanaryRuntimeRejected:
        routeCanarySubmission?.runtimeRejected === true,
      routeCanaryFailClosed: routeCanarySubmission?.failClosed === true,
      routeCanarySignature: routeCanarySubmission?.signature ?? null,
      sourceBurnSubmitted: sourceBurnSubmission?.submitted === true,
      sourceBurnSignature: sourceBurnSubmission?.signature ?? null,
      sourceBurnTokenAddress: sourceBurnSubmission?.sourceTokenAddress ?? null,
      sourceBurnAmountBaseUnits: sourceBurnSubmission?.amountBaseUnits ?? null,
      sourceBurnTairaRecipient: sourceBurnSubmission?.tairaRecipient ?? null,
    },
    blockers,
    productionBlockers,
  };
};

const readSolanaDeploymentAddress = ({
  publicConfig,
  manifest,
  accounts,
  keys,
}) => {
  const fromManifest = readFirstManifestString(manifest, ...keys.manifest);
  if (fromManifest) {
    return fromManifest;
  }
  for (const key of keys.publicConfig ?? []) {
    if (typeof publicConfig?.[key] === "string" && publicConfig[key]) {
      return publicConfig[key];
    }
  }
  const accountValue = keys.accounts?.reduce((value, key) => {
    if (value === undefined || value === null) {
      return value;
    }
    return value[key];
  }, accounts);
  return typeof accountValue === "string" && accountValue ? accountValue : null;
};

const solanaPostDeployDeploymentAddresses = ({
  publicConfig,
  manifest,
  accounts,
}) => ({
  verifierProgramId: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: ["solanaVerifierProgramId", "solana_verifier_program_id"],
      publicConfig: ["verifierProgramId", "programId"],
    },
  }),
  nativeVerifierProgramId: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: [
        "solanaNativeVerifierProgramId",
        "solana_native_verifier_program_id",
        "nativeVerifierProgramId",
        "native_verifier_program_id",
        "nativeRecursiveVerifierProgramId",
        "native_recursive_verifier_program_id",
      ],
      publicConfig: [
        "nativeVerifierProgramId",
        "solanaNativeVerifierProgramId",
        "nativeRecursiveVerifierProgramId",
      ],
    },
  }),
  bridgeProgramId: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: [
        "solanaProgramId",
        "solana_program_id",
        "tairaXorSolanaProgramId",
        "taira_xor_solana_program_id",
      ],
      publicConfig: ["bridgeProgramId"],
    },
  }),
  sourceBridgeProgramId: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: [
        "sccpSolanaSourceBridgeAddress",
        "sccp_solana_source_bridge_address",
        "solanaSourceBridgeAddress",
        "solana_source_bridge_address",
      ],
      publicConfig: ["sourceBridgeProgramId"],
    },
  }),
  tokenMintAddress: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: [
        "solanaTokenMint",
        "solana_token_mint",
        "tairaXorTokenAddress",
        "taira_xor_token_address",
      ],
      publicConfig: ["tokenMintAddress"],
      accounts: ["tokenMint", "address"],
    },
  }),
  verifierStateAddress: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: ["solanaVerifierStateAddress", "solana_verifier_state_address"],
      publicConfig: ["verifierStateAddress"],
      accounts: ["verifierState", "address"],
    },
  }),
  sourceStateAddress: readSolanaDeploymentAddress({
    publicConfig,
    manifest,
    accounts,
    keys: {
      manifest: [
        "sccpSolanaSourceStateAddress",
        "sccp_solana_source_state_address",
        "solanaSourceStateAddress",
        "solana_source_state_address",
        "sourceBridgeStateAddress",
        "source_bridge_state_address",
      ],
      publicConfig: ["sourceStateAddress"],
      accounts: ["sourceState", "address"],
    },
  }),
});

export const buildSolanaSourceBurnProofRequestFromSubmission = ({
  sourceBurnSubmission,
  publicConfig = null,
  manifest = null,
  accounts = null,
  postDeployEvidence = null,
  args = {},
  solanaRpcUrl = null,
  checkedAt,
} = {}) => {
  const deploymentAddresses = solanaPostDeployDeploymentAddresses({
    publicConfig,
    manifest,
    accounts,
  });
  const ownerAddress =
    sourceBurnSubmission?.ownerAddress ??
    sourceBurnSubmission?.sourceProofRequest?.sourceBurn?.ownerAddress;
  return buildSolanaSourceBurnProofRequestScaffold({
    signature: sourceBurnSubmission?.signature,
    ownerAddress,
    sourceTokenAddress: sourceBurnSubmission?.sourceTokenAddress ?? null,
    tokenMintAddress: deploymentAddresses.tokenMintAddress ?? null,
    sourceBridgeProgramId: deploymentAddresses.sourceBridgeProgramId ?? null,
    sourceStateAddress: deploymentAddresses.sourceStateAddress ?? null,
    sourceBurnReceiptAddress:
      sourceBurnSubmission?.sourceBurnReceiptAddress ??
      sourceBurnSubmission?.sourceProofRequest?.sourceBurn
        ?.sourceBurnReceiptAddress ??
      null,
    amountBaseUnits: sourceBurnSubmission?.amountBaseUnits,
    tairaRecipient: sourceBurnSubmission?.tairaRecipient,
    nonce: sourceBurnSubmission?.nonce,
    sourceBurnHash:
      postDeployEvidence?.observedSourceState?.lastBurnHash ?? null,
    explorerUrl: sourceBurnSubmission?.explorerUrl ?? null,
    solanaRpcUrl:
      solanaRpcUrl || args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
    checkedAt,
  });
};

export const solanaFinalizedReadbackRole = (evidence, role) =>
  evidence?.schema === SOLANA_FINALIZED_READBACK_EVIDENCE_SCHEMA &&
  isRecord(evidence.snapshot?.roles?.[role])
    ? evidence.snapshot.roles[role]
    : null;

const outerVerifierEvidenceFacts = (evidence) => {
  const role = solanaFinalizedReadbackRole(evidence, "outerVerifier");
  return {
    programId: role?.program?.address ?? null,
    programDataAddress: role?.programdata?.address ?? null,
    programDataSlot: role?.loaderV3?.deploymentSlot ?? null,
    executableBlake2b256: role?.loaderV3?.executableBlake2b256 ?? null,
  };
};

export const buildSolanaObservedSourceBridgeConfig = ({
  addresses,
  expectedMintAuthority,
  observed,
  manifest,
  verifierEvidence,
  verifierLiveEvidence,
} = {}) => {
  const outerEvidence = outerVerifierEvidenceFacts(verifierEvidence);
  const tokenMintConfig = observed?.tokenMint
    ? {
        mintAuthority: observed.tokenMint.mintAuthority,
        decimals: observed.tokenMint.decimals,
        initialized: observed.tokenMint.initialized,
        freezeAuthority: observed.tokenMint.freezeAuthority,
      }
    : null;
  const verifierStateConfig = observed?.verifierState
    ? {
        authority: observed.verifierState.authority,
        storedMint: observed.verifierState.storedMint,
      }
    : null;
  const sourceStateConfig = observed?.sourceState
    ? {
        authority: observed.sourceState.authority,
        storedMint: observed.sourceState.storedMint,
      }
    : null;
  return {
    schema: "iroha-demo-sccp-solana-observed-source-bridge-config/v1",
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    networkId: SOLANA_TESTNET_NETWORK_ID,
    chainIdHex: SOLANA_TESTNET_CHAIN_ID_HEX,
    counterpartyDomain: SCCP_SOLANA_DOMAIN,
    tokenProgramId: TOKEN_PROGRAM_ID.toBase58(),
    destinationBindingHash:
      readFirstManifestString(
        manifest,
        "destinationBindingHash",
        "destination_binding_hash",
      ) || SOLANA_DESTINATION_BINDING_HASH,
    verifierProgramId: addresses?.verifierProgramId ?? null,
    bridgeProgramId: addresses?.bridgeProgramId ?? null,
    sourceBridgeProgramId: addresses?.sourceBridgeProgramId ?? null,
    tokenMintAddress: addresses?.tokenMintAddress ?? null,
    verifierStateAddress: addresses?.verifierStateAddress ?? null,
    sourceStateAddress: addresses?.sourceStateAddress ?? null,
    expectedMintAuthority: expectedMintAuthority ?? null,
    accountOwners: {
      tokenMint: observed?.accounts?.tokenMintAccount?.owner ?? null,
      verifierState: observed?.accounts?.verifierStateAccount?.owner ?? null,
      sourceState: observed?.accounts?.sourceStateAccount?.owner ?? null,
      verifierProgram:
        observed?.accounts?.verifierProgramAccount?.owner ?? null,
      bridgeProgram: observed?.accounts?.bridgeProgramAccount?.owner ?? null,
      sourceBridgeProgram:
        observed?.accounts?.sourceBridgeProgramAccount?.owner ?? null,
    },
    tokenMint: tokenMintConfig,
    verifierState: verifierStateConfig,
    sourceState: sourceStateConfig,
    verifierProgramdataAddress:
      outerEvidence.programDataAddress ||
      readFirstManifestString(
        manifest,
        "solanaProgramdataAddress",
        "solana_programdata_address",
        "programDataAddress",
        "programdataAddress",
      ) ||
      verifierLiveEvidence?.programdata_address ||
      null,
    verifierProgramdataSlot:
      outerEvidence.programDataSlot ||
      readFirstManifestStringLike(
        manifest,
        "solanaProgramdataSlot",
        "solana_programdata_slot",
        "programDataSlot",
        "programdataSlot",
      ) ||
      verifierLiveEvidence?.programdata_slot ||
      null,
    verifierCodeHash:
      outerEvidence.executableBlake2b256 ||
      readFirstManifestString(
        manifest,
        "verifierCodeHash",
        "verifier_code_hash",
      ) ||
      verifierLiveEvidence?.verifier_code_hash ||
      null,
  };
};

export const buildSolanaPostDeployEvidenceReportBody = ({
  args = {},
  manifest = null,
  publicConfig = null,
  verifierEvidence = null,
  verifierLiveEvidence = null,
  accounts = null,
  observed = null,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const addresses = solanaPostDeployDeploymentAddresses({
    publicConfig,
    manifest,
    accounts,
  });
  const expectedMintAuthority =
    readFirstManifestString(
      manifest,
      "solanaMintAuthorityAddress",
      "solana_mint_authority_address",
    ) ||
    observed?.expectedMintAuthority ||
    publicConfig?.mintAuthorityAddress ||
    null;
  const observedSourceBridgeConfig = buildSolanaObservedSourceBridgeConfig({
    addresses,
    expectedMintAuthority,
    observed,
    manifest,
    verifierEvidence,
    verifierLiveEvidence,
  });
  const observedSourceBridgeConfigHash = sha256JsonHex(
    observedSourceBridgeConfig,
  );
  const postDeployLiveEvidence = readFirstManifestRecord(
    manifest,
    "postDeployLiveEvidence",
    "post_deploy_live_evidence",
  );
  const postDeploy = reportPostDeployStatuses(postDeployLiveEvidence);
  const blockers = [];
  const requiredAddresses = [
    ["verifierProgramId", "Solana verifier program id"],
    ["bridgeProgramId", "Solana bridge program id"],
    ["sourceBridgeProgramId", "Solana source bridge program id"],
    ["tokenMintAddress", "Solana SPL TairaXOR mint"],
    ["verifierStateAddress", "Solana verifier state"],
    ["sourceStateAddress", "Solana source bridge state"],
  ];
  for (const [key, label] of requiredAddresses) {
    if (!addresses[key]) {
      blockers.push({
        id: `missing-${key}`,
        detail: `${label} is missing from deployment evidence.`,
      });
    }
  }
  if (!observed?.tokenMint) {
    blockers.push({
      id: "token-mint-readback",
      detail: "The Solana SPL TairaXOR mint account was not read back.",
    });
  } else {
    if (
      observed.accounts?.tokenMintAccount?.owner !== TOKEN_PROGRAM_ID.toBase58()
    ) {
      blockers.push({
        id: "token-mint-owner",
        detail:
          "The Solana SPL TairaXOR mint is not owned by the SPL Token program.",
      });
    }
    if (observed.tokenMint.initialized !== true) {
      blockers.push({
        id: "token-mint-initialized",
        detail: "The Solana SPL TairaXOR mint is not initialized.",
      });
    }
    if (observed.tokenMint.decimals !== SPL_TOKEN_DECIMALS) {
      blockers.push({
        id: "token-mint-decimals",
        detail: `The Solana SPL TairaXOR mint must use ${SPL_TOKEN_DECIMALS} decimals.`,
      });
    }
    if (
      expectedMintAuthority &&
      observed.tokenMint.mintAuthority !== expectedMintAuthority
    ) {
      blockers.push({
        id: "token-mint-authority",
        detail:
          "The Solana SPL TairaXOR mint authority does not match the verifier PDA.",
      });
    }
  }
  for (const [key, expectedOwner] of [
    ["verifierStateAccount", addresses.verifierProgramId],
    ["sourceStateAccount", addresses.sourceBridgeProgramId],
  ]) {
    const account = observed?.accounts?.[key];
    if (!account) {
      blockers.push({
        id: `${key}-readback`,
        detail: `${key} was not read back from Solana RPC.`,
      });
    } else if (expectedOwner && account.owner !== expectedOwner) {
      blockers.push({
        id: `${key}-owner`,
        detail: `${key} owner does not match the deployed program id.`,
      });
    }
  }
  if (!observed?.verifierState) {
    blockers.push({
      id: "verifier-state-readback",
      detail: "The Solana verifier state account was not parsed.",
    });
  } else if (
    addresses.tokenMintAddress &&
    observed.verifierState.storedMint !== addresses.tokenMintAddress
  ) {
    blockers.push({
      id: "verifier-state-mint",
      detail:
        "The Solana verifier state stored mint does not match the deployment mint.",
    });
  }
  if (!observed?.sourceState) {
    blockers.push({
      id: "source-state-readback",
      detail: "The Solana source bridge state account was not parsed.",
    });
  } else {
    if (
      addresses.tokenMintAddress &&
      observed.sourceState.storedMint !== addresses.tokenMintAddress
    ) {
      blockers.push({
        id: "source-state-mint",
        detail:
          "The Solana source bridge state stored mint does not match the deployment mint.",
      });
    }
    if (parsePositiveU64(observed.sourceState.totalBurned) <= 0n) {
      blockers.push({
        id: "source-burn-event",
        detail:
          "No Solana burn_to_taira source event has been recorded in the deployed source bridge state.",
      });
    }
    if (!observed.sourceState.lastBurnHash) {
      blockers.push({
        id: "source-burn-hash",
        detail:
          "The deployed Solana source bridge state has no last burn hash to bind into a TAIRA settlement proof.",
      });
    }
  }
  const manifestSourceBridgeConfigHashStatus = postDeploy.liveStatuses.find(
    (status) => status.key === "sourceBridgeConfigHash",
  );
  if (
    observed &&
    manifestSourceBridgeConfigHashStatus?.status === "present" &&
    manifestSourceBridgeConfigHashStatus.value !==
      observedSourceBridgeConfigHash
  ) {
    blockers.push({
      id: "manifest-source-bridge-config-hash-mismatch",
      detail:
        "The manifest source-bridge config hash does not match the freshly recomputed Solana deployment readback.",
      expected: manifestSourceBridgeConfigHashStatus.value,
      observed: observedSourceBridgeConfigHash,
    });
  }
  const liveReadbackBlockers = [...blockers];
  const missingPostDeploy = missingOrInvalid(postDeploy.liveStatuses);
  if (missingPostDeploy.length > 0) {
    liveReadbackBlockers.push({
      id: "manifest-post-deploy-live-evidence",
      missingOrInvalid: missingPostDeploy.map((status) => status.key),
    });
  }
  if (
    postDeploy.sourceEventSignature &&
    postDeploy.routeCanarySignature &&
    postDeploy.sourceEventSignature === postDeploy.routeCanarySignature
  ) {
    liveReadbackBlockers.push({
      id: "manifest-post-deploy-distinct-signatures",
      detail:
        "Source-event and route-canary transaction signatures must be distinct.",
    });
  }
  const productionBlockers = [...liveReadbackBlockers];
  const missingOfflineToml = missingOrInvalid([
    {
      key: "fullTomlReady",
      status: postDeploy.fullTomlReady ? "present" : "missing",
    },
    ...postDeploy.offlineTomlStatuses,
  ]);
  if (missingOfflineToml.length > 0) {
    productionBlockers.push({
      id: "offline-full-toml",
      detail:
        "A reviewed final Solana evidence TOML hash is required before postDeployLiveEvidence.fullTomlReady can be true.",
      missingOrInvalid: missingOfflineToml.map((status) => status.key),
    });
  }
  const liveReadbackReady = liveReadbackBlockers.length === 0;
  const readyForProductionPostDeploy = productionBlockers.length === 0;
  return {
    schema: "iroha-demo-sccp-solana-post-deploy-evidence/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    solanaRpcUrl: args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
    ready: readyForProductionPostDeploy,
    liveReadbackReady,
    readyForProductionPostDeploy,
    note: "Observed Solana account evidence is real readback evidence. It is not a substitute for governed source verifier material, route-canary evidence, or signed TAIRA route-manifest publication.",
    deployment: addresses,
    expectedMintAuthority,
    finalizedSlot: observed?.finalizedSlot ?? null,
    observedSourceBridgeConfig,
    observedSourceBridgeConfigHash,
    manifestSourceBridgeConfigHash:
      manifestSourceBridgeConfigHashStatus?.status === "present"
        ? manifestSourceBridgeConfigHashStatus.value
        : null,
    sourceBridgeConfigHashMatchesManifest:
      manifestSourceBridgeConfigHashStatus?.status === "present"
        ? manifestSourceBridgeConfigHashStatus.value ===
          observedSourceBridgeConfigHash
        : false,
    observedStateHashes: {
      tokenMintDataSha256:
        observed?.accountDataHashes?.tokenMintDataSha256 ?? null,
      verifierStateDataSha256:
        observed?.accountDataHashes?.verifierStateDataSha256 ?? null,
      sourceStateDataSha256:
        observed?.accountDataHashes?.sourceStateDataSha256 ?? null,
    },
    observedAccounts: observed?.accounts ?? null,
    observedTokenMint: observed?.tokenMint ?? null,
    observedVerifierState: observed?.verifierState ?? null,
    observedSourceState: observed?.sourceState ?? null,
    manifestPostDeployLiveEvidence: postDeployLiveEvidence,
    manifestPostDeployStatuses: postDeploy.statuses,
    manifestPostDeployLiveStatuses: postDeploy.liveStatuses,
    verifierEvidence: {
      programdataAddress:
        outerVerifierEvidenceFacts(verifierEvidence).programDataAddress ||
        readFirstManifestString(
          manifest,
          "solanaProgramdataAddress",
          "solana_programdata_address",
          "programDataAddress",
          "programdataAddress",
        ) ||
        verifierLiveEvidence?.programdata_address ||
        null,
      programdataSlot:
        outerVerifierEvidenceFacts(verifierEvidence).programDataSlot ||
        readFirstManifestStringLike(
          manifest,
          "solanaProgramdataSlot",
          "solana_programdata_slot",
          "programDataSlot",
          "programdataSlot",
        ) ||
        verifierLiveEvidence?.programdata_slot ||
        null,
      verifierCodeHash:
        outerVerifierEvidenceFacts(verifierEvidence).executableBlake2b256 ||
        readFirstManifestString(
          manifest,
          "verifierCodeHash",
          "verifier_code_hash",
        ) ||
        verifierLiveEvidence?.verifier_code_hash ||
        null,
    },
    blockers: productionBlockers,
    blockerIds: blockerIds(productionBlockers),
    liveReadbackBlockers,
    liveReadbackBlockerIds: blockerIds(liveReadbackBlockers),
    productionBlockers,
    productionBlockerIds: blockerIds(productionBlockers),
  };
};

