const productionRequirements = async (args) => {
  const paths = artifactPaths(args);
  const reportInputs = resolveSolanaPublicReportInputPaths(args, paths);
  const manifestPath = path.resolve(args.manifest || paths.routeManifest);
  const material = await loadSelectedSolanaDeploymentMaterial({
    args,
    paths,
    manifestPath,
  });
  const manifest = material.manifest;
  const publicConfig = material.publicConfig;
  const postDeployEvidence = await readOptionalJson(
    reportInputs.postDeployEvidence,
  );
  if (postDeployEvidence) {
    postDeployEvidence.path = reportInputs.postDeployEvidence;
  }
  const routeCanarySubmission = await readOptionalJson(
    reportInputs.routeCanarySubmission,
  );
  if (routeCanarySubmission) {
    routeCanarySubmission.path = reportInputs.routeCanarySubmission;
  }
  const sourceBurnSubmission = await readOptionalJson(
    reportInputs.sourceBurnSubmission,
  );
  if (sourceBurnSubmission) {
    sourceBurnSubmission.path = reportInputs.sourceBurnSubmission;
  }
  const sourceBurnReadiness = await readOptionalJson(
    reportInputs.sourceBurnReadiness,
  );
  if (sourceBurnReadiness) {
    sourceBurnReadiness.path = reportInputs.sourceBurnReadiness;
  }
  const proverReadiness = await readOptionalJson(reportInputs.proverReadiness);
  if (proverReadiness) {
    proverReadiness.path = reportInputs.proverReadiness;
  }
  const verifierLinkageReadiness = await readOptionalJson(
    reportInputs.verifierLinkageReadiness,
  );
  if (verifierLinkageReadiness) {
    verifierLinkageReadiness.path = reportInputs.verifierLinkageReadiness;
  }
  const programFinalizationReadiness = await readOptionalJson(
    reportInputs.programFinalizationReadiness,
  );
  if (programFinalizationReadiness) {
    programFinalizationReadiness.path =
      reportInputs.programFinalizationReadiness;
  }
  const programFinalization = await readOptionalJson(
    reportInputs.programFinalization,
  );
  if (programFinalization) {
    programFinalization.path = reportInputs.programFinalization;
  }
  const productionMaterialInventoryResult =
    args["production-material-inventory-report"] !== undefined
      ? {
          productionMaterialInventoryPath:
            reportInputs.productionMaterialInventory,
          report: await readJson(reportInputs.productionMaterialInventory),
        }
      : await productionMaterialInventory(args);
  const productionMaterialInventoryReport =
    productionMaterialInventoryResult.report;
  productionMaterialInventoryReport.path =
    productionMaterialInventoryResult.productionMaterialInventoryPath;
  const fileBackedKeyMaterialAudit = await auditFileBackedSolanaKeyMaterial();
  fileBackedKeyMaterialAudit.path = paths.fileBackedKeyMaterialAudit;
  await writePublicJson(
    paths.fileBackedKeyMaterialAudit,
    fileBackedKeyMaterialAudit,
  );
  const sourceMaterialHandoffVerification = await readOptionalJson(
    paths.sourceMaterialHandoffVerification,
  );
  if (sourceMaterialHandoffVerification) {
    sourceMaterialHandoffVerification.path =
      paths.sourceMaterialHandoffVerification;
  }
  const accounts = material.accounts;
  if (accounts) {
    accounts.path = material.materialPaths.accounts;
  }
  const report = buildSolanaProductionRequirementsReportBody({
    args,
    manifest,
    manifestPath,
    publicConfig,
    verifierEvidence: material.verifierEvidence,
    verifierLiveEvidence: material.verifierLiveEvidence,
    verifierLinkageReadiness,
    programFinalizationReadiness,
    programFinalization,
    postDeployEvidence,
    routeCanarySubmission,
    sourceBurnSubmission,
    sourceBurnReadiness,
    proverReadiness,
    productionMaterialInventory: productionMaterialInventoryReport,
    fileBackedKeyMaterialAudit,
    sourceMaterialHandoffVerification,
    accounts,
  });
  await writePublicJson(paths.productionRequirements, report);
  return {
    productionRequirementsPath: paths.productionRequirements,
    report,
  };
};

const ROUTE_PUBLISH_ENDPOINT_CHECK_IDS = [
  "taira-endpoint",
  "sccp-capabilities-load",
  "sccp-submit-capabilities",
];
const ROUTE_PUBLISH_MCP_TRANSACTION_TOOLS = [
  "iroha.transactions.submit",
  "iroha.transactions.submit_and_wait",
];
const ROUTE_PUBLISH_MCP_DEDICATED_TOOL_RE =
  /(?:sccp.*route.*manifest|route.*manifest.*sccp|UpsertSccpRouteManifest)/iu;

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

const shouldRetryHttpStatus = (status) =>
  status === 429 || status === 502 || status === 503 || status === 504;

export const solanaRpcErrorIsRetryable = (error) => {
  const message =
    error instanceof Error ? error.message : error == null ? "" : String(error);
  const status =
    error?.status ??
    error?.statusCode ??
    error?.code ??
    error?.cause?.status ??
    error?.cause?.statusCode ??
    error?.cause?.code;
  if (shouldRetryHttpStatus(Number(status))) {
    return true;
  }
  return (
    /\b(?:429|502|503|504)\b/u.test(message) ||
    /(?:rate limit|rate limits|too many requests|temporarily unavailable|gateway timeout)/iu.test(
      message,
    )
  );
};

const defaultFetchTimeoutMs = () => {
  const value = Number(
    process.env.SCCP_SOLANA_FETCH_TIMEOUT_MS ?? DEFAULT_FETCH_TIMEOUT_MS,
  );
  return Number.isFinite(value) && value > 0 ? value : DEFAULT_FETCH_TIMEOUT_MS;
};

const readPositiveIntegerOption = (value) => {
  if (value === undefined || value === null || value === "") {
    return undefined;
  }
  const parsed = Number(value);
  return Number.isInteger(parsed) && parsed > 0 ? parsed : undefined;
};

const solanaDeployFetchOptions = (args = {}) => {
  const timeoutMs = readPositiveIntegerOption(
    args["fetch-timeout-ms"] ?? args.timeoutMs,
  );
  const attempts = readPositiveIntegerOption(
    args["fetch-attempts"] ?? args.attempts,
  );
  return {
    ...(timeoutMs ? { timeoutMs } : {}),
    ...(attempts ? { attempts } : {}),
  };
};

const solanaRpcRetryOptions = (args = {}) => ({
  attempts:
    readPositiveIntegerOption(
      args["solana-rpc-attempts"] ??
        args["fetch-attempts"] ??
        args.attempts ??
        process.env.SCCP_SOLANA_RPC_ATTEMPTS,
    ) ?? 4,
  delayMs:
    readPositiveIntegerOption(
      args["solana-rpc-retry-delay-ms"] ??
        process.env.SCCP_SOLANA_RPC_RETRY_DELAY_MS,
    ) ?? 350,
});

export const withSolanaRpcRetry = async (
  read,
  { label = "Solana RPC read", attempts = 4, delayMs = 350 } = {},
) => {
  const totalAttempts = Math.max(1, Number(attempts) || 1);
  let lastError = null;
  for (let attempt = 1; attempt <= totalAttempts; attempt += 1) {
    try {
      return await read({ attempt, attempts: totalAttempts });
    } catch (error) {
      lastError = error;
      if (attempt >= totalAttempts || !solanaRpcErrorIsRetryable(error)) {
        throw error;
      }
      await sleep(delayMs * 2 ** (attempt - 1));
    }
  }
  throw new Error(
    `${label} failed after ${totalAttempts} attempts: ${
      lastError instanceof Error ? lastError.message : String(lastError)
    }`,
  );
};

