export const assertNoRoutePublishReadinessOverrideForMutation = (args = {}) => {
  const reportOverride = reportOverridePath(args, [
    "route-publish-readiness-report",
    "publish-readiness-report",
    "public-preflight-report",
    "preflight-report",
  ]);
  if (reportOverride) {
    throw new Error(
      "Route publication must recompute readiness and public preflight from live, manifest-bound inputs; report overrides are not accepted by mutating commands.",
    );
  }
  if (
    args["skip-solana-rpc"] !== undefined &&
    args["skip-solana-rpc"] !== false &&
    args["skip-solana-rpc"] !== "false"
  ) {
    throw new Error(
      "Route publication requires fresh finalized Solana RPC readback; --skip-solana-rpc cannot be enabled by mutating commands.",
    );
  }
};

