export const fetchTextWithRetry = async (
  url,
  options = {},
  attempts = undefined,
) => {
  const requestAttempts = Math.max(
    1,
    Number(attempts ?? options.attempts ?? 3),
  );
  const timeoutMs = Math.max(
    1,
    Number(options.timeoutMs ?? defaultFetchTimeoutMs()),
  );
  let lastError = null;
  for (let attempt = 1; attempt <= requestAttempts; attempt += 1) {
    const controller = new AbortController();
    const timeout = setTimeout(() => {
      controller.abort();
    }, timeoutMs);
    try {
      const response = await fetch(url, {
        ...Object.fromEntries(
          Object.entries(options).filter(
            ([key]) => !["attempts", "signal", "timeoutMs"].includes(key),
          ),
        ),
        signal: controller.signal,
      });
      const text = await response.text();
      if (!response.ok) {
        const error = new Error(
          `HTTP ${response.status}${response.statusText ? ` ${response.statusText}` : ""}: ${text.slice(0, 300)}`,
        );
        error.status = response.status;
        throw error;
      }
      return text;
    } catch (error) {
      const fetchError =
        controller.signal.aborted && error?.name === "AbortError"
          ? new Error(`HTTP request timed out after ${timeoutMs}ms: ${url}`)
          : error;
      lastError = fetchError;
      const status = Number(fetchError?.status);
      if (
        attempt >= requestAttempts ||
        (status && !shouldRetryHttpStatus(status))
      ) {
        throw fetchError;
      }
      await sleep(250 * attempt);
    } finally {
      clearTimeout(timeout);
    }
  }
  throw lastError;
};

const parseJsonRecordOrArray = (value) => {
  if (typeof value !== "string") {
    return value;
  }
  const trimmed = value.trim();
  if (
    !trimmed ||
    !(
      (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
      (trimmed.startsWith("[") && trimmed.endsWith("]"))
    )
  ) {
    return value;
  }
  try {
    return JSON.parse(trimmed);
  } catch (_error) {
    return value;
  }
};

const mcpTextContentBodies = (payload) => {
  const content = payload?.result?.content ?? payload?.content;
  if (!Array.isArray(content)) {
    return [];
  }
  return content
    .map((entry) => parseJsonRecordOrArray(entry?.text ?? entry))
    .filter((entry) => entry && typeof entry === "object");
};

const mcpStructuredBody = (payload) => {
  const directBody =
    payload?.result?.structuredContent?.body ??
    payload?.structuredContent?.body ??
    payload?.body;
  if (directBody !== undefined) {
    return parseJsonRecordOrArray(directBody);
  }
  const [firstTextBody] = mcpTextContentBodies(payload);
  return firstTextBody ?? payload;
};

const permissionNamesFromPayload = (payload) => {
  const body = mcpStructuredBody(payload);
  const items = Array.isArray(body?.items)
    ? body.items
    : Array.isArray(body?.permissions)
      ? body.permissions
      : Array.isArray(body)
        ? body
        : [];
  return Array.from(
    new Set(
      items
        .map((item) => {
          if (typeof item === "string") {
            return item.trim();
          }
          if (!item || typeof item !== "object") {
            return "";
          }
          return String(item.name ?? item.permission ?? item.id ?? "").trim();
        })
        .filter(Boolean),
    ),
  ).sort();
};

const summarizePreflightChecks = (publicPreflight) =>
  Array.isArray(publicPreflight?.checks)
    ? publicPreflight.checks.map((check) => ({
        id: check.id,
        status: check.status,
        detail: check.detail ?? null,
      }))
    : [];

const routePublishEndpointStatus = (publicPreflight) => {
  const checks = summarizePreflightChecks(publicPreflight);
  const byId = new Map(checks.map((check) => [check.id, check]));
  const requiredChecks = ROUTE_PUBLISH_ENDPOINT_CHECK_IDS.map((id) => {
    const check = byId.get(id) ?? null;
    return {
      id,
      status: check?.status ?? "missing",
      detail: check?.detail ?? null,
    };
  });
  return {
    ready: requiredChecks.every((check) => check.status === "pass"),
    requiredChecks,
    failingChecks: requiredChecks.filter((check) => check.status !== "pass"),
  };
};

const compactTairaIngressError = (value) => {
  const text = String(value ?? "")
    .replace(/<[^>]+>/gu, " ")
    .replace(/\s+/gu, " ")
    .trim();
  return text.length > 240 ? `${text.slice(0, 237)}...` : text;
};

const hasOwnOption = (args, key) =>
  isRecord(args) && Object.prototype.hasOwnProperty.call(args, key);

const normalizeEndpointUrl = (value) =>
  String(value ?? "")
    .trim()
    .replace(/\/+$/u, "");

const tairaMcpUrlFromToriiRoot = (toriiUrl) =>
  `${normalizeEndpointUrl(toriiUrl)}/v1/mcp`;

export const resolveTairaRoutePublishTarget = (args = {}) => {
  const explicitToriiUrl = hasOwnOption(args, "torii-url");
  const explicitMcpUrl = hasOwnOption(args, "mcp-url");
  const toriiUrl = normalizeEndpointUrl(
    explicitToriiUrl ? args["torii-url"] : DEFAULT_TAIRA_TORII_URL,
  );
  const mcpUrl = normalizeEndpointUrl(
    explicitMcpUrl ? args["mcp-url"] : DEFAULT_TAIRA_MCP_URL,
  );
  const defaultToriiRoot =
    toriiUrl === normalizeEndpointUrl(DEFAULT_TAIRA_TORII_URL);
  const defaultMcpRoot = mcpUrl === normalizeEndpointUrl(DEFAULT_TAIRA_MCP_URL);
  const canonicalPublicNodeRoot =
    CANONICAL_TAIRA_PUBLIC_NODE_ROOTS.has(toriiUrl);
  const expectedMcpUrl = tairaMcpUrlFromToriiRoot(toriiUrl);
  const mcpMatchesToriiRoot = mcpUrl === expectedMcpUrl;
  const explicitPublicNode =
    explicitToriiUrl &&
    explicitMcpUrl &&
    !defaultToriiRoot &&
    !defaultMcpRoot &&
    canonicalPublicNodeRoot &&
    mcpMatchesToriiRoot;
  return {
    toriiUrl,
    mcpUrl,
    toriiUrlSource: explicitToriiUrl ? "argument" : "default",
    mcpUrlSource: explicitMcpUrl ? "argument" : "default",
    targetKind: explicitPublicNode
      ? EXPLICIT_TAIRA_PUBLIC_NODE_KIND
      : DEFAULT_TAIRA_PUBLIC_ROOT_KIND,
    defaultConvenienceRoot: defaultToriiRoot,
    defaultConvenienceMcp: defaultMcpRoot,
    canonicalPublicNodeRoot,
    expectedMcpUrl,
    mcpMatchesToriiRoot,
    canonicalRolloutTargetReady: explicitPublicNode,
    canonicalRolloutRequiresExplicitPublicNode: true,
    requiredArguments: ["--torii-url", "--mcp-url"],
    operatorAction:
      "Provide one of the canonical https://taira-validator-N.sora.org public-node roots with --torii-url and that exact root's /v1/mcp endpoint with --mcp-url before route publication.",
  };
};

export const buildSolanaRouteAbsenceMutationFence = ({
  args = {},
  publicPreflight = null,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const target = resolveTairaRoutePublishTarget(args);
  const checks = Array.isArray(publicPreflight?.checks)
    ? publicPreflight.checks
    : [];
  const byId = new Map(checks.map((check) => [check?.id, check]));
  const routeInstance = byId.get("solana-route-instance-publication") ?? null;
  const manifestLoad = byId.get("sccp-manifest-load") ?? null;
  const endpointReady = routePublishEndpointStatus(publicPreflight).ready;
  const publicationSurfaceReady =
    byId.get("public-route-publication")?.status === "pass";
  const routePublished = routeInstance?.status === "pass";
  const routeAbsent =
    routeInstance?.status === "fail" &&
    routeInstance?.evidence?.routeAbsent === true &&
    routeInstance?.evidence?.expectedRouteId === SCCP_SOLANA_XOR_ROUTE_ID &&
    routeInstance?.evidence?.expectedAssetKey === SCCP_XOR_ASSET_KEY;
  const publicManifestEnvelopeReady =
    manifestLoad?.status === "pass" &&
    manifestLoad?.evidence?.source === "public" &&
    Number.isSafeInteger(manifestLoad?.evidence?.recordCount) &&
    manifestLoad.evidence.recordCount >= 0;
  const authoritativeManifestReadReady =
    publicManifestEnvelopeReady &&
    manifestLoad?.evidence?.cacheBypassRequested === true &&
    manifestLoad?.evidence?.cacheBypassVerified === true &&
    manifestLoad?.evidence?.finalityBoundRead === true &&
    Number.isSafeInteger(manifestLoad?.evidence?.finalizedHeightBefore) &&
    Number.isSafeInteger(manifestLoad?.evidence?.finalizedHeightAfter) &&
    Number.isSafeInteger(manifestLoad?.evidence?.manifestFinalizedHeight) &&
    manifestLoad.evidence.finalizedHeightBefore > 0 &&
    manifestLoad.evidence.manifestFinalizedHeight >=
      manifestLoad.evidence.finalizedHeightBefore &&
    manifestLoad.evidence.manifestFinalizedHeight <=
      manifestLoad.evidence.finalizedHeightAfter &&
    manifestLoad.evidence.finalizedHeightAfter >=
      manifestLoad.evidence.finalizedHeightBefore;
  const blockers = uniqueStrings([
    ...(target.canonicalRolloutTargetReady
      ? []
      : ["explicit-canonical-taira-public-node-required"]),
    ...(endpointReady ? [] : ["taira-route-endpoint-readiness-required"]),
    ...(publicationSurfaceReady
      ? []
      : ["taira-route-publication-surface-required"]),
    ...(publicManifestEnvelopeReady
      ? []
      : ["public-manifest-envelope-readiness-required"]),
    ...(authoritativeManifestReadReady
      ? []
      : ["authoritative-finality-bound-manifest-read-required"]),
    ...(routeAbsent
      ? []
      : [
          routePublished
            ? "published-route-mutation-procedure-required"
            : "public-route-absence-not-proven",
        ]),
  ]);
  return {
    schema: "iroha-demo-sccp-solana-route-absence-mutation-fence/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    ready: blockers.length === 0,
    target,
    endpointReady,
    publicationSurfaceReady,
    publicManifestEnvelopeReady,
    authoritativeManifestReadReady,
    routePublished,
    routeAbsent,
    blockers: blockers.map((id) => ({ id })),
    blockerIds: blockers,
  };
};

export const runFreshSolanaRouteAbsenceMutationFence = async (
  args,
  {
    stage = "irreversible-solana-mutation-route-absence-fence",
    strict = true,
  } = {},
) => {
  const paths = artifactPaths(args);
  const fetchOptions = solanaDeployFetchOptions(args);
  const validatorRoots = [...CANONICAL_TAIRA_PUBLIC_NODE_ROOTS].sort();
  const nodeResults = await Promise.all(
    validatorRoots.map(async (toriiUrl, index) => {
      const nodeArgs = {
        ...args,
        "torii-url": toriiUrl,
        "mcp-url": `${toriiUrl}/v1/mcp`,
      };
      const preflight = await runSccpSolanaRoutePreflight({
        toriiUrl,
        solanaRpcUrl: args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
        outputDir: path.join(paths.outputDir, stage, `validator-${index + 1}`),
        fetchTimeoutMs: fetchOptions.timeoutMs,
        fetchAttempts: fetchOptions.attempts,
        skipSolanaRpc: false,
        requireAuthoritativeManifestRead: true,
      });
      const fence = buildSolanaRouteAbsenceMutationFence({
        args: nodeArgs,
        publicPreflight: preflight.report,
      });
      const preflightArtifact = await readStablePublicSolanaJsonArtifact({
        file: preflight.reportPath,
        label: `Fresh authoritative TAIRA route-absence preflight for ${toriiUrl}`,
      });
      if (
        JSON.stringify(preflightArtifact.value) !==
        JSON.stringify(preflight.report)
      ) {
        throw new Error(
          `Fresh authoritative TAIRA route-absence preflight changed for ${toriiUrl}.`,
        );
      }
      const manifestReadEvidence = preflight.report?.checks?.find(
        (check) => check?.id === "sccp-manifest-load",
      )?.evidence;
      return {
        toriiUrl,
        mcpUrl: `${toriiUrl}/v1/mcp`,
        ready: fence.ready === true,
        blockerIds: fence.blockerIds,
        routeAbsent: fence.routeAbsent === true,
        manifestFinalizedHeight:
          manifestReadEvidence?.manifestFinalizedHeight ?? null,
        finalizedHeightBefore:
          manifestReadEvidence?.finalizedHeightBefore ?? null,
        finalizedHeightAfter:
          manifestReadEvidence?.finalizedHeightAfter ?? null,
        cacheBypassVerified: manifestReadEvidence?.cacheBypassVerified === true,
        finalityBoundRead: manifestReadEvidence?.finalityBoundRead === true,
        nodeIdentity: manifestReadEvidence?.nodeIdentity ?? null,
        irohaStateHash: manifestReadEvidence?.irohaStateHash ?? null,
        preflightPath: preflightArtifact.path,
        preflightArtifactSha256: preflightArtifact.sha256,
        preflight: preflight.report,
        fence,
      };
    }),
  );
  const commonHeights = uniqueStrings(
    nodeResults.map((node) =>
      Number.isSafeInteger(node.manifestFinalizedHeight)
        ? String(node.manifestFinalizedHeight)
        : "",
    ),
  );
  const commonFinalizedHeight =
    commonHeights.length === 1 ? Number(commonHeights[0]) : null;
  const nodeIdentities = uniqueStrings(
    nodeResults.map((node) => node.nodeIdentity),
  );
  const commonStateHashes = uniqueStrings(
    nodeResults.map((node) => node.irohaStateHash),
  );
  const commonIrohaStateHash =
    commonStateHashes.length === 1 ? commonStateHashes[0] : null;
  const quorumReady =
    nodeResults.length === validatorRoots.length &&
    nodeResults.every((node) => node.ready === true) &&
    nodeIdentities.length === validatorRoots.length &&
    /^0x[0-9a-f]{64}$/u.test(commonIrohaStateHash ?? "") &&
    Number.isSafeInteger(commonFinalizedHeight) &&
    commonFinalizedHeight > 0;
  const selectedNode =
    nodeResults.find(
      (node) => node.toriiUrl === normalizeEndpointUrl(args["torii-url"] ?? ""),
    ) ?? nodeResults[0];
  const blockerIdsForQuorum = uniqueStrings([
    ...nodeResults.flatMap((node) => node.blockerIds),
    ...(nodeResults.length === validatorRoots.length &&
    nodeResults.every((node) => node.ready === true)
      ? []
      : ["authoritative-taira-validator-quorum-required"]),
    ...(commonFinalizedHeight
      ? []
      : ["common-finalized-manifest-height-required"]),
    ...(nodeIdentities.length === validatorRoots.length
      ? []
      : ["distinct-taira-validator-identities-required"]),
    ...(commonIrohaStateHash
      ? []
      : ["common-finalized-iroha-state-hash-required"]),
  ]);
  const fence = {
    ...selectedNode.fence,
    checkedAt: new Date().toISOString(),
    ready: quorumReady && blockerIdsForQuorum.length === 0,
    quorumReady,
    quorumEvidence: {
      schema: "iroha-demo-sccp-solana-route-absence-quorum/v1",
      ready: quorumReady,
      requiredValidatorCount: validatorRoots.length,
      observedValidatorCount: nodeResults.length,
      commonManifestFinalizedHeight: commonFinalizedHeight,
      commonIrohaStateHash,
      validators: nodeResults.map((node) => ({
        toriiUrl: node.toriiUrl,
        mcpUrl: node.mcpUrl,
        ready: node.ready,
        routeAbsent: node.routeAbsent,
        manifestFinalizedHeight: node.manifestFinalizedHeight,
        finalizedHeightBefore: node.finalizedHeightBefore,
        finalizedHeightAfter: node.finalizedHeightAfter,
        cacheBypassVerified: node.cacheBypassVerified,
        finalityBoundRead: node.finalityBoundRead,
        nodeIdentity: node.nodeIdentity,
        irohaStateHash: node.irohaStateHash,
        preflightPath: node.preflightPath,
        preflightArtifactSha256: node.preflightArtifactSha256,
        blockerIds: node.blockerIds,
      })),
    },
    manifestReadEvidence: {
      cacheBypassRequested: true,
      cacheBypassVerified: selectedNode.cacheBypassVerified,
      finalityBoundRead: selectedNode.finalityBoundRead,
      finalizedHeightBefore: selectedNode.finalizedHeightBefore,
      manifestFinalizedHeight: selectedNode.manifestFinalizedHeight,
      finalizedHeightAfter: selectedNode.finalizedHeightAfter,
    },
    blockers: blockerIdsForQuorum.map((id) => ({ id })),
    blockerIds: blockerIdsForQuorum,
  };
  const quorumReportPath = path.join(
    paths.outputDir,
    stage,
    "taira-route-absence-quorum.json",
  );
  const expectedQuorumSha256 = sha256BufferHex(
    Buffer.from(`${JSON.stringify(fence, null, 2)}\n`),
  );
  await writePublicJson(quorumReportPath, fence);
  const quorumArtifact = await readStablePublicSolanaJsonArtifact({
    file: quorumReportPath,
    label: "Fresh authoritative TAIRA route-absence quorum",
    expectedSha256: expectedQuorumSha256,
  });
  const result = {
    reportPath: quorumArtifact.path,
    reportArtifactSha256: quorumArtifact.sha256,
    publicPreflight: selectedNode.preflight,
    report: {
      ...fence,
      quorumArtifactSha256: quorumArtifact.sha256,
      publicPreflightPath: selectedNode.preflightPath,
      publicPreflightArtifactSha256: selectedNode.preflightArtifactSha256,
    },
  };
  if (strict && !fence.ready) {
    const error = new Error(
      `Irreversible Solana mutation is blocked by the fresh TAIRA route-absence fence: ${fence.blockerIds.join(", ")}`,
    );
    error.routeAbsenceFence = result.report;
    throw error;
  }
  return result;
};

const routePublishEndpointCommandArgs = (
  target,
  { includeMissingPlaceholders = false } = {},
) => {
  const commandArgs = [];
  if (target?.toriiUrlSource === "argument" && !target.defaultConvenienceRoot) {
    commandArgs.push("--torii-url", target.toriiUrl);
  } else if (includeMissingPlaceholders) {
    commandArgs.push("--torii-url", TAIRA_PUBLIC_NODE_ROOT_URL_PLACEHOLDER);
  }
  if (target?.mcpUrlSource === "argument" && !target.defaultConvenienceMcp) {
    commandArgs.push("--mcp-url", target.mcpUrl);
  } else if (includeMissingPlaceholders) {
    commandArgs.push("--mcp-url", TAIRA_PUBLIC_NODE_MCP_URL_PLACEHOLDER);
  }
  return commandArgs;
};

const routePreflightEndpointCommandArgs = (
  target,
  { includeMissingPlaceholders = false } = {},
) => {
  if (target?.toriiUrlSource === "argument" && !target.defaultConvenienceRoot) {
    return ["--torii-url", target.toriiUrl];
  }
  return includeMissingPlaceholders
    ? ["--torii-url", TAIRA_PUBLIC_NODE_ROOT_URL_PLACEHOLDER]
    : [];
};

export const tairaPublicNodeCandidatesFromDnsRecords = (
  payload,
  sourceFile,
) => {
  const records = Array.isArray(payload?.records) ? payload.records : [];
  return records
    .filter(
      (record) =>
        isRecord(record) &&
        record.type === "A" &&
        /^taira-validator-\d+\.sora\.org$/u.test(String(record.name ?? "")),
    )
    .map((record) => {
      const host = String(record.name).trim();
      const toriiUrl = `https://${host}`;
      return {
        host,
        toriiUrl,
        mcpUrl: tairaMcpUrlFromToriiRoot(toriiUrl),
        dnsRecordType: record.type,
        expectedAddress: typeof record.value === "string" ? record.value : null,
        ttl: Number.isFinite(record.ttl) ? record.ttl : null,
        purpose: typeof record.purpose === "string" ? record.purpose : null,
        sourceFile: sourceFile ?? null,
      };
    });
};

const loadTairaPublicNodeCandidates = async () => {
  try {
    const payload = await readJson(TAIRA_DNS_RECORDS_PATH);
    return {
      sourceFile: TAIRA_DNS_RECORDS_PATH,
      candidates: tairaPublicNodeCandidatesFromDnsRecords(
        payload,
        TAIRA_DNS_RECORDS_PATH,
      ),
      error: null,
    };
  } catch (error) {
    return {
      sourceFile: TAIRA_DNS_RECORDS_PATH,
      candidates: [],
      error: error instanceof Error ? error.message : String(error),
    };
  }
};

const lookupTairaPublicNodeCandidate = async (host) => {
  try {
    const addresses = await dns.lookup(host, { all: true });
    return {
      dnsReady: addresses.length > 0,
      resolvedAddresses: addresses.map((entry) => entry.address).sort(),
      dnsError: null,
    };
  } catch (error) {
    return {
      dnsReady: false,
      resolvedAddresses: [],
      dnsError: error instanceof Error ? error.message : String(error),
    };
  }
};

const checkTairaPublicNodeCandidateTls = ({
  host,
  address,
  timeoutMs = 3000,
} = {}) =>
  new Promise((resolve) => {
    if (!host || !address) {
      resolve({
        tlsReady: false,
        tlsChecked: false,
        tlsError: "candidate host or expected address is missing",
      });
      return;
    }
    let settled = false;
    const settle = (result) => {
      if (settled) {
        return;
      }
      settled = true;
      socket.destroy();
      resolve(result);
    };
    const socket = tls.connect({
      host: address,
      port: 443,
      servername: host,
      rejectUnauthorized: true,
      timeout: timeoutMs,
    });
    socket.once("secureConnect", () => {
      const certificate = socket.getPeerCertificate();
      settle({
        tlsReady: socket.authorized === true,
        tlsChecked: true,
        tlsError: socket.authorized ? null : socket.authorizationError,
        certificateSubject:
          typeof certificate?.subject?.CN === "string"
            ? certificate.subject.CN
            : null,
        certificateSubjectAltName:
          typeof certificate?.subjectaltname === "string"
            ? certificate.subjectaltname
            : null,
      });
    });
    socket.once("timeout", () => {
      settle({
        tlsReady: false,
        tlsChecked: true,
        tlsError: `TLS check timed out after ${timeoutMs}ms`,
      });
    });
    socket.once("error", (error) => {
      settle({
        tlsReady: false,
        tlsChecked: true,
        tlsError: error instanceof Error ? error.message : String(error),
      });
    });
  });

const probeTairaPublicNodeCandidateEdge = ({
  host,
  address,
  path = "/status",
  method = "GET",
  body = "",
  resultPrefix = "edgeStatusProbe",
  timeoutMs = 3000,
} = {}) =>
  new Promise((resolve) => {
    const readyKey = `${resultPrefix}Ready`;
    const checkedKey = `${resultPrefix}Checked`;
    const tlsDisabledKey = `${resultPrefix}TlsVerificationDisabled`;
    const httpStatusKey = `${resultPrefix}HttpStatus`;
    const errorKey = `${resultPrefix}Error`;
    if (!host || !address) {
      resolve({
        [readyKey]: false,
        [checkedKey]: false,
        [errorKey]: "candidate host or expected address is missing",
      });
      return;
    }
    const request = https.request(
      {
        host: address,
        port: 443,
        servername: host,
        method,
        path,
        rejectUnauthorized: false,
        timeout: timeoutMs,
        headers: {
          host,
          accept: "application/json, text/event-stream",
          ...(body
            ? {
                "content-type": "application/json",
                "content-length": Buffer.byteLength(body),
              }
            : {}),
        },
      },
      (response) => {
        let text = "";
        response.setEncoding("utf8");
        response.on("data", (chunk) => {
          if (text.length < 512) {
            text += chunk;
          }
        });
        response.on("end", () => {
          const statusCode = response.statusCode ?? 0;
          resolve({
            [readyKey]: statusCode >= 200 && statusCode < 300,
            [checkedKey]: true,
            [tlsDisabledKey]: true,
            [httpStatusKey]: statusCode,
            [errorKey]:
              statusCode >= 200 && statusCode < 300
                ? null
                : `HTTP ${statusCode}: ${compactTairaIngressError(text)}`,
          });
        });
      },
    );
    request.once("timeout", () => {
      request.destroy();
      resolve({
        [readyKey]: false,
        [checkedKey]: true,
        [tlsDisabledKey]: true,
        [httpStatusKey]: null,
        [errorKey]: `HTTP request timed out after ${timeoutMs}ms`,
      });
    });
    request.once("error", (error) => {
      resolve({
        [readyKey]: false,
        [checkedKey]: true,
        [tlsDisabledKey]: true,
        [httpStatusKey]: null,
        [errorKey]: error instanceof Error ? error.message : String(error),
      });
    });
    request.end(body || undefined);
  });

const probeTairaPublicNodeCandidateEdgeStatus = ({
  host,
  address,
  timeoutMs = 3000,
} = {}) =>
  probeTairaPublicNodeCandidateEdge({
    host,
    address,
    path: "/status",
    method: "GET",
    resultPrefix: "edgeStatusProbe",
    timeoutMs,
  });

const probeTairaPublicNodeCandidateEdgeMcp = ({
  host,
  address,
  timeoutMs = 3000,
} = {}) =>
  probeTairaPublicNodeCandidateEdge({
    host,
    address,
    path: "/v1/mcp",
    method: "POST",
    body: JSON.stringify({
      jsonrpc: "2.0",
      id: 1,
      method: "tools/list",
      params: {},
    }),
    resultPrefix: "edgeMcpProbe",
    timeoutMs,
  });

const auditTairaPublicNodeCandidates = async ({ fetchOptions = {} } = {}) => {
  const loaded = await loadTairaPublicNodeCandidates();
  const probeFetchOptions = {
    ...fetchOptions,
    attempts: 1,
    timeoutMs: Math.min(
      fetchOptions.timeoutMs ?? DEFAULT_FETCH_TIMEOUT_MS,
      3000,
    ),
  };
  const candidates = [];
  for (const candidate of loaded.candidates) {
    const dnsStatus = await lookupTairaPublicNodeCandidate(candidate.host);
    const tlsStatus = await checkTairaPublicNodeCandidateTls({
      host: candidate.host,
      address: candidate.expectedAddress,
      timeoutMs: probeFetchOptions.timeoutMs,
    });
    const edgeStatusProbe = await probeTairaPublicNodeCandidateEdgeStatus({
      host: candidate.host,
      address: candidate.expectedAddress,
      timeoutMs: probeFetchOptions.timeoutMs,
    });
    const edgeMcpProbe = await probeTairaPublicNodeCandidateEdgeMcp({
      host: candidate.host,
      address: candidate.expectedAddress,
      timeoutMs: probeFetchOptions.timeoutMs,
    });
    let mcpTransactionTools = null;
    if (dnsStatus.dnsReady) {
      mcpTransactionTools = await fetchTairaMcpTransactionToolStatus(
        candidate.mcpUrl,
        probeFetchOptions,
      );
    }
    candidates.push({
      ...candidate,
      ...dnsStatus,
      ...tlsStatus,
      ...edgeStatusProbe,
      ...edgeMcpProbe,
      mcpTransactionTools,
      ready: dnsStatus.dnsReady === true && mcpTransactionTools?.ready === true,
    });
  }
  const readyCandidate =
    candidates.find((candidate) => candidate.ready === true) ?? null;
  const dnsReadyCount = candidates.filter(
    (candidate) => candidate.dnsReady === true,
  ).length;
  const mcpReadyCount = candidates.filter(
    (candidate) => candidate.mcpTransactionTools?.ready === true,
  ).length;
  const tlsReadyCount = candidates.filter(
    (candidate) => candidate.tlsReady === true,
  ).length;
  const edgeMcpProbeReadyCount = candidates.filter(
    (candidate) => candidate.edgeMcpProbeReady === true,
  ).length;
  const edgeStatusProbeReadyCount = candidates.filter(
    (candidate) => candidate.edgeStatusProbeReady === true,
  ).length;
  const blockerIds = [];
  if (loaded.error) {
    blockerIds.push("taira-public-node-candidate-source");
  }
  if (candidates.length === 0) {
    blockerIds.push("taira-public-node-candidates-missing");
  }
  if (candidates.length > 0 && dnsReadyCount === 0) {
    blockerIds.push("taira-public-node-dns");
  }
  if (candidates.length > 0 && tlsReadyCount === 0) {
    blockerIds.push("taira-public-node-tls");
  }
  if (candidates.length > 0 && edgeMcpProbeReadyCount === 0) {
    blockerIds.push("taira-public-node-edge-routing");
  }
  if (candidates.length > 0 && edgeStatusProbeReadyCount === 0) {
    blockerIds.push("taira-public-node-status-routing");
  }
  if (dnsReadyCount > 0 && mcpReadyCount === 0) {
    blockerIds.push("taira-public-node-mcp");
  }
  return {
    schema: "iroha-demo-sccp-solana-taira-public-node-candidates/v1",
    sourceFile: loaded.sourceFile,
    ready: Boolean(readyCandidate),
    readyCandidate: readyCandidate
      ? {
          host: readyCandidate.host,
          toriiUrl: readyCandidate.toriiUrl,
          mcpUrl: readyCandidate.mcpUrl,
        }
      : null,
    candidateCount: candidates.length,
    dnsReadyCount,
    tlsReadyCount,
    edgeStatusProbeReadyCount,
    edgeMcpProbeReadyCount,
    mcpReadyCount,
    blockerIds,
    error: loaded.error,
    candidates,
  };
};

const tairaPublicNodeCommandToken = (value, fallback) => {
  const text = typeof value === "string" ? value.trim() : "";
  return /^[A-Za-z0-9_.:-]+$/u.test(text) ? text : fallback;
};

const tairaPublicNodeRepairPlan = ({
  publicNodeCandidates = null,
  refreshPublishReadinessCommand = [],
} = {}) => {
  const candidates = Array.isArray(publicNodeCandidates?.candidates)
    ? publicNodeCandidates.candidates
    : [];
  const primaryCandidate =
    (isRecord(publicNodeCandidates?.readyCandidate)
      ? publicNodeCandidates.readyCandidate
      : null) ??
    candidates.find((candidate) => candidate.ready === true) ??
    candidates[0] ??
    null;
  const primaryHost = tairaPublicNodeCommandToken(
    primaryCandidate?.host,
    "taira-validator-1.sora.org",
  );
  const primaryAddress = tairaPublicNodeCommandToken(
    primaryCandidate?.expectedAddress,
    "208.83.1.62",
  );
  const primaryToriiUrl =
    typeof primaryCandidate?.toriiUrl === "string" &&
    primaryCandidate.toriiUrl.trim()
      ? primaryCandidate.toriiUrl.trim()
      : `https://${primaryHost}`;
  const primaryMcpUrl =
    typeof primaryCandidate?.mcpUrl === "string" &&
    primaryCandidate.mcpUrl.trim()
      ? primaryCandidate.mcpUrl.trim()
      : `${primaryToriiUrl}/v1/mcp`;
  const hostnames = uniqueStrings(
    candidates
      .map((candidate) => candidate.host)
      .filter((host) => typeof host === "string" && host.trim()),
  );
  const requiredDnsRecords = candidates.map((candidate) => ({
    name: candidate.host ?? null,
    type: candidate.dnsRecordType ?? "A",
    value: candidate.expectedAddress ?? null,
    ttl: candidate.ttl ?? null,
    ready: candidate.dnsReady === true,
    resolvedAddresses: Array.isArray(candidate.resolvedAddresses)
      ? candidate.resolvedAddresses
      : [],
    error: candidate.dnsError ?? null,
  }));
  const requiredOutcomes = [
    {
      id: "direct-validator-dns",
      ready:
        candidates.length > 0 &&
        candidates.every((candidate) => candidate.dnsReady === true),
      detail:
        "Every published taira-validator-N.sora.org public-node hostname resolves to the shared TAIRA edge address from dns_records.json.",
    },
    {
      id: "direct-validator-tls-san",
      ready:
        candidates.length > 0 &&
        candidates.every((candidate) => candidate.tlsReady === true),
      detail:
        "The edge TLS certificate validates for every direct validator hostname through SNI.",
    },
    {
      id: "direct-validator-status-routing",
      ready:
        candidates.length > 0 &&
        candidates.every(
          (candidate) => candidate.edgeStatusProbeReady === true,
        ),
      detail:
        "Forced-edge HTTPS probes to /status return a 2xx upstream Torii response for each direct validator hostname.",
    },
    {
      id: "direct-validator-mcp-routing",
      ready:
        candidates.length > 0 &&
        candidates.every((candidate) => candidate.edgeMcpProbeReady === true),
      detail:
        "Forced-edge JSON-RPC tools/list probes to /v1/mcp return a 2xx MCP response for each direct validator hostname.",
    },
    {
      id: "mcp-transaction-tools",
      ready:
        candidates.length > 0 &&
        candidates.every(
          (candidate) => candidate.mcpTransactionTools?.ready === true,
        ),
      detail:
        "The selected public-node MCP endpoint exposes iroha.transactions.submit and iroha.transactions.submit_and_wait.",
    },
  ];
  const commands = {
    renderEdgeNginxCandidate: [
      "bash",
      "../iroha/configs/soranexus/taira/install_taira_edge_nginx_conf.sh",
    ],
    validatePrimaryDns: ["dig", "+short", primaryHost],
    validatePrimaryTls: [
      "sh",
      "-lc",
      `timeout 10 openssl s_client -brief -verify_return_error -connect ${primaryAddress}:443 -servername ${primaryHost} </dev/null`,
    ],
    validatePrimaryStatusForcedEdge: [
      "curl",
      "-sS",
      "--resolve",
      `${primaryHost}:443:${primaryAddress}`,
      `${primaryToriiUrl}/status`,
    ],
    validatePrimaryMcpForcedEdge: [
      "curl",
      "-sS",
      "--resolve",
      `${primaryHost}:443:${primaryAddress}`,
      "-H",
      "content-type: application/json",
      "--data",
      JSON.stringify({
        jsonrpc: "2.0",
        id: 1,
        method: "tools/list",
        params: {},
      }),
      primaryMcpUrl,
    ],
    smokePrimaryMcpRollout: [
      "bash",
      "../iroha/configs/soranexus/taira/check_mcp_rollout.sh",
      "--skip-local",
      "--public-root",
      primaryToriiUrl,
      "--skip-write-canary",
    ],
    smokePrimaryMcpRolloutForcedEdge: [
      "bash",
      "../iroha/configs/soranexus/taira/check_mcp_rollout.sh",
      "--skip-local",
      "--public-root",
      primaryToriiUrl,
      "--resolve-host",
      `${primaryHost}:443:${primaryAddress}`,
      "--skip-write-canary",
    ],
    refreshPublishReadinessAfterRepair: refreshPublishReadinessCommand,
  };
  return {
    schema: "iroha-demo-sccp-solana-taira-public-node-repair-plan/v1",
    ready: publicNodeCandidates?.ready === true,
    sourceFile: publicNodeCandidates?.sourceFile ?? null,
    primaryCandidate: primaryCandidate
      ? {
          host: primaryCandidate.host ?? null,
          expectedAddress: primaryCandidate.expectedAddress ?? null,
          toriiUrl: primaryToriiUrl,
          mcpUrl: primaryMcpUrl,
        }
      : null,
    blockerIds: Array.isArray(publicNodeCandidates?.blockerIds)
      ? publicNodeCandidates.blockerIds
      : [],
    requiredDnsRecords,
    requiredTlsSubjectAlternativeNames: hostnames,
    requiredNginxServerNames: hostnames,
    requiredOutcomes,
    candidates: candidates.map((candidate) => ({
      host: candidate.host ?? null,
      expectedAddress: candidate.expectedAddress ?? null,
      toriiUrl: candidate.toriiUrl ?? null,
      mcpUrl: candidate.mcpUrl ?? null,
      dnsReady: candidate.dnsReady === true,
      tlsReady: candidate.tlsReady === true,
      edgeStatusProbeReady: candidate.edgeStatusProbeReady === true,
      edgeStatusProbeHttpStatus: candidate.edgeStatusProbeHttpStatus ?? null,
      edgeStatusProbeError: candidate.edgeStatusProbeError ?? null,
      edgeMcpProbeReady: candidate.edgeMcpProbeReady === true,
      edgeMcpProbeHttpStatus: candidate.edgeMcpProbeHttpStatus ?? null,
      edgeMcpProbeError: candidate.edgeMcpProbeError ?? null,
      mcpReady: candidate.mcpTransactionTools?.ready === true,
      ready: candidate.ready === true,
    })),
    commands,
    operatorSequence: [
      "publish-direct-validator-dns-records",
      "refresh-edge-tls-certificate-san-list",
      "render-and-reload-taira-edge-nginx-config",
      "validate-forced-edge-status-and-mcp-routing",
      "run-mcp-rollout-smoke",
      "rerun-solana-route-publish-readiness-with-explicit-public-node",
    ],
    note: "This is an operator repair plan for the public TAIRA edge. It is read-only from this workstation and contains no signing secrets.",
  };
};

const classifyTairaPublicIngressHealth = ({
  args = {},
  publicPreflight = null,
  publicPreflightError = null,
  mcpTransactionTools = null,
} = {}) => {
  const target = resolveTairaRoutePublishTarget(args);
  const toriiUrl = target.toriiUrl;
  const mcpUrl = target.mcpUrl;
  const observedErrors = uniqueStrings(
    [
      publicPreflightError,
      ...(Array.isArray(publicPreflight?.checks)
        ? publicPreflight.checks
            .filter((check) => check?.status !== "pass")
            .map((check) => check?.detail)
        : []),
      mcpTransactionTools?.error,
    ]
      .map(compactTairaIngressError)
      .filter(Boolean),
  );
  const joined = observedErrors.join("\n");
  const degraded =
    /\bHTTP\s+(?:502|503)\b|502 Bad Gateway|503 Service Unavailable/iu.test(
      joined,
    );
  const timeout =
    /\btimeout|timed out|ETIMEDOUT|ECONNRESET|Could not resolve host|ENOTFOUND\b/iu.test(
      joined,
    );
  const unavailable = degraded || timeout || Boolean(publicPreflightError);
  return {
    status: degraded
      ? "degraded"
      : timeout
        ? "unreachable"
        : unavailable
          ? "unavailable"
          : publicPreflight?.ready === true
            ? "ready"
            : "unknown",
    degraded,
    unavailable,
    toriiUrl,
    mcpUrl,
    observedErrors,
    detail: degraded
      ? "Public TAIRA ingress returned HTTP 502/503; treat this as rollout or upstream health before debugging route-manifest content."
      : timeout
        ? "Public TAIRA ingress could not be reached from this runtime."
        : unavailable
          ? "Public TAIRA ingress did not return usable route-publish readiness data."
          : publicPreflight?.ready === true
            ? "Public TAIRA ingress is reachable for the current preflight."
            : "Public TAIRA ingress health is inconclusive from the current preflight.",
    operatorAction: degraded
      ? "Run the TAIRA MCP rollout smoke against the exact public root and inspect nginx upstream routing before attempting route publication."
      : "Rerun route publish readiness after the public TAIRA root is reachable and MCP route checks can complete.",
    diagnosticCommands: [
      ["curl", "-vI", toriiUrl],
      ["curl", "-sS", mcpUrl || tairaMcpUrlFromToriiRoot(toriiUrl)],
      [
        "bash",
        "../iroha/configs/soranexus/taira/check_mcp_rollout.sh",
        "--skip-local",
        "--public-root",
        toriiUrl,
        "--skip-write-canary",
      ],
    ],
  };
};

const routeAlreadyPublicStatus = (
  publicPreflight,
  { expectedManifestCanonicalSha256 = null } = {},
) => {
  const checks = Array.isArray(publicPreflight?.checks)
    ? publicPreflight.checks
    : [];
  const byId = new Map(checks.map((check) => [check.id, check]));
  const requiredChecks = [
    "public-route-publication",
    "solana-lane-publication",
    "solana-route-instance-publication",
    "route-manifest-shape",
  ];
  const publicationChecks = requiredChecks.map((id) => {
    const check = byId.get(id) ?? null;
    return {
      id,
      status: check?.status ?? "missing",
      detail: check?.detail ?? null,
    };
  });
  const observedManifestCanonicalSha256 =
    byId.get("route-manifest-shape")?.evidence?.manifestCanonicalSha256 ?? null;
  const exactManifestMatches = Boolean(
    expectedManifestCanonicalSha256 &&
      observedManifestCanonicalSha256 === expectedManifestCanonicalSha256,
  );
  const genericPublished = publicationChecks.every(
    (check) => check.status === "pass",
  );
  return {
    published: genericPublished && exactManifestMatches,
    genericPublished,
    publicationChecks,
    expectedManifestCanonicalSha256,
    observedManifestCanonicalSha256,
    exactManifestMatches,
  };
};

