const stableSolanaLaneBlockerId = (reason) => {
  const text = typeof reason === "string" ? reason.trim() : "";
  if (!text) {
    return "";
  }
  const known = SOLANA_LANE_BLOCKER_ID_BY_REASON.get(text);
  if (known) {
    return known;
  }
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/gu, "-")
    .replace(/^-+|-+$/gu, "")
    .slice(0, 96);
};

const summarizeSolanaLaneBlockerDetails = (reasons) => {
  const details = [];
  const seenIds = new Set();
  for (const reason of reasons) {
    const detail = typeof reason === "string" ? reason.trim() : "";
    const id = stableSolanaLaneBlockerId(detail);
    if (!id || seenIds.has(id)) {
      continue;
    }
    seenIds.add(id);
    details.push({ id, detail });
  }
  return details;
};

const normalizeSolanaLaneBlockerEntries = (entries) => {
  const details = [];
  const seenIds = new Set();
  for (const entry of Array.isArray(entries) ? entries : []) {
    const rawId = typeof entry === "string" ? entry : entry?.id;
    const rawDetail = typeof entry === "string" ? entry : entry?.detail;
    const detail =
      typeof rawDetail === "string" && rawDetail.trim()
        ? rawDetail.trim()
        : typeof rawId === "string"
          ? rawId.trim()
          : "";
    const idCandidate =
      typeof rawId === "string" && rawId.trim() ? rawId.trim() : detail;
    const id = stableSolanaLaneBlockerId(idCandidate);
    if (!id || seenIds.has(id)) {
      continue;
    }
    seenIds.add(id);
    details.push({ id, detail });
  }
  return details;
};

const publicSolanaLaneStatus = (publicPreflight) => {
  const lane = publicPreflight?.publicSolanaLane ?? null;
  const laneCheck = Array.isArray(publicPreflight?.checks)
    ? publicPreflight.checks.find(
        (check) => check?.id === "solana-lane-publication",
      )
    : null;
  const laneCheckEvidence = isRecord(laneCheck?.evidence)
    ? laneCheck.evidence
    : null;
  const fallbackBlockerDetails = summarizeSolanaLaneBlockerDetails([
    ...(Array.isArray(lane?.destinationRollout?.blockers)
      ? lane.destinationRollout.blockers
      : []),
    ...(Array.isArray(lane?.productionReadiness?.blockers)
      ? lane.productionReadiness.blockers
      : []),
    ...(Array.isArray(lane?.sourceAdapterEngine?.blockers)
      ? lane.sourceAdapterEngine.blockers
      : []),
    ...(Array.isArray(lane?.routeAllowlist?.blockers)
      ? lane.routeAllowlist.blockers
      : []),
  ]);
  const evidenceBlockerDetails = normalizeSolanaLaneBlockerEntries(
    Array.isArray(laneCheckEvidence?.blockerDetails) &&
      laneCheckEvidence.blockerDetails.length > 0
      ? laneCheckEvidence.blockerDetails
      : laneCheckEvidence?.blockerIds,
  );
  const normalizedBlockerIds =
    evidenceBlockerDetails.length > 0
      ? evidenceBlockerDetails.map((entry) => entry.id)
      : fallbackBlockerDetails.map((entry) => entry.id);
  const normalizedBlockerDetails =
    evidenceBlockerDetails.length > 0
      ? evidenceBlockerDetails
      : fallbackBlockerDetails;
  return {
    present: isRecord(lane),
    ready: laneCheck?.status === "pass",
    check: laneCheck
      ? {
          status: laneCheck.status ?? null,
          detail: laneCheck.detail ?? null,
        }
      : null,
    lane,
    blockerIds: uniqueStrings(normalizedBlockerIds),
    blockerDetails: normalizedBlockerDetails,
  };
};

const isImmutableSolanaProgramEvidence = (evidence) => {
  if (evidence?.schema === SOLANA_FINALIZED_READBACK_EVIDENCE_SCHEMA) {
    return SOLANA_FINALIZED_READBACK_ROLE_SPECS.every(
      (spec) =>
        evidence.snapshot?.roles?.[spec.role]?.loaderV3?.immutable === true &&
        evidence.snapshot?.roles?.[spec.role]?.loaderV3
          ?.upgradeAuthorityAddress === null,
    );
  }
  return (
    evidence?.schema === SOLANA_FINALIZED_READBACK_ROLE_EVIDENCE_SCHEMA &&
    evidence.authority === "none" &&
    evidence.raw?.immutable === true
  );
};

export const solanaProgramDeploymentModeLabel = (evidence) => {
  if (!isRecord(evidence)) {
    return "unverified";
  }
  return isImmutableSolanaProgramEvidence(evidence)
    ? "immutable"
    : "upgradeable staging";
};

const isUpgradeableProgramLiveEvidenceError = (error) =>
  /Solana verifier program must be immutable; upgrade authority is still set/iu.test(
    error instanceof Error ? error.message : String(error),
  );

export const buildUpgradeableSolanaDraftLiveEvidence = ({
  publicConfig,
  verifierEvidence,
  liveReadback = null,
  error,
  checkedAt = new Date().toISOString(),
}) => {
  const parsedProgram = liveReadback?.parsedProgram ?? null;
  const parsedProgramdata = liveReadback?.parsedProgramdata ?? null;
  const outerEvidence = outerVerifierEvidenceFacts(verifierEvidence);
  const programdataAddress =
    parsedProgram?.programdataAddress ??
    outerEvidence.programDataAddress ??
    null;
  const programdataSlot =
    parsedProgramdata?.slot ?? outerEvidence.programDataSlot ?? null;
  const upgradeAuthority =
    parsedProgramdata?.upgradeAuthorityAddress ??
    solanaFinalizedReadbackRole(verifierEvidence, "outerVerifier")?.loaderV3
      ?.upgradeAuthorityAddress ??
    null;
  const verifierCodeHash = parsedProgramdata?.executableBlake2b256 ?? null;
  const verifierCodeSha256 = parsedProgramdata?.executableSha256 ?? null;
  return {
    schema: "iroha-demo-sccp-solana-upgradeable-draft-live-evidence/v1",
    checkedAt,
    ready: false,
    verifier_program_id: publicConfig?.verifierProgramId ?? null,
    verifierProgramId: publicConfig?.verifierProgramId ?? null,
    programdata_address: programdataAddress,
    programdataAddress,
    programdata_slot: programdataSlot,
    programdataSlot,
    programdata_account_context_slot:
      liveReadback?.programdata?.contextSlot ?? null,
    programdataAccountContextSlot:
      liveReadback?.programdata?.contextSlot ?? null,
    immutable_verifier_ready: false,
    immutableVerifierReady: false,
    upgradeable: true,
    upgrade_authority: upgradeAuthority,
    upgradeAuthority,
    production_ready: false,
    productionReady: false,
    ...(verifierCodeHash
      ? {
          verifier_code_hash: verifierCodeHash,
          verifierCodeHash,
          programdata_executable_blake2b256: verifierCodeHash,
          programdataExecutableBlake2b256: verifierCodeHash,
        }
      : {}),
    ...(verifierCodeSha256
      ? {
          programdata_executable_sha256: verifierCodeSha256,
          programdataExecutableSha256: verifierCodeSha256,
        }
      : {}),
    blockerIds: ["solana-verifier-programdata-mutable"],
    blockers: [
      {
        id: "solana-verifier-programdata-mutable",
        detail:
          "Solana verifier ProgramData still has an upgrade authority. Link the native recursive verifier first, then finalize the program before production route publication.",
      },
    ],
    error: error instanceof Error ? error.message : String(error),
    disabled_reason:
      "Solana verifier program is deployed as upgradeable staging evidence; production route publication requires an immutable verifier after native recursive proof material is linked.",
    disabledReason:
      "Solana verifier program is deployed as upgradeable staging evidence; production route publication requires an immutable verifier after native recursive proof material is linked.",
  };
};

export const buildTairaMcpTransactionToolStatus = ({
  mcpUrl = DEFAULT_TAIRA_MCP_URL,
  toolsPayload = null,
  capabilitiesPayload = null,
  error = null,
} = {}) => {
  const capabilities = isRecord(capabilitiesPayload)
    ? {
        ready: true,
        protocolVersion:
          typeof capabilitiesPayload.protocolVersion === "string"
            ? capabilitiesPayload.protocolVersion
            : null,
        serverName:
          typeof capabilitiesPayload.serverInfo?.name === "string"
            ? capabilitiesPayload.serverInfo.name
            : null,
        serverVersion:
          typeof capabilitiesPayload.serverInfo?.version === "string"
            ? capabilitiesPayload.serverInfo.version
            : null,
        toolCount: Number.isFinite(
          capabilitiesPayload.capabilities?.tools?.count,
        )
          ? capabilitiesPayload.capabilities.tools.count
          : null,
        toolsetVersion:
          typeof capabilitiesPayload.capabilities?.tools?.toolsetVersion ===
          "string"
            ? capabilitiesPayload.capabilities.tools.toolsetVersion
            : null,
        listChanged:
          typeof capabilitiesPayload.capabilities?.tools?.listChanged ===
          "boolean"
            ? capabilitiesPayload.capabilities.tools.listChanged
            : null,
      }
    : null;
  const toolRecords = Array.isArray(toolsPayload?.result?.tools)
    ? toolsPayload.result.tools.filter(isRecord)
    : [];
  const toolNames = toolRecords
    .map((tool) => (typeof tool?.name === "string" ? tool.name : ""))
    .filter(Boolean);
  const toolsByName = new Map(toolRecords.map((tool) => [tool.name, tool]));
  const presentTools = ROUTE_PUBLISH_MCP_TRANSACTION_TOOLS.filter((tool) =>
    toolNames.includes(tool),
  );
  const missingTools = ROUTE_PUBLISH_MCP_TRANSACTION_TOOLS.filter(
    (tool) => !toolNames.includes(tool),
  );
  const signedTransactionSchemas = ROUTE_PUBLISH_MCP_TRANSACTION_TOOLS.map(
    (toolName) => {
      const tool = toolsByName.get(toolName);
      const inputSchema = isRecord(tool?.inputSchema) ? tool.inputSchema : null;
      const properties = isRecord(inputSchema?.properties)
        ? inputSchema.properties
        : {};
      const bodyBase64 = isRecord(properties.body_base64)
        ? properties.body_base64
        : null;
      return {
        tool: toolName,
        present: Boolean(tool),
        bodyBase64Required:
          Array.isArray(inputSchema?.required) &&
          inputSchema.required.includes("body_base64"),
        bodyBase64Type:
          typeof bodyBase64?.type === "string" ? bodyBase64.type : null,
        additionalProperties:
          typeof inputSchema?.additionalProperties === "boolean"
            ? inputSchema.additionalProperties
            : null,
      };
    },
  );
  const signedTransactionSchemaReady = signedTransactionSchemas.every(
    (schema) =>
      schema.present &&
      schema.bodyBase64Required &&
      schema.bodyBase64Type === "string",
  );
  const dedicatedRouteManifestTools = toolNames
    .filter((name) => ROUTE_PUBLISH_MCP_DEDICATED_TOOL_RE.test(name))
    .sort();
  const readOnlyManifestTools = toolNames
    .filter(
      (name) =>
        /manifest/iu.test(name) && !dedicatedRouteManifestTools.includes(name),
    )
    .sort();
  const ready =
    !error && missingTools.length === 0 && signedTransactionSchemaReady;
  return {
    mcpUrl,
    ready,
    error: error ? String(error) : null,
    capabilities,
    toolCount: toolNames.length,
    requiredTools: ROUTE_PUBLISH_MCP_TRANSACTION_TOOLS,
    presentTools,
    missingTools,
    publicationMode: "signed-transaction-body-base64",
    signedTransactionSubmission: {
      ready: signedTransactionSchemaReady,
      schemas: signedTransactionSchemas,
    },
    dedicatedRouteManifestTools,
    readOnlyManifestTools,
    note:
      dedicatedRouteManifestTools.length > 0
        ? "Dedicated route-manifest tools are present, but this deployment still uses signed transaction submission."
        : "No dedicated route-manifest publish tool is exposed; publication uses signed transaction body_base64 submission.",
  };
};

export const fetchTairaMcpTransactionToolStatus = async (
  mcpUrl,
  fetchOptions = {},
) => {
  let capabilitiesPayload = null;
  try {
    const text = await fetchTextWithRetry(mcpUrl, {
      ...fetchOptions,
      method: "POST",
      headers: {
        ...(fetchOptions.headers ?? {}),
        accept: "application/json, text/event-stream",
        "content-type": "application/json",
      },
      body: JSON.stringify({
        jsonrpc: "2.0",
        id: 1,
        method: "tools/list",
        params: {},
      }),
    });
    const payload = parseTairaMcpJsonRpcResponseText(text) ?? {};
    if (payload.error) {
      throw new Error(payload.error.message ?? JSON.stringify(payload.error));
    }
    return buildTairaMcpTransactionToolStatus({
      mcpUrl,
      toolsPayload: payload,
    });
  } catch (error) {
    try {
      const capabilityTimeoutMs = Math.max(
        Number(fetchOptions.timeoutMs ?? 0) || 0,
        TAIRA_MCP_CAPABILITIES_FALLBACK_TIMEOUT_MS,
      );
      const capabilitiesText = await fetchTextWithRetry(mcpUrl, {
        ...fetchOptions,
        timeoutMs: capabilityTimeoutMs,
        attempts: 1,
        method: "GET",
        headers: {
          ...(fetchOptions.headers ?? {}),
          accept: "application/json",
        },
      });
      capabilitiesPayload = capabilitiesText
        ? JSON.parse(capabilitiesText)
        : {};
    } catch {
      capabilitiesPayload = null;
    }
    return buildTairaMcpTransactionToolStatus({
      mcpUrl,
      capabilitiesPayload,
      error: error instanceof Error ? error.message : String(error),
    });
  }
};

export const buildTairaRouteManagerPermissionStatus = ({
  authority = "",
  mcpUrl = DEFAULT_TAIRA_MCP_URL,
  permissionsPayload = null,
  error = null,
} = {}) => {
  const normalizedAuthority = typeof authority === "string" ? authority : "";
  const checked =
    Boolean(normalizedAuthority) &&
    !isPlaceholderRouteAuthority(normalizedAuthority) &&
    isCanonicalTairaRouteAuthority(normalizedAuthority);
  const permissions =
    !checked || error ? [] : permissionNamesFromPayload(permissionsPayload);
  const hasRequiredPermission = permissions.includes(
    TAIRA_ROUTE_MANIFEST_PERMISSION,
  );
  return {
    mcpUrl,
    authority: normalizedAuthority || null,
    checked,
    ready: checked && !error && hasRequiredPermission,
    requiredPermission: TAIRA_ROUTE_MANIFEST_PERMISSION,
    hasRequiredPermission,
    permissions,
    error: error ? String(error) : null,
  };
};

const fetchTairaRouteManagerPermissionStatus = async ({
  mcpUrl,
  authority,
  fetchOptions = {},
}) => {
  if (!authority || !isConcreteTairaRouteAuthority(authority)) {
    return buildTairaRouteManagerPermissionStatus({ mcpUrl, authority });
  }
  try {
    const text = await fetchTextWithRetry(mcpUrl, {
      ...fetchOptions,
      method: "POST",
      headers: {
        ...(fetchOptions.headers ?? {}),
        accept: "application/json, text/event-stream",
        "content-type": "application/json",
      },
      body: JSON.stringify({
        jsonrpc: "2.0",
        id: 1,
        method: "tools/call",
        params: {
          name: "iroha.accounts.permissions",
          arguments: {
            account_id: authority,
          },
        },
      }),
    });
    const payload = parseTairaMcpJsonRpcResponseText(text) ?? {};
    if (payload.error) {
      throw new Error(payload.error.message ?? JSON.stringify(payload.error));
    }
    return buildTairaRouteManagerPermissionStatus({
      mcpUrl,
      authority,
      permissionsPayload: payload,
    });
  } catch (error) {
    return buildTairaRouteManagerPermissionStatus({
      mcpUrl,
      authority,
      error: error instanceof Error ? error.message : String(error),
    });
  }
};

const routeManagerAuthorityEnvName = (args = {}) =>
  normalizeRuntimeSecretEnvName(
    args["authority-env"],
    DEFAULT_TAIRA_ROUTE_MANIFEST_AUTHORITY_ENV,
  );

const routeManagerPrivateKeyEnvName = (args = {}) =>
  normalizeRuntimeSecretEnvName(
    args["private-key-env"],
    DEFAULT_TAIRA_ROUTE_MANIFEST_PRIVATE_KEY_ENV,
  );

const hasNonEmptyEnvValue = (name) =>
  typeof process.env[name] === "string" && process.env[name].trim().length > 0;

const resolveRouteManagerAuthority = (args = {}) => {
  if (typeof args.authority === "string" && args.authority.trim()) {
    return args.authority.trim();
  }
  const envName = routeManagerAuthorityEnvName(args);
  const envAuthority = process.env[envName];
  return typeof envAuthority === "string" ? envAuthority.trim() : "";
};

const isPlaceholderRouteAuthority = (authority) =>
  !authority ||
  /[<>]/u.test(authority) ||
  /route[-_]manager[-_]account[-_]id/iu.test(authority);

const isCanonicalTairaRouteAuthority = (authority) => {
  if (
    typeof authority !== "string" ||
    authority !== authority.trim() ||
    isPlaceholderRouteAuthority(authority)
  ) {
    return false;
  }
  try {
    const canonical = AccountAddress.fromAccountId(
      authority,
      TAIRA_NETWORK_PREFIX,
    ).toI105(TAIRA_NETWORK_PREFIX);
    return canonical === authority && authority.startsWith("testu");
  } catch (_error) {
    return false;
  }
};

const isConcreteTairaRouteAuthority = (authority) =>
  isCanonicalTairaRouteAuthority(authority);

export const buildSolanaRoutePublishReadinessReportBody = ({
  args = {},
  productionRequirements: requirementsReport = null,
  publicPreflight = null,
  publicPreflightPath = null,
  publicPreflightError = null,
  isiArtifact = null,
  isiPath = null,
  isiArtifactSha256 = null,
  manifestArtifactPath = null,
  manifestArtifactSha256 = null,
  manifestCanonicalSha256 = null,
  isiError = null,
  mcpTransactionTools = null,
  authorityPermission = null,
  publicNodeCandidates = null,
  checkedAt = new Date().toISOString(),
  privateKeyEnvPresent = undefined,
} = {}) => {
  const privateKeyEnv = routeManagerPrivateKeyEnvName(args);
  const authorityEnv = routeManagerAuthorityEnvName(args);
  const explicitAuthority =
    typeof args.authority === "string" && args.authority.trim();
  const authorityEnvPresent =
    !explicitAuthority && hasNonEmptyEnvValue(authorityEnv);
  const authority = resolveRouteManagerAuthority(args);
  const authorityFormatReady = isConcreteTairaRouteAuthority(authority);
  const authorityReady = authorityFormatReady;
  const resolvedPrivateKeyEnvPresent =
    privateKeyEnvPresent ?? Boolean(process.env[privateKeyEnv]);
  const routePublishTarget = resolveTairaRoutePublishTarget(args);
  const endpoint = routePublishEndpointStatus(publicPreflight);
  const publicIngressHealth = classifyTairaPublicIngressHealth({
    args,
    publicPreflight,
    publicPreflightError,
    mcpTransactionTools,
  });
  const selectedIsiManifest =
    isiArtifact?.instruction?.UpsertSccpRouteManifest?.manifest ?? null;
  const derivedManifestCanonicalSha256 = selectedIsiManifest
    ? solanaRouteManifestCanonicalSha256(selectedIsiManifest)
    : null;
  const expectedManifestCanonicalSha256 =
    manifestCanonicalSha256 ?? derivedManifestCanonicalSha256;
  let independentlyPinnedManifestArtifactSha256 = null;
  try {
    independentlyPinnedManifestArtifactSha256 =
      args["expected-manifest-sha256"] === undefined
        ? null
        : normalizeExpectedSolanaUpgradePlanSha256(
            args["expected-manifest-sha256"],
            "expected reviewed Solana route manifest SHA-256",
          );
  } catch {
    independentlyPinnedManifestArtifactSha256 = null;
  }
  const isiBindingReady =
    isRecord(isiArtifact) &&
    /^0x[0-9a-f]{64}$/u.test(isiArtifactSha256 ?? "") &&
    isiArtifactSha256 === sha256JsonHex(isiArtifact) &&
    typeof manifestArtifactPath === "string" &&
    manifestArtifactPath.length > 0 &&
    /^0x[0-9a-f]{64}$/u.test(manifestArtifactSha256 ?? "") &&
    manifestArtifactSha256 === independentlyPinnedManifestArtifactSha256 &&
    expectedManifestCanonicalSha256 === derivedManifestCanonicalSha256;
  const alreadyPublic = routeAlreadyPublicStatus(publicPreflight, {
    expectedManifestCanonicalSha256,
  });
  const publicSolanaLane = publicSolanaLaneStatus(publicPreflight);
  const mcpTransactionToolsReady =
    isRecord(mcpTransactionTools) && mcpTransactionTools.ready === true;
  const defaultPresetPublicationReady =
    routePublishTarget.defaultConvenienceRoot === true &&
    routePublishTarget.defaultConvenienceMcp === true &&
    endpoint.ready === true &&
    mcpTransactionToolsReady;
  const routePublicationTargetReady =
    routePublishTarget.canonicalRolloutTargetReady === true;
  const endpointCommandArgs = routePublishEndpointCommandArgs(
    routePublishTarget,
    {
      includeMissingPlaceholders: !routePublicationTargetReady,
    },
  );
  const reviewedManifestCommandArgs = solanaRouteManifestSelectionCommandArgs({
    manifestArtifactPath,
    manifestArtifactSha256: independentlyPinnedManifestArtifactSha256,
  });
  const refreshPublishReadinessCommand = solanaDeployCommandWithRouteAuthority({
    command: "publish-readiness",
    commandArgs: [...reviewedManifestCommandArgs, ...endpointCommandArgs],
    authority,
    authorityEnv,
  });
  const explicitPublicNodeRepairPlan = tairaPublicNodeRepairPlan({
    publicNodeCandidates,
    refreshPublishReadinessCommand,
  });
  const authorityPermissionReady =
    authorityReady &&
    isRecord(authorityPermission) &&
    authorityPermission.ready === true;
  const requirementsReady = requirementsReport?.readyToBuildIsi === true;
  const productionRequirementBlockerIds = Array.isArray(
    requirementsReport?.blockers,
  )
    ? requirementsReport.blockers.map((blocker) => blocker.id)
    : [];
  const routeManifestIsiBlockedByProductionRequirements = !requirementsReady;
  const rawRouteManifestIsiArtifactReady =
    isRecord(isiArtifact) &&
    isiArtifact.schema === "iroha-sccp-route-manifest-isi/v1" &&
    isiArtifact.routeId === SCCP_SOLANA_XOR_ROUTE_ID &&
    isiArtifact.assetKey === SCCP_XOR_ASSET_KEY &&
    isiArtifact.productionReady === true;
  const routeManifestIsiReady =
    requirementsReady && rawRouteManifestIsiArtifactReady && isiBindingReady;
  const routeManifestIsiBlockedBy =
    routeManifestIsiBlockedByProductionRequirements
      ? uniqueStrings([
          "production-requirements",
          ...productionRequirementBlockerIds,
        ])
      : [];
  const routeManifestIsiError = routeManifestIsiReady
    ? null
    : routeManifestIsiBlockedByProductionRequirements
      ? "Route-manifest ISI generation is intentionally withheld until Solana production requirements pass."
      : rawRouteManifestIsiArtifactReady && !isiBindingReady
        ? "The production route-manifest ISI is not bound to the independently pinned exact manifest bytes and in-memory ISI object."
        : isiError ||
          "A production UpsertSccpRouteManifest ISI artifact is not available.";
  const blockers = [];
  if (!requirementsReady) {
    blockers.push({
      id: "production-requirements",
      detail:
        "Solana route manifest cannot be submitted until production requirements pass.",
      blockers: productionRequirementBlockerIds,
    });
  }
  if (!endpoint.ready) {
    blockers.push({
      id: "taira-public-endpoint",
      detail:
        publicIngressHealth.degraded === true
          ? publicIngressHealth.detail
          : publicPreflightError ||
            "TAIRA public endpoint does not expose the SCCP capabilities required for route publication.",
      failingChecks: endpoint.failingChecks,
      ingressHealth: publicIngressHealth.status,
    });
  }
  if (
    !routePublicationTargetReady &&
    endpoint.ready === true &&
    mcpTransactionToolsReady
  ) {
    blockers.push({
      id: "taira-explicit-public-node-target",
      detail:
        "Route publication readiness requires an explicit TAIRA public-node root and MCP URL; the convenience taira.sora.org preset is read-only diagnostic evidence for production rollout.",
      targetKind: routePublishTarget.targetKind,
      toriiUrlSource: routePublishTarget.toriiUrlSource,
      mcpUrlSource: routePublishTarget.mcpUrlSource,
      requiredArguments: routePublishTarget.requiredArguments,
      candidateAudit: isRecord(publicNodeCandidates)
        ? {
            ready: publicNodeCandidates.ready === true,
            candidateCount: publicNodeCandidates.candidateCount ?? null,
            dnsReadyCount: publicNodeCandidates.dnsReadyCount ?? null,
            tlsReadyCount: publicNodeCandidates.tlsReadyCount ?? null,
            edgeStatusProbeReadyCount:
              publicNodeCandidates.edgeStatusProbeReadyCount ?? null,
            edgeMcpProbeReadyCount:
              publicNodeCandidates.edgeMcpProbeReadyCount ?? null,
            mcpReadyCount: publicNodeCandidates.mcpReadyCount ?? null,
            blockerIds: Array.isArray(publicNodeCandidates.blockerIds)
              ? publicNodeCandidates.blockerIds
              : [],
          }
        : null,
      repairPlan: {
        schema: explicitPublicNodeRepairPlan.schema,
        ready: explicitPublicNodeRepairPlan.ready,
        primaryCandidate: explicitPublicNodeRepairPlan.primaryCandidate,
        requiredOutcomes: explicitPublicNodeRepairPlan.requiredOutcomes.map(
          (outcome) => ({
            id: outcome.id,
            ready: outcome.ready,
          }),
        ),
        operatorSequence: explicitPublicNodeRepairPlan.operatorSequence,
      },
    });
  }
  if (!mcpTransactionToolsReady) {
    blockers.push({
      id: "taira-mcp-transaction-tools",
      detail: isRecord(mcpTransactionTools)
        ? "TAIRA MCP must expose iroha.transactions.submit and iroha.transactions.submit_and_wait before route publication."
        : "TAIRA MCP transaction-tool audit is missing; route publication requires an explicit iroha.transactions submit/readiness check.",
      missingTools: Array.isArray(mcpTransactionTools?.missingTools)
        ? mcpTransactionTools.missingTools
        : ROUTE_PUBLISH_MCP_TRANSACTION_TOOLS,
      error: mcpTransactionTools?.error ?? null,
    });
  }
  if (!alreadyPublic.published && !routeManifestIsiReady) {
    blockers.push({
      id: "route-manifest-isi",
      detail: routeManifestIsiError,
      blockedBy: routeManifestIsiBlockedBy,
      artifactReady: rawRouteManifestIsiArtifactReady,
      exactByteBindingReady: isiBindingReady,
    });
  }
  if (!alreadyPublic.published && !authorityReady) {
    blockers.push({
      id: "route-manager-authority",
      detail: `${authorityEnv} or --authority must name a real TAIRA testnet I105 account starting with testu and holding ${TAIRA_ROUTE_MANIFEST_PERMISSION}.`,
      authority: authority || null,
      expectedPrefix: "testu",
    });
  }
  if (!alreadyPublic.published && authorityReady && !authorityPermissionReady) {
    blockers.push({
      id: "route-manager-permission",
      detail: isRecord(authorityPermission)
        ? `The route-manager authority must hold ${TAIRA_ROUTE_MANIFEST_PERMISSION}.`
        : `Route-manager permission audit is missing; the authority must be checked for ${TAIRA_ROUTE_MANIFEST_PERMISSION}.`,
      requiredPermission: TAIRA_ROUTE_MANIFEST_PERMISSION,
      hasRequiredPermission:
        authorityPermission?.hasRequiredPermission === true,
      error: authorityPermission?.error ?? null,
    });
  }
  if (!alreadyPublic.published && !resolvedPrivateKeyEnvPresent) {
    blockers.push({
      id: "runtime-signing-key",
      detail: `${privateKeyEnv} is not set in the current runtime.`,
    });
  }
  const readyForRuntimeSigner =
    requirementsReady &&
    routePublicationTargetReady &&
    endpoint.ready &&
    mcpTransactionToolsReady &&
    authorityReady &&
    authorityPermissionReady &&
    routeManifestIsiReady;
  const publicationSatisfied = alreadyPublic.published;
  const submissionRequired = !publicationSatisfied;
  const commands = {
    refreshPublishReadiness: refreshPublishReadinessCommand,
    refreshPreflight: [
      "npm",
      "run",
      "e2e:sccp:solana-preflight",
      "--",
      "--allow-incomplete",
      "true",
      ...routePreflightEndpointCommandArgs(routePublishTarget, {
        includeMissingPlaceholders: !routePublicationTargetReady,
      }),
    ],
    productionRequirements: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "production-requirements",
    ],
    routeManifestIsi: [
      "npm",
      "run",
      "sccp:solana:deploy",
      "--",
      "route-manifest-isi",
      ...reviewedManifestCommandArgs,
    ],
    routeManagerAccessRequest: solanaDeployCommandWithRouteAuthority({
      command: "route-manager-access-request",
      commandArgs: [...reviewedManifestCommandArgs, ...endpointCommandArgs],
      authority,
      authorityEnv,
    }),
    publishRouteManifest: solanaDeployCommandWithRouteAuthority({
      command: "publish-route-manifest",
      commandArgs: [
        "--submit",
        "true",
        ...reviewedManifestCommandArgs,
        ...endpointCommandArgs,
      ],
      authority,
      authorityEnv,
      privateKeyEnv,
    }),
    repairTairaPublicNodeRenderNginx:
      explicitPublicNodeRepairPlan.commands.renderEdgeNginxCandidate,
    repairTairaPublicNodeValidateDns:
      explicitPublicNodeRepairPlan.commands.validatePrimaryDns,
    repairTairaPublicNodeValidateTls:
      explicitPublicNodeRepairPlan.commands.validatePrimaryTls,
    repairTairaPublicNodeValidateStatus:
      explicitPublicNodeRepairPlan.commands.validatePrimaryStatusForcedEdge,
    repairTairaPublicNodeValidateMcp:
      explicitPublicNodeRepairPlan.commands.validatePrimaryMcpForcedEdge,
    repairTairaPublicNodeSmokeMcp:
      explicitPublicNodeRepairPlan.commands.smokePrimaryMcpRollout,
    repairTairaPublicNodeSmokeMcpForcedEdge:
      explicitPublicNodeRepairPlan.commands.smokePrimaryMcpRolloutForcedEdge,
  };
  const readyToSubmitWithCurrentRuntime =
    submissionRequired &&
    readyForRuntimeSigner &&
    authorityReady &&
    authorityPermissionReady &&
    resolvedPrivateKeyEnvPresent;
  const ready = publicationSatisfied || readyToSubmitWithCurrentRuntime;
  const activeBlockers = publicationSatisfied ? [] : blockers;
  const diagnosticBlockers = publicationSatisfied ? blockers : [];
  const requiredPublicationAction = {
    kind: "UpsertSccpRouteManifest",
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    network: "taira-testnet",
    routeManifestIsiReady,
    routeManifestIsiPath: isiPath,
    isiArtifactSha256,
    manifestArtifactPath,
    manifestArtifactSha256,
    manifestCanonicalSha256: expectedManifestCanonicalSha256,
    manifestSha256: isiArtifact?.manifestSha256 ?? null,
    instructionManifestSha256: isiArtifact?.instructionManifestSha256 ?? null,
    publicationMode:
      mcpTransactionTools?.publicationMode ?? "signed-transaction-body-base64",
    requiredPermission: TAIRA_ROUTE_MANIFEST_PERMISSION,
    authority: authority || null,
    authorityEnv,
    authorityReady,
    authorityPermissionReady,
    publicationSatisfied,
    submissionRequired,
    runtimeSigningRequired: submissionRequired,
    privateKeyEnv,
    privateKeyEnvPresent: resolvedPrivateKeyEnvPresent,
    privateKeyStoredInReport: false,
    readyForRuntimeSigner,
    readyToSubmitWithCurrentRuntime,
  };
  const publishReadinessActionForBlocker = (blockerId) => {
    switch (blockerId) {
      case "production-requirements":
        return "complete-production-requirements";
      case "taira-public-endpoint":
      case "taira-mcp-transaction-tools":
        return "refresh-taira-route-publish-preflight";
      case "taira-explicit-public-node-target":
        return "provide-explicit-taira-public-node-target";
      case "route-manifest-isi":
        return requirementsReady
          ? "build-production-route-manifest-isi"
          : "complete-production-requirements";
      case "route-manager-authority":
      case "route-manager-permission":
        return "grant-taira-route-manager-access";
      case "runtime-signing-key":
        return "set-runtime-route-manager-private-key";
      default:
        return blockerId;
    }
  };
  const nextActions = uniqueStrings(
    activeBlockers.map((blocker) =>
      publishReadinessActionForBlocker(blocker.id),
    ),
  );
  const governedProofMaterialDelegatedActions =
    delegatedActionDetailsFromReports(requirementsReport);
  const explicitPublicNodeDelegatedActions = [
    {
      id: "publish-direct-validator-dns-records",
      title: "Publish direct validator DNS records",
      detail:
        "Create or repair the taira-validator-N.sora.org A records so every direct public-node hostname resolves to the shared TAIRA edge IP.",
      command: commands.repairTairaPublicNodeValidateDns,
      requiredInputs: ["taira-edge-dns-zone-access"],
    },
    {
      id: "refresh-edge-tls-certificate-san-list",
      title: "Refresh edge TLS SAN certificate",
      detail:
        "Issue or refresh the edge TLS certificate so SNI validation succeeds for the direct validator hostnames.",
      command: commands.repairTairaPublicNodeValidateTls,
      requiredInputs: ["taira-edge-tls-acme-access"],
    },
    {
      id: "render-and-reload-taira-edge-nginx-config",
      title: "Render and reload TAIRA edge nginx",
      detail:
        "Render the checked-in TAIRA edge nginx config on the edge host, install it after review, and reload nginx.",
      command: commands.repairTairaPublicNodeRenderNginx,
      validationCommands: [
        commands.repairTairaPublicNodeValidateStatus,
        commands.repairTairaPublicNodeValidateMcp,
      ],
      requiredInputs: ["taira-edge-shell-access"],
    },
    {
      id: "run-mcp-rollout-smoke",
      title: "Run MCP rollout smoke",
      detail:
        "Run the TAIRA MCP rollout smoke against the explicit public-node root before attempting Solana route publication.",
      command: commands.repairTairaPublicNodeSmokeMcp,
      validationCommands: [
        commands.repairTairaPublicNodeSmokeMcpForcedEdge,
        commands.refreshPublishReadiness,
      ],
    },
  ];
  const nextActionDetails = buildActionDetails({
    nextActions,
    blockers: activeBlockers,
    blockerToAction: publishReadinessActionForBlocker,
    commands,
    definitions: {
      "complete-production-requirements": {
        title: "Complete production requirements",
        detail:
          "Rebuild the Solana production requirements after governed proof material and prover sidecars are available.",
        commandKey: "productionRequirements",
        requiredInputs: defaultSolanaRequiredProductionInputIds(),
        validationCommandKeys: ["productionRequirements", "routeManifestIsi"],
        delegatedActions: governedProofMaterialDelegatedActions,
      },
      "refresh-taira-route-publish-preflight": {
        title: "Refresh TAIRA route-publish preflight",
        detail:
          "Recheck the public TAIRA SCCP endpoint and MCP transaction submission tools.",
        commandKey: "refreshPreflight",
      },
      "provide-explicit-taira-public-node-target": {
        title: "Provide explicit TAIRA public node",
        detail:
          "Repair and use the exact TAIRA public-node root and matching /v1/mcp endpoint for route publication readiness instead of the convenience preset.",
        commandKey: "refreshPublishReadiness",
        requiredInputs: [
          {
            id: "taira-public-node-root-url",
            kind: "url",
            argument: "--torii-url",
          },
          {
            id: "taira-public-node-mcp-url",
            kind: "url",
            argument: "--mcp-url",
          },
        ],
        validationCommands: [
          commands.repairTairaPublicNodeValidateDns,
          commands.repairTairaPublicNodeValidateTls,
          commands.repairTairaPublicNodeValidateStatus,
          commands.repairTairaPublicNodeValidateMcp,
          commands.repairTairaPublicNodeSmokeMcp,
        ],
        delegatedActions: explicitPublicNodeDelegatedActions,
      },
      "build-production-route-manifest-isi": {
        title: "Build production route-manifest ISI",
        detail:
          "Rebuild the UpsertSccpRouteManifest ISI from a production-safe Solana route manifest.",
        commandKey: "routeManifestIsi",
      },
      "grant-taira-route-manager-access": {
        title: "Grant TAIRA route-manager access",
        detail:
          "Use a concrete TAIRA testnet route-manager account holding CanManageSccpRouteManifests.",
        commandKey: "routeManagerAccessRequest",
        requiredInputs: [
          "taira-route-manager-i105-account",
          TAIRA_ROUTE_MANIFEST_PERMISSION,
        ],
      },
      "set-runtime-route-manager-private-key": {
        title: "Set runtime route-manager private key",
        detail:
          "Provide the route-manager private key only in the publication runtime; reports must not store it.",
        commandKey: "publishRouteManifest",
        requiredInputs: [privateKeyEnv],
      },
    },
  });
  return {
    schema: "iroha-demo-sccp-solana-route-publish-readiness/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    ready,
    publicationSatisfied,
    submissionRequired,
    readyForRuntimeSigner,
    readyToSubmitWithCurrentRuntime,
    requiredPublicationAction,
    proposalDraft: requiredPublicationAction,
    productionRequirements: requirementsReport
      ? {
          path: requirementsReport.path ?? null,
          ready: requirementsReady,
          readyToBuildIsi: requirementsReady,
          blockerIds: Array.isArray(requirementsReport.blockers)
            ? requirementsReport.blockers.map((blocker) => blocker.id)
            : [],
          requiredProductionInputs:
            requiredProductionInputsFromReports(requirementsReport),
          missingProductionInputIds: requirementsReady
            ? []
            : missingProductionInputIdsFromReports(requirementsReport),
        }
      : null,
    publicEndpoint: {
      toriiUrl: routePublishTarget.toriiUrl,
      mcpUrl: routePublishTarget.mcpUrl,
      target: routePublishTarget,
      publicationTargetReady: routePublicationTargetReady,
      defaultPresetPublicationReady,
      directPublicNodePublicationReady:
        routePublishTarget.canonicalRolloutTargetReady === true,
      explicitPublicNodeCandidates: isRecord(publicNodeCandidates)
        ? publicNodeCandidates
        : null,
      explicitPublicNodeRepairPlan,
      preflightPath: publicPreflightPath,
      preflightReady: publicPreflight?.ready === true,
      endpointReady: endpoint.ready,
      endpointChecks: endpoint.requiredChecks,
      ingressHealth: publicIngressHealth,
      mcpTransactionTools: isRecord(mcpTransactionTools)
        ? mcpTransactionTools
        : null,
      routeAlreadyPublic: alreadyPublic.published,
      publicationSatisfied,
      expectedManifestCanonicalSha256:
        alreadyPublic.expectedManifestCanonicalSha256,
      observedManifestCanonicalSha256:
        alreadyPublic.observedManifestCanonicalSha256,
      exactManifestMatches: alreadyPublic.exactManifestMatches,
      publicationChecks: alreadyPublic.publicationChecks,
      publicSolanaLane,
      note:
        alreadyPublic.published === true
          ? "Public TAIRA already exposes taira_sol_xor."
          : "Missing public taira_sol_xor is expected before route publication and is reported separately from endpoint readiness.",
    },
    routeManifestIsi: {
      path: isiPath,
      ready: routeManifestIsiReady,
      artifactReady: rawRouteManifestIsiArtifactReady,
      exactByteBindingReady: isiBindingReady,
      blockedByProductionRequirements:
        routeManifestIsiBlockedByProductionRequirements,
      blockedBy: routeManifestIsiBlockedBy,
      error: routeManifestIsiError,
      isiArtifactSha256,
      manifestArtifactPath,
      manifestArtifactSha256,
      manifestCanonicalSha256: expectedManifestCanonicalSha256,
      manifestSha256: isiArtifact?.manifestSha256 ?? null,
      instructionManifestSha256: isiArtifact?.instructionManifestSha256 ?? null,
      gasAssetId: isiArtifact?.gasAssetId ?? null,
      gasLimit: isiArtifact?.gasLimit ?? null,
    },
    runtimeSigning: {
      authority: authority || null,
      authorityEnv,
      authorityEnvPresent,
      authoritySource: explicitAuthority
        ? "argument"
        : authorityEnvPresent
          ? "environment"
          : "missing",
      authorityReady,
      authorityFormatReady,
      requiredPermission: TAIRA_ROUTE_MANIFEST_PERMISSION,
      permissionAudit: isRecord(authorityPermission)
        ? authorityPermission
        : null,
      privateKeyEnv,
      privateKeyEnvPresent: resolvedPrivateKeyEnvPresent,
      privateKeyStoredInReport: false,
    },
    commands,
    nextActions,
    nextActionDetails: withActionRequiredInputIdsList(nextActionDetails),
    blockers: activeBlockers,
    blockerIds: blockerIds(activeBlockers),
    diagnosticBlockers,
    diagnosticBlockerIds: blockerIds(diagnosticBlockers),
  };
};

export const assertProductionSolanaManifest = (manifest) => {
  if (!isRecord(manifest)) {
    throw new Error("Solana route manifest must be an object.");
  }
  assertNoForbiddenManifestFields(manifest);
  if (
    requireManifestString(
      manifest,
      ["route_id", "routeId"],
      "Solana route id",
    ) !== SCCP_SOLANA_XOR_ROUTE_ID
  ) {
    throw new Error("Solana route manifest route_id must be taira_sol_xor.");
  }
  if (
    requireManifestString(
      manifest,
      ["asset_key", "assetKey"],
      "Solana asset key",
    ) !== SCCP_XOR_ASSET_KEY
  ) {
    throw new Error("Solana route manifest asset_key must be xor.");
  }
  if (
    Number(manifest.counterparty_domain ?? manifest.counterpartyDomain) !==
    SCCP_SOLANA_DOMAIN
  ) {
    throw new Error("Solana route manifest counterparty_domain must be 3.");
  }
  if (
    requireManifestString(
      manifest,
      ["chain_id_hex", "chainIdHex"],
      "Solana chain id",
    ) !== SOLANA_TESTNET_CHAIN_ID_HEX
  ) {
    throw new Error("Solana route manifest must target Solana testnet.");
  }
  const productionReady = readManifestBooleanAlias(
    manifest,
    "productionReady",
    "production_ready",
    "Solana production-ready flag",
  );
  if (!productionReady) {
    throw new Error("Solana route manifest is not production-ready.");
  }
  for (const [keys, label] of [
    [
      [
        "solanaTokenMint",
        "solana_token_mint",
        "tairaXorTokenAddress",
        "taira_xor_token_address",
      ],
      "Solana token mint",
    ],
    [
      [
        "taira_xor_bridge_address",
        "solanaProgramId",
        "solana_program_id",
        "tairaXorSolanaProgramId",
        "taira_xor_solana_program_id",
      ],
      "Solana bridge program",
    ],
    [
      [
        "sccpSolanaSourceBridgeAddress",
        "sccp_solana_source_bridge_address",
        "solanaSourceBridgeAddress",
        "solana_source_bridge_address",
      ],
      "Solana source bridge program",
    ],
    [
      [
        "sccpSolanaSourceStateAddress",
        "sccp_solana_source_state_address",
        "solanaSourceStateAddress",
        "solana_source_state_address",
        "sourceBridgeStateAddress",
        "source_bridge_state_address",
      ],
      "Solana source bridge state",
    ],
    [
      ["solanaVerifierProgramId", "solana_verifier_program_id"],
      "Solana verifier program",
    ],
    [
      ["solanaNativeVerifierProgramId", "solana_native_verifier_program_id"],
      "Solana native verifier program",
    ],
    [
      [
        "solanaNativeVerifierProgramdataAddress",
        "solana_native_verifier_programdata_address",
      ],
      "Solana native verifier ProgramData",
    ],
    [
      ["destinationBindingKey", "destination_binding_key"],
      "destination binding key",
    ],
  ]) {
    requireManifestString(manifest, keys, label);
  }
  for (const [keys, label] of [
    [["verifierCodeHash", "verifier_code_hash"], "Solana verifier code hash"],
    [["verifierKeyHash", "verifier_key_hash"], "Solana verifier key hash"],
    [
      ["destinationBindingHash", "destination_binding_hash"],
      "destination binding hash",
    ],
    [
      ["solanaNativeVerifierCodeHash", "solana_native_verifier_code_hash"],
      "Solana native verifier code hash",
    ],
    [
      [
        "solanaNativeVerifierArtifactSha256",
        "solana_native_verifier_artifact_sha256",
      ],
      "Solana native verifier artifact SHA-256",
    ],
    [
      [
        "solanaNativeVerifierMaterialHash",
        "solana_native_verifier_material_hash",
      ],
      "Solana native verifier material hash",
    ],
    [
      ["solanaNativeVerifierConfigHash", "solana_native_verifier_config_hash"],
      "Solana native verifier config hash",
    ],
    [
      ["solanaNativeVerifierKeyHash", "solana_native_verifier_key_hash"],
      "Solana native verifier key hash",
    ],
    [
      [
        "solanaNativeVerifierGovernanceApprovalEvidenceHash",
        "solana_native_verifier_governance_approval_evidence_hash",
      ],
      "Solana native verifier governance approval evidence hash",
    ],
  ]) {
    const value = requireConsistentManifestString(manifest, keys, label);
    if (label.startsWith("Solana native verifier")) {
      normalizeProductionMaterialHex32(value, label);
    } else {
      normalizeManifestHex32(value, label);
    }
  }
  for (const [keys, label] of [
    [
      ["solanaNativeVerifierProgramId", "solana_native_verifier_program_id"],
      "Solana native verifier program",
    ],
    [
      [
        "solanaNativeVerifierProgramdataAddress",
        "solana_native_verifier_programdata_address",
      ],
      "Solana native verifier ProgramData",
    ],
  ]) {
    normalizedGovernedNativeVerifierPublicKey(manifest, keys, label);
  }
  for (const [keys, label, expected] of [
    [
      ["verifierTarget", "verifier_target"],
      "Solana verifier target",
      SOLANA_VERIFIER_TARGET,
    ],
    [
      ["destinationVerifierPlan", "destination_verifier_plan"],
      "Solana destination verifier plan",
      SOLANA_DESTINATION_VERIFIER_PLAN,
    ],
    [
      ["solanaGenesisHash", "solana_genesis_hash"],
      "Solana genesis hash",
      SOLANA_TESTNET_GENESIS_HASH,
    ],
  ]) {
    const value = requireConsistentManifestString(manifest, keys, label);
    if (value !== expected) {
      throw new Error(`${label} must be ${expected}.`);
    }
  }
  assertBrowserProver(
    manifest,
    [
      "destinationBrowserProver",
      "destination_browser_prover",
      "solanaDestinationBrowserProver",
      "solana_destination_browser_prover",
    ],
    "Solana destination browser prover",
    "destination",
  );
  assertBrowserProver(
    manifest,
    [
      "sourceBrowserProver",
      "source_browser_prover",
      "solanaSourceBrowserProver",
      "solana_source_browser_prover",
    ],
    "Solana source browser prover",
    "source",
  );
  assertSolanaDestinationProofAdmission(manifest);
  const destinationProofAdmission = readDestinationProofAdmission(manifest);
  for (const [topLevelKeys, admissionKeys, label] of [
    [
      ["solanaNativeVerifierProgramId", "solana_native_verifier_program_id"],
      ["nativeVerifierProgramId", "native_verifier_program_id"],
      "native verifier program id",
    ],
    [
      [
        "solanaNativeVerifierProgramdataAddress",
        "solana_native_verifier_programdata_address",
      ],
      [
        "nativeVerifierProgramdataAddress",
        "native_verifier_programdata_address",
      ],
      "native verifier ProgramData address",
    ],
    [
      ["solanaNativeVerifierCodeHash", "solana_native_verifier_code_hash"],
      ["nativeVerifierCodeHash", "native_verifier_code_hash"],
      "native verifier code hash",
    ],
    [
      [
        "solanaNativeVerifierArtifactSha256",
        "solana_native_verifier_artifact_sha256",
      ],
      ["nativeVerifierArtifactSha256", "native_verifier_artifact_sha256"],
      "native verifier artifact SHA-256",
    ],
    [
      [
        "solanaNativeVerifierMaterialHash",
        "solana_native_verifier_material_hash",
      ],
      ["nativeVerifierMaterialHash", "native_verifier_material_hash"],
      "native verifier material hash",
    ],
    [
      ["solanaNativeVerifierConfigHash", "solana_native_verifier_config_hash"],
      ["nativeVerifierConfigHash", "native_verifier_config_hash"],
      "native verifier config hash",
    ],
    [
      ["solanaNativeVerifierKeyHash", "solana_native_verifier_key_hash"],
      ["nativeVerifierKeyHash", "native_verifier_key_hash"],
      "native verifier key hash",
    ],
    [
      [
        "solanaNativeVerifierGovernanceApprovalEvidenceHash",
        "solana_native_verifier_governance_approval_evidence_hash",
      ],
      [
        "nativeVerifierGovernanceApprovalEvidenceHash",
        "native_verifier_governance_approval_evidence_hash",
      ],
      "native verifier governance approval evidence hash",
    ],
  ]) {
    const topLevelValue = requireManifestString(
      manifest,
      topLevelKeys,
      `Solana ${label}`,
    );
    const admissionValue = requireManifestString(
      destinationProofAdmission,
      admissionKeys,
      `destinationProofAdmission.${label}`,
    );
    if (topLevelValue !== admissionValue) {
      throw new Error(
        `destinationProofAdmission.${label} must match the top-level Solana pin.`,
      );
    }
  }
  const outerVerifierProgramId = new PublicKey(
    requireManifestString(
      manifest,
      ["solanaVerifierProgramId", "solana_verifier_program_id"],
      "Solana verifier program",
    ),
  ).toBase58();
  const nativeVerifierProgramId = new PublicKey(
    requireManifestString(
      manifest,
      ["solanaNativeVerifierProgramId", "solana_native_verifier_program_id"],
      "Solana native verifier program",
    ),
  ).toBase58();
  if (outerVerifierProgramId === nativeVerifierProgramId) {
    throw new Error(
      "Solana native verifier program must be distinct from the outer SCCP verifier program.",
    );
  }
  assertProductionVerifierEnforcement(manifest);
  assertSourceVerifierMaterial(manifest);
  if (
    !readFirstManifestRecord(
      manifest,
      "sourceAdapterEngineDeployment",
      "source_adapter_engine_deployment",
    )
  ) {
    throw new Error("Solana source adapter engine deployment is missing.");
  }
  assertPostDeployEvidence(manifest);
};

export const buildSolanaRouteManifestIsiArtifact = ({
  manifest,
  gasAssetId = DEFAULT_TAIRA_ROUTE_MANIFEST_GAS_ASSET_ID,
  gasLimit = DEFAULT_TAIRA_ROUTE_MANIFEST_GAS_LIMIT,
}) => {
  assertProductionSolanaManifest(manifest);
  const instructionManifest = clonePublicJson(manifest);
  const instruction = {
    UpsertSccpRouteManifest: {
      manifest: instructionManifest,
    },
  };
  return {
    schema: "iroha-sccp-route-manifest-isi/v1",
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    routeKey: {
      routeId: SCCP_SOLANA_XOR_ROUTE_ID,
      assetKey: SCCP_XOR_ASSET_KEY,
      counterpartyDomain: SCCP_SOLANA_DOMAIN,
      chainIdHex: SOLANA_TESTNET_CHAIN_ID_HEX,
    },
    requiredPermission: "CanManageSccpRouteManifests",
    instruction,
    manifestSha256: sha256JsonHex(manifest),
    instructionManifestSha256: sha256JsonHex(instructionManifest),
    productionReady: true,
    gasAssetId,
    gasLimit,
  };
};

const readBurnRecordMaterial = async () => {
  const file = path.resolve(
    repoRoot,
    "../iroha/artifacts/sccp-taira/taira-xor-burn-record.contract.json",
  );
  const burnRecord = await readJson(file);
  return {
    sourceFile: file,
    artifactB64: burnRecord.artifact_b64,
    artifactSha256: hex32(burnRecord.artifact_sha256),
    codeHash: hex32(burnRecord.code_hash),
    vkBackend: burnRecord.vkRef?.backend ?? "halo2/ipa",
    vkName: burnRecord.vkRef?.name ?? "taira_xor_burn_record_v1",
  };
};

const installSolanaCliIfRequested = (args) => {
  if (commandExists("solana")) {
    return { installed: false, reason: "already-installed" };
  }
  if (!asBoolean(args["install-solana-cli"])) {
    return { installed: false, reason: "not-requested" };
  }
  if (!commandExists("brew")) {
    throw new Error(
      "Solana CLI is missing and Homebrew is not available for automatic install.",
    );
  }
  run("brew", ["install", "solana"], { stdio: "inherit" });
  if (!commandExists("solana")) {
    throw new Error(
      "Homebrew install completed but solana is still not on PATH.",
    );
  }
  return { installed: true, reason: "homebrew" };
};

const readProgramId = async (paths) => {
  if (existsSync(paths.publicConfig)) {
    const config = await readSolanaPublicConfig(paths.publicConfig);
    if (typeof config.programId === "string" && config.programId) {
      return config.programId;
    }
  }
  throw new Error(
    "Solana program id is missing from the reviewed public deployment config.",
  );
};

const LEGACY_TAIRA_ROUTE_ENDPOINT_CHECK =
  "taira-governance-sccp-route-endpoint";

export const normalizeSolanaDoctorSiblingChecks = (checks = []) =>
  Array.isArray(checks)
    ? checks.map((check) =>
        check?.name === LEGACY_TAIRA_ROUTE_ENDPOINT_CHECK
          ? {
              ...check,
              optional: true,
              legacy: true,
              supersededBy: "taira-mcp-transaction-tools",
              note: "Legacy route endpoint is informational for this workflow; Solana route publication uses signed transaction submission through TAIRA MCP.",
            }
          : check,
      )
    : [];

const doctor = async (args) => {
  const paths = artifactPaths(args);
  await mkdir(paths.outputDir, { recursive: true });
  const install = installSolanaCliIfRequested(args);
  const mcpUrl = args["mcp-url"] || DEFAULT_TAIRA_MCP_URL;
  const checks = [
    {
      name: "sibling-deploy-helper",
      ok: existsSync(siblingDeployScript),
      path: siblingDeployScript,
    },
    {
      name: "solana-cli",
      ok: commandExists("solana"),
      install,
    },
    {
      name: "solana-keygen",
      ok: commandExists("solana-keygen"),
    },
  ];
  let siblingDoctor = null;
  try {
    siblingDoctor = JSON.parse(
      runNodeHelper([
        "doctor",
        "--solana-rpc-url",
        args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
        "--torii-url",
        args["torii-url"] || DEFAULT_TAIRA_TORII_URL,
      ]),
    );
    checks.push(...normalizeSolanaDoctorSiblingChecks(siblingDoctor.checks));
  } catch (error) {
    checks.push({
      name: "sibling-doctor",
      ok: false,
      error: error instanceof Error ? error.message : String(error),
    });
  }
  const mcpTransactionTools = await fetchTairaMcpTransactionToolStatus(
    mcpUrl,
    solanaDeployFetchOptions(args),
  );
  checks.push({
    name: "taira-mcp-transaction-tools",
    ok: mcpTransactionTools.ready === true,
    mcpUrl,
    publicationMode: mcpTransactionTools.publicationMode,
    presentTools: mcpTransactionTools.presentTools,
    missingTools: mcpTransactionTools.missingTools,
    error: mcpTransactionTools.error,
  });
  const report = {
    schema: "iroha-demo-sccp-solana-deploy-doctor/v1",
    checkedAt: new Date().toISOString(),
    ok: checks.every((check) => check.ok || check.optional),
    outputDir: paths.outputDir,
    solanaRpcUrl: args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
    toriiUrl: args["torii-url"] || DEFAULT_TAIRA_TORII_URL,
    mcpUrl,
    siblingDoctor,
    mcpTransactionTools,
    checks,
  };
  await writePublicJson(paths.doctorReport, report);
  return { report, reportPath: paths.doctorReport };
};

const rejectFileBackedSolanaKeyLifecycle = async () => {
  throw runtimeOnlySolanaDeploymentBlocker();
};

const fund = async (args) => {
  const paths = artifactPaths(args);
  assertNoFileBackedSolanaSignerOptions(args);
  const publicConfig = await readSolanaPublicConfig(paths.publicConfig);
  const deployer = runtimeSolanaSigner({
    args,
    expectedAddress: publicConfig.deployerAddress,
    label: "Solana deployer funding",
  });
  try {
    const rpcUrl = args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL;
    const connection = createConnection(args);
    const solanaGenesisHash =
      await assertSolanaTestnetRpcConnection(connection);
    const minBalance = asPositiveNumber(
      args["min-balance-sol"],
      DEFAULT_MIN_BALANCE_SOL,
      "--min-balance-sol",
    );
    const airdropSol = asPositiveNumber(
      args["airdrop-sol"],
      1,
      "--airdrop-sol",
    );
    const attempts = asNonNegativeInteger(
      args["airdrop-attempts"],
      5,
      "--airdrop-attempts",
    );
    const events = [];
    let balance =
      (await connection.getBalance(deployer.publicKey, "confirmed")) /
      1_000_000_000;
    for (
      let attempt = 1;
      balance < minBalance && attempt <= attempts;
      attempt += 1
    ) {
      try {
        await assertSolanaTestnetRpcConnection(connection);
        const signature = await connection.requestAirdrop(
          deployer.publicKey,
          Math.floor(airdropSol * 1_000_000_000),
        );
        await connection.confirmTransaction(signature, "confirmed");
        events.push({ attempt, ok: true, signature });
      } catch {
        events.push({
          attempt,
          ok: false,
          error: "Solana testnet airdrop attempt failed.",
        });
      }
      balance =
        (await connection.getBalance(deployer.publicKey, "confirmed")) /
        1_000_000_000;
    }
    const report = {
      schema: "iroha-demo-sccp-solana-funding/v1",
      checkedAt: new Date().toISOString(),
      ready: balance >= minBalance,
      deployerAddress: publicConfig.deployerAddress,
      balanceSol: balance,
      minBalanceSol: minBalance,
      rpcUrl,
      solanaGenesisHash,
      airdropEvents: events,
      fundingInstruction:
        balance >= minBalance
          ? null
          : `Fund ${publicConfig.deployerAddress} on Solana testnet with at least ${
              minBalance - balance
            } SOL, then rerun this command.`,
    };
    await writePublicJson(paths.fundingReport, report);
    if (!report.ready) {
      throw new Error(report.fundingInstruction);
    }
    return { report, reportPath: paths.fundingReport };
  } finally {
    deployer.secretKey.fill(0);
  }
};

const createSplMintInstructionData = (mintAuthority) => {
  const data = Buffer.alloc(67);
  data[0] = 0;
  data[1] = SPL_TOKEN_DECIMALS;
  Buffer.from(mintAuthority.toBytes()).copy(data, 2);
  data.writeUInt32LE(0, 34);
  return data;
};

const createSplTokenInitializeAccountInstructionData = () =>
  Buffer.from([TOKEN_INSTRUCTION_INITIALIZE_ACCOUNT]);

const readSplMintAuthority = (account) => {
  if (!account?.data || account.data.length < SPL_TOKEN_MINT_SPACE) {
    return null;
  }
  const authorityOption = account.data.readUInt32LE(0);
  if (authorityOption !== 1) {
    return null;
  }
  return new PublicKey(account.data.subarray(4, 36));
};

const createTokenMintIfMissing = async ({
  connection,
  deployer,
  mint,
  mintAuthority,
}) => {
  const existing = await getAccount(connection, mint.publicKey);
  if (existing) {
    if (!existing.owner.equals(TOKEN_PROGRAM_ID)) {
      throw new Error(
        `Existing Solana token mint ${mint.publicKey.toBase58()} is not owned by SPL Token.`,
      );
    }
    const existingAuthority = readSplMintAuthority(existing);
    if (!existingAuthority?.equals(mintAuthority)) {
      throw new Error(
        `Existing Solana token mint ${mint.publicKey.toBase58()} is not controlled by mint authority PDA ${mintAuthority.toBase58()}.`,
      );
    }
    return {
      created: false,
      address: mint.publicKey.toBase58(),
      mintAuthorityAddress: mintAuthority.toBase58(),
    };
  }
  const lamports =
    await connection.getMinimumBalanceForRentExemption(SPL_TOKEN_MINT_SPACE);
  const transaction = new Transaction().add(
    SystemProgram.createAccount({
      fromPubkey: deployer.publicKey,
      newAccountPubkey: mint.publicKey,
      lamports,
      space: SPL_TOKEN_MINT_SPACE,
      programId: TOKEN_PROGRAM_ID,
    }),
    new TransactionInstruction({
      programId: TOKEN_PROGRAM_ID,
      keys: [
        { pubkey: mint.publicKey, isSigner: false, isWritable: true },
        { pubkey: SYSVAR_RENT_PUBKEY, isSigner: false, isWritable: false },
      ],
      data: createSplMintInstructionData(mintAuthority),
    }),
  );
  const signature = await sendSolanaTransaction(connection, transaction, [
    deployer,
    mint,
  ]);
  return {
    created: true,
    address: mint.publicKey.toBase58(),
    signature,
    decimals: SPL_TOKEN_DECIMALS,
    mintAuthorityAddress: mintAuthority.toBase58(),
  };
};

const createOrReuseCanaryTokenAccount = async ({
  connection,
  deployer,
  owner,
  mint,
}) => {
  const existing = await connection.getTokenAccountsByOwner(
    owner.publicKey,
    { mint: mint.publicKey },
    { commitment: "confirmed" },
  );
  const summaries = existing.value
    .map((entry) => tokenAccountSummary(entry, existing.context.slot))
    .filter(
      (entry) =>
        entry.owner === owner.publicKey.toBase58() &&
        entry.mint === mint.publicKey.toBase58() &&
        entry.isInitialized,
    )
    .sort(tokenAccountSort);
  if (summaries.length > 0) {
    return {
      created: false,
      address: summaries[0].address,
      account: new PublicKey(summaries[0].address),
      existingTokenAccounts: summaries,
    };
  }
  const tokenAccount = Keypair.generate();
  const lamports = await connection.getMinimumBalanceForRentExemption(
    SPL_TOKEN_ACCOUNT_SPACE,
  );
  const transaction = new Transaction().add(
    SystemProgram.createAccount({
      fromPubkey: deployer.publicKey,
      newAccountPubkey: tokenAccount.publicKey,
      lamports,
      space: SPL_TOKEN_ACCOUNT_SPACE,
      programId: TOKEN_PROGRAM_ID,
    }),
    new TransactionInstruction({
      programId: TOKEN_PROGRAM_ID,
      keys: [
        { pubkey: tokenAccount.publicKey, isSigner: false, isWritable: true },
        { pubkey: mint.publicKey, isSigner: false, isWritable: false },
        { pubkey: owner.publicKey, isSigner: false, isWritable: false },
        { pubkey: SYSVAR_RENT_PUBKEY, isSigner: false, isWritable: false },
      ],
      data: createSplTokenInitializeAccountInstructionData(),
    }),
  );
  const signature = await sendSolanaTransaction(connection, transaction, [
    deployer,
    tokenAccount,
  ]);
  return {
    created: true,
    address: tokenAccount.publicKey.toBase58(),
    account: tokenAccount.publicKey,
    createSignature: signature,
    existingTokenAccounts: summaries,
  };
};

const createProgramStateIfMissing = async ({
  connection,
  deployer,
  state,
  programId,
  label,
}) => {
  const existing = await getAccount(connection, state.publicKey);
  if (existing) {
    if (!existing.owner.equals(programId)) {
      throw new Error(
        `Existing Solana ${label} state ${state.publicKey.toBase58()} is not owned by ${programId.toBase58()}.`,
      );
    }
    return { created: false, address: state.publicKey.toBase58() };
  }
  const lamports = await connection.getMinimumBalanceForRentExemption(
    SCCP_SOLANA_STATE_SPACE,
  );
  const transaction = new Transaction().add(
    SystemProgram.createAccount({
      fromPubkey: deployer.publicKey,
      newAccountPubkey: state.publicKey,
      lamports,
      space: SCCP_SOLANA_STATE_SPACE,
      programId,
    }),
  );
  const signature = await sendSolanaTransaction(connection, transaction, [
    deployer,
    state,
  ]);
  return { created: true, address: state.publicKey.toBase58(), signature };
};

const initializeProgramState = async ({
  connection,
  deployer,
  state,
  mint,
  programId,
  label,
}) => {
  const existing = await getAccount(connection, state.publicKey);
  const inspection = inspectSolanaStateInitialization({
    account: existing,
    programId,
    stateAddress: state.publicKey.toBase58(),
    authorityAddress: deployer.publicKey,
    mintAddress: mint.publicKey,
    label,
  });
  if (!inspection.shouldInitialize) {
    return {
      initialized: false,
      alreadyInitialized: true,
      address: state.publicKey.toBase58(),
      reason: inspection.reason,
      storedMint: inspection.parsed.storedMint,
      authority: inspection.parsed.authority,
    };
  }
  const transaction = new Transaction().add(
    new TransactionInstruction({
      programId,
      keys: [
        { pubkey: deployer.publicKey, isSigner: true, isWritable: false },
        { pubkey: state.publicKey, isSigner: false, isWritable: true },
        { pubkey: mint.publicKey, isSigner: false, isWritable: false },
      ],
      data: encodeBorshVecs(SCCP_SOLANA_INITIALIZE_ENTRYPOINT),
    }),
  );
  const signature = await sendSolanaTransaction(connection, transaction, [
    deployer,
  ]);
  return {
    initialized: true,
    alreadyInitialized: false,
    address: state.publicKey.toBase58(),
    reason: inspection.reason,
    signature,
  };
};

const initializeSolanaAccounts = async (args) => {
  const paths = artifactPaths(args);
  assertNoFileBackedSolanaSignerOptions(args);
  const publicConfig = await readSolanaPublicConfig(paths.publicConfig);
  let deployer = null;
  let state = null;
  let sourceState = null;
  let mint = null;
  try {
    deployer = runtimeSolanaSigner({
      args,
      expectedAddress: publicConfig.deployerAddress,
      label: "Solana account initialization",
    });
    state = loadRuntimeSolanaSigner({
      envName: SOLANA_VERIFIER_STATE_RUNTIME_SIGNER_ENV,
      expectedAddress: publicConfig.verifierStateAddress,
      label: "Solana verifier state creation",
    });
    sourceState = loadRuntimeSolanaSigner({
      envName: SOLANA_SOURCE_STATE_RUNTIME_SIGNER_ENV,
      expectedAddress: publicConfig.sourceStateAddress,
      label: "Solana source state creation",
    });
    mint = loadRuntimeSolanaSigner({
      envName: SOLANA_TOKEN_MINT_RUNTIME_SIGNER_ENV,
      expectedAddress: publicConfig.tokenMintAddress,
      label: "Solana token mint creation",
    });
    const connection = createConnection(args);
    const verifierProgramId = new PublicKey(
      publicConfig.verifierProgramId || publicConfig.programId,
    );
    const sourceBridgeProgramId = new PublicKey(
      publicConfig.sourceBridgeProgramId,
    );
    const [mintAuthority, mintAuthorityBump] = deriveMintAuthority(
      verifierProgramId,
      state.publicKey,
    );
    const tokenMint = await createTokenMintIfMissing({
      connection,
      deployer,
      mint,
      mintAuthority,
    });
    const verifierState = await createProgramStateIfMissing({
      connection,
      deployer,
      state,
      programId: verifierProgramId,
      label: "verifier",
    });
    const sourceStateReport = await createProgramStateIfMissing({
      connection,
      deployer,
      state: sourceState,
      programId: sourceBridgeProgramId,
      label: "source bridge",
    });
    const stateInitialization = await initializeProgramState({
      connection,
      deployer,
      state,
      mint,
      programId: verifierProgramId,
      label: "verifier",
    });
    const sourceStateInitialization = await initializeProgramState({
      connection,
      deployer,
      state: sourceState,
      mint,
      programId: sourceBridgeProgramId,
      label: "source bridge",
    });
    const report = {
      schema: "iroha-demo-sccp-solana-accounts/v1",
      checkedAt: new Date().toISOString(),
      tokenMint,
      mintAuthority: {
        address: mintAuthority.toBase58(),
        bump: mintAuthorityBump,
        seed: SCCP_SOLANA_MINT_AUTHORITY_SEED,
      },
      verifierState,
      sourceState: sourceStateReport,
      stateInitialization,
      sourceStateInitialization,
    };
    await writePublicJson(paths.accountsReport, report);
    return { report, reportPath: paths.accountsReport };
  } finally {
    deployer?.secretKey.fill(0);
    state?.secretKey.fill(0);
    sourceState?.secretKey.fill(0);
    mint?.secretKey.fill(0);
  }
};

const ensureNativeVerifierPublicConfig = async (args, paths) => {
  if (!existsSync(paths.publicConfig)) {
    throw new Error(
      "Reviewed Solana public deployment config is required; signer-file generation is forbidden.",
    );
  }
  const publicConfig = await readSolanaPublicConfig(paths.publicConfig);
  const nativeVerifierProgramId = new PublicKey(
    publicConfig.nativeVerifierProgramId ||
      publicConfig.solanaNativeVerifierProgramId,
  ).toBase58();
  await writeSolanaPublicConfig(paths.publicConfig, publicConfig);
  return {
    publicConfig,
    nativeVerifierProgramId,
  };
};

const buildConfigureNativeVerifierInstructionData = ({
  verifierMaterialHash,
  verifierConfigHash,
}) =>
  encodeBorshVecs(
    SCCP_SOLANA_CONFIGURE_VERIFIER_ENTRYPOINT,
    hex32Buffer(verifierMaterialHash, "native verifier material hash"),
    hex32Buffer(verifierConfigHash, "native verifier config hash"),
  );

export const buildConfigureNativeVerifierAccountMetas = ({
  authorityAddress,
  verifierStateAddress,
  nativeVerifierProgramId,
  nativeVerifierProgramdataAddress,
  verifierProgramId,
  verifierProgramdataAddress,
} = {}) => [
  {
    pubkey: new PublicKey(authorityAddress),
    isSigner: true,
    isWritable: false,
  },
  {
    pubkey: new PublicKey(verifierStateAddress),
    isSigner: false,
    isWritable: true,
  },
  {
    pubkey: new PublicKey(nativeVerifierProgramId),
    isSigner: false,
    isWritable: false,
  },
  {
    pubkey: new PublicKey(nativeVerifierProgramdataAddress),
    isSigner: false,
    isWritable: false,
  },
  {
    pubkey: new PublicKey(verifierProgramId),
    isSigner: false,
    isWritable: false,
  },
  {
    pubkey: new PublicKey(verifierProgramdataAddress),
    isSigner: false,
    isWritable: false,
  },
];

export const buildSolanaNativeVerifierConfigurationReadinessReportBody = ({
  verifierProgramId,
  nativeVerifierProgramId,
  outerLiveReadback = null,
  nativeLiveReadback = null,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const outerProgramId = new PublicKey(verifierProgramId).toBase58();
  const nativeProgramId = new PublicKey(nativeVerifierProgramId).toBase58();
  const programStatuses = ({ prefix, expectedProgramId, readback }) => [
    linkageStatus({
      key: `${prefix}LiveReadback`,
      description: `${prefix} Program and ProgramData must be readable immediately before one-shot verifier configuration.`,
      present: Boolean(readback),
      value: Boolean(readback),
      expected: true,
      blockerId: `solana-configure-${prefix.toLowerCase()}-live-readback`,
    }),
    linkageStatus({
      key: `${prefix}ProgramId`,
      description: `${prefix} live program id must match the selected deployment.`,
      present: readback?.program?.address === expectedProgramId,
      invalid: Boolean(readback?.program?.address),
      value: readback?.program?.address ?? null,
      expected: expectedProgramId,
      blockerId: `solana-configure-${prefix.toLowerCase()}-program-id`,
    }),
    linkageStatus({
      key: `${prefix}ProgramOwner`,
      description: `${prefix} Program must be owned by the upgradeable loader.`,
      present: readback?.program?.owner === SOLANA_UPGRADEABLE_LOADER_ID,
      invalid: Boolean(readback?.program?.owner),
      value: readback?.program?.owner ?? null,
      expected: SOLANA_UPGRADEABLE_LOADER_ID,
      blockerId: `solana-configure-${prefix.toLowerCase()}-program-owner`,
    }),
    linkageStatus({
      key: `${prefix}ProgramExecutable`,
      description: `${prefix} Program must be executable.`,
      present: readback?.program?.executable === true,
      invalid: readback?.program?.executable === false,
      value: readback?.program?.executable ?? null,
      expected: true,
      blockerId: `solana-configure-${prefix.toLowerCase()}-program-executable`,
    }),
    linkageStatus({
      key: `${prefix}ProgramdataAddress`,
      description: `${prefix} Program must resolve to the live ProgramData account supplied to configuration.`,
      present:
        Boolean(readback?.parsedProgram?.programdataAddress) &&
        readback?.programdata?.address ===
          readback?.parsedProgram?.programdataAddress,
      invalid: Boolean(
        readback?.parsedProgram?.programdataAddress ||
          readback?.programdata?.address,
      ),
      value: readback?.programdata?.address ?? null,
      expected:
        readback?.parsedProgram?.programdataAddress ??
        "live upgradeable-loader ProgramData address",
      blockerId: `solana-configure-${prefix.toLowerCase()}-programdata-address`,
    }),
    linkageStatus({
      key: `${prefix}ProgramdataOwner`,
      description: `${prefix} ProgramData must be owned by the upgradeable loader.`,
      present: readback?.programdata?.owner === SOLANA_UPGRADEABLE_LOADER_ID,
      invalid: Boolean(readback?.programdata?.owner),
      value: readback?.programdata?.owner ?? null,
      expected: SOLANA_UPGRADEABLE_LOADER_ID,
      blockerId: `solana-configure-${prefix.toLowerCase()}-programdata-owner`,
    }),
    linkageStatus({
      key: `${prefix}ProgramImmutable`,
      description: `${prefix} ProgramData upgrade authority must already be removed before one-shot verifier configuration.`,
      present: readback?.parsedProgramdata?.immutable === true,
      invalid: readback?.parsedProgramdata?.immutable === false,
      value: readback?.parsedProgramdata?.immutable ?? null,
      expected: true,
      blockerId: `solana-configure-${prefix.toLowerCase()}-programdata-mutable`,
    }),
  ];
  const statuses = [
    linkageStatus({
      key: "distinctPrograms",
      description:
        "The outer SCCP verifier and native recursive verifier programs must be distinct.",
      present: outerProgramId !== nativeProgramId,
      invalid: outerProgramId === nativeProgramId,
      value: { outerProgramId, nativeProgramId },
      expected: "distinct program ids",
      blockerId: "solana-configure-distinct-verifier-programs",
    }),
    ...programStatuses({
      prefix: "OuterVerifier",
      expectedProgramId: outerProgramId,
      readback: outerLiveReadback,
    }),
    ...programStatuses({
      prefix: "NativeVerifier",
      expectedProgramId: nativeProgramId,
      readback: nativeLiveReadback,
    }),
  ];
  const blockers = buildSolanaVerifierLinkageBlockers(statuses);
  return {
    schema: "iroha-demo-sccp-solana-native-verifier-configuration-readiness/v1",
    checkedAt,
    ready: blockers.length === 0,
    oneShotConfiguration: true,
    verifierProgramId: outerProgramId,
    verifierProgramdataAddress:
      outerLiveReadback?.parsedProgram?.programdataAddress ?? null,
    nativeVerifierProgramId: nativeProgramId,
    nativeVerifierProgramdataAddress:
      nativeLiveReadback?.parsedProgram?.programdataAddress ?? null,
    statuses,
    blockers,
    blockerIds: blockers.map((blocker) => blocker.id),
  };
};

export const configureSolanaNativeVerifierState = async ({
  connection,
  deployer,
  verifierProgramId,
  verifierStateAddress,
  nativeVerifierProgramId,
  verifierMaterialHash,
  verifierConfigHash,
  beforeBroadcast = null,
  persistIntent,
  persistResolution,
  resolveAmbiguousIntent,
  intentBindings = {},
  mutationTarget,
  operationBinding,
  dependencies = {},
}) => {
  const readProgramLinkage =
    dependencies.readProgramLinkage ??
    ((programId, label) =>
      readSolanaUpgradeableProgramLinkageLiveReadback({
        connection,
        programId,
        label,
      }));
  const getLatestBlockhash =
    dependencies.getLatestBlockhash ??
    (() => connection.getLatestBlockhash("finalized"));
  const sendRawTransaction =
    dependencies.sendRawTransaction ??
    ((raw, options) => connection.sendRawTransaction(raw, options));
  const confirmTransaction =
    dependencies.confirmTransaction ??
    ((strategy, commitment) =>
      connection.confirmTransaction(strategy, commitment));
  const readStateAccount =
    dependencies.readStateAccount ??
    (() =>
      readSolanaAccountWithContext(
        connection,
        verifierStateAddress.toBase58(),
        "Solana SCCP verifier state",
      ));
  const assertRpcIdentity =
    dependencies.assertRpcIdentity ?? assertSolanaTestnetRpcConnection;
  const [outerLiveReadback, nativeLiveReadback] = await Promise.all([
    readProgramLinkage(verifierProgramId.toBase58(), "Solana outer verifier"),
    readProgramLinkage(
      nativeVerifierProgramId.toBase58(),
      "Solana native verifier",
    ),
  ]);
  const configurationReadiness =
    buildSolanaNativeVerifierConfigurationReadinessReportBody({
      verifierProgramId: verifierProgramId.toBase58(),
      nativeVerifierProgramId: nativeVerifierProgramId.toBase58(),
      outerLiveReadback,
      nativeLiveReadback,
    });
  if (!configurationReadiness.ready) {
    const error = new Error(
      `Solana native verifier configuration is blocked until the outer and native programs are immutable: ${configurationReadiness.blockerIds.join(", ")}`,
    );
    error.configurationReadiness = configurationReadiness;
    throw error;
  }
  const transaction = new Transaction().add(
    new TransactionInstruction({
      programId: verifierProgramId,
      keys: buildConfigureNativeVerifierAccountMetas({
        authorityAddress: deployer.publicKey,
        verifierStateAddress,
        nativeVerifierProgramId,
        nativeVerifierProgramdataAddress:
          configurationReadiness.nativeVerifierProgramdataAddress,
        verifierProgramId,
        verifierProgramdataAddress:
          configurationReadiness.verifierProgramdataAddress,
      }),
      data: buildConfigureNativeVerifierInstructionData({
        verifierMaterialHash,
        verifierConfigHash,
      }),
    }),
  );
  if (
    typeof beforeBroadcast !== "function" ||
    typeof persistIntent !== "function" ||
    typeof persistResolution !== "function" ||
    typeof resolveAmbiguousIntent !== "function"
  ) {
    throw new Error(
      "Native-verifier configuration requires a fresh mutation fence, durable intent persistence, and ambiguity resolution.",
    );
  }
  const latestBlockhash = await getLatestBlockhash();
  if (
    !isCanonicalSolanaBlockhash(latestBlockhash?.blockhash) ||
    !Number.isSafeInteger(latestBlockhash?.lastValidBlockHeight)
  ) {
    throw new Error(
      "Native-verifier configuration requires a fresh finalized Solana blockhash.",
    );
  }
  transaction.feePayer = deployer.publicKey;
  transaction.recentBlockhash = latestBlockhash.blockhash;
  transaction.sign(deployer);
  const rawTransaction = transaction.serialize({
    requireAllSignatures: true,
    verifySignatures: true,
  });
  const routeAbsenceAuthorization = await beforeBroadcast({
    configurationReadiness,
  });
  const nativeRouteAbsenceAuthorization = {
    ...routeAbsenceAuthorization,
    phase: "before-broadcast",
    publicPreflightArtifactSha256:
      routeAbsenceAuthorization?.quorumArtifactSha256,
  };
  if (
    !buildSolanaRouteAbsenceMutationAuthorizationValidation({
      authorization: nativeRouteAbsenceAuthorization,
      expectedPhase: "before-broadcast",
    }).ready
  ) {
    throw new Error(
      "Native-verifier configuration requires a fresh authoritative four-validator TAIRA route-absence quorum immediately before broadcast.",
    );
  }
  const mutationIntent = buildSolanaOneShotMutationIntent({
    operation: "native-verifier-configuration",
    transaction,
    rawTransaction,
    latestBlockhash,
    authority: deployer.publicKey.toBase58(),
    target: mutationTarget,
    operationBinding,
    bindings: {
      ...intentBindings,
      verifierProgramId: verifierProgramId.toBase58(),
      verifierStateAddress: verifierStateAddress.toBase58(),
      nativeVerifierProgramId: nativeVerifierProgramId.toBase58(),
      nativeVerifierProgramdataAddress:
        configurationReadiness.nativeVerifierProgramdataAddress,
      verifierProgramdataAddress:
        configurationReadiness.verifierProgramdataAddress,
      verifierMaterialHash,
      verifierConfigHash,
      routeAbsencePublicPreflightArtifactSha256:
        routeAbsenceAuthorization?.quorumArtifactSha256 ?? null,
      routeAbsenceMutationAuthorization: nativeRouteAbsenceAuthorization,
    },
  });
  const intentArtifact = await persistIntent({ intent: mutationIntent });
  let broadcastError = null;
  try {
    await assertRpcIdentity(connection);
    const returnedSignature = await sendRawTransaction(rawTransaction, {
      skipPreflight: false,
      maxRetries: 0,
    });
    if (returnedSignature !== mutationIntent.expectedSignature) {
      throw new Error(
        "Solana RPC returned a different native-verifier configuration signature.",
      );
    }
    try {
      await confirmTransaction(
        {
          signature: mutationIntent.expectedSignature,
          blockhash: latestBlockhash.blockhash,
          lastValidBlockHeight: latestBlockhash.lastValidBlockHeight,
        },
        "finalized",
      );
    } catch {
      // Exact signature reconciliation below is authoritative.
    }
  } catch (error) {
    broadcastError = error;
  }
  let mutationResolution;
  try {
    mutationResolution = await resolveAmbiguousIntent({
      intent: mutationIntent,
      rawTransaction,
      cause: broadcastError,
    });
  } catch (cause) {
    throw solanaOneShotMutationError({
      intent: mutationIntent,
      resolution: { status: "ambiguity-resolution-read-failed" },
      cause,
    });
  }
  let resolutionArtifact = null;
  if (["finalized", "failed", "expired"].includes(mutationResolution?.status)) {
    try {
      resolutionArtifact = await persistResolution({
        intent: mutationIntent,
        resolution: mutationResolution,
      });
    } catch (cause) {
      throw solanaOneShotMutationError({
        intent: mutationIntent,
        resolution: { status: "durable-resolution-write-failed" },
        cause,
      });
    }
  }
  if (mutationResolution?.status !== "finalized") {
    throw solanaOneShotMutationError({
      intent: mutationIntent,
      resolution: mutationResolution,
      cause: broadcastError,
    });
  }
  const configureSignature = mutationIntent.expectedSignature;
  const finalizedSlot = mutationResolution.finalizedSlot;
  let configuredState = null;
  for (let attempt = 1; attempt <= 8; attempt += 1) {
    try {
      const stateReadback = await readStateAccount();
      const parsed = parseSolanaSccpStateAccountData(stateReadback.info.data);
      configuredState = {
        address: verifierStateAddress.toBase58(),
        contextSlot: stateReadback.contextSlot,
        parsed,
        dataSha256: sha256BufferHex(stateReadback.info.data),
        readAttempt: attempt,
      };
      if (
        parsed.nativeVerifierProgramId === nativeVerifierProgramId.toBase58() &&
        parsed.verifierMaterialHash === verifierMaterialHash &&
        parsed.verifierConfigHash === verifierConfigHash
      ) {
        break;
      }
    } catch (error) {
      configuredState = {
        address: verifierStateAddress.toBase58(),
        error: error instanceof Error ? error.message : String(error),
        readAttempt: attempt,
      };
    }
    await sleep(500);
  }
  const configuredStateReady = Boolean(
    configuredState?.parsed?.nativeVerifierProgramId ===
      nativeVerifierProgramId.toBase58() &&
      configuredState?.parsed?.verifierMaterialHash === verifierMaterialHash &&
      configuredState?.parsed?.verifierConfigHash === verifierConfigHash &&
      configuredState?.parsed?.verifierConfiguredSlot ===
        String(finalizedSlot) &&
      Number.isSafeInteger(configuredState?.contextSlot) &&
      configuredState.contextSlot >= finalizedSlot,
  );
  return {
    configureSignature,
    finalizedSlot,
    mutationIntent,
    intentArtifactSha256: intentArtifact?.sha256 ?? null,
    resolutionArtifactSha256: resolutionArtifact?.sha256 ?? null,
    configuredState,
    configuredStateReady,
    configurationReadiness,
  };
};

export const buildSolanaNativeVerifierDeploymentPolicyReportBody = ({
  governedPackagePresent = false,
  configureOnly = false,
  finalizeNativeVerifier = false,
  repositoryStagingArtifact = true,
  executableElf = false,
  cpiMarkerPresent = false,
  governedMaterialNotLinkedSentinelPresent = false,
} = {}) => {
  const policies = [
    {
      id: "solana-native-verifier-combined-finalization",
      ready: !finalizeNativeVerifier,
      error:
        "--final-native-verifier is disabled in the combined deploy/configure command. Deploy and inspect the mutable program first, finalize it separately after review, then run configure-native-verifier.",
    },
    {
      id: "solana-native-verifier-configure-package",
      ready: !configureOnly || governedPackagePresent,
      error:
        "--configure-only requires --governed-native-verifier-package PATH.",
    },
    {
      id: "solana-native-verifier-custom-ungoverned-artifact",
      ready: governedPackagePresent || repositoryStagingArtifact,
      error:
        "Ungoverned native-verifier deployment only permits the repository staging artifact; custom --native-verifier-so requires a governed package.",
    },
    {
      id: "solana-native-verifier-artifact-elf",
      ready: executableElf,
      error: "Native verifier artifact must be a BPF ELF.",
    },
    {
      id: "solana-native-verifier-cpi-marker",
      ready: cpiMarkerPresent,
      error:
        "Native verifier artifact must contain the reviewed SCCP native-verifier CPI marker.",
    },
    {
      id: "solana-native-verifier-staging-sentinel",
      ready: governedPackagePresent
        ? !governedMaterialNotLinkedSentinelPresent
        : governedMaterialNotLinkedSentinelPresent,
      error: governedPackagePresent
        ? "Governed native verifier artifact still contains the staging fail-closed sentinel."
        : "Repository staging native verifier artifact is missing its fail-closed sentinel.",
    },
  ];
  const blockers = policies.filter((policy) => !policy.ready);
  return {
    schema: "iroha-demo-sccp-solana-native-verifier-deployment-policy/v1",
    ready: blockers.length === 0,
    governedPackagePresent,
    configureOnly,
    finalizeNativeVerifier,
    repositoryStagingArtifact,
    policies,
    blockers,
    blockerIds: blockers.map((blocker) => blocker.id),
  };
};

export const buildSolanaGovernedNativeVerifierManifestBinding = ({
  manifest = null,
  packageValidation = null,
} = {}) => {
  const manifestPins = resolveSolanaNativeVerifierPins({
    manifest,
    nativeVerifierConfiguration: null,
  });
  const manifestPinKeys = {
    programId: [
      "solanaNativeVerifierProgramId",
      "solana_native_verifier_program_id",
      "nativeVerifierProgramId",
      "native_verifier_program_id",
    ],
    programdataAddress: [
      "solanaNativeVerifierProgramdataAddress",
      "solana_native_verifier_programdata_address",
      "nativeVerifierProgramdataAddress",
      "native_verifier_programdata_address",
    ],
    programdataSlot: [
      "solanaNativeVerifierProgramdataSlot",
      "solana_native_verifier_programdata_slot",
      "nativeVerifierProgramdataSlot",
      "native_verifier_programdata_slot",
    ],
    codeHash: [
      "solanaNativeVerifierCodeHash",
      "solana_native_verifier_code_hash",
      "nativeVerifierCodeHash",
      "native_verifier_code_hash",
    ],
    artifactSha256: [
      "solanaNativeVerifierArtifactSha256",
      "solana_native_verifier_artifact_sha256",
      "nativeVerifierArtifactSha256",
      "native_verifier_artifact_sha256",
    ],
    verifierMaterialHash: [
      "solanaNativeVerifierMaterialHash",
      "solana_native_verifier_material_hash",
      "nativeVerifierMaterialHash",
      "native_verifier_material_hash",
    ],
    verifierConfigHash: [
      "solanaNativeVerifierConfigHash",
      "solana_native_verifier_config_hash",
      "nativeVerifierConfigHash",
      "native_verifier_config_hash",
    ],
    verifierKeyHash: [
      "solanaNativeVerifierKeyHash",
      "solana_native_verifier_key_hash",
      "nativeVerifierKeyHash",
      "native_verifier_key_hash",
    ],
    governanceApprovalEvidenceHash: [
      "solanaNativeVerifierGovernanceApprovalEvidenceHash",
      "solana_native_verifier_governance_approval_evidence_hash",
      "nativeVerifierGovernanceApprovalEvidenceHash",
      "native_verifier_governance_approval_evidence_hash",
    ],
  };
  const manifestRecords = solanaVerifierEnforcementRecords(manifest);
  const manifestPinValues = Object.fromEntries(
    Object.entries(manifestPinKeys).map(([key, aliases]) => [
      key,
      uniqueStrings(
        manifestRecords.flatMap((record) =>
          aliases
            .map((alias) => record?.[alias])
            .filter((value) => typeof value === "string" && value.trim())
            .map((value) => value.trim()),
        ),
      ),
    ]),
  );
  const packagePins = {
    programId: packageValidation?.expectedNativeVerifier?.programId ?? null,
    programdataAddress:
      packageValidation?.expectedNativeVerifier?.programdataAddress ?? null,
    programdataSlot:
      packageValidation?.expectedNativeVerifier?.programdataSlot ?? null,
    codeHash: packageValidation?.expectedNativeVerifier?.codeHash ?? null,
    artifactSha256:
      packageValidation?.expectedNativeVerifier?.artifactSha256 ?? null,
    verifierMaterialHash: packageValidation?.verifierMaterialHash ?? null,
    verifierConfigHash: packageValidation?.verifierConfigHash ?? null,
    verifierKeyHash:
      packageValidation?.expectedNativeVerifier?.verifierKeyHash ?? null,
    governanceApprovalEvidenceHash:
      packageValidation?.expectedNativeVerifier
        ?.governanceApprovalEvidenceHash ?? null,
  };
  const mismatches = Object.keys(packagePins).filter((key) => {
    const expected = packagePins[key];
    const observed = manifestPinValues[key] ?? [];
    return (
      typeof expected !== "string" ||
      !expected ||
      observed.length === 0 ||
      observed.some((value) => value !== expected)
    );
  });
  return {
    schema:
      "iroha-demo-sccp-solana-governed-native-verifier-manifest-binding/v1",
    ready: packageValidation?.ready === true && mismatches.length === 0,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    packageSha256: packageValidation?.packageSha256 ?? null,
    manifestPins,
    manifestPinValues,
    packagePins,
    mismatches,
    blockerIds: mismatches.map(
      (key) => `governed-native-verifier-manifest-${key}`,
    ),
  };
};

const deployNativeVerifier = async (args) => {
  assertNoFileBackedSolanaSignerOptions(args);
  const configureOnly = asBoolean(args["configure-only"]);
  if (!configureOnly) {
    throw runtimeOnlySolanaDeploymentBlocker();
  }
  const paths = artifactPaths(args);
  const nativeVerifierSo = path.resolve(
    args["native-verifier-so"] || DEFAULT_NATIVE_VERIFIER_SO,
  );
  if (!existsSync(nativeVerifierSo)) {
    throw new Error(
      `Compiled Solana native verifier SBF not found: ${nativeVerifierSo}`,
    );
  }
  const nativeVerifierBytes = await readFile(nativeVerifierSo);
  const nativeVerifierExecutableElf =
    nativeVerifierBytes.subarray(0, 4).toString("hex") === SOLANA_BPF_ELF_MAGIC;
  const nativeVerifierCpiMarkerPresent = nativeVerifierBytes.includes(
    Buffer.from(SOLANA_NATIVE_VERIFIER_CPI_MARKER, "utf8"),
  );
  const governedMaterialNotLinkedSentinelPresent = nativeVerifierBytes.includes(
    Buffer.from(
      SOLANA_NATIVE_VERIFIER_GOVERNED_MATERIAL_NOT_LINKED_LOG,
      "utf8",
    ),
  );
  const governedPackageArg =
    args["governed-native-verifier-package"] ||
    args["native-verifier-material-file"] ||
    null;
  const finalizeNativeVerifier = asBoolean(args["final-native-verifier"]);
  const deploymentPolicy = buildSolanaNativeVerifierDeploymentPolicyReportBody({
    governedPackagePresent: Boolean(governedPackageArg),
    configureOnly,
    finalizeNativeVerifier,
    repositoryStagingArtifact:
      nativeVerifierSo === path.resolve(DEFAULT_NATIVE_VERIFIER_SO),
    executableElf: nativeVerifierExecutableElf,
    cpiMarkerPresent: nativeVerifierCpiMarkerPresent,
    governedMaterialNotLinkedSentinelPresent,
  });
  if (!deploymentPolicy.ready) {
    throw new Error(deploymentPolicy.blockers[0].error);
  }
  const { publicConfig, nativeVerifierProgramId } =
    await ensureNativeVerifierPublicConfig(args, paths);
  const nativeVerifierArtifactSha256 = sha256BufferHex(nativeVerifierBytes);
  const verifierProgramId = new PublicKey(
    publicConfig.verifierProgramId || publicConfig.programId,
  );
  const verifierStateAddress = new PublicKey(publicConfig.verifierStateAddress);
  const nativeVerifierProgramAddress = new PublicKey(nativeVerifierProgramId);
  const connection = createConnection(args);
  const mutationTarget = {
    verifierProgramId: verifierProgramId.toBase58(),
    verifierStateAddress: verifierStateAddress.toBase58(),
  };
  const mutationJournalPaths = solanaOneShotMutationJournalPaths({
    operation: "native-verifier-configuration",
    target: mutationTarget,
  });
  let governedPackageValidation = null;
  let governedPackagePath = null;
  let governedPackageArtifact = null;
  let governedManifestArtifact = null;
  let governedManifestBinding = null;
  let loadGovernedPackageSelection = null;
  if (governedPackageArg) {
    governedPackagePath = path.resolve(governedPackageArg);
    if (
      args["expected-governed-native-verifier-package-sha256"] === undefined
    ) {
      throw new Error(
        "--expected-governed-native-verifier-package-sha256 is required before governed native-verifier configuration.",
      );
    }
    if (args["expected-manifest-sha256"] === undefined) {
      throw new Error(
        "--expected-manifest-sha256 is required before governed native-verifier configuration.",
      );
    }
    loadGovernedPackageSelection = async () => {
      const [packageArtifact, manifestArtifact, governanceApprovalValidation] =
        await Promise.all([
          readStablePublicSolanaJsonArtifact({
            file: governedPackagePath,
            label: "Reviewed governed native-verifier package",
            expectedSha256:
              args["expected-governed-native-verifier-package-sha256"],
          }),
          readStablePublicSolanaJsonArtifact({
            file: path.resolve(args.manifest || paths.routeManifest),
            label:
              "Reviewed Solana route manifest for native-verifier configuration",
            expectedSha256: args["expected-manifest-sha256"],
          }),
          loadSolanaProductionGovernanceApprovalValidation({ args }),
        ]);
      const validation = buildSolanaGovernedNativeVerifierPackageValidation({
        packageRecord: packageArtifact.value,
        nativeVerifierProgramId,
        nativeVerifierArtifactSha256,
        governanceApprovalValidation,
        packagePath: packageArtifact.path,
        packageSha256: packageArtifact.sha256,
      });
      const manifestBinding = buildSolanaGovernedNativeVerifierManifestBinding({
        manifest: manifestArtifact.value,
        packageValidation: validation,
      });
      return { packageArtifact, manifestArtifact, validation, manifestBinding };
    };
    const selected = await loadGovernedPackageSelection();
    governedPackageArtifact = selected.packageArtifact;
    governedManifestArtifact = selected.manifestArtifact;
    governedPackageValidation = selected.validation;
    governedManifestBinding = selected.manifestBinding;
    if (!governedPackageValidation.ready) {
      const blocked = {
        schema: "iroha-demo-sccp-solana-native-verifier-configure/v1",
        checkedAt: new Date().toISOString(),
        ready: false,
        configured: false,
        productionReady: false,
        reason: "Governed native verifier package validation failed.",
        nativeVerifierSo,
        nativeVerifierArtifactSha256,
        nativeVerifierProgramId,
        verifierProgramId: verifierProgramId.toBase58(),
        verifierStateAddress: verifierStateAddress.toBase58(),
        governedPackageValidation,
        blockerIds: governedPackageValidation.blockerIds,
      };
      await writePublicJson(paths.nativeVerifierConfigureReport, blocked);
      throw new Error(
        `Governed native verifier package validation failed: ${governedPackageValidation.blockerIds.join(", ")}`,
      );
    }
    if (!governedManifestBinding.ready) {
      throw new Error(
        `Governed native verifier package does not match the exact reviewed route manifest: ${governedManifestBinding.blockerIds.join(", ")}`,
      );
    }
    if (!asBoolean(args["confirm-governed-native-verifier"])) {
      throw new Error(
        "--confirm-governed-native-verifier true is required before deploying or configuring reviewed native verifier material.",
      );
    }
  }

  const output = "";

  let materialDescriptor = null;
  let configDescriptor = null;
  let verifierMaterialHash = null;
  let verifierConfigHash = null;
  let nativeVerifierLiveReadiness = null;
  if (governedPackageValidation) {
    materialDescriptor = governedPackageValidation.materialDescriptor;
    configDescriptor = governedPackageValidation.configDescriptor;
    verifierMaterialHash = governedPackageValidation.verifierMaterialHash;
    verifierConfigHash = governedPackageValidation.verifierConfigHash;
    let nativeLiveReadback = null;
    let nativeReadbackError = null;
    try {
      nativeLiveReadback =
        await readSolanaUpgradeableProgramLinkageLiveReadback({
          connection,
          programId: nativeVerifierProgramId,
          label: "Solana native verifier",
          retryOptions: solanaRpcRetryOptions(args),
        });
    } catch (error) {
      nativeReadbackError =
        error instanceof Error ? error.message : String(error);
    }
    nativeVerifierLiveReadiness =
      buildSolanaGovernedNativeVerifierLiveReadinessReportBody({
        packageValidation: governedPackageValidation,
        liveReadback: nativeLiveReadback,
        readbackError: nativeReadbackError,
        artifactBytes: nativeVerifierBytes,
      });
    if (!nativeVerifierLiveReadiness.ready) {
      const blocked = {
        schema: "iroha-demo-sccp-solana-native-verifier-configure/v1",
        checkedAt: new Date().toISOString(),
        ready: false,
        configured: false,
        productionReady: false,
        reason:
          "Governed native verifier live ProgramData is not immutable or does not match reviewed pins; outer verifier state was not changed.",
        nativeVerifierSo,
        nativeVerifierArtifactSha256,
        nativeVerifierProgramId,
        verifierProgramId: verifierProgramId.toBase58(),
        verifierStateAddress: verifierStateAddress.toBase58(),
        deploySignature:
          output.match(/Signature:\s+([1-9A-HJ-NP-Za-km-z]+)/u)?.[1] ?? null,
        governedPackageValidation,
        nativeVerifierLiveReadiness,
        blockerIds: nativeVerifierLiveReadiness.blockerIds,
      };
      await writePublicJson(paths.nativeVerifierConfigureReport, blocked);
      return {
        nativeVerifierDeployLogPath: configureOnly
          ? null
          : paths.nativeVerifierDeployLog,
        nativeVerifierConfigureReportPath: paths.nativeVerifierConfigureReport,
        report: blocked,
      };
    }
  } else {
    let nativeLiveReadback = null;
    let nativeReadbackError = null;
    try {
      nativeLiveReadback =
        await readSolanaUpgradeableProgramLinkageLiveReadback({
          connection,
          programId: nativeVerifierProgramId,
          label: "Solana staging native verifier",
          retryOptions: solanaRpcRetryOptions(args),
        });
    } catch (error) {
      nativeReadbackError =
        error instanceof Error ? error.message : String(error);
    }
    const parsedProgramdata = nativeLiveReadback?.parsedProgramdata ?? null;
    const stagingStatuses = buildNativeVerifierProgramStatuses({
      expected: {
        programId: nativeVerifierProgramId,
        programdataAddress:
          nativeLiveReadback?.parsedProgram?.programdataAddress ?? null,
        programdataSlot: parsedProgramdata?.slot ?? null,
        artifactSha256: nativeVerifierArtifactSha256,
        codeHash: parsedProgramdata?.executableBlake2b256 ?? null,
      },
      liveReadback: nativeLiveReadback,
      readbackError: nativeReadbackError,
      artifactBytes: nativeVerifierBytes,
      requireImmutable: false,
      expectedGovernedMaterialNotLinkedSentinelPresent: true,
    });
    const stagingBlockers = buildSolanaVerifierLinkageBlockers(stagingStatuses);
    nativeVerifierLiveReadiness = {
      schema:
        "iroha-demo-sccp-solana-staging-native-verifier-live-readiness/v1",
      checkedAt: new Date().toISOString(),
      routeId: SCCP_SOLANA_XOR_ROUTE_ID,
      ready: stagingBlockers.length === 0,
      productionReady: false,
      liveNativeVerifier: parsedProgramdata
        ? {
            programId: nativeLiveReadback?.program?.address ?? null,
            programdataAddress:
              nativeLiveReadback?.parsedProgram?.programdataAddress ?? null,
            programdataSlot: parsedProgramdata.slot,
            codeHash: parsedProgramdata.executableBlake2b256,
            executableSha256: parsedProgramdata.executableSha256,
            immutable: parsedProgramdata.immutable,
          }
        : null,
      statuses: stagingStatuses,
      blockers: stagingBlockers,
      blockerIds: stagingBlockers.map((blocker) => blocker.id),
    };
    if (!nativeVerifierLiveReadiness.ready) {
      const blocked = {
        schema: "iroha-demo-sccp-solana-native-verifier-configure/v1",
        checkedAt: new Date().toISOString(),
        ready: false,
        configured: false,
        productionReady: false,
        reason:
          "Staging native verifier live bytes do not match the exact fail-closed repository artifact; outer verifier state was not changed.",
        nativeVerifierSo,
        nativeVerifierArtifactSha256,
        nativeVerifierProgramId,
        verifierProgramId: verifierProgramId.toBase58(),
        verifierStateAddress: verifierStateAddress.toBase58(),
        nativeVerifierLiveReadiness,
        blockerIds: nativeVerifierLiveReadiness.blockerIds,
      };
      await writePublicJson(paths.nativeVerifierConfigureReport, blocked);
      return {
        nativeVerifierDeployLogPath: paths.nativeVerifierDeployLog,
        nativeVerifierConfigureReportPath: paths.nativeVerifierConfigureReport,
        report: blocked,
      };
    }
    materialDescriptor = {
      schema: "iroha-demo-sccp-solana-native-verifier-failclosed-material/v1",
      routeId: SCCP_SOLANA_XOR_ROUTE_ID,
      assetKey: SCCP_XOR_ASSET_KEY,
      nativeVerifierProgramId,
      nativeVerifierArtifactSha256,
      cpiMarker: SOLANA_NATIVE_VERIFIER_CPI_MARKER,
      failClosedLog: SOLANA_NATIVE_VERIFIER_GOVERNED_MATERIAL_NOT_LINKED_LOG,
      productionProofMaterial: false,
    };
    verifierMaterialHash = sha256JsonHex(materialDescriptor);
    configDescriptor = {
      schema: "iroha-demo-sccp-solana-native-verifier-failclosed-config/v1",
      routeId: SCCP_SOLANA_XOR_ROUTE_ID,
      verifierProgramId: verifierProgramId.toBase58(),
      verifierStateAddress: verifierStateAddress.toBase58(),
      nativeVerifierProgramId,
      verifierMaterialHash,
      productionReady: false,
    };
    verifierConfigHash = sha256JsonHex(configDescriptor);
  }
  if (governedPackageValidation) {
    const refreshed = await loadGovernedPackageSelection();
    if (
      refreshed.packageArtifact.sha256 !== governedPackageArtifact.sha256 ||
      refreshed.manifestArtifact.sha256 !== governedManifestArtifact.sha256 ||
      refreshed.validation.ready !== true ||
      refreshed.manifestBinding.ready !== true ||
      refreshed.validation.verifierMaterialHash !== verifierMaterialHash ||
      refreshed.validation.verifierConfigHash !== verifierConfigHash
    ) {
      throw new Error(
        "Governed native-verifier package or manifest binding changed before configuration signing.",
      );
    }
    governedPackageArtifact = refreshed.packageArtifact;
    governedManifestArtifact = refreshed.manifestArtifact;
    governedPackageValidation = refreshed.validation;
    governedManifestBinding = refreshed.manifestBinding;
  }
  const operationBinding = {
    authority: publicConfig.deployerAddress,
    governedPackageArtifactSha256: governedPackageArtifact?.sha256 ?? null,
    governedManifestArtifactSha256: governedManifestArtifact?.sha256 ?? null,
    governanceApprovalSha256:
      governedPackageValidation?.governanceApproval?.approvalSha256 ?? null,
    nativeVerifierArtifactSha256,
    nativeVerifierProgramId,
    verifierMaterialHash,
    verifierConfigHash,
  };
  const priorConfigurationMutation =
    await reconcileExistingSolanaOneShotMutation({
      connection,
      intentPath: mutationJournalPaths.intent,
      resolutionPath: mutationJournalPaths.resolution,
      expectedOperation: "native-verifier-configuration",
      expectedTarget: mutationTarget,
      expectedOperationBinding: operationBinding,
    });
  if (
    priorConfigurationMutation &&
    priorConfigurationMutation.intent.operation !==
      "native-verifier-configuration"
  ) {
    throw new Error(
      "Existing Solana native-verifier configuration intent has the wrong operation identity.",
    );
  }
  const currentStateReadback = await readSolanaAccountWithContext(
    connection,
    verifierStateAddress.toBase58(),
    "Solana SCCP verifier state before native-verifier configuration",
    solanaRpcRetryOptions(args),
  );
  const currentConfiguredState = parseSolanaSccpStateAccountData(
    currentStateReadback.info.data,
  );
  if (currentConfiguredState.verifierConfiguredSlot !== null) {
    const reconstructionAccounts = await readOptionalJson(
      path.resolve(args.accounts || paths.accountsReport),
    );
    const reconstructionLiveReadback =
      await readSolanaVerifierLinkageLiveReadback({
        args,
        manifest: governedManifestArtifact.value,
        publicConfig,
        accounts: reconstructionAccounts,
      });
    const reconstructionLinkage = buildSolanaVerifierLinkageReadinessReportBody(
      {
        args,
        manifest: governedManifestArtifact.value,
        publicConfig,
        accounts: reconstructionAccounts,
        nativeVerifierConfiguration: null,
        liveReadback: reconstructionLiveReadback,
        nativeVerifierBytes,
      },
    );
    const exactExistingConfiguration =
      currentConfiguredState.nativeVerifierProgramId ===
        nativeVerifierProgramAddress.toBase58() &&
      currentConfiguredState.verifierMaterialHash === verifierMaterialHash &&
      currentConfiguredState.verifierConfigHash === verifierConfigHash &&
      (!priorConfigurationMutation ||
        (currentConfiguredState.verifierConfiguredSlot ===
          String(priorConfigurationMutation.resolution.finalizedSlot) &&
          currentStateReadback.contextSlot >=
            priorConfigurationMutation.resolution.finalizedSlot)) &&
      reconstructionLinkage.ready === true;
    if (!exactExistingConfiguration) {
      throw new Error(
        "The one-shot Solana native-verifier state is already configured with different governed hashes.",
      );
    }
    const reconstructedReport = {
      schema: "iroha-demo-sccp-solana-native-verifier-configure/v1",
      checkedAt: new Date().toISOString(),
      ready: true,
      configured: true,
      productionReady: true,
      mode: "idempotent-live-state-reconstruction",
      reason:
        "Reconstructed the exact governed native-verifier configuration report from finalized live state without signing or mutating.",
      nativeVerifierSo,
      nativeVerifierArtifactSha256,
      nativeVerifierProgramId,
      verifierProgramId: verifierProgramId.toBase58(),
      verifierStateAddress: verifierStateAddress.toBase58(),
      deploySignature: null,
      configureSignature: null,
      explorerUrl: null,
      materialDescriptor,
      configDescriptor,
      verifierMaterialHash,
      verifierConfigHash,
      configuredState: {
        address: verifierStateAddress.toBase58(),
        contextSlot: currentStateReadback.contextSlot,
        parsed: currentConfiguredState,
        dataSha256: sha256BufferHex(currentStateReadback.info.data),
      },
      verifierLinkageReadiness: reconstructionLinkage,
      governedPackageValidation,
      governedPackageArtifactSha256: governedPackageArtifact?.sha256 ?? null,
      governedManifestArtifactSha256: governedManifestArtifact?.sha256 ?? null,
      governedManifestBinding,
      priorMutationResolution: priorConfigurationMutation
        ? {
            schema: priorConfigurationMutation.resolution.schema,
            operation: priorConfigurationMutation.resolution.operation,
            status: priorConfigurationMutation.resolution.status,
            expectedSignature:
              priorConfigurationMutation.resolution.expectedSignature,
            finalizedSlot: priorConfigurationMutation.resolution.finalizedSlot,
            intentSha256: priorConfigurationMutation.resolution.intentSha256,
            resolutionSha256:
              priorConfigurationMutation.resolution.resolutionSha256,
            intentArtifactSha256:
              priorConfigurationMutation.intentArtifactSha256,
            resolutionArtifactSha256:
              priorConfigurationMutation.resolutionArtifactSha256,
            routeAbsencePublicPreflightArtifactSha256:
              priorConfigurationMutation.intent.bindings
                ?.routeAbsencePublicPreflightArtifactSha256 ?? null,
            routeAbsenceMutationAuthorization:
              priorConfigurationMutation.intent.bindings
                ?.routeAbsenceMutationAuthorization ?? null,
          }
        : null,
      routeAbsenceFence: null,
      nativeVerifierLiveReadiness,
      nativeVerifierProgramdataAddress:
        nativeVerifierLiveReadiness?.liveNativeVerifier?.programdataAddress ??
        null,
      nativeVerifierProgramdataSlot:
        nativeVerifierLiveReadiness?.liveNativeVerifier?.programdataSlot ??
        null,
      nativeVerifierCodeHash:
        nativeVerifierLiveReadiness?.liveNativeVerifier?.codeHash ?? null,
      nativeVerifierKeyHash:
        governedPackageValidation?.expectedNativeVerifier?.verifierKeyHash ??
        null,
      nativeVerifierGovernanceApprovalEvidenceHash:
        governedPackageValidation?.expectedNativeVerifier
          ?.governanceApprovalEvidenceHash ?? null,
      blockerIds: [],
    };
    await writePublicJson(
      paths.nativeVerifierConfigureReport,
      reconstructedReport,
    );
    return {
      nativeVerifierDeployLogPath: null,
      nativeVerifierConfigureReportPath: paths.nativeVerifierConfigureReport,
      nativeVerifierConfigurationIntentPath: mutationJournalPaths.intent,
      nativeVerifierConfigurationResolutionPath:
        mutationJournalPaths.resolution,
      report: reconstructedReport,
    };
  }
  if (priorConfigurationMutation) {
    throw new Error(
      "A finalized native-verifier configuration intent did not produce the exact governed one-shot state; no replacement transaction is permitted.",
    );
  }
  if (args[SOLANA_NATIVE_CONFIG_RECONSTRUCTION_ONLY] === true) {
    throw new Error(
      "Read-only native-verifier configuration report reconstruction found unconfigured live state; mutation remains required.",
    );
  }
  const configurationRouteAbsenceFence =
    await runFreshSolanaRouteAbsenceMutationFence(args, {
      stage: "configure-native-verifier-route-absence-fence",
    });
  let configurationBroadcastFence = null;
  const deployer = runtimeSolanaSigner({
    args,
    expectedAddress: publicConfig.deployerAddress,
    label: "Solana native verifier configuration",
  });
  let configuration;
  try {
    configuration = await configureSolanaNativeVerifierState({
      connection,
      deployer,
      verifierProgramId,
      verifierStateAddress,
      nativeVerifierProgramId: nativeVerifierProgramAddress,
      verifierMaterialHash,
      verifierConfigHash,
      beforeBroadcast: async () => {
        configurationBroadcastFence =
          await runFreshSolanaRouteAbsenceMutationFence(args, {
            stage:
              "configure-native-verifier-route-absence-fence-before-broadcast",
          });
        return configurationBroadcastFence.report;
      },
      persistIntent: ({ intent }) =>
        persistSolanaOneShotMutationIntent({
          file: mutationJournalPaths.intent,
          intent,
        }),
      persistResolution: ({ intent, resolution }) =>
        persistSolanaOneShotMutationResolution({
          file: mutationJournalPaths.resolution,
          intent,
          resolution,
        }),
      resolveAmbiguousIntent: ({ intent }) =>
        resolveSolanaOneShotMutationIntent({ connection, intent }),
      intentBindings: {
        governedPackageArtifactSha256: governedPackageArtifact?.sha256 ?? null,
        governedManifestArtifactSha256:
          governedManifestArtifact?.sha256 ?? null,
        governanceApprovalSha256:
          governedPackageValidation?.governanceApproval?.approvalSha256 ?? null,
        nativeVerifierArtifactSha256,
        routeAbsenceBeforeSignerArtifactSha256:
          configurationRouteAbsenceFence.reportArtifactSha256 ??
          configurationRouteAbsenceFence.report
            ?.publicPreflightArtifactSha256 ??
          null,
      },
      mutationTarget,
      operationBinding,
    });
  } catch (error) {
    const mutationAmbiguous = error?.mutationAmbiguous === true;
    const mutationAttempted = error?.mutationAttempted === true;
    const blocked = {
      schema: "iroha-demo-sccp-solana-native-verifier-configure/v1",
      checkedAt: new Date().toISOString(),
      ready: false,
      configured: false,
      productionReady: false,
      reason: mutationAttempted
        ? "The one-shot native verifier configuration transaction has durable intent evidence but is not safely resolved; no replacement transaction is permitted."
        : "The one-shot native verifier configuration requires both the outer and native verifier ProgramData accounts to be immutable first.",
      nativeVerifierSo,
      nativeVerifierArtifactSha256,
      nativeVerifierProgramId,
      verifierProgramId: verifierProgramId.toBase58(),
      verifierStateAddress: verifierStateAddress.toBase58(),
      governedPackageValidation,
      nativeVerifierLiveReadiness,
      configurationReadiness: error?.configurationReadiness ?? null,
      mutationAttempted,
      mutationSubmitted: error?.mutationSubmitted === true,
      mutationAmbiguous,
      transactionHash: error?.transactionHash ?? null,
      blockerIds: error?.configurationReadiness?.blockerIds ?? [
        mutationAmbiguous
          ? "solana-native-verifier-configuration-ambiguous"
          : "solana-native-verifier-configuration-readiness",
      ],
      error: error instanceof Error ? error.message : String(error),
    };
    await writePublicJson(paths.nativeVerifierConfigureReport, blocked);
    throw error;
  } finally {
    deployer.secretKey.fill(0);
  }
  const productionReady = Boolean(
    governedPackageValidation?.ready === true &&
      nativeVerifierLiveReadiness?.ready === true &&
      configuration.configuredStateReady,
  );
  const report = {
    schema: "iroha-demo-sccp-solana-native-verifier-configure/v1",
    checkedAt: new Date().toISOString(),
    ready: productionReady,
    configured: configuration.configuredStateReady,
    productionReady,
    reason: productionReady
      ? "Configured reviewed governed native verifier material after immutable live ProgramData and code pins matched."
      : "Configured a distinct fail-closed native verifier CPI target. It validates CPI envelope shape and rejects every proof until governed native recursive verifier material exists.",
    nativeVerifierSo,
    nativeVerifierArtifactSha256,
    nativeVerifierProgramId,
    verifierProgramId: verifierProgramId.toBase58(),
    verifierStateAddress: verifierStateAddress.toBase58(),
    deploySignature:
      output.match(/Signature:\s+([1-9A-HJ-NP-Za-km-z]+)/u)?.[1] ?? null,
    configureSignature: configuration.configureSignature,
    transactionFinalizedSlot: configuration.finalizedSlot,
    mutationIntentSha256: configuration.mutationIntent.intentSha256,
    mutationPacketSha256: configuration.mutationIntent.packetSha256,
    mutationMessageSha256: configuration.mutationIntent.messageSha256,
    mutationIntentArtifactSha256: configuration.intentArtifactSha256,
    mutationResolutionArtifactSha256: configuration.resolutionArtifactSha256,
    mutationIntentPath: mutationJournalPaths.intent,
    mutationResolutionPath: mutationJournalPaths.resolution,
    explorerUrl: `https://explorer.solana.com/tx/${configuration.configureSignature}?cluster=testnet`,
    materialDescriptor,
    configDescriptor,
    verifierMaterialHash,
    verifierConfigHash,
    configuredState: configuration.configuredState,
    configurationReadiness: configuration.configurationReadiness,
    governedPackageValidation,
    governedPackageArtifactSha256: governedPackageArtifact?.sha256 ?? null,
    governedManifestArtifactSha256: governedManifestArtifact?.sha256 ?? null,
    governedManifestBinding,
    routeAbsenceFence: {
      beforeSigner: configurationRouteAbsenceFence.report,
      beforeBroadcast: configurationBroadcastFence?.report ?? null,
    },
    nativeVerifierLiveReadiness,
    nativeVerifierProgramdataAddress:
      nativeVerifierLiveReadiness?.liveNativeVerifier?.programdataAddress ??
      null,
    nativeVerifierProgramdataSlot:
      nativeVerifierLiveReadiness?.liveNativeVerifier?.programdataSlot ?? null,
    nativeVerifierCodeHash:
      nativeVerifierLiveReadiness?.liveNativeVerifier?.codeHash ?? null,
    nativeVerifierKeyHash:
      governedPackageValidation?.expectedNativeVerifier?.verifierKeyHash ??
      null,
    nativeVerifierGovernanceApprovalEvidenceHash:
      governedPackageValidation?.expectedNativeVerifier
        ?.governanceApprovalEvidenceHash ?? null,
    blockerIds: productionReady ? [] : ["governed-native-verifier-material"],
  };
  await writePublicJson(paths.nativeVerifierConfigureReport, report);
  return {
    nativeVerifierDeployLogPath: null,
    nativeVerifierConfigureReportPath: paths.nativeVerifierConfigureReport,
    nativeVerifierConfigurationIntentPath: mutationJournalPaths.intent,
    nativeVerifierConfigurationResolutionPath: mutationJournalPaths.resolution,
    report,
  };
};

const finalizationStatus = ({
  key,
  description,
  present,
  invalid = false,
  value = null,
  expected = null,
  source = null,
  error = null,
  blockerId = null,
}) => ({
  key,
  description,
  status: present ? "present" : invalid ? "invalid" : "missing",
  value,
  expected,
  source,
  error,
  blockerId,
});

const buildSolanaProgramFinalizationBlockers = (statuses) =>
  statuses
    .filter((status) => status.status !== "present")
    .map((status) => ({
      id: status.blockerId || `program-finalization-${status.key}`,
      key: status.key,
      detail: status.description,
      status: status.status,
      value: status.value ?? null,
      expected: status.expected ?? null,
      error: status.error ?? null,
    }));

const buildSolanaProgramdataExecutableNormalization = ({
  artifactBytes,
  liveProgramdata,
} = {}) => {
  const artifact = artifactBytes ? Buffer.from(artifactBytes) : null;
  const liveExecutable = liveProgramdata?.executableBytes
    ? Buffer.from(liveProgramdata.executableBytes)
    : null;
  if (
    !artifact ||
    !liveExecutable ||
    liveExecutable.length <= artifact.length
  ) {
    return null;
  }
  const livePrefix = liveExecutable.subarray(0, artifact.length);
  const padding = liveExecutable.subarray(artifact.length);
  const prefixMatches = livePrefix.equals(artifact);
  const zeroPaddingOnly = prefixMatches
    ? padding.every((byte) => byte === 0)
    : false;
  const base = {
    artifactExecutableLength: artifact.length,
    liveExecutableLength: liveExecutable.length,
    zeroPaddingBytes: padding.length,
    prefixMatches,
    zeroPaddingOnly,
  };
  if (!prefixMatches || !zeroPaddingOnly) {
    return {
      ...base,
      normalized: false,
      reason: prefixMatches
        ? "live-programdata-tail-is-not-zero-padding"
        : "live-programdata-prefix-does-not-match-local-artifact",
    };
  }
  return {
    ...base,
    normalized: true,
    reason: "live-programdata-zero-padded-local-artifact",
    executableSha256: sha256BufferHex(liveExecutable),
    executableBlake2b256: solanaExecutableBlake2b256(liveExecutable),
  };
};

const finalizationManifestRecords = (manifest, keys) =>
  keys.map((key) => manifest?.[key]).filter((value) => isRecord(value));

const finalizationAliasedString = (records, keys, label) => {
  const values = [];
  for (const record of records) {
    for (const key of keys) {
      if (!Object.hasOwn(record ?? {}, key)) {
        continue;
      }
      const value = record[key];
      if (typeof value !== "string" || !value.trim()) {
        return { value: "", error: `${label} aliases must be strings.` };
      }
      values.push(value.trim());
    }
  }
  if (values.length === 0) {
    return { value: "", error: `${label} is missing.` };
  }
  if (values.some((value) => value !== values[0])) {
    return { value: values[0], error: `${label} aliases disagree.` };
  }
  return { value: values[0], error: null };
};

const buildSolanaFinalizationManifestAliasValidation = (manifest) => {
  if (!isRecord(manifest)) {
    return {
      errors: ["Selected Solana route manifest is missing."],
      verifierCodeHash: "",
      admissionMode: "",
      proofSystem: "",
      proofVerificationMode: "",
      productionReady: false,
    };
  }
  const admissionRecords = finalizationManifestRecords(manifest, [
    "destinationProofAdmission",
    "destination_proof_admission",
    "solanaDestinationProofAdmission",
    "solana_destination_proof_admission",
    "verifierAdmission",
    "verifier_admission",
  ]);
  const enforcementRecords = [
    ...finalizationManifestRecords(manifest, [
      "verifierEnforcement",
      "verifier_enforcement",
      "destinationVerifierEnforcement",
      "destination_verifier_enforcement",
      "destinationRollout",
      "destination_rollout",
      "productionReadiness",
      "production_readiness",
    ]),
    ...admissionRecords,
    manifest,
  ];
  const checks = {
    routeId: finalizationAliasedString(
      [manifest],
      ["routeId", "route_id"],
      "manifest.routeId",
    ),
    assetKey: finalizationAliasedString(
      [manifest],
      ["assetKey", "asset_key"],
      "manifest.assetKey",
    ),
    verifierCodeHash: finalizationAliasedString(
      [manifest, ...admissionRecords],
      ["verifierCodeHash", "verifier_code_hash"],
      "manifest.verifierCodeHash",
    ),
    verifierArtifactSha256: finalizationAliasedString(
      [manifest],
      ["verifierProgramArtifactSha256", "verifier_program_artifact_sha256"],
      "manifest.verifierProgramArtifactSha256",
    ),
    destinationBindingHash: finalizationAliasedString(
      [manifest, ...admissionRecords],
      ["destinationBindingHash", "destination_binding_hash"],
      "manifest.destinationBindingHash",
    ),
    admissionMode: finalizationAliasedString(
      admissionRecords,
      ["admissionMode", "admission_mode"],
      "manifest.destinationProofAdmission.admissionMode",
    ),
    proofSystem: finalizationAliasedString(
      admissionRecords,
      ["proofSystem", "proof_system", "proofFamily", "proof_family"],
      "manifest.destinationProofAdmission.proofSystem",
    ),
    proofVerificationMode: finalizationAliasedString(
      enforcementRecords,
      [
        "proofVerificationMode",
        "proof_verification_mode",
        "verifierEnforcementMode",
        "verifier_enforcement_mode",
      ],
      "manifest.proofVerificationMode",
    ),
  };
  const errors = [
    checks.routeId,
    checks.assetKey,
    checks.verifierCodeHash,
    checks.verifierArtifactSha256,
    checks.destinationBindingHash,
  ]
    .map((check) => check.error)
    .filter(Boolean);
  for (const check of [
    checks.admissionMode,
    checks.proofSystem,
    checks.proofVerificationMode,
  ]) {
    if (check.error && !check.error.endsWith(" is missing.")) {
      errors.push(check.error);
    }
  }
  if (checks.routeId.value !== SCCP_SOLANA_XOR_ROUTE_ID) {
    errors.push(`manifest.routeId must be ${SCCP_SOLANA_XOR_ROUTE_ID}.`);
  }
  if (checks.assetKey.value !== SCCP_XOR_ASSET_KEY) {
    errors.push(`manifest.assetKey must be ${SCCP_XOR_ASSET_KEY}.`);
  }
  let productionReady = false;
  try {
    productionReady =
      readManifestBooleanAlias(
        manifest,
        "productionReady",
        "production_ready",
        "manifest.productionReady",
      ) === true;
  } catch (error) {
    errors.push(error instanceof Error ? error.message : String(error));
  }
  for (const [label, keys] of [
    [
      "manifest native verifier program id",
      [
        "solanaNativeVerifierProgramId",
        "solana_native_verifier_program_id",
        "nativeVerifierProgramId",
        "native_verifier_program_id",
      ],
    ],
    [
      "manifest native verifier ProgramData address",
      [
        "solanaNativeVerifierProgramdataAddress",
        "solana_native_verifier_programdata_address",
        "nativeVerifierProgramdataAddress",
        "native_verifier_programdata_address",
      ],
    ],
    [
      "manifest native verifier code hash",
      [
        "solanaNativeVerifierCodeHash",
        "solana_native_verifier_code_hash",
        "nativeVerifierCodeHash",
        "native_verifier_code_hash",
      ],
    ],
    [
      "manifest native verifier artifact SHA-256",
      [
        "solanaNativeVerifierArtifactSha256",
        "solana_native_verifier_artifact_sha256",
        "nativeVerifierArtifactSha256",
        "native_verifier_artifact_sha256",
      ],
    ],
    [
      "manifest native verifier material hash",
      [
        "solanaNativeVerifierMaterialHash",
        "solana_native_verifier_material_hash",
        "nativeVerifierMaterialHash",
        "native_verifier_material_hash",
      ],
    ],
    [
      "manifest native verifier config hash",
      [
        "solanaNativeVerifierConfigHash",
        "solana_native_verifier_config_hash",
        "nativeVerifierConfigHash",
        "native_verifier_config_hash",
      ],
    ],
  ]) {
    const check = finalizationAliasedString(enforcementRecords, keys, label);
    if (check.error) {
      errors.push(check.error);
    }
  }
  return {
    errors: [...new Set(errors)],
    verifierCodeHash: checks.verifierCodeHash.value,
    verifierArtifactSha256: checks.verifierArtifactSha256.value,
    destinationBindingHash: checks.destinationBindingHash.value,
    admissionMode: checks.admissionMode.value,
    proofSystem: checks.proofSystem.value,
    proofVerificationMode: checks.proofVerificationMode.value,
    productionReady,
  };
};

export const buildSolanaProgramFinalizationReadinessReportBody = ({
  args = {},
  programSo = null,
  programBytes = null,
  programReadError = null,
  nativeVerifierSo = null,
  nativeVerifierBytes = null,
  nativeVerifierReadError = null,
  nativeVerifierConfigReportInput = null,
  governedNativeVerifierValidation = null,
  manifest = null,
  liveReadback = null,
  checkedAt = new Date().toISOString(),
} = {}) => {
  const bytes = programBytes ? Buffer.from(programBytes) : null;
  const artifactPresent = Boolean(bytes) && !programReadError;
  const executableMagic = bytes?.subarray(0, 4).toString("hex") ?? null;
  const executableElf = executableMagic === SOLANA_BPF_ELF_MAGIC;
  const artifactSha256 = bytes ? sha256BufferHex(bytes) : null;
  const artifactBlake2b256 = bytes ? solanaExecutableBlake2b256(bytes) : null;
  const liveProgramdata = liveReadback?.parsedProgramdata ?? null;
  const programdataExecutableNormalization =
    buildSolanaProgramdataExecutableNormalization({
      artifactBytes: bytes,
      liveProgramdata,
    });
  const deploymentNormalizedExecutable =
    programdataExecutableNormalization?.normalized === true
      ? programdataExecutableNormalization
      : null;
  const verifierCodeHashForFinalization =
    deploymentNormalizedExecutable?.executableBlake2b256 ?? artifactBlake2b256;
  const verifierCodeHashForFinalizationSource =
    deploymentNormalizedExecutable?.reason ?? "local-artifact";
  const failClosedSentinelPresent =
    bytes?.includes(
      Buffer.from(SOLANA_VERIFIER_FAIL_CLOSED_SENTINEL, "utf8"),
    ) === true;
  const nativeVerifierCpiMarkerPresent =
    bytes?.includes(Buffer.from(SOLANA_NATIVE_VERIFIER_CPI_MARKER, "utf8")) ===
    true;
  const manifestAliasValidation =
    buildSolanaFinalizationManifestAliasValidation(manifest);
  const expectedVerifierCodeHash = manifestAliasValidation.verifierCodeHash;
  const expectedVerifierArtifactSha256 =
    manifestAliasValidation.verifierArtifactSha256;
  const expectedDestinationBindingHash =
    manifestAliasValidation.destinationBindingHash;
  let normalizedExpectedVerifierCodeHash = "";
  let verifierCodeHashError = null;
  let normalizedExpectedVerifierArtifactSha256 = "";
  let verifierArtifactSha256Error = null;
  let normalizedExpectedDestinationBindingHash = "";
  let destinationBindingHashError = null;
  try {
    normalizedExpectedVerifierCodeHash = normalizeOptionalManifestHex32(
      expectedVerifierCodeHash,
      "verifierCodeHash",
    );
  } catch (error) {
    verifierCodeHashError =
      error instanceof Error ? error.message : String(error);
  }
  try {
    normalizedExpectedVerifierArtifactSha256 = normalizeProductionMaterialHex32(
      expectedVerifierArtifactSha256,
      "verifierProgramArtifactSha256",
    );
  } catch (error) {
    verifierArtifactSha256Error =
      error instanceof Error ? error.message : String(error);
  }
  try {
    normalizedExpectedDestinationBindingHash = normalizeManifestHex32(
      expectedDestinationBindingHash,
      "destinationBindingHash",
    );
  } catch (error) {
    destinationBindingHashError =
      error instanceof Error ? error.message : String(error);
  }
  const admissionMode = manifestAliasValidation.admissionMode;
  const proofSystem = manifestAliasValidation.proofSystem;
  const proofVerificationMode = manifestAliasValidation.proofVerificationMode;
  const manifestProductionReady = manifestAliasValidation.productionReady;
  const manifestPublicKey = (keys) => {
    const value = readFirstManifestString(manifest, ...keys);
    if (!value) {
      return "";
    }
    try {
      return new PublicKey(value).toBase58();
    } catch {
      return "";
    }
  };
  const outerVerifierProgramId = manifestPublicKey([
    "solanaVerifierProgramId",
    "solana_verifier_program_id",
  ]);
  const verifierStateAddress = manifestPublicKey([
    "solanaVerifierStateAddress",
    "solana_verifier_state_address",
  ]);
  const tokenMintAddress = manifestPublicKey([
    "solanaTokenMint",
    "solana_token_mint",
    "tairaXorTokenAddress",
    "taira_xor_token_address",
  ]);
  const governedValidationSchemaReady =
    governedNativeVerifierValidation?.schema ===
      "iroha-demo-sccp-solana-governed-native-verifier-validation/v1" &&
    governedNativeVerifierValidation?.ready === true &&
    governedNativeVerifierValidation?.productionReady === true &&
    Array.isArray(governedNativeVerifierValidation?.statuses) &&
    governedNativeVerifierValidation.statuses.length > 0 &&
    governedNativeVerifierValidation.statuses.every(
      (status) => status?.status === "present",
    );
  let governedPackageSha256 = "";
  try {
    governedPackageSha256 = normalizeProductionMaterialHex32(
      governedNativeVerifierValidation?.packageSha256,
      "governed native verifier package SHA-256",
    );
  } catch {
    governedPackageSha256 = "";
  }
  const governedPreconfigurationIntentReady =
    governedValidationSchemaReady && Boolean(governedPackageSha256);
  const governedIntentProofSystem =
    governedNativeVerifierValidation?.materialDescriptor?.proofSystem ?? null;
  const governedIntentProofVerificationMode =
    governedNativeVerifierValidation?.configDescriptor?.proofVerificationMode ??
    null;
  const governedExpectedNativeVerifier =
    governedNativeVerifierValidation?.expectedNativeVerifier ?? {};
  const manifestNativeVerifierPins = resolveSolanaNativeVerifierPins({
    manifest,
    nativeVerifierConfiguration: null,
  });
  const governedNativePinPairs = [
    ["programId", governedExpectedNativeVerifier.programId],
    ["programdataAddress", governedExpectedNativeVerifier.programdataAddress],
    ["programdataSlot", governedExpectedNativeVerifier.programdataSlot],
    ["artifactSha256", governedExpectedNativeVerifier.artifactSha256],
    ["codeHash", governedExpectedNativeVerifier.codeHash],
    [
      "verifierMaterialHash",
      governedNativeVerifierValidation?.verifierMaterialHash,
    ],
    [
      "verifierConfigHash",
      governedNativeVerifierValidation?.verifierConfigHash,
    ],
    ["verifierKeyHash", governedExpectedNativeVerifier.verifierKeyHash],
    [
      "governanceApprovalEvidenceHash",
      governedExpectedNativeVerifier.governanceApprovalEvidenceHash,
    ],
  ];
  const governedNativePinsMatch =
    governedPreconfigurationIntentReady &&
    governedNativePinPairs.every(
      ([key, expected]) =>
        typeof expected === "string" &&
        expected.length > 0 &&
        String(manifestNativeVerifierPins[key] ?? "") === String(expected),
    );
  let verifierCodeHashOverrideError = null;
  const verifierCodeHashOverride = args["expected-verifier-code-hash"];
  if (verifierCodeHashOverride !== undefined) {
    try {
      const normalizedOverride = normalizeManifestHex32(
        verifierCodeHashOverride,
        "--expected-verifier-code-hash",
      );
      if (normalizedOverride !== normalizedExpectedVerifierCodeHash) {
        verifierCodeHashOverrideError =
          "--expected-verifier-code-hash must equal the selected manifest verifierCodeHash.";
      }
    } catch (error) {
      verifierCodeHashOverrideError =
        error instanceof Error ? error.message : String(error);
    }
  }
  const confirmFinalizeLinkedVerifier = asBoolean(
    args["confirm-finalize-linked-verifier"],
  );
  const alreadyFinalizedNoOpAssessment =
    args[SOLANA_FINISH_ALREADY_FINALIZED_NOOP] === true;
  const finalizationConfirmationSatisfied =
    confirmFinalizeLinkedVerifier || alreadyFinalizedNoOpAssessment;
  const verifierLinkageReadiness =
    buildSolanaVerifierLinkageReadinessReportBody({
      args,
      manifest,
      liveReadback,
      nativeVerifierBytes,
      readbackError: liveReadback
        ? null
        : "Live Solana verifier linkage readback is unavailable.",
      checkedAt,
    });
  const nativeVerifierLinkageStatuses =
    verifierLinkageReadiness.statuses.filter(
      (status) =>
        status.key.startsWith("nativeVerifier") &&
        !status.key.startsWith("nativeVerifierState"),
    );
  const nativeVerifierLinkageReady =
    nativeVerifierLinkageStatuses.length > 0 &&
    nativeVerifierLinkageStatuses.every(
      (status) => status.status === "present",
    );
  const preconfigurationExcludedStatusKeys = new Set([
    "programImmutable",
    "nativeVerifierStateReadback",
    "nativeVerifierStateProgramId",
    "nativeVerifierStateMaterialHash",
    "nativeVerifierStateConfigHash",
    "proofVerificationMode",
  ]);
  const finalizationLinkageStatuses = verifierLinkageReadiness.statuses.filter(
    (status) => !preconfigurationExcludedStatusKeys.has(status.key),
  );
  const finalizationLinkageBlockers = buildSolanaVerifierLinkageBlockers(
    finalizationLinkageStatuses,
  );
  const finalizationLinkageReady = finalizationLinkageBlockers.length === 0;
  const verifierStateConfigured = verifierLinkageReadiness.ready === true;
  const statuses = [
    finalizationStatus({
      key: "governedPreconfigurationIntent",
      description:
        "A strict validation report for the reviewed governed native-verifier package, including its public package SHA-256, is required before irreversible outer finalization.",
      present: governedPreconfigurationIntentReady,
      invalid: Boolean(governedNativeVerifierValidation),
      value: governedPackageSha256 || null,
      expected:
        "reviewed governed package validation with a non-placeholder hash",
      blockerId: "program-finalization-governed-preconfiguration-intent",
    }),
    finalizationStatus({
      key: "governedNativeVerifierPins",
      description:
        "Every native-verifier manifest pin must exactly match the reviewed governed package validation rather than a self-asserted intent record.",
      present: governedNativePinsMatch,
      invalid: Boolean(manifest),
      value: manifestNativeVerifierPins,
      expected: governedPreconfigurationIntentReady
        ? Object.fromEntries(
            governedNativePinPairs.map(([key, value]) => [key, value ?? null]),
          )
        : "validated governed package pins",
      blockerId: "program-finalization-governed-native-verifier-pins",
    }),
    finalizationStatus({
      key: "outerVerifierProgramPin",
      description:
        "The live outer verifier program id and verifier state owner must match the reviewed manifest program pin.",
      present:
        Boolean(outerVerifierProgramId) &&
        liveReadback?.program?.address === outerVerifierProgramId &&
        liveReadback?.state?.owner === outerVerifierProgramId,
      invalid: Boolean(
        liveReadback?.program?.address || outerVerifierProgramId,
      ),
      value: {
        manifest: outerVerifierProgramId || null,
        live: liveReadback?.program?.address ?? null,
        stateOwner: liveReadback?.state?.owner ?? null,
      },
      expected: outerVerifierProgramId || "canonical outer verifier program id",
      blockerId: "program-finalization-outer-program-pin",
    }),
    finalizationStatus({
      key: "outerVerifierArtifactSha256",
      description:
        "The exact local outer verifier artifact SHA-256 must match the reviewed manifest artifact pin.",
      present:
        Boolean(normalizedExpectedVerifierArtifactSha256) &&
        artifactSha256 === normalizedExpectedVerifierArtifactSha256,
      invalid: Boolean(
        verifierArtifactSha256Error ||
          artifactSha256 ||
          normalizedExpectedVerifierArtifactSha256,
      ),
      value: artifactSha256,
      expected: normalizedExpectedVerifierArtifactSha256 || null,
      error: verifierArtifactSha256Error,
      blockerId: "program-finalization-outer-artifact-sha256",
    }),
    finalizationStatus({
      key: "verifierStatePin",
      description:
        "The live initialized outer verifier state address must match the reviewed manifest state pin.",
      present:
        Boolean(verifierStateAddress) &&
        liveReadback?.state?.address === verifierStateAddress,
      invalid: Boolean(liveReadback?.state?.address || verifierStateAddress),
      value: liveReadback?.state?.address ?? null,
      expected: verifierStateAddress || null,
      blockerId: "program-finalization-verifier-state-pin",
    }),
    finalizationStatus({
      key: "tokenMintPin",
      description:
        "The mint stored in the initialized outer verifier state must match the reviewed manifest SPL mint pin.",
      present:
        Boolean(tokenMintAddress) &&
        liveReadback?.parsedState?.storedMint === tokenMintAddress,
      invalid: Boolean(
        liveReadback?.parsedState?.storedMint || tokenMintAddress,
      ),
      value: liveReadback?.parsedState?.storedMint ?? null,
      expected: tokenMintAddress || null,
      blockerId: "program-finalization-token-mint-pin",
    }),
    finalizationStatus({
      key: "destinationBindingPin",
      description:
        "The reviewed destination binding hash must be the canonical taira_sol_xor Solana settlement binding.",
      present:
        normalizedExpectedDestinationBindingHash ===
        SOLANA_DESTINATION_BINDING_HASH,
      invalid: Boolean(
        destinationBindingHashError || normalizedExpectedDestinationBindingHash,
      ),
      value: normalizedExpectedDestinationBindingHash || null,
      expected: SOLANA_DESTINATION_BINDING_HASH,
      error: destinationBindingHashError,
      blockerId: "program-finalization-destination-binding-pin",
    }),
    finalizationStatus({
      key: "programArtifactPresent",
      description: "Compiled Solana SBF artifact must be readable.",
      present: artifactPresent,
      invalid: Boolean(programReadError),
      value: programSo,
      expected: "readable BPF ELF artifact",
      error: programReadError,
      blockerId: "program-artifact",
    }),
    finalizationStatus({
      key: "programArtifactElf",
      description: "Compiled Solana SBF artifact must be a BPF ELF.",
      present: artifactPresent && executableElf,
      invalid: artifactPresent && !executableElf,
      value: executableMagic,
      expected: SOLANA_BPF_ELF_MAGIC,
      blockerId: "program-artifact-elf",
    }),
    finalizationStatus({
      key: "failClosedSentinelAbsent",
      description:
        "Compiled Solana SBF must not contain the unlinked native recursive verifier sentinel.",
      present: artifactPresent && !failClosedSentinelPresent,
      invalid: artifactPresent && failClosedSentinelPresent,
      value: artifactPresent ? !failClosedSentinelPresent : null,
      expected: true,
      blockerId: "program-finalization-fail-closed-sentinel",
    }),
    finalizationStatus({
      key: "nativeVerifierCpiMarkerPresent",
      description:
        "Compiled Solana SBF must contain the native recursive verifier CPI marker.",
      present: artifactPresent && nativeVerifierCpiMarkerPresent,
      invalid: artifactPresent && !nativeVerifierCpiMarkerPresent,
      value: artifactPresent ? nativeVerifierCpiMarkerPresent : null,
      expected: true,
      blockerId: "program-finalization-verifier-cpi",
    }),
    finalizationStatus({
      key: "manifestPresent",
      description:
        "A selected Solana route manifest is required before finalization.",
      present: isRecord(manifest),
      value: Boolean(manifest),
      expected: true,
      blockerId: "program-finalization-manifest",
    }),
    finalizationStatus({
      key: "manifestAliasConsistency",
      description:
        "All selected manifest aliases and nested enforcement records must agree on route, admission, proof, and native-verifier pins.",
      present: manifestAliasValidation.errors.length === 0,
      invalid: isRecord(manifest),
      value: manifestAliasValidation.errors,
      expected: [],
      error: manifestAliasValidation.errors.join(" ") || null,
      blockerId: "program-finalization-manifest-aliases",
    }),
    finalizationStatus({
      key: "verifierCodeHashOverride",
      description:
        "A CLI expected verifier code hash, when supplied, must equal the selected manifest pin and cannot override it.",
      present: verifierCodeHashOverrideError === null,
      invalid: verifierCodeHashOverride !== undefined,
      value: verifierCodeHashOverride ?? null,
      expected: normalizedExpectedVerifierCodeHash || null,
      error: verifierCodeHashOverrideError,
      blockerId: "program-finalization-code-hash-override",
    }),
    finalizationStatus({
      key: "verifierCodeHash",
      description:
        "Compiled SBF executable BLAKE2b hash, or its exact zero-padded live ProgramData form, must match the selected route manifest verifierCodeHash before immutable finalization.",
      present:
        Boolean(normalizedExpectedVerifierCodeHash) &&
        verifierCodeHashForFinalization === normalizedExpectedVerifierCodeHash,
      invalid: Boolean(
        verifierCodeHashError ||
          verifierCodeHashForFinalization ||
          normalizedExpectedVerifierCodeHash,
      ),
      value: verifierCodeHashForFinalization,
      expected: normalizedExpectedVerifierCodeHash || null,
      source: verifierCodeHashForFinalizationSource,
      error: verifierCodeHashError,
      blockerId: "program-finalization-code-hash",
    }),
    finalizationStatus({
      key: "admissionMode",
      description:
        "Reviewed governed preconfiguration intent must authorize native recursive destination proof admission; the live route manifest remains fail-closed until configuration readback.",
      present:
        governedPreconfigurationIntentReady &&
        governedIntentProofVerificationMode ===
          SOLANA_PRODUCTION_VERIFIER_ENFORCEMENT_MODE,
      invalid: Boolean(governedNativeVerifierValidation),
      value: governedPreconfigurationIntentReady
        ? SOLANA_PRODUCTION_ADMISSION_MODE
        : null,
      expected: SOLANA_PRODUCTION_ADMISSION_MODE,
      blockerId: "program-finalization-admission-mode",
    }),
    finalizationStatus({
      key: "proofSystem",
      description:
        "Reviewed governed preconfiguration intent must pin the production Solana proof system.",
      present:
        governedPreconfigurationIntentReady &&
        governedIntentProofSystem === SOLANA_DESTINATION_PROOF_SYSTEM,
      invalid: Boolean(governedNativeVerifierValidation),
      value: governedIntentProofSystem,
      expected: SOLANA_DESTINATION_PROOF_SYSTEM,
      blockerId: "program-finalization-proof-system",
    }),
    finalizationStatus({
      key: "proofVerificationMode",
      description:
        "Reviewed governed preconfiguration intent must pin native recursive verifier enforcement.",
      present:
        governedPreconfigurationIntentReady &&
        governedIntentProofVerificationMode ===
          SOLANA_PRODUCTION_VERIFIER_ENFORCEMENT_MODE,
      invalid: Boolean(governedNativeVerifierValidation),
      value: governedIntentProofVerificationMode,
      expected: SOLANA_PRODUCTION_VERIFIER_ENFORCEMENT_MODE,
      blockerId: "program-finalization-enforcement-mode",
    }),
    finalizationStatus({
      key: "nativeVerifierLinkage",
      description:
        "The governed native verifier must already be immutable and code-pinned, while the exact outer verifier ProgramData must be ready for finalization; state configuration intentionally occurs only after outer finalization.",
      present: finalizationLinkageReady,
      invalid: Boolean(liveReadback),
      value: finalizationLinkageReady,
      expected: true,
      error: finalizationLinkageReady
        ? null
        : finalizationLinkageBlockers.map((blocker) => blocker.id).join(", "),
      blockerId: "program-finalization-native-verifier-linkage",
    }),
    finalizationStatus({
      key: "operatorConfirmation",
      description:
        "--confirm-finalize-linked-verifier true is required before immutable Solana finalization, but not when a validated canonical report proves every role is already finalized.",
      present: finalizationConfirmationSatisfied,
      value: confirmFinalizeLinkedVerifier,
      expected: true,
      blockerId: "program-finalization-confirmation",
    }),
  ];
  const blockers = buildSolanaProgramFinalizationBlockers(statuses);
  const ready = blockers.length === 0;
  return {
    schema: "iroha-demo-sccp-solana-program-finalization-readiness/v1",
    checkedAt,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    ready,
    readyToFinalizeWithCurrentInputs: ready,
    programSo,
    nativeVerifierSo,
    reviewedInputs: {
      nativeVerifierConfigReport: nativeVerifierConfigReportInput,
    },
    finalizationVerifierCodeHash: verifierCodeHashForFinalization,
    finalizationVerifierCodeHashSource: verifierCodeHashForFinalizationSource,
    programArtifact: bytes
      ? {
          sha256: artifactSha256,
          executableBlake2b256: artifactBlake2b256,
          executableLength: bytes.length,
          executableMagic,
          executableElf,
          failClosedSentinelPresent,
          nativeVerifierCpiMarkerPresent,
          deploymentNormalizedExecutable:
            deploymentNormalizedExecutable ?? null,
          liveProgramdataComparison: programdataExecutableNormalization
            ? {
                normalized: programdataExecutableNormalization.normalized,
                reason: programdataExecutableNormalization.reason,
                artifactExecutableLength:
                  programdataExecutableNormalization.artifactExecutableLength,
                liveExecutableLength:
                  programdataExecutableNormalization.liveExecutableLength,
                zeroPaddingBytes:
                  programdataExecutableNormalization.zeroPaddingBytes,
                prefixMatches: programdataExecutableNormalization.prefixMatches,
                zeroPaddingOnly:
                  programdataExecutableNormalization.zeroPaddingOnly,
              }
            : null,
        }
      : null,
    liveProgramArtifact: liveProgramdata
      ? {
          programdataAddress:
            liveReadback?.parsedProgram?.programdataAddress ?? null,
          programdataSlot: liveProgramdata.slot,
          executableBlake2b256: liveProgramdata.executableBlake2b256,
          executableSha256: liveProgramdata.executableSha256,
          executableLength: liveProgramdata.executableLength,
          executableElf: liveProgramdata.executableElf,
          failClosedSentinelPresent: liveProgramdata.failClosedSentinelPresent,
          nativeVerifierCpiMarkerPresent:
            liveProgramdata.nativeVerifierCpiMarkerPresent,
        }
      : null,
    governedPreconfigurationIntent: {
      source: "strict-governed-native-verifier-package-validation",
      reviewed: governedPreconfigurationIntentReady,
      packageSha256: governedPackageSha256 || null,
      nativeVerifierPinsMatch: governedNativePinsMatch,
      expectedNativeVerifier: governedPreconfigurationIntentReady
        ? governedNativeVerifierValidation.expectedNativeVerifier
        : null,
      verifierMaterialHash: governedPreconfigurationIntentReady
        ? governedNativeVerifierValidation.verifierMaterialHash
        : null,
      verifierConfigHash: governedPreconfigurationIntentReady
        ? governedNativeVerifierValidation.verifierConfigHash
        : null,
      selfAssertedManifestIntentAccepted: false,
    },
    manifest: manifest
      ? {
          productionReadyObserved: manifestProductionReady,
          productionReadyRequiredBeforeFinalization: false,
          verifierCodeHash: normalizedExpectedVerifierCodeHash || null,
          verifierArtifactSha256:
            normalizedExpectedVerifierArtifactSha256 || null,
          outerVerifierProgramId: outerVerifierProgramId || null,
          verifierStateAddress: verifierStateAddress || null,
          tokenMintAddress: tokenMintAddress || null,
          destinationBindingHash:
            normalizedExpectedDestinationBindingHash || null,
          admissionMode: admissionMode || null,
          proofSystem: proofSystem || null,
          proofVerificationMode: proofVerificationMode || null,
        }
      : null,
    nativeVerifierLinkage: {
      ready: finalizationLinkageReady,
      nativeOnlyReady: nativeVerifierLinkageReady,
      verifierStateConfigured,
      allBlockerIds: finalizationLinkageBlockers.map((blocker) => blocker.id),
      postConfigurationBlockerIds: verifierLinkageReadiness.blockerIds,
      nativeVerifierReadError,
      pins: verifierLinkageReadiness.nativeVerifierPins,
      liveVerifierState: verifierLinkageReadiness.liveVerifierState,
      liveNativeVerifier: verifierLinkageReadiness.liveNativeVerifier,
      statuses: nativeVerifierLinkageStatuses,
      blockerIds: finalizationLinkageBlockers
        .map((blocker) => blocker.id)
        .filter((id) => id.startsWith("solana-native-verifier-")),
    },
    confirmation: {
      confirmFinalizeLinkedVerifier,
      satisfied: finalizationConfirmationSatisfied,
      satisfiedByAlreadyFinalizedNoOp: alreadyFinalizedNoOpAssessment,
      flag: "--confirm-finalize-linked-verifier true",
    },
    statuses,
    blockers,
    blockerIds: blockerIds(blockers),
    nextActions: ready
      ? ["finalize-solana-programs"]
      : ["link-solana-native-recursive-verifier"],
    note: ready
      ? "The selected SBF is bound to reviewed governed preconfiguration intent and exact deployment pins, so the outer program can be finalized before the one-shot state configuration."
      : "Solana program finalization is blocked until the compiled SBF is sentinel-free, CPI-bound to the immutable governed native verifier, bound to reviewed program/state/mint/destination pins, and explicitly confirmed. Route productionReady is intentionally evaluated only after finalization and configuration readback.",
  };
};

export const loadStableSolanaNativeVerifierConfigReport = async (
  args,
  paths,
) => {
  const explicitPath = args["native-verifier-config-report"] ?? null;
  const requestedPath = path.resolve(
    explicitPath || paths.nativeVerifierConfigureReport,
  );
  const expectedSha256 =
    args["expected-native-verifier-config-report-sha256"] ?? null;
  let selected;
  try {
    selected = await readStablePublicSolanaJsonArtifact({
      file: requestedPath,
      label: "Reviewed native-verifier configuration report",
      expectedSha256,
    });
  } catch (error) {
    if (error?.code !== "ENOENT" || explicitPath || expectedSha256) {
      throw error;
    }
    return {
      report: null,
      input: {
        selection: "output-dir-default",
        requestedPath,
        path: null,
        present: false,
        stableRead: false,
        sha256: null,
        expectedSha256: null,
      },
    };
  }
  if (
    selected.value.schema !==
    "iroha-demo-sccp-solana-native-verifier-configure/v1"
  ) {
    throw new Error(
      "Reviewed native-verifier configuration report schema is invalid.",
    );
  }
  return {
    report: selected.value,
    input: {
      selection: explicitPath ? "explicit" : "output-dir-default",
      requestedPath,
      path: selected.path,
      present: true,
      stableRead: true,
      sizeBytes: selected.sizeBytes,
      sha256: selected.sha256,
      expectedSha256,
    },
  };
};

const programFinalizationReadiness = async (args) => {
  const paths = artifactPaths(args);
  const programSo = path.resolve(args["program-so"] || DEFAULT_PROGRAM_SO);
  const nativeVerifierSo = path.resolve(
    args["native-verifier-so"] || DEFAULT_NATIVE_VERIFIER_SO,
  );
  const manifestPath = path.resolve(args.manifest || paths.routeManifest);
  const manifestArtifact =
    existsSync(manifestPath) || args["expected-manifest-sha256"] !== undefined
      ? await readStablePublicSolanaJsonArtifact({
          file: manifestPath,
          label: "Reviewed Solana route manifest for program finalization",
          expectedSha256: args["expected-manifest-sha256"] ?? null,
        })
      : null;
  const manifest = manifestArtifact?.value ?? null;
  const nativeVerifierConfigurationInput =
    await loadStableSolanaNativeVerifierConfigReport(args, paths);
  const nativeVerifierConfiguration = nativeVerifierConfigurationInput.report;
  let programBytes = null;
  let programReadError = null;
  let nativeVerifierBytes = null;
  let nativeVerifierReadError = null;
  try {
    programBytes = await readFile(programSo);
  } catch (error) {
    programReadError = error instanceof Error ? error.message : String(error);
  }
  try {
    nativeVerifierBytes = await readFile(nativeVerifierSo);
  } catch (error) {
    nativeVerifierReadError =
      error instanceof Error ? error.message : String(error);
  }
  let governedNativeVerifierValidation = null;
  const storedGovernedValidation =
    nativeVerifierConfiguration?.governedPackageValidation ?? null;
  const explicitGovernedPackagePath =
    args["governed-native-verifier-package"] ||
    args["native-verifier-material-file"] ||
    null;
  const governedPackagePath = explicitGovernedPackagePath
    ? path.resolve(explicitGovernedPackagePath)
    : storedGovernedValidation?.packagePath
      ? path.resolve(storedGovernedValidation.packagePath)
      : null;
  let governedPackageArtifact = null;
  let governedPackageSelectionError = null;
  if (governedPackagePath && nativeVerifierBytes) {
    try {
      const governanceApprovalValidation =
        await loadSolanaProductionGovernanceApprovalValidation({
          args,
          fallbackApprovalPath:
            storedGovernedValidation?.governanceApproval?.approvalPath ?? null,
        });
      if (
        explicitGovernedPackagePath &&
        args["expected-governed-native-verifier-package-sha256"] === undefined
      ) {
        throw new Error(
          "Explicit governed native-verifier package requires --expected-governed-native-verifier-package-sha256.",
        );
      }
      const packageArtifact = await readStablePublicSolanaJsonArtifact({
        file: governedPackagePath,
        label: "Reviewed governed native-verifier package",
        expectedSha256: explicitGovernedPackagePath
          ? args["expected-governed-native-verifier-package-sha256"]
          : (storedGovernedValidation?.packageSha256 ?? null),
      });
      governedPackageArtifact = packageArtifact;
      const packageRecord = packageArtifact.value;
      const nativeVerifierProgramId = readFirstManifestString(
        manifest,
        "solanaNativeVerifierProgramId",
        "solana_native_verifier_program_id",
      );
      governedNativeVerifierValidation =
        buildSolanaGovernedNativeVerifierPackageValidation({
          packageRecord,
          nativeVerifierProgramId,
          nativeVerifierArtifactSha256: sha256BufferHex(nativeVerifierBytes),
          governanceApprovalValidation,
          packagePath: packageArtifact.path,
          packageSha256: packageArtifact.sha256,
        });
    } catch (error) {
      governedNativeVerifierValidation = null;
      governedPackageSelectionError =
        error instanceof Error ? error.message : String(error);
    }
  }
  let liveReadback = null;
  if (!asBoolean(args["skip-solana-rpc"])) {
    try {
      const publicConfigPath = path.resolve(
        args["public-config"] || paths.publicConfig,
      );
      const accountsPath = path.resolve(args.accounts || paths.accountsReport);
      const publicConfig =
        await readOptionalSolanaPublicConfig(publicConfigPath);
      const accounts = await readOptionalJson(accountsPath);
      if (publicConfig) {
        liveReadback = await readSolanaVerifierLinkageLiveReadback({
          args,
          manifest,
          publicConfig,
          accounts,
        });
      }
    } catch {
      liveReadback = null;
    }
  }
  const report = {
    ...buildSolanaProgramFinalizationReadinessReportBody({
      args,
      programSo,
      programBytes,
      programReadError,
      nativeVerifierSo,
      nativeVerifierBytes,
      nativeVerifierReadError,
      nativeVerifierConfigReportInput: nativeVerifierConfigurationInput.input,
      governedNativeVerifierValidation,
      manifest,
      liveReadback,
    }),
    reviewedInputs: {
      nativeVerifierConfigReport: nativeVerifierConfigurationInput.input,
      manifest: manifestArtifact
        ? {
            path: manifestArtifact.path,
            sha256: manifestArtifact.sha256,
            stableRead: true,
          }
        : null,
      governedNativeVerifierPackage: governedPackageArtifact
        ? {
            path: governedPackageArtifact.path,
            sha256: governedPackageArtifact.sha256,
            stableRead: true,
          }
        : {
            path: governedPackagePath,
            sha256: null,
            stableRead: false,
            error: governedPackageSelectionError,
          },
    },
  };
  await writePublicJson(paths.programFinalizationReadiness, report);
  if (asBoolean(args.strict) && !report.ready) {
    throw new Error(
      `Solana program finalization readiness failed: ${report.blockerIds.join(", ")}`,
    );
  }
  return {
    programFinalizationReadinessPath: paths.programFinalizationReadiness,
    report,
  };
};

const deploy = async (args) => {
  assertNoFileBackedSolanaSignerOptions(args);
  if (exactFinalizationConfirmation(args.final)) {
    return finalizePrograms(args);
  }
  throw runtimeOnlySolanaDeploymentBlocker();
};

const normalizeFinalizedReadbackSlot = (value, label) => {
  if (!Number.isSafeInteger(value) || value <= 0) {
    throw new Error(`${label} must be a positive safe-integer Solana slot.`);
  }
  return value;
};

const normalizeFinalizedReadbackPublicKey = (value, label) => {
  try {
    return new PublicKey(value).toBase58();
  } catch {
    throw new Error(`${label} must be a canonical Solana public key.`);
  }
};

const readFinalizedReadbackConfigAddress = (publicConfig, spec) => {
  const values = spec.publicConfigKeys
    .map((key) => publicConfig?.[key])
    .filter((value) => typeof value === "string" && value.trim())
    .map((value) =>
      normalizeFinalizedReadbackPublicKey(
        value.trim(),
        `public config ${spec.label} program id`,
      ),
    );
  if (values.length === 0) {
    throw new Error(
      `Reviewed public config is missing the ${spec.label} program id.`,
    );
  }
  if (new Set(values).size !== 1) {
    throw new Error(
      `Reviewed public config contains conflicting ${spec.label} program ids.`,
    );
  }
  return values[0];
};

const normalizeFinalizedReadbackAccountInfo = (info, label) => {
  if (!isRecord(info) || info.data === undefined || info.owner === undefined) {
    throw new Error(`${label} RPC account payload is invalid.`);
  }
  const data = Buffer.from(info.data);
  const owner = normalizeFinalizedReadbackPublicKey(
    typeof info.owner?.toBase58 === "function"
      ? info.owner.toBase58()
      : info.owner,
    `${label} owner`,
  );
  if (typeof info.executable !== "boolean") {
    throw new Error(`${label} executable flag is invalid.`);
  }
  if (!Number.isSafeInteger(info.lamports) || info.lamports < 0) {
    throw new Error(`${label} lamport balance is invalid.`);
  }
  const rentEpoch = info.rentEpoch;
  if (
    !(
      (typeof rentEpoch === "bigint" && rentEpoch >= 0n) ||
      (Number.isSafeInteger(rentEpoch) && rentEpoch >= 0)
    )
  ) {
    throw new Error(`${label} rent epoch is invalid.`);
  }
  return {
    owner: new PublicKey(owner),
    executable: info.executable,
    lamports: info.lamports,
    rentEpoch,
    data,
  };
};

const finalizedReadbackAccountFingerprint = (address, info) => ({
  address,
  owner: info.owner.toBase58(),
  executable: info.executable,
  lamports: info.lamports,
  rentEpoch: String(info.rentEpoch),
  dataLength: info.data.length,
  dataSha256: sha256BufferHex(info.data),
});

const readFinalizedMultipleAccounts = async ({
  connection,
  addresses,
  label,
  retryOptions,
  minContextSlot = null,
}) => {
  if (!Array.isArray(addresses) || addresses.length === 0) {
    throw new Error(`${label} requires at least one account address.`);
  }
  if (addresses.length > SOLANA_FINALIZED_READBACK_MAX_ACCOUNTS) {
    throw new Error(
      `${label} exceeds the bounded finalized-readback account count.`,
    );
  }
  const normalizedAddresses = addresses.map((address, index) =>
    normalizeFinalizedReadbackPublicKey(address, `${label}[${index}]`),
  );
  if (new Set(normalizedAddresses).size !== normalizedAddresses.length) {
    throw new Error(`${label} contains duplicate account roles.`);
  }
  const config = { commitment: "finalized" };
  if (minContextSlot !== null) {
    config.minContextSlot = normalizeFinalizedReadbackSlot(
      minContextSlot,
      `${label} minimum context slot`,
    );
  }
  const response = await withSolanaRpcRetry(
    () =>
      connection.getMultipleAccountsInfoAndContext(
        normalizedAddresses.map((address) => new PublicKey(address)),
        config,
      ),
    { label, ...retryOptions },
  );
  const contextSlot = normalizeFinalizedReadbackSlot(
    response?.context?.slot,
    `${label} context slot`,
  );
  if (
    minContextSlot !== null &&
    contextSlot < normalizeFinalizedReadbackSlot(minContextSlot, label)
  ) {
    throw new Error(`${label} returned a backward Solana context slot.`);
  }
  if (
    !Array.isArray(response?.value) ||
    response.value.length !== normalizedAddresses.length
  ) {
    throw new Error(`${label} returned a mismatched account vector.`);
  }
  const accounts = new Map();
  for (let index = 0; index < normalizedAddresses.length; index += 1) {
    const address = normalizedAddresses[index];
    const info = response.value[index];
    if (!info) {
      throw new Error(`${label} account ${address} does not exist.`);
    }
    accounts.set(
      address,
      normalizeFinalizedReadbackAccountInfo(
        info,
        `${label} account ${address}`,
      ),
    );
  }
  return { contextSlot, accounts };
};

const readFinalizedOwnerTokenAccounts = async ({
  connection,
  ownerAddress,
  mintAddress,
  retryOptions,
  label,
  minContextSlot,
}) => {
  const response = await withSolanaRpcRetry(
    () =>
      connection.getTokenAccountsByOwner(
        new PublicKey(ownerAddress),
        { mint: new PublicKey(mintAddress) },
        { commitment: "finalized", minContextSlot },
      ),
    { label, ...retryOptions },
  );
  const contextSlot = normalizeFinalizedReadbackSlot(
    response?.context?.slot,
    `${label} context slot`,
  );
  if (contextSlot < minContextSlot) {
    throw new Error(`${label} returned a backward Solana context slot.`);
  }
  if (!Array.isArray(response?.value)) {
    throw new Error(`${label} returned an invalid token-account vector.`);
  }
  if (
    response.value.length > SOLANA_FINALIZED_READBACK_MAX_SOURCE_TOKEN_ACCOUNTS
  ) {
    throw new Error(`${label} exceeds the bounded source token-account count.`);
  }
  const entries = response.value
    .map((entry, index) => {
      const address = normalizeFinalizedReadbackPublicKey(
        typeof entry?.pubkey?.toBase58 === "function"
          ? entry.pubkey.toBase58()
          : entry?.pubkey,
        `${label}[${index}] address`,
      );
      const info = normalizeFinalizedReadbackAccountInfo(
        entry?.account,
        `${label} account ${address}`,
      );
      return {
        address,
        info,
        fingerprint: finalizedReadbackAccountFingerprint(address, info),
      };
    })
    .sort((left, right) => left.address.localeCompare(right.address));
  if (new Set(entries.map((entry) => entry.address)).size !== entries.length) {
    throw new Error(`${label} returned duplicate token accounts.`);
  }
  return { contextSlot, entries };
};

const assertFinalizedTokenEnumerationMatchesSnapshot = ({
  enumeration,
  snapshotAccounts,
  label,
}) => {
  const snapshot = enumeration.entries.map((entry) => {
    const info = snapshotAccounts.get(entry.address);
    if (!info) {
      throw new Error(
        `${label} token-account set changed around the atomic snapshot.`,
      );
    }
    return finalizedReadbackAccountFingerprint(entry.address, info);
  });
  const enumerated = enumeration.entries.map((entry) => entry.fingerprint);
  if (JSON.stringify(snapshot) !== JSON.stringify(enumerated)) {
    throw new Error(
      `${label} token-account content changed around the atomic snapshot.`,
    );
  }
};

const finalizedReadbackRoleViewFromRole = ({
  role,
  solanaGenesisHash,
  canonicalSnapshotSha256,
}) => {
  const raw = {
    programId: role.program.address,
    owner: role.program.owner,
    programdataAddress: role.programdata.address,
    authority: role.loaderV3.upgradeAuthorityAddress ?? "none",
    lastDeploySlot: role.loaderV3.deploymentSlot,
    dataLen: role.programdata.dataLength,
    lamports: role.programdata.lamports,
    immutable: role.loaderV3.immutable,
    executableSha256: role.loaderV3.executableSha256,
    executableBlake2b256: role.loaderV3.executableBlake2b256,
  };
  return {
    schema: SOLANA_FINALIZED_READBACK_ROLE_EVIDENCE_SCHEMA,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    solanaNetwork: "testnet",
    solanaGenesisHash,
    role: role.role,
    canonicalSnapshotSha256,
    programId: role.program.address,
    programDataAddress: role.programdata.address,
    programDataSlot: role.loaderV3.deploymentSlot,
    authority: raw.authority,
    raw,
    evidenceSha256: sha256Hex(JSON.stringify(raw)),
  };
};

export const solanaFinalizedReadbackRoleEvidence = (evidence, roleName) => {
  const role = solanaFinalizedReadbackRole(evidence, roleName);
  return role
    ? finalizedReadbackRoleViewFromRole({
        role,
        solanaGenesisHash: evidence.solanaGenesisHash,
        canonicalSnapshotSha256: evidence.canonicalSnapshotSha256,
      })
    : null;
};

const expectedSourceBridgeConfigHashFromManifest = (manifest) => {
  const postDeployLiveEvidence = readFirstManifestRecord(
    manifest,
    "postDeployLiveEvidence",
    "post_deploy_live_evidence",
  );
  return (
    readFirstManifestString(
      postDeployLiveEvidence,
      "sourceBridgeConfigHash",
      "source_bridge_config_hash",
    ) || null
  );
};

const solanaFinalizedReadbackCanonicalSnapshotSha256 = ({
  routeId,
  assetKey,
  solanaNetwork,
  solanaGenesisHash,
  snapshot,
}) =>
  sha256JsonHex({
    schema: SOLANA_FINALIZED_READBACK_EVIDENCE_SCHEMA,
    routeId,
    assetKey,
    solanaNetwork,
    solanaGenesisHash,
    snapshot,
  });

const publicSolanaRpcUrlEvidence = (value) => {
  if (typeof value !== "string" || !value.trim()) {
    return { rpcUrl: null, rpcUrlRedacted: false };
  }
  let parsed;
  try {
    parsed = new URL(value);
  } catch {
    throw new Error("Solana finalized readback RPC URL is invalid.");
  }
  if (!new Set(["https:", "http:"]).has(parsed.protocol)) {
    throw new Error("Solana finalized readback RPC URL protocol is invalid.");
  }
  const redacted = Boolean(
    parsed.username || parsed.password || parsed.search || parsed.hash,
  );
  parsed.username = "";
  parsed.password = "";
  parsed.search = "";
  parsed.hash = "";
  return { rpcUrl: parsed.href, rpcUrlRedacted: redacted };
};

export const validateSolanaFinalizedReadbackEvidence = (evidence) => {
  if (
    !isRecord(evidence) ||
    evidence.schema !== SOLANA_FINALIZED_READBACK_EVIDENCE_SCHEMA ||
    !isRecord(evidence.snapshot)
  ) {
    throw new Error("Solana finalized readback evidence schema is invalid.");
  }
  for (const retiredKey of [
    "programId",
    "programDataAddress",
    "programDataSlot",
    "authority",
    "raw",
    "evidenceSha256",
  ]) {
    if (Object.prototype.hasOwnProperty.call(evidence, retiredKey)) {
      throw new Error(
        `Solana finalized readback evidence contains retired outer-role alias ${retiredKey}.`,
      );
    }
  }
  if (
    Object.prototype.hasOwnProperty.call(evidence.inputs ?? {}, "manifest") ||
    Object.prototype.hasOwnProperty.call(
      evidence.snapshot.publicInputs ?? {},
      "manifestSha256",
    ) ||
    Object.prototype.hasOwnProperty.call(
      evidence.snapshot.sourceBridgeConfig ?? {},
      "expectedHash",
    ) ||
    Object.prototype.hasOwnProperty.call(
      evidence.snapshot.sourceBridgeConfig ?? {},
      "matchesExpected",
    )
  ) {
    throw new Error(
      "Solana finalized readback evidence contains retired manifest-dependent canonical fields.",
    );
  }
  if (
    evidence.routeId !== SCCP_SOLANA_XOR_ROUTE_ID ||
    evidence.assetKey !== SCCP_XOR_ASSET_KEY ||
    evidence.solanaNetwork !== "testnet" ||
    evidence.solanaGenesisHash !== SOLANA_TESTNET_GENESIS_HASH
  ) {
    throw new Error(
      "Solana finalized readback route or testnet identity is invalid.",
    );
  }
  const rpcUrlEvidence = publicSolanaRpcUrlEvidence(evidence.rpcUrl);
  if (
    rpcUrlEvidence.rpcUrl !== evidence.rpcUrl ||
    rpcUrlEvidence.rpcUrlRedacted ||
    typeof evidence.rpcUrlRedacted !== "boolean"
  ) {
    throw new Error(
      "Solana finalized readback report contains a non-public RPC URL.",
    );
  }
  const expectedSnapshotSha256 =
    solanaFinalizedReadbackCanonicalSnapshotSha256(evidence);
  if (evidence.canonicalSnapshotSha256 !== expectedSnapshotSha256) {
    throw new Error(
      "Solana finalized readback canonical snapshot hash is invalid.",
    );
  }
  const roles = SOLANA_FINALIZED_READBACK_ROLE_SPECS.map((spec) => {
    const role = evidence.snapshot.roles?.[spec.role];
    if (!isRecord(role) || role.role !== spec.role) {
      throw new Error(
        `Solana finalized readback is missing the ${spec.label} role.`,
      );
    }
    return role;
  });
  const programIds = roles.map((role) => role.program?.address);
  const programdataAddresses = roles.map((role) => role.programdata?.address);
  for (const [index, address] of programIds.entries()) {
    normalizeFinalizedReadbackPublicKey(
      address,
      `${SOLANA_FINALIZED_READBACK_ROLE_SPECS[index].label} program id`,
    );
  }
  for (const [index, address] of programdataAddresses.entries()) {
    normalizeFinalizedReadbackPublicKey(
      address,
      `${SOLANA_FINALIZED_READBACK_ROLE_SPECS[index].label} ProgramData address`,
    );
  }
  if (
    new Set(programIds).size !== programIds.length ||
    new Set(programdataAddresses).size !== programdataAddresses.length ||
    programIds.some((address) => programdataAddresses.includes(address))
  ) {
    throw new Error(
      "Solana finalized readback program roles are not distinct.",
    );
  }
  for (const role of roles) {
    if (
      role.program?.owner !== SOLANA_UPGRADEABLE_LOADER_ID ||
      role.program?.executable !== true ||
      role.programdata?.owner !== SOLANA_UPGRADEABLE_LOADER_ID ||
      role.programdata?.executable !== false ||
      role.loaderV3?.programTag !== 2 ||
      role.loaderV3?.programdataTag !== 3 ||
      role.loaderV3?.programdataAddress !== role.programdata.address ||
      role.loaderV3?.executableElf !== true ||
      role.program?.dataLength !== 36 ||
      role.programdata?.dataLength !==
        role.loaderV3?.executableLength + SOLANA_PROGRAMDATA_METADATA_LEN ||
      ![0, 1].includes(role.loaderV3?.upgradeAuthorityOption) ||
      role.loaderV3?.immutable !==
        (role.loaderV3?.upgradeAuthorityOption === 0) ||
      (role.loaderV3?.upgradeAuthorityOption === 0) !==
        (role.loaderV3?.upgradeAuthorityAddress === null) ||
      !/^[1-9][0-9]*$/u.test(String(role.loaderV3?.deploymentSlot ?? "")) ||
      !/^0x[0-9a-f]{64}$/u.test(role.loaderV3?.executableSha256 ?? "") ||
      !/^0x[0-9a-f]{64}$/u.test(role.loaderV3?.executableBlake2b256 ?? "") ||
      !(
        role.loaderV3?.upgradeAuthorityAddress === null ||
        normalizeFinalizedReadbackPublicKey(
          role.loaderV3.upgradeAuthorityAddress,
          `${role.role} upgrade authority`,
        ) === role.loaderV3.upgradeAuthorityAddress
      )
    ) {
      throw new Error(
        `Solana finalized readback ${role.role} Loader-v3 linkage is invalid.`,
      );
    }
  }
  for (const [roleName, reviewedProgramKey] of [
    ["outerVerifier", "verifierProgramId"],
    ["nativeVerifier", "nativeVerifierProgramId"],
    ["destinationBridge", "bridgeProgramId"],
    ["sourceBridge", "sourceBridgeProgramId"],
  ]) {
    const role = evidence.snapshot.roles[roleName];
    if (
      role.program.address !==
        evidence.snapshot.reviewedAddresses?.[reviewedProgramKey] ||
      role.programdata.address !==
        evidence.snapshot.reviewedAddresses?.programdataAddresses?.[roleName]
    ) {
      throw new Error(
        `Solana finalized readback ${roleName} was substituted or role-swapped.`,
      );
    }
  }
  const slots = evidence.snapshot.consistency;
  if (
    evidence.snapshot.commitment !== "finalized" ||
    slots?.tokenEnumerationStable !== true ||
    slots?.identityRecheckedAfterFence !== true
  ) {
    throw new Error(
      "Solana finalized readback commitment or final identity fence is invalid.",
    );
  }
  const orderedSlots = [
    slots?.discoveryContextSlot,
    slots?.preEnumerationContextSlot,
    slots?.snapshotContextSlot,
    slots?.postEnumerationContextSlot,
  ].map((slot, index) =>
    normalizeFinalizedReadbackSlot(slot, `finalized readback slot ${index}`),
  );
  if (
    orderedSlots.some(
      (slot, index) => index > 0 && slot < orderedSlots[index - 1],
    )
  ) {
    throw new Error(
      "Solana finalized readback context slots are not monotonic.",
    );
  }
  const reviewed = evidence.snapshot.reviewedAddresses;
  const verifierState = evidence.snapshot.stateAccounts?.verifier;
  const sourceState = evidence.snapshot.stateAccounts?.source;
  const tokenMint = evidence.snapshot.tokenMint;
  const nativeConfig = evidence.snapshot.nativeVerifierConfig;
  if (
    evidence.snapshot.publicInputs?.publicConfigSha256 !==
      evidence.inputs?.publicConfig?.sha256 ||
    evidence.snapshot.publicInputs?.nativeVerifierConfigSha256 !==
      (evidence.inputs?.nativeVerifierConfig?.sha256 ?? null) ||
    nativeConfig?.programId !==
      (nativeConfig?.present ? reviewed?.nativeVerifierProgramId : null)
  ) {
    throw new Error(
      "Solana finalized readback stable public-input binding is invalid.",
    );
  }
  for (const [actual, expected, label] of [
    [
      nativeConfig?.outerVerifierProgramId,
      reviewed?.verifierProgramId,
      "outer verifier program id",
    ],
    [
      nativeConfig?.verifierStateAddress,
      reviewed?.verifierStateAddress,
      "verifier state address",
    ],
    [
      nativeConfig?.programdataAddress,
      evidence.snapshot.roles.nativeVerifier.programdata.address,
      "native verifier ProgramData address",
    ],
    [
      nativeConfig?.programdataSlot,
      evidence.snapshot.roles.nativeVerifier.loaderV3.deploymentSlot,
      "native verifier ProgramData slot",
    ],
    [
      nativeConfig?.codeHash,
      evidence.snapshot.roles.nativeVerifier.loaderV3.executableBlake2b256,
      "native verifier code hash",
    ],
    [
      nativeConfig?.verifierMaterialHash,
      verifierState?.parsed?.verifierMaterialHash,
      "native verifier material hash",
    ],
    [
      nativeConfig?.verifierConfigHash,
      verifierState?.parsed?.verifierConfigHash,
      "native verifier config hash",
    ],
    [
      nativeConfig?.configuredStateDataSha256,
      verifierState?.account?.dataSha256,
      "configured verifier-state data hash",
    ],
  ]) {
    if (
      actual !== null &&
      actual !== undefined &&
      String(actual) !== String(expected)
    ) {
      throw new Error(
        `Solana finalized readback native-config ${label} binding is invalid.`,
      );
    }
  }
  if (
    verifierState?.account?.owner !== reviewed?.verifierProgramId ||
    verifierState?.account?.executable !== false ||
    sourceState?.account?.owner !== reviewed?.sourceBridgeProgramId ||
    sourceState?.account?.executable !== false ||
    tokenMint?.account?.owner !== TOKEN_PROGRAM_ID.toBase58() ||
    tokenMint?.account?.executable !== false ||
    verifierState?.parsed?.storedMint !== reviewed?.tokenMintAddress ||
    sourceState?.parsed?.storedMint !== reviewed?.tokenMintAddress ||
    (verifierState?.parsed?.nativeVerifierProgramId !== null &&
      verifierState?.parsed?.nativeVerifierProgramId !==
        reviewed?.nativeVerifierProgramId)
  ) {
    throw new Error(
      "Solana finalized readback state, mint, or native-verifier role binding is invalid.",
    );
  }
  const [derivedMintAuthority, derivedMintAuthorityBump] = deriveMintAuthority(
    new PublicKey(reviewed.verifierProgramId),
    new PublicKey(reviewed.verifierStateAddress),
  );
  if (
    tokenMint.account.address !== reviewed.tokenMintAddress ||
    verifierState.account.address !== reviewed.verifierStateAddress ||
    sourceState.account.address !== reviewed.sourceStateAddress ||
    tokenMint.parsed?.mintAuthority !== derivedMintAuthority.toBase58() ||
    tokenMint.expectedMintAuthority !== derivedMintAuthority.toBase58() ||
    tokenMint.expectedMintAuthorityBump !== derivedMintAuthorityBump ||
    tokenMint.parsed?.initialized !== true ||
    tokenMint.parsed?.decimals !== SPL_TOKEN_DECIMALS ||
    !/^[0-9]+$/u.test(String(tokenMint.parsed?.supply ?? ""))
  ) {
    throw new Error(
      "Solana finalized readback state addresses or mint configuration are invalid.",
    );
  }
  if (
    tokenMint.parsed.freezeAuthority !== null ||
    evidence.snapshot.sourceBridgeConfig?.observed?.destinationBindingHash !==
      SOLANA_DESTINATION_BINDING_HASH
  ) {
    throw new Error(
      "Solana finalized readback mint freeze authority or destination binding is invalid.",
    );
  }
  const tokenAccounts = evidence.snapshot.sourceOwnerTokenAccounts;
  if (
    tokenAccounts?.ownerAddress !== reviewed?.sourceTokenOwnerAddress ||
    !Array.isArray(tokenAccounts?.accounts) ||
    tokenAccounts.accounts.length !== slots?.sourceTokenAccountCount ||
    tokenAccounts.accounts.length >
      SOLANA_FINALIZED_READBACK_MAX_SOURCE_TOKEN_ACCOUNTS ||
    slots?.accountCount !== 11 + tokenAccounts.accounts.length ||
    slots.accountCount > SOLANA_FINALIZED_READBACK_MAX_ACCOUNTS
  ) {
    throw new Error(
      "Solana finalized readback source token-account cardinality is invalid.",
    );
  }
  const tokenAccountIds = [];
  let tokenBalance = 0n;
  for (const account of tokenAccounts.accounts) {
    normalizeFinalizedReadbackPublicKey(
      account?.address,
      "source token-account address",
    );
    if (
      account?.owner !== TOKEN_PROGRAM_ID.toBase58() ||
      account?.executable !== false ||
      account?.parsed?.mint !== reviewed.tokenMintAddress ||
      account?.parsed?.owner !== reviewed.sourceTokenOwnerAddress ||
      account?.parsed?.isInitialized !== true ||
      account?.parsed?.isFrozen !== false ||
      !/^[0-9]+$/u.test(String(account?.parsed?.amount ?? ""))
    ) {
      throw new Error(
        "Solana finalized readback source token-account binding is invalid.",
      );
    }
    tokenAccountIds.push(account.address);
    tokenBalance += BigInt(account.parsed.amount);
  }
  if (
    new Set(tokenAccountIds).size !== tokenAccountIds.length ||
    JSON.stringify(tokenAccountIds) !==
      JSON.stringify(
        [...tokenAccountIds].sort((left, right) => left.localeCompare(right)),
      ) ||
    tokenBalance > BigInt(tokenMint.parsed.supply) ||
    tokenBalance.toString() !== tokenAccounts.balance ||
    tokenBalance.toString() !== tokenAccounts.spendableBalance
  ) {
    throw new Error(
      "Solana finalized readback source token-account balance is invalid.",
    );
  }
  const snapshotSlot = BigInt(slots.snapshotContextSlot);
  for (const role of roles) {
    if (BigInt(role.loaderV3.deploymentSlot) > snapshotSlot) {
      throw new Error(
        `Solana finalized readback ${role.role} deployment slot is from the future.`,
      );
    }
  }
  for (const state of [verifierState.parsed, sourceState.parsed]) {
    if (
      !/^[0-9]+$/u.test(String(state.lastSlot ?? "")) ||
      BigInt(state.lastSlot) > snapshotSlot
    ) {
      throw new Error(
        "Solana finalized readback state slot is from the future.",
      );
    }
  }
  const configuredSlot = verifierState.parsed.verifierConfiguredSlot;
  if (
    configuredSlot !== null &&
    (!/^[1-9][0-9]*$/u.test(String(configuredSlot)) ||
      BigInt(configuredSlot) > snapshotSlot)
  ) {
    throw new Error(
      "Solana finalized readback verifier configured slot is invalid.",
    );
  }
  const recomputedSourceBridgeConfig = buildSolanaObservedSourceBridgeConfig({
    addresses: reviewed,
    expectedMintAuthority: tokenMint.expectedMintAuthority,
    observed: {
      tokenMint: tokenMint.parsed,
      verifierState: verifierState.parsed,
      sourceState: sourceState.parsed,
      accounts: {
        tokenMintAccount: tokenMint.account,
        verifierStateAccount: verifierState.account,
        sourceStateAccount: sourceState.account,
        verifierProgramAccount: evidence.snapshot.roles.outerVerifier.program,
        bridgeProgramAccount: evidence.snapshot.roles.destinationBridge.program,
        sourceBridgeProgramAccount:
          evidence.snapshot.roles.sourceBridge.program,
      },
    },
    manifest: {
      destinationBindingHash:
        evidence.snapshot.sourceBridgeConfig?.observed?.destinationBindingHash,
    },
    verifierEvidence: finalizedReadbackRoleViewFromRole({
      role: evidence.snapshot.roles.outerVerifier,
      solanaGenesisHash: evidence.solanaGenesisHash,
      canonicalSnapshotSha256: evidence.canonicalSnapshotSha256,
    }),
    verifierLiveEvidence: null,
  });
  if (
    JSON.stringify(evidence.snapshot.sourceBridgeConfig?.observed) !==
      JSON.stringify(recomputedSourceBridgeConfig) ||
    evidence.snapshot.sourceBridgeConfig?.observedHash !==
      sha256JsonHex(recomputedSourceBridgeConfig)
  ) {
    throw new Error(
      "Solana finalized readback source-bridge config hash is invalid.",
    );
  }
  const manifestComparison = evidence.manifestComparison;
  if (!isRecord(manifestComparison)) {
    throw new Error(
      "Solana finalized readback manifest comparison is missing.",
    );
  }
  if (
    manifestComparison.input !== null &&
    !isRecord(manifestComparison.input)
  ) {
    throw new Error(
      "Solana finalized readback manifest comparison input is invalid.",
    );
  }
  const expectedHash = manifestComparison.expectedSourceBridgeConfigHash;
  if (
    expectedHash !== null &&
    normalizeManifestHex32(
      expectedHash,
      "manifest comparison source-bridge config hash",
    ) !== expectedHash
  ) {
    throw new Error(
      "Solana finalized readback manifest comparison hash is invalid.",
    );
  }
  if (
    manifestComparison.input !== null &&
    !/^0x[0-9a-f]{64}$/u.test(manifestComparison.input?.sha256 ?? "")
  ) {
    throw new Error(
      "Solana finalized readback manifest comparison input hash is invalid.",
    );
  }
  const matchesExpected =
    expectedHash === null
      ? null
      : expectedHash === evidence.snapshot.sourceBridgeConfig.observedHash;
  if (
    manifestComparison.observedSourceBridgeConfigHash !==
      evidence.snapshot.sourceBridgeConfig.observedHash ||
    manifestComparison.matchesExpected !== matchesExpected ||
    manifestComparison.ready !== (matchesExpected === true)
  ) {
    throw new Error(
      "Solana finalized readback source-bridge pin result is invalid.",
    );
  }
  const expectedManifestComparisonBlockerIds =
    matchesExpected === true
      ? []
      : [
          expectedHash === null
            ? "manifest-source-bridge-config-pin-missing"
            : "source-bridge-config-hash-mismatch",
        ];
  if (
    JSON.stringify(manifestComparison.blockerIds) !==
    JSON.stringify(expectedManifestComparisonBlockerIds)
  ) {
    throw new Error(
      "Solana finalized readback manifest comparison blockers are invalid.",
    );
  }
  const expectedBlockerIds = [
    ...(verifierState.parsed.nativeVerifierProgramId === null ||
    verifierState.parsed.verifierMaterialHash === null ||
    verifierState.parsed.verifierConfigHash === null ||
    verifierState.parsed.verifierConfiguredSlot === null
      ? ["native-verifier-state-unconfigured"]
      : []),
  ];
  if (
    evidence.ready !== (expectedBlockerIds.length === 0) ||
    JSON.stringify(evidence.blockerIds) !== JSON.stringify(expectedBlockerIds)
  ) {
    throw new Error("Solana finalized readback readiness result is invalid.");
  }
  return evidence;
};

export const assertSolanaFinalizedReadbackMatchesSelection = ({
  evidence,
  publicConfig,
  manifest = null,
  ownerAddress = null,
} = {}) => {
  validateSolanaFinalizedReadbackEvidence(evidence);
  if (!isRecord(publicConfig)) {
    throw new Error(
      "Canonical Solana finalized readback requires the exact selected public config.",
    );
  }
  const reviewed = evidence.snapshot.reviewedAddresses;
  for (const spec of SOLANA_FINALIZED_READBACK_ROLE_SPECS) {
    const selectedProgramId = readFinalizedReadbackConfigAddress(
      publicConfig,
      spec,
    );
    if (
      evidence.snapshot.roles[spec.role].program.address !== selectedProgramId
    ) {
      throw new Error(
        `Canonical Solana finalized readback ${spec.label} does not match the selected public config.`,
      );
    }
  }
  for (const [selectedValue, reviewedKey, label] of [
    [
      publicConfig.verifierStateAddress,
      "verifierStateAddress",
      "verifier state",
    ],
    [publicConfig.sourceStateAddress, "sourceStateAddress", "source state"],
    [publicConfig.tokenMintAddress, "tokenMintAddress", "token mint"],
    [
      ownerAddress || publicConfig.deployerAddress,
      "sourceTokenOwnerAddress",
      "reviewed token owner",
    ],
  ]) {
    if (
      normalizeFinalizedReadbackPublicKey(
        selectedValue,
        `selected ${label}`,
      ) !== reviewed[reviewedKey]
    ) {
      throw new Error(
        `Canonical Solana finalized readback ${label} does not match the selected public config.`,
      );
    }
  }
  if (!manifest) return evidence;
  const manifestAddresses = solanaPostDeployDeploymentAddresses({
    publicConfig: null,
    manifest,
    accounts: null,
  });
  for (const [manifestKey, reviewedKey, label] of [
    ["verifierProgramId", "verifierProgramId", "outer verifier"],
    ["bridgeProgramId", "bridgeProgramId", "destination bridge"],
    ["sourceBridgeProgramId", "sourceBridgeProgramId", "source bridge"],
    ["tokenMintAddress", "tokenMintAddress", "token mint"],
    ["verifierStateAddress", "verifierStateAddress", "verifier state"],
    ["sourceStateAddress", "sourceStateAddress", "source state"],
  ]) {
    const selectedValue = manifestAddresses[manifestKey];
    if (
      selectedValue &&
      normalizeFinalizedReadbackPublicKey(
        selectedValue,
        `manifest ${label}`,
      ) !== reviewed[reviewedKey]
    ) {
      throw new Error(
        `Canonical Solana finalized readback ${label} does not match the selected manifest.`,
      );
    }
  }
  for (const spec of SOLANA_GOVERNANCE_PROGRAM_ROLE_SPECS) {
    const role = evidence.snapshot.roles[spec.role];
    const manifestProgramId = readFirstManifestString(
      manifest,
      ...spec.manifestProgramIdKeys,
    );
    const manifestProgramdataAddress = readFirstManifestString(
      manifest,
      ...spec.manifestProgramdataAddressKeys,
    );
    const manifestProgramdataSlot = readFirstManifestStringLike(
      manifest,
      ...spec.manifestProgramdataSlotKeys,
    );
    const manifestCodeHash = readFirstManifestString(
      manifest,
      ...spec.manifestCodeHashKeys,
    );
    if (
      (manifestProgramId &&
        normalizeFinalizedReadbackPublicKey(
          manifestProgramId,
          `manifest ${spec.label} program id`,
        ) !== role.program.address) ||
      (manifestProgramdataAddress &&
        normalizeFinalizedReadbackPublicKey(
          manifestProgramdataAddress,
          `manifest ${spec.label} ProgramData address`,
        ) !== role.programdata.address) ||
      (manifestProgramdataSlot &&
        String(manifestProgramdataSlot) !==
          String(role.loaderV3.deploymentSlot)) ||
      (manifestCodeHash &&
        normalizeManifestHex32(
          manifestCodeHash,
          `manifest ${spec.label} code hash`,
        ) !== role.loaderV3.executableBlake2b256)
    ) {
      throw new Error(
        `Canonical Solana finalized readback ${spec.label} pins do not match the selected manifest.`,
      );
    }
  }
  const manifestDestinationBindingHash = readFirstManifestString(
    manifest,
    "destinationBindingHash",
    "destination_binding_hash",
  );
  if (
    manifestDestinationBindingHash &&
    normalizeManifestHex32(
      manifestDestinationBindingHash,
      "manifest destination binding hash",
    ) !== SOLANA_DESTINATION_BINDING_HASH
  ) {
    throw new Error(
      "Selected Solana manifest destination binding hash is not canonical.",
    );
  }
  return evidence;
};

export const captureSolanaFinalizedReadbackEvidence = async ({
  connection,
  publicConfig,
  publicConfigInput,
  manifest = null,
  manifestInput = null,
  nativeVerifierConfigReport = null,
  nativeVerifierConfigInput = null,
  ownerAddress = null,
  retryOptions = {},
  capturedAt = new Date().toISOString(),
} = {}) => {
  if (!connection || !isRecord(publicConfig) || !isRecord(publicConfigInput)) {
    throw new Error(
      "Finalized Solana readback requires a connection and stable public-config input evidence.",
    );
  }
  const roleProgramIds = Object.fromEntries(
    SOLANA_FINALIZED_READBACK_ROLE_SPECS.map((spec) => [
      spec.role,
      readFinalizedReadbackConfigAddress(publicConfig, spec),
    ]),
  );
  const roleIdValues = Object.values(roleProgramIds);
  if (new Set(roleIdValues).size !== roleIdValues.length) {
    throw new Error(
      "Solana finalized readback program roles must be distinct.",
    );
  }
  const verifierStateAddress = normalizeFinalizedReadbackPublicKey(
    publicConfig.verifierStateAddress,
    "verifier state address",
  );
  const sourceStateAddress = normalizeFinalizedReadbackPublicKey(
    publicConfig.sourceStateAddress,
    "source state address",
  );
  const tokenMintAddress = normalizeFinalizedReadbackPublicKey(
    publicConfig.tokenMintAddress,
    "token mint address",
  );
  const reviewedOwnerAddress = normalizeFinalizedReadbackPublicKey(
    ownerAddress || publicConfig.deployerAddress,
    "reviewed source token owner",
  );
  const coreAddresses = [
    ...roleIdValues,
    verifierStateAddress,
    sourceStateAddress,
    tokenMintAddress,
  ];
  if (new Set(coreAddresses).size !== coreAddresses.length) {
    throw new Error(
      "Solana finalized readback core account roles must be distinct.",
    );
  }

  const solanaGenesisHash = await assertSolanaTestnetRpcConnection(connection);
  const discovery = await readFinalizedMultipleAccounts({
    connection,
    addresses: roleIdValues,
    label: "Solana finalized program-linkage discovery",
    retryOptions,
  });
  const discoveredProgramdataAddresses = {};
  for (const spec of SOLANA_FINALIZED_READBACK_ROLE_SPECS) {
    const programId = roleProgramIds[spec.role];
    const info = discovery.accounts.get(programId);
    if (
      info.owner.toBase58() !== SOLANA_UPGRADEABLE_LOADER_ID ||
      info.executable !== true
    ) {
      throw new Error(
        `Solana ${spec.label} is not an executable Loader-v3 program.`,
      );
    }
    discoveredProgramdataAddresses[spec.role] =
      parseUpgradeableProgramAccountData(info.data).programdataAddress;
  }
  const programdataValues = Object.values(discoveredProgramdataAddresses);
  if (
    new Set(programdataValues).size !== programdataValues.length ||
    programdataValues.some((address) => coreAddresses.includes(address))
  ) {
    throw new Error(
      "Solana finalized readback ProgramData account roles must be distinct.",
    );
  }

  const preEnumeration = await readFinalizedOwnerTokenAccounts({
    connection,
    ownerAddress: reviewedOwnerAddress,
    mintAddress: tokenMintAddress,
    retryOptions,
    label: "Solana source token-account pre-enumeration",
    minContextSlot: discovery.contextSlot,
  });
  const tokenAccountAddresses = preEnumeration.entries.map(
    (entry) => entry.address,
  );
  const snapshotAddresses = [
    ...roleIdValues,
    ...programdataValues,
    verifierStateAddress,
    sourceStateAddress,
    tokenMintAddress,
    ...tokenAccountAddresses,
  ];
  if (new Set(snapshotAddresses).size !== snapshotAddresses.length) {
    throw new Error(
      "Solana finalized readback account roles overlap source token accounts.",
    );
  }
  const snapshot = await readFinalizedMultipleAccounts({
    connection,
    addresses: snapshotAddresses,
    label: "Solana atomic finalized account snapshot",
    retryOptions,
    minContextSlot: preEnumeration.contextSlot,
  });
  assertFinalizedTokenEnumerationMatchesSnapshot({
    enumeration: preEnumeration,
    snapshotAccounts: snapshot.accounts,
    label: "Pre-snapshot",
  });
  const postEnumeration = await readFinalizedOwnerTokenAccounts({
    connection,
    ownerAddress: reviewedOwnerAddress,
    mintAddress: tokenMintAddress,
    retryOptions,
    label: "Solana source token-account post-enumeration",
    minContextSlot: snapshot.contextSlot,
  });
  if (
    JSON.stringify(postEnumeration.entries.map((entry) => entry.address)) !==
    JSON.stringify(tokenAccountAddresses)
  ) {
    throw new Error(
      "Solana source token-account set changed around the atomic snapshot.",
    );
  }
  assertFinalizedTokenEnumerationMatchesSnapshot({
    enumeration: postEnumeration,
    snapshotAccounts: snapshot.accounts,
    label: "Post-snapshot",
  });
  const finalSolanaGenesisHash =
    await assertSolanaTestnetRpcConnection(connection);
  if (finalSolanaGenesisHash !== solanaGenesisHash) {
    throw new Error(
      "Solana RPC identity changed during finalized readback capture.",
    );
  }

  const roles = {};
  for (const spec of SOLANA_FINALIZED_READBACK_ROLE_SPECS) {
    const programId = roleProgramIds[spec.role];
    const programInfo = snapshot.accounts.get(programId);
    const parsedProgram = parseUpgradeableProgramAccountData(programInfo.data);
    const discoveredProgramdataAddress =
      discoveredProgramdataAddresses[spec.role];
    if (parsedProgram.programdataAddress !== discoveredProgramdataAddress) {
      throw new Error(
        `Solana ${spec.label} ProgramData linkage changed during finalized capture.`,
      );
    }
    const programdataInfo = snapshot.accounts.get(discoveredProgramdataAddress);
    if (
      programInfo.owner.toBase58() !== SOLANA_UPGRADEABLE_LOADER_ID ||
      programInfo.executable !== true ||
      programdataInfo.owner.toBase58() !== SOLANA_UPGRADEABLE_LOADER_ID ||
      programdataInfo.executable !== false
    ) {
      throw new Error(
        `Solana ${spec.label} Loader-v3 owner/executable linkage is invalid.`,
      );
    }
    const parsedProgramdata = parseSolanaProgramdataAccountDataForLinkage(
      programdataInfo.data,
    );
    roles[spec.role] = {
      role: spec.role,
      label: spec.label,
      program: finalizedReadbackAccountFingerprint(programId, programInfo),
      programdata: finalizedReadbackAccountFingerprint(
        discoveredProgramdataAddress,
        programdataInfo,
      ),
      loaderV3: {
        programTag: 2,
        programdataTag: parsedProgramdata.tag,
        programdataAddress: discoveredProgramdataAddress,
        deploymentSlot: parsedProgramdata.slot,
        immutable: parsedProgramdata.immutable,
        upgradeAuthorityOption: parsedProgramdata.upgradeAuthorityOption,
        upgradeAuthorityAddress: parsedProgramdata.upgradeAuthorityAddress,
        executableLength: parsedProgramdata.executableLength,
        executableSha256: parsedProgramdata.executableSha256,
        executableBlake2b256: parsedProgramdata.executableBlake2b256,
        executableElf: parsedProgramdata.executableElf,
        failClosedSentinelPresent: parsedProgramdata.failClosedSentinelPresent,
        nativeVerifierCpiMarkerPresent:
          parsedProgramdata.nativeVerifierCpiMarkerPresent,
        governedMaterialNotLinkedSentinelPresent:
          parsedProgramdata.governedMaterialNotLinkedSentinelPresent,
      },
    };
  }

  const configuredNativeVerifierProgramId = readFirstManifestString(
    nativeVerifierConfigReport,
    "nativeVerifierProgramId",
    "solanaNativeVerifierProgramId",
  );
  if (
    configuredNativeVerifierProgramId &&
    normalizeFinalizedReadbackPublicKey(
      configuredNativeVerifierProgramId,
      "native-verifier config report program id",
    ) !== roleProgramIds.nativeVerifier
  ) {
    throw new Error(
      "Reviewed native-verifier config report does not match the captured native-verifier role.",
    );
  }

  const verifierStateInfo = snapshot.accounts.get(verifierStateAddress);
  const sourceStateInfo = snapshot.accounts.get(sourceStateAddress);
  const tokenMintInfo = snapshot.accounts.get(tokenMintAddress);
  if (
    verifierStateInfo.owner.toBase58() !== roleProgramIds.outerVerifier ||
    verifierStateInfo.executable ||
    sourceStateInfo.owner.toBase58() !== roleProgramIds.sourceBridge ||
    sourceStateInfo.executable ||
    tokenMintInfo.owner.toBase58() !== TOKEN_PROGRAM_ID.toBase58() ||
    tokenMintInfo.executable
  ) {
    throw new Error(
      "Solana finalized readback state or mint account ownership is invalid.",
    );
  }
  const verifierState = parseSolanaSccpStateAccountData(verifierStateInfo.data);
  const sourceState = parseSolanaSccpStateAccountData(sourceStateInfo.data);
  const tokenMint = parseSolanaSplTokenMintData(tokenMintInfo.data);
  if (
    verifierState.storedMint !== tokenMintAddress ||
    sourceState.storedMint !== tokenMintAddress
  ) {
    throw new Error(
      "Solana finalized readback state accounts do not bind the reviewed mint.",
    );
  }
  if (
    verifierState.nativeVerifierProgramId &&
    verifierState.nativeVerifierProgramId !== roleProgramIds.nativeVerifier
  ) {
    throw new Error(
      "Solana verifier state does not bind the reviewed native verifier role.",
    );
  }
  const nativeVerifierConfigBinding = {
    present: Boolean(nativeVerifierConfigReport),
    programId: configuredNativeVerifierProgramId || null,
    outerVerifierProgramId:
      readFirstManifestString(
        nativeVerifierConfigReport,
        "verifierProgramId",
      ) || null,
    verifierStateAddress:
      readFirstManifestString(
        nativeVerifierConfigReport,
        "verifierStateAddress",
      ) || null,
    programdataAddress:
      readFirstManifestString(
        nativeVerifierConfigReport,
        "nativeVerifierProgramdataAddress",
      ) || null,
    programdataSlot:
      readFirstManifestStringLike(
        nativeVerifierConfigReport,
        "nativeVerifierProgramdataSlot",
      ) || null,
    codeHash:
      readFirstManifestString(
        nativeVerifierConfigReport,
        "nativeVerifierCodeHash",
      ) || null,
    verifierMaterialHash:
      readFirstManifestString(
        nativeVerifierConfigReport,
        "verifierMaterialHash",
      ) || null,
    verifierConfigHash:
      readFirstManifestString(
        nativeVerifierConfigReport,
        "verifierConfigHash",
      ) || null,
    configuredStateDataSha256:
      readFirstManifestString(
        nativeVerifierConfigReport?.configuredState,
        "dataSha256",
      ) || null,
  };
  for (const [actual, expected, label] of [
    [
      nativeVerifierConfigBinding.outerVerifierProgramId,
      roleProgramIds.outerVerifier,
      "outer verifier program id",
    ],
    [
      nativeVerifierConfigBinding.verifierStateAddress,
      verifierStateAddress,
      "verifier state address",
    ],
    [
      nativeVerifierConfigBinding.programdataAddress,
      roles.nativeVerifier.programdata.address,
      "native verifier ProgramData address",
    ],
    [
      nativeVerifierConfigBinding.programdataSlot,
      roles.nativeVerifier.loaderV3.deploymentSlot,
      "native verifier ProgramData slot",
    ],
    [
      nativeVerifierConfigBinding.codeHash,
      roles.nativeVerifier.loaderV3.executableBlake2b256,
      "native verifier code hash",
    ],
    [
      nativeVerifierConfigBinding.verifierMaterialHash,
      verifierState.verifierMaterialHash,
      "native verifier material hash",
    ],
    [
      nativeVerifierConfigBinding.verifierConfigHash,
      verifierState.verifierConfigHash,
      "native verifier config hash",
    ],
    [
      nativeVerifierConfigBinding.configuredStateDataSha256,
      sha256BufferHex(verifierStateInfo.data),
      "configured verifier-state data hash",
    ],
  ]) {
    if (actual !== null && String(actual) !== String(expected)) {
      throw new Error(
        `Reviewed native-verifier config report ${label} does not match the finalized snapshot.`,
      );
    }
  }
  const [expectedMintAuthority, expectedMintAuthorityBump] =
    deriveMintAuthority(
      new PublicKey(roleProgramIds.outerVerifier),
      new PublicKey(verifierStateAddress),
    );
  if (
    tokenMint.mintAuthority !== expectedMintAuthority.toBase58() ||
    tokenMint.decimals !== SPL_TOKEN_DECIMALS ||
    tokenMint.initialized !== true ||
    tokenMint.freezeAuthority !== null
  ) {
    throw new Error(
      "Solana finalized readback mint configuration does not match the reviewed route.",
    );
  }

  const sourceTokenAccounts = tokenAccountAddresses.map((address) => {
    const info = snapshot.accounts.get(address);
    if (
      info.owner.toBase58() !== TOKEN_PROGRAM_ID.toBase58() ||
      info.executable
    ) {
      throw new Error(
        `Solana source token account ${address} has an invalid program owner.`,
      );
    }
    const parsed = parseSolanaSplTokenAccountData(info.data);
    if (
      parsed.mint !== tokenMintAddress ||
      parsed.owner !== reviewedOwnerAddress ||
      parsed.isInitialized !== true ||
      parsed.isFrozen !== false
    ) {
      throw new Error(
        `Solana source token account ${address} is not bound to the reviewed owner and mint.`,
      );
    }
    return {
      ...finalizedReadbackAccountFingerprint(address, info),
      parsed,
    };
  });
  const sourceTokenBalance = sourceTokenAccounts
    .reduce((total, account) => total + BigInt(account.parsed.amount), 0n)
    .toString();

  const observedAccounts = {
    tokenMintAccount: finalizedReadbackAccountFingerprint(
      tokenMintAddress,
      tokenMintInfo,
    ),
    verifierStateAccount: finalizedReadbackAccountFingerprint(
      verifierStateAddress,
      verifierStateInfo,
    ),
    sourceStateAccount: finalizedReadbackAccountFingerprint(
      sourceStateAddress,
      sourceStateInfo,
    ),
    verifierProgramAccount: roles.outerVerifier.program,
    bridgeProgramAccount: roles.destinationBridge.program,
    sourceBridgeProgramAccount: roles.sourceBridge.program,
  };
  const addresses = {
    verifierProgramId: roleProgramIds.outerVerifier,
    nativeVerifierProgramId: roleProgramIds.nativeVerifier,
    bridgeProgramId: roleProgramIds.destinationBridge,
    sourceBridgeProgramId: roleProgramIds.sourceBridge,
    verifierStateAddress,
    sourceStateAddress,
    tokenMintAddress,
  };
  const observedSourceBridgeConfig = buildSolanaObservedSourceBridgeConfig({
    addresses,
    expectedMintAuthority: expectedMintAuthority.toBase58(),
    observed: {
      tokenMint,
      verifierState,
      sourceState,
      accounts: observedAccounts,
    },
    manifest: { destinationBindingHash: SOLANA_DESTINATION_BINDING_HASH },
    verifierEvidence: finalizedReadbackRoleViewFromRole({
      role: roles.outerVerifier,
      solanaGenesisHash,
      canonicalSnapshotSha256: null,
    }),
    verifierLiveEvidence: null,
  });
  const observedSourceBridgeConfigHash = sha256JsonHex(
    observedSourceBridgeConfig,
  );
  const expectedSourceBridgeConfigHashRaw =
    expectedSourceBridgeConfigHashFromManifest(manifest);
  const expectedSourceBridgeConfigHash = expectedSourceBridgeConfigHashRaw
    ? normalizeManifestHex32(
        expectedSourceBridgeConfigHashRaw,
        "manifest post-deploy source-bridge config hash",
      )
    : null;
  const sourceBridgeConfigMatchesExpected = expectedSourceBridgeConfigHash
    ? expectedSourceBridgeConfigHash === observedSourceBridgeConfigHash
    : null;

  const canonicalSnapshot = {
    commitment: "finalized",
    publicInputs: {
      publicConfigSha256: publicConfigInput.sha256,
      nativeVerifierConfigSha256: nativeVerifierConfigInput?.sha256 ?? null,
    },
    nativeVerifierConfig: nativeVerifierConfigBinding,
    reviewedAddresses: {
      ...addresses,
      sourceTokenOwnerAddress: reviewedOwnerAddress,
      programdataAddresses: discoveredProgramdataAddresses,
    },
    consistency: {
      discoveryContextSlot: discovery.contextSlot,
      preEnumerationContextSlot: preEnumeration.contextSlot,
      snapshotContextSlot: snapshot.contextSlot,
      postEnumerationContextSlot: postEnumeration.contextSlot,
      accountCount: snapshotAddresses.length,
      sourceTokenAccountCount: sourceTokenAccounts.length,
      tokenEnumerationStable: true,
      identityRecheckedAfterFence: true,
    },
    roles,
    stateAccounts: {
      verifier: {
        account: observedAccounts.verifierStateAccount,
        parsed: verifierState,
      },
      source: {
        account: observedAccounts.sourceStateAccount,
        parsed: sourceState,
      },
    },
    tokenMint: {
      account: observedAccounts.tokenMintAccount,
      parsed: tokenMint,
      expectedMintAuthority: expectedMintAuthority.toBase58(),
      expectedMintAuthorityBump,
    },
    sourceOwnerTokenAccounts: {
      ownerAddress: reviewedOwnerAddress,
      balance: sourceTokenBalance,
      spendableBalance: sourceTokenBalance,
      accounts: sourceTokenAccounts,
    },
    sourceBridgeConfig: {
      observed: observedSourceBridgeConfig,
      observedHash: observedSourceBridgeConfigHash,
    },
  };
  const canonicalSnapshotSha256 =
    solanaFinalizedReadbackCanonicalSnapshotSha256({
      routeId: SCCP_SOLANA_XOR_ROUTE_ID,
      assetKey: SCCP_XOR_ASSET_KEY,
      solanaNetwork: "testnet",
      solanaGenesisHash,
      snapshot: canonicalSnapshot,
    });
  const blockers = [
    ...(verifierState.nativeVerifierProgramId === null ||
    verifierState.verifierMaterialHash === null ||
    verifierState.verifierConfigHash === null ||
    verifierState.verifierConfiguredSlot === null
      ? [
          {
            id: "native-verifier-state-unconfigured",
            detail:
              "The finalized verifier state does not contain a complete native-verifier program/material/config binding.",
          },
        ]
      : []),
  ];
  const manifestComparisonBlockerIds =
    sourceBridgeConfigMatchesExpected === true
      ? []
      : [
          expectedSourceBridgeConfigHash === null
            ? "manifest-source-bridge-config-pin-missing"
            : "source-bridge-config-hash-mismatch",
        ];
  const report = {
    schema: SOLANA_FINALIZED_READBACK_EVIDENCE_SCHEMA,
    routeId: SCCP_SOLANA_XOR_ROUTE_ID,
    assetKey: SCCP_XOR_ASSET_KEY,
    solanaNetwork: "testnet",
    solanaGenesisHash,
    capturedAt,
    ...publicSolanaRpcUrlEvidence(connection.rpcEndpoint ?? null),
    inputs: {
      publicConfig: publicConfigInput,
      nativeVerifierConfig: nativeVerifierConfigInput,
    },
    manifestComparison: {
      input: manifestInput,
      expectedSourceBridgeConfigHash,
      observedSourceBridgeConfigHash,
      matchesExpected: sourceBridgeConfigMatchesExpected,
      ready: sourceBridgeConfigMatchesExpected === true,
      blockerIds: manifestComparisonBlockerIds,
    },
    ready: blockers.length === 0,
    blockers,
    blockerIds: blockers.map((blocker) => blocker.id),
    canonicalSnapshotSha256,
    snapshot: canonicalSnapshot,
  };
  return validateSolanaFinalizedReadbackEvidence(report);
};

export const loadStableSolanaFinalizedReadbackEvidence = async ({
  file,
  expectedSha256 = null,
  required = true,
} = {}) => {
  const resolvedPath = path.resolve(file);
  if (!existsSync(resolvedPath) && !required) {
    return null;
  }
  const artifact = await readStablePublicSolanaJsonArtifact({
    file: resolvedPath,
    label: "Canonical Solana finalized-readback evidence",
    expectedSha256,
  });
  return {
    artifact: {
      path: artifact.path,
      sizeBytes: artifact.sizeBytes,
      sha256: artifact.sha256,
      stableRead: artifact.stableRead,
    },
    evidence: validateSolanaFinalizedReadbackEvidence(artifact.value),
  };
};

const evidence = async (args) => {
  assertNoFileBackedSolanaSignerOptions(args);
  const paths = artifactPaths(args);
  const publicConfigPath = path.resolve(
    args["public-config"] || paths.publicConfig,
  );
  const publicConfigArtifact = await readStablePublicSolanaJsonArtifact({
    file: publicConfigPath,
    label: "Reviewed Solana public deployment config",
    expectedSha256: args["expected-public-config-sha256"] ?? null,
  });
  const publicConfig = sanitizeSolanaPublicConfig(publicConfigArtifact.value);
  if (
    JSON.stringify(publicConfig) !== JSON.stringify(publicConfigArtifact.value)
  ) {
    throw new Error(
      "Reviewed Solana public deployment config contains prohibited secret-bearing fields; the read-only evidence command never reads, copies, or rewrites them.",
    );
  }
  const configuredOuterProgramId = readFinalizedReadbackConfigAddress(
    publicConfig,
    SOLANA_FINALIZED_READBACK_ROLE_SPECS[0],
  );
  for (const [label, value] of [
    ["--program-id", args["program-id"]],
    ["--verifier-program-id", args["verifier-program-id"]],
  ]) {
    if (
      typeof value === "string" &&
      normalizeFinalizedReadbackPublicKey(value, label) !==
        configuredOuterProgramId
    ) {
      throw new Error(
        `${label} does not match the stable reviewed public config.`,
      );
    }
  }
  const configuredNativeProgramId = readFinalizedReadbackConfigAddress(
    publicConfig,
    SOLANA_FINALIZED_READBACK_ROLE_SPECS[1],
  );
  for (const [label, value] of [
    ["--native-verifier-program-id", args["native-verifier-program-id"]],
    [
      "--solana-native-verifier-program-id",
      args["solana-native-verifier-program-id"],
    ],
  ]) {
    if (
      typeof value === "string" &&
      normalizeFinalizedReadbackPublicKey(value, label) !==
        configuredNativeProgramId
    ) {
      throw new Error(
        `${label} does not match the stable reviewed public config.`,
      );
    }
  }
  const manifestPath = path.resolve(args.manifest || paths.routeManifest);
  let manifestArtifact = null;
  if (
    existsSync(manifestPath) ||
    Object.prototype.hasOwnProperty.call(args, "manifest") ||
    Object.prototype.hasOwnProperty.call(args, "expected-manifest-sha256")
  ) {
    manifestArtifact = await readStablePublicSolanaJsonArtifact({
      file: manifestPath,
      label: "Reviewed Solana route manifest",
      expectedSha256: args["expected-manifest-sha256"] ?? null,
    });
  }
  const nativeVerifierConfiguration =
    await loadStableSolanaNativeVerifierConfigReport(args, paths);
  const connection = createConnection(args);
  const inputEvidence = (artifact, selection, requestedPath) =>
    artifact
      ? {
          selection,
          requestedPath,
          path: artifact.path,
          sizeBytes: artifact.sizeBytes,
          sha256: artifact.sha256,
          stableRead: artifact.stableRead,
        }
      : null;
  const report = await captureSolanaFinalizedReadbackEvidence({
    connection,
    publicConfig,
    publicConfigInput: inputEvidence(
      publicConfigArtifact,
      Object.prototype.hasOwnProperty.call(args, "public-config")
        ? "explicit"
        : "default",
      publicConfigPath,
    ),
    manifest: manifestArtifact?.value ?? null,
    manifestInput: inputEvidence(
      manifestArtifact,
      Object.prototype.hasOwnProperty.call(args, "manifest")
        ? "explicit"
        : "default",
      manifestPath,
    ),
    nativeVerifierConfigReport: nativeVerifierConfiguration.report,
    nativeVerifierConfigInput: nativeVerifierConfiguration.input,
    ownerAddress: args.owner ?? null,
    retryOptions: solanaRpcRetryOptions(args),
  });
  const evidenceBytes = Buffer.from(`${JSON.stringify(report, null, 2)}\n`);
  const evidenceArtifactSha256 = sha256BufferHex(evidenceBytes);
  await writePublicArtifactAtomically(paths.evidence, evidenceBytes);
  if (
    asBoolean(args.strict) &&
    (report.ready !== true || report.manifestComparison.ready !== true)
  ) {
    throw new Error(
      `Solana finalized readback evidence failed: ${uniqueStrings([
        ...report.blockerIds,
        ...report.manifestComparison.blockerIds,
      ]).join(", ")}`,
    );
  }
  return {
    evidencePath: paths.evidence,
    evidenceArtifactSha256,
    evidence: report,
  };
};

export const buildSolanaLiveEvidenceHelperArgs = ({
  args = {},
  publicConfig,
  verifierEvidence = null,
  verifierLiveEvidence = null,
  manifest = null,
  verifierProgramId,
}) => {
  const resolvedVerifierProgramId =
    verifierProgramId ||
    args["program-id"] ||
    publicConfig?.verifierProgramId ||
    publicConfig?.programId;
  if (!resolvedVerifierProgramId) {
    throw new Error("Solana verifier program id is required.");
  }
  const expectedVerifierCodeHash = asBoolean(
    args["discover-verifier-code-hash"],
  )
    ? null
    : args["expected-verifier-code-hash"] ||
      readFirstManifestString(
        manifest,
        "verifierCodeHash",
        "verifier_code_hash",
      ) ||
      readFirstManifestString(
        verifierLiveEvidence,
        "verifier_code_hash",
        "verifierCodeHash",
      );
  const expectedProgramdataAddress =
    args["expected-programdata-address"] ||
    readFirstManifestString(
      verifierLiveEvidence,
      "programdata_address",
      "programdataAddress",
    ) ||
    readFirstManifestString(
      manifest,
      "solanaProgramdataAddress",
      "solana_programdata_address",
    ) ||
    outerVerifierEvidenceFacts(verifierEvidence).programDataAddress;
  const expectedProgramdataSlot =
    args["expected-programdata-slot"] ||
    readFirstManifestStringLike(
      verifierLiveEvidence,
      "programdata_slot",
      "programdataSlot",
    ) ||
    readFirstManifestString(
      manifest,
      "solanaProgramdataSlot",
      "solana_programdata_slot",
    ) ||
    outerVerifierEvidenceFacts(verifierEvidence).programDataSlot;
  const expectedDestinationBindingHash =
    args["expected-destination-binding-hash"] ||
    readFirstManifestString(
      manifest,
      "destinationBindingHash",
      "destination_binding_hash",
    ) ||
    SOLANA_DESTINATION_BINDING_HASH;
  const helperArgs = [
    siblingLiveEvidenceScript,
    "--rpc-url",
    args["solana-rpc-url"] || DEFAULT_SOLANA_RPC_URL,
    "--verifier-program-id",
    resolvedVerifierProgramId,
    "--commitment",
    args.commitment || "finalized",
  ];
  if (expectedVerifierCodeHash) {
    helperArgs.push("--expected-verifier-code-hash", expectedVerifierCodeHash);
  }
  if (expectedProgramdataAddress) {
    helperArgs.push(
      "--expected-programdata-address",
      expectedProgramdataAddress,
    );
  }
  if (expectedProgramdataSlot) {
    helperArgs.push(
      "--expected-programdata-slot",
      String(expectedProgramdataSlot),
    );
  }
  if (expectedDestinationBindingHash) {
    helperArgs.push(
      "--expected-destination-binding-hash",
      expectedDestinationBindingHash,
    );
  }
  return helperArgs;
};

const solanaLiveEvidenceMatchesDeployment = ({
  liveEvidence,
  publicConfig,
  verifierEvidence,
  manifest = null,
}) => {
  if (!liveEvidence || !publicConfig) {
    return false;
  }
  const verifierProgramId =
    publicConfig.verifierProgramId || publicConfig.programId;
  if (
    verifierProgramId &&
    liveEvidence.verifier_program_id !== verifierProgramId
  ) {
    return false;
  }
  const expectedProgramdataAddress =
    readFirstManifestString(
      manifest,
      "solanaProgramdataAddress",
      "solana_programdata_address",
    ) || outerVerifierEvidenceFacts(verifierEvidence).programDataAddress;
  if (
    expectedProgramdataAddress &&
    liveEvidence.programdata_address !== expectedProgramdataAddress
  ) {
    return false;
  }
  const expectedProgramdataSlot =
    readFirstManifestStringLike(
      manifest,
      "solanaProgramdataSlot",
      "solana_programdata_slot",
    ) || outerVerifierEvidenceFacts(verifierEvidence).programDataSlot;
  if (
    expectedProgramdataSlot &&
    String(liveEvidence.programdata_slot) !== String(expectedProgramdataSlot)
  ) {
    return false;
  }
  return typeof liveEvidence.verifier_code_hash === "string";
};

const solanaLiveEvidenceMatchesSelectedDeployment = ({
  liveEvidence,
  publicConfig,
  verifierEvidence,
  manifest,
}) => {
  if (
    !solanaLiveEvidenceMatchesDeployment({
      liveEvidence,
      publicConfig,
      verifierEvidence,
      manifest,
    })
  ) {
    return false;
  }
  const expectedProgramdataAddress = readFirstManifestString(
    manifest,
    "solanaProgramdataAddress",
    "solana_programdata_address",
  );
  if (
    deploymentAddressMismatch(
      liveEvidence.programdata_address,
      expectedProgramdataAddress,
    )
  ) {
    return false;
  }
  const expectedProgramdataSlot = readFirstManifestStringLike(
    manifest,
    "solanaProgramdataSlot",
    "solana_programdata_slot",
  );
  return !(
    expectedProgramdataSlot &&
    String(liveEvidence.programdata_slot ?? "") !==
      String(expectedProgramdataSlot)
  );
};

const solanaPublicConfigMatchesDeployment = (publicConfig, addresses) => {
  if (!publicConfig) {
    return false;
  }
  return ![
    [
      publicConfig.verifierProgramId ?? publicConfig.programId,
      "verifierProgramId",
    ],
    [publicConfig.bridgeProgramId, "bridgeProgramId"],
    [publicConfig.sourceBridgeProgramId, "sourceBridgeProgramId"],
    [publicConfig.tokenMintAddress, "tokenMintAddress"],
    [publicConfig.verifierStateAddress, "verifierStateAddress"],
    [publicConfig.sourceStateAddress, "sourceStateAddress"],
  ].some(([actual, key]) => deploymentAddressMismatch(actual, addresses[key]));
};

export const loadSelectedSolanaDeploymentMaterial = async ({
  args = {},
  paths = artifactPaths(args),
  manifestPath = path.resolve(args.manifest || paths.routeManifest),
  verifierEvidenceOverride = null,
  requireEvidenceSha256Pin = true,
  requireManifestSha256Pin = true,
} = {}) => {
  const selectedPublicConfigPath = path.resolve(
    args["public-config"] || paths.publicConfig,
  );
  const selectedAccountsPath = path.resolve(
    args.accounts || paths.accountsReport,
  );
  const selectedVerifierEvidencePath = path.resolve(
    args.evidence || paths.evidence,
  );
  const selectedVerifierLiveEvidencePath = path.resolve(
    args["live-evidence"] || paths.liveEvidence,
  );
  const readOptionalStableInput = async ({
    file,
    label,
    required = false,
    expectedSha256 = null,
  }) => {
    const resolvedPath = path.resolve(file);
    if (!existsSync(resolvedPath) && !required) {
      return null;
    }
    return readStablePublicSolanaJsonArtifact({
      file: resolvedPath,
      label,
      expectedSha256,
    });
  };
  const manifestInput = await readOptionalStableInput({
    file: manifestPath,
    label: "Selected Solana route manifest",
    required:
      Object.prototype.hasOwnProperty.call(args, "manifest") ||
      Object.prototype.hasOwnProperty.call(args, "expected-manifest-sha256"),
    expectedSha256: args["expected-manifest-sha256"] ?? null,
  });
  if (
    requireManifestSha256Pin &&
    verifierEvidenceOverride === null &&
    manifestInput &&
    args["expected-manifest-sha256"] === undefined
  ) {
    throw new Error(
      "An existing Solana route manifest may authorize production behavior only with --expected-manifest-sha256. Capture evidence against it in this process or provide an independently reviewed exact-byte SHA-256 pin.",
    );
  }
  const publicConfigInput = await readOptionalStableInput({
    file: selectedPublicConfigPath,
    label: "Selected Solana public deployment config",
    required:
      Object.prototype.hasOwnProperty.call(args, "public-config") ||
      Object.prototype.hasOwnProperty.call(
        args,
        "expected-public-config-sha256",
      ),
    expectedSha256: args["expected-public-config-sha256"] ?? null,
  });
  const accountsInput = await readOptionalStableInput({
    file: selectedAccountsPath,
    label: "Selected public Solana accounts report",
    required: Object.prototype.hasOwnProperty.call(args, "accounts"),
  });
  const liveEvidenceInput = await readOptionalStableInput({
    file: selectedVerifierLiveEvidencePath,
    label: "Selected public Solana live-evidence report",
    required: Object.prototype.hasOwnProperty.call(args, "live-evidence"),
  });
  const selectedManifest = manifestInput?.value ?? null;
  const selectedPublicConfig = publicConfigInput
    ? sanitizeSolanaPublicConfig(publicConfigInput.value)
    : null;
  if (
    publicConfigInput &&
    JSON.stringify(selectedPublicConfig) !==
      JSON.stringify(publicConfigInput.value)
  ) {
    throw new Error(
      "Selected Solana public deployment config contains prohibited secret-bearing fields.",
    );
  }
  const expectedEvidenceSha256 = args["expected-evidence-sha256"] ?? null;
  if (
    requireEvidenceSha256Pin &&
    verifierEvidenceOverride === null &&
    expectedEvidenceSha256 === null
  ) {
    throw new Error(
      "An existing canonical Solana finalized-readback evidence artifact may authorize production behavior only with --expected-evidence-sha256. Capture it in this process or provide an independently reviewed exact-byte SHA-256 pin.",
    );
  }
  let selectedVerifierEvidenceInput = null;
  if (verifierEvidenceOverride !== null) {
    const overrideEvidence = validateSolanaFinalizedReadbackEvidence(
      verifierEvidenceOverride.evidence,
    );
    const overrideSha256 = normalizeManifestHex32(
      verifierEvidenceOverride.evidenceArtifactSha256,
      "fresh canonical finalized-readback evidence artifact SHA-256",
    );
    if (
      manifestInput &&
      overrideEvidence.manifestComparison?.input?.sha256 !==
        manifestInput.sha256
    ) {
      throw new Error(
        "Fresh canonical Solana finalized-readback evidence was captured from different selected manifest bytes.",
      );
    }
    if (
      expectedEvidenceSha256 !== null &&
      normalizeManifestHex32(
        expectedEvidenceSha256,
        "expected canonical finalized-readback evidence artifact SHA-256",
      ) !== overrideSha256
    ) {
      throw new Error(
        "Fresh canonical Solana finalized-readback evidence does not match --expected-evidence-sha256.",
      );
    }
    selectedVerifierEvidenceInput = {
      artifact: {
        path: path.resolve(
          verifierEvidenceOverride.evidencePath ?? selectedVerifierEvidencePath,
        ),
        sha256: overrideSha256,
        stableRead: false,
        sameProcessCapture: true,
      },
      evidence: overrideEvidence,
    };
  } else {
    selectedVerifierEvidenceInput =
      await loadStableSolanaFinalizedReadbackEvidence({
        file: selectedVerifierEvidencePath,
        expectedSha256: expectedEvidenceSha256,
        required:
          requireEvidenceSha256Pin ||
          Object.prototype.hasOwnProperty.call(args, "evidence") ||
          Object.prototype.hasOwnProperty.call(
            args,
            "expected-evidence-sha256",
          ) ||
          existsSync(selectedVerifierEvidencePath),
      });
  }
  const deploymentAddresses = solanaPostDeployDeploymentAddresses({
    publicConfig: null,
    manifest: selectedManifest,
    accounts: null,
  });
  const publicConfig = selectedPublicConfig;
  if (
    publicConfig &&
    selectedManifest &&
    !solanaPublicConfigMatchesDeployment(publicConfig, deploymentAddresses)
  ) {
    throw new Error(
      "Selected Solana public deployment config does not match the selected route manifest.",
    );
  }
  const accounts = accountsInput?.value ?? null;
  if (
    accounts &&
    !selectSolanaAccountsReport({
      candidates: [accounts],
      publicConfig,
      manifest: selectedManifest,
    })
  ) {
    throw new Error(
      "Selected public Solana accounts report does not match the selected deployment.",
    );
  }
  const verifierEvidence = selectedVerifierEvidenceInput?.evidence ?? null;
  if (verifierEvidence) {
    assertSolanaFinalizedReadbackMatchesSelection({
      evidence: verifierEvidence,
      publicConfig,
      manifest: selectedManifest,
      ownerAddress: args.owner ?? null,
    });
  }
  if (verifierEvidence && publicConfigInput) {
    const capturedConfigSha256 =
      verifierEvidence.snapshot.publicInputs?.publicConfigSha256 ?? null;
    if (capturedConfigSha256 !== publicConfigInput.sha256) {
      throw new Error(
        "Canonical Solana finalized-readback evidence was captured from different public-config bytes.",
      );
    }
  }
  const verifierLiveEvidence = liveEvidenceInput?.value ?? null;
  if (
    verifierLiveEvidence &&
    !solanaLiveEvidenceMatchesSelectedDeployment({
      liveEvidence: verifierLiveEvidence,
      publicConfig,
      verifierEvidence,
      manifest: selectedManifest,
    })
  ) {
    throw new Error(
      "Selected public Solana live evidence does not match the selected deployment.",
    );
  }
  return {
    id: "canonical",
    manifestPath,
    manifest: selectedManifest,
    publicConfig,
    accounts,
    verifierEvidence,
    verifierLiveEvidence,
    materialPaths: {
      publicConfig: selectedPublicConfigPath,
      manifest: manifestPath,
      accounts: selectedAccountsPath,
      verifierEvidence:
        selectedVerifierEvidenceInput?.artifact?.path ??
        selectedVerifierEvidencePath,
      verifierLiveEvidence: selectedVerifierLiveEvidencePath,
    },
    verifierEvidenceArtifact: selectedVerifierEvidenceInput?.artifact ?? null,
    selectedArtifacts: {
      manifest: manifestInput
        ? { path: manifestInput.path, sha256: manifestInput.sha256 }
        : null,
      publicConfig: publicConfigInput
        ? { path: publicConfigInput.path, sha256: publicConfigInput.sha256 }
        : null,
      accounts: accountsInput
        ? { path: accountsInput.path, sha256: accountsInput.sha256 }
        : null,
      liveEvidence: liveEvidenceInput
        ? {
            path: liveEvidenceInput.path,
            sha256: liveEvidenceInput.sha256,
          }
        : null,
      finalizedReadback: selectedVerifierEvidenceInput?.artifact ?? null,
    },
  };
};

