const parseDeploySignatures = async (paths) => {
  if (!existsSync(paths.deployLog)) {
    return {};
  }
  const text = await readFile(paths.deployLog, "utf8");
  const entries = {};
  for (const match of text.matchAll(
    /^#\s+([^\n]+)\n[\s\S]*?Signature:\s+([1-9A-HJ-NP-Za-km-z]+)/gmu,
  )) {
    entries[match[1].trim()] = match[2];
  }
  return entries;
};

const parseWebVttCues = (webvtt) => {
  const blocks = String(webvtt ?? "")
    .trim()
    .split(/\n\s*\n/u)
    .filter(Boolean);
  const cues = [];
  for (const block of blocks) {
    const lines = block
      .split(/\r?\n/u)
      .map((line) => line.trim())
      .filter(Boolean);
    const timingLine = lines.find((line) => line.includes("-->"));
    if (!timingLine) {
      continue;
    }
    const [start, end] = timingLine
      .split(/\s+-->\s+/u)
      .map((part) => part.trim());
    const text = lines.slice(lines.indexOf(timingLine) + 1).join(" ");
    cues.push({
      index: cues.length + 1,
      start,
      end,
      text,
      step: Number(text.match(/^Step\s+(\d+):/u)?.[1] ?? 0) || null,
    });
  }
  return cues;
};

const parseWebVttTimestampSeconds = (value) => {
  const parts = String(value ?? "")
    .trim()
    .split(":");
  if (parts.length < 2 || parts.length > 3) {
    return null;
  }
  const seconds = Number(parts.pop());
  if (!Number.isFinite(seconds) || seconds < 0) {
    return null;
  }
  let total = seconds;
  let multiplier = 60;
  while (parts.length > 0) {
    const part = Number(parts.pop());
    if (!Number.isSafeInteger(part) || part < 0) {
      return null;
    }
    total += part * multiplier;
    multiplier *= 60;
  }
  return total;
};

