export const buildSolanaLiveVideoGateOptions = ({
  args = {},
  paths,
  toriiUrl,
  solanaRpcUrl,
  skipSolanaRpc = true,
  productionGatePath = null,
  productionGateArtifactSha256 = null,
  preflightReport = null,
  successMode = Boolean(args["live-evidence"]) &&
    skipSolanaRpc === false &&
    CANONICAL_TAIRA_PUBLIC_NODE_ROOTS.has(
      String(toriiUrl ?? "").replace(/\/+$/u, ""),
    ) &&
    String(solanaRpcUrl ?? "").replace(/\/+$/u, "") === DEFAULT_SOLANA_RPC_URL,
} = {}) => {
  const common = {
    toriiUrl,
    solanaRpcUrl,
    outputDir: path.join(paths.outputDir, "live-video"),
    fetchTimeoutMs: args["fetch-timeout-ms"],
    fetchAttempts: args["fetch-attempts"],
  };
  const generatedChain = {
    productionRequirements: paths.productionRequirements,
    publishReadiness: paths.routeManifestPublishReadiness,
    routePublicationRequest:
      reportOverridePath(args, ["route-publication-request-report"]) ??
      paths.routePublicationRequest,
    smokeReadiness: paths.smokeReadiness,
    handoffVerification: paths.sourceMaterialHandoffVerification,
    proofMaterialBundle: paths.proofMaterialBundle,
    activationPackage:
      reportOverridePath(args, ["activation-package-report"]) ??
      paths.activationPackage,
    deploymentVideoTranscript: paths.deploymentVideoTranscript,
    operatorHandoff:
      reportOverridePath(args, ["operator-handoff-report"]) ??
      paths.operatorHandoff,
    productionGate: productionGatePath,
  };
  if (successMode) {
    if (
      !CANONICAL_TAIRA_PUBLIC_NODE_ROOTS.has(
        String(toriiUrl ?? "").replace(/\/+$/u, ""),
      ) ||
      String(solanaRpcUrl ?? "").replace(/\/+$/u, "") !==
        DEFAULT_SOLANA_RPC_URL ||
      !args["live-evidence"] ||
      !productionGatePath ||
      !normalizeProductionMaterialHex32(
        productionGateArtifactSha256,
        "pre-live production-gate report SHA-256",
      )
    ) {
      throw new Error(
        "Solana live-video success mode requires a canonical TAIRA validator root, canonical Solana testnet RPC, explicit live evidence, and one exact pinned pre-live production-gate report.",
      );
    }
    return {
      ...common,
      productionGateSnapshot: path.resolve(productionGatePath),
      productionGateSnapshotSha256: productionGateArtifactSha256,
      liveEvidence: args["live-evidence"],
      skipSolanaRpc: false,
    };
  }
  return {
    ...common,
    ...(args["live-evidence"] ? { liveEvidence: args["live-evidence"] } : {}),
    ...(preflightReport ? { preflightReport } : {}),
    skipSolanaRpc,
    ...generatedChain,
  };
};

const refreshStepSummary = (name, result) => {
  const report = result?.report ?? result ?? {};
  const failedCheckIds = Array.isArray(report?.checks)
    ? report.checks
        .filter((check) => check?.status !== "pass")
        .map((check) => check.id)
        .filter(Boolean)
    : [];
  const blockerIds = Array.isArray(report?.blockerIds)
    ? report.blockerIds
    : Array.isArray(report?.blockers)
      ? report.blockers.map((blocker) => blocker.id).filter(Boolean)
      : [];
  return {
    name,
    ready:
      report?.ready === true ||
      report?.readyToSubmitWithCurrentRuntime === true ||
      report?.readyToPublish === true ||
      report?.productionActivationReady === true ||
      (name === "deployment-video" &&
        typeof result?.videoPath === "string" &&
        typeof result?.transcriptPath === "string"),
    schema: typeof report?.schema === "string" ? report.schema : null,
    failedCheckIds,
    blockerIds,
    paths: Object.fromEntries(
      Object.entries(result ?? {})
        .filter(
          ([key, value]) =>
            key.endsWith("Path") && typeof value === "string" && value.trim(),
        )
        .map(([key, value]) => [key, value]),
    ),
  };
};

const SOLANA_REPORT_ACTION_ALIASES = new Map([
  ["publish-public-taira-solana-route", "publish-taira-solana-route-manifest"],
  [
    "provide-sourceVerifierMaterialHash",
    "provide-source-verifier-material-hash",
  ],
  [
    "provide-sourceAdapterEngineDeploymentHash",
    "provide-source-adapter-engine-deployment-hash",
  ],
  ["provide-routeAllowlistHash", "provide-route-allowlist-hash"],
]);

const SOLANA_REPORT_BLOCKER_ALIASES = new Map([
  ["sourceVerifierMaterialHash", "source-verifier-material-hash"],
  [
    "sourceAdapterEngineDeploymentHash",
    "source-adapter-engine-deployment-hash",
  ],
  ["routeAllowlistHash", "route-allowlist-hash"],
]);

const normalizeSolanaReportActionId = (id) =>
  SOLANA_REPORT_ACTION_ALIASES.get(id) ?? id;

const normalizeSolanaReportBlockerId = (id) => {
  const normalized = typeof id === "string" ? id.trim() : "";
  return SOLANA_REPORT_BLOCKER_ALIASES.get(normalized) ?? normalized;
};

const normalizeSolanaReportBlockerDetail = (detail, rawId, normalizedId) => {
  if (
    typeof detail === "string" &&
    rawId &&
    normalizedId &&
    rawId !== normalizedId &&
    detail.trim() === `${rawId} is required.`
  ) {
    return `${normalizedId} is required.`;
  }
  return detail;
};

const normalizeSolanaReportBlockerIds = (ids) =>
  uniqueStrings(
    (Array.isArray(ids) ? ids : [])
      .map((id) => normalizeSolanaReportBlockerId(id))
      .filter(Boolean),
  );

const normalizeSolanaReportBlockerObject = (blocker) => {
  if (!isRecord(blocker)) {
    return blocker;
  }
  const rawId = typeof blocker.id === "string" ? blocker.id.trim() : "";
  const normalizedId = rawId ? normalizeSolanaReportBlockerId(rawId) : rawId;
  return {
    ...blocker,
    ...(rawId ? { id: normalizedId } : {}),
    detail: normalizeSolanaReportBlockerDetail(
      blocker.detail,
      rawId,
      normalizedId,
    ),
    ...(Array.isArray(blocker.blockers)
      ? { blockers: normalizeSolanaReportBlockerIds(blocker.blockers) }
      : {}),
    ...(Array.isArray(blocker.blockerIds)
      ? { blockerIds: normalizeSolanaReportBlockerIds(blocker.blockerIds) }
      : {}),
  };
};

const normalizeSolanaReportBlockedBy = (blockedBy) =>
  Array.isArray(blockedBy)
    ? blockedBy.map((blocker) =>
        typeof blocker === "string"
          ? normalizeSolanaReportBlockerId(blocker)
          : isRecord(blocker)
            ? normalizeSolanaReportBlockerObject(blocker)
            : blocker,
      )
    : [];

