const solanaBlockerCoreId = (id) => {
  const normalized = normalizeSolanaReportBlockerId(id);
  return normalized.includes(":")
    ? normalized.slice(normalized.lastIndexOf(":") + 1)
    : normalized;
};

const findSolanaBlockerResolutionDefinition = (id) => {
  const coreId = solanaBlockerCoreId(id);
  return SOLANA_BLOCKER_RESOLUTION_DEFINITIONS.find((definition) =>
    definition.patterns.some(
      (pattern) => pattern.test(id) || pattern.test(coreId),
    ),
  );
};

export const buildSolanaBlockerResolution = (ids = []) => {
  const normalizedIds = normalizeSolanaReportBlockerIds(ids);
  const categoryEntries = SOLANA_BLOCKER_RESOLUTION_DEFINITIONS.map(
    (definition) => ({
      id: definition.id,
      title: definition.title,
      detail: definition.detail,
      operatorActionable: definition.operatorActionable === true,
      repoActionable: definition.repoActionable === true,
      unsafeToAutoFix: definition.unsafeToAutoFix === true,
      blockerIds: [],
    }),
  );
  const categoryById = new Map(
    categoryEntries.map((entry) => [entry.id, entry]),
  );
  const unknown = {
    id: "unknown",
    title: "Unclassified blocker",
    detail:
      "This blocker does not yet have a Solana SCCP deployment resolution class.",
    operatorActionable: true,
    repoActionable: false,
    unsafeToAutoFix: true,
    blockerIds: [],
  };

  for (const id of normalizedIds) {
    const definition = findSolanaBlockerResolutionDefinition(id);
    const entry = definition ? categoryById.get(definition.id) : unknown;
    entry.blockerIds.push(id);
  }

  const categories = [...categoryEntries, unknown]
    .filter((entry) => entry.blockerIds.length > 0)
    .map((entry) => ({
      ...entry,
      blockerIds: uniqueStrings(entry.blockerIds),
      count: uniqueStrings(entry.blockerIds).length,
    }));
  const categoryIds = (predicate) =>
    uniqueStrings(
      categories.filter(predicate).flatMap((entry) => entry.blockerIds),
    );

  return {
    schema: "iroha-demo-sccp-solana-blocker-resolution/v1",
    blockerCount: normalizedIds.length,
    categoryCounts: Object.fromEntries(
      categories.map((entry) => [entry.id, entry.count]),
    ),
    categories,
    runtimeInputBlockerIds: categoryById.get("runtime-input").blockerIds,
    tairaGovernanceBlockerIds: categoryById.get("taira-governance").blockerIds,
    governedProofMaterialBlockerIds: categoryById.get("governed-proof-material")
      .blockerIds,
    solanaVerifierBlockerIds: categoryById.get("solana-verifier").blockerIds,
    keyCustodyBlockerIds: categoryById.get("key-custody").blockerIds,
    liveEvidenceBlockerIds: categoryById.get("live-evidence").blockerIds,
    manifestMaterialBlockerIds:
      categoryById.get("manifest-material").blockerIds,
    publicEndpointBlockerIds: categoryById.get("public-endpoint").blockerIds,
    unknownBlockerIds: unknown.blockerIds,
    repoActionableBlockerIds: categoryIds((entry) => entry.repoActionable),
    operatorActionableBlockerIds: categoryIds(
      (entry) => entry.operatorActionable,
    ),
    unsafeToAutoFixBlockerIds: categoryIds((entry) => entry.unsafeToAutoFix),
    currentRuntimeCanSubmitRoute:
      categoryById.get("runtime-input").blockerIds.length === 0 &&
      categoryById.get("public-endpoint").blockerIds.length === 0,
    repoOnlyCompletionPossible: categories.every(
      (entry) => entry.repoActionable && !entry.unsafeToAutoFix,
    ),
  };
};

